INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1206431SF$$, $$Advanced EHF MILSATCOM (SPACE)$$, $$rdte_sf_ba5$$, $$ssc_milcom$$, 2026, 13825000, 0, 1020000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$The Space Modernization Initiative (SMI) evolves current and future SATCOM systems to develop a more affordable and resilient integrated enterprise capable of meeting near-term and emerging requirements. SMI will demonstrate technologies and Concepts of Operations (CONOPS) supporting the Protected Anti-jam Tactical SATCOM (PATS) family-of-systems capability that provides tactical-level military SATCOM (MILSATCOM) users protected, anti-jam SATCOM while operating in a contested environment. PATS is an integrated approach that includes the Protected Tactical Satellite Communications (PTS) and Protected Tactical Enterprise Service (PTES) programs to mitigate adversarial jamming effects by using the Protected Tactical Waveform (PTW). For this effort, SMI includes the Air Force - Army Anti-Jam Modem (A3M) to develop PTW-capable modems, providing high throughput and enhanced anti-jam capability in benign and contested environments. Finally, Global Broadcast Service (GBS) functionality will be added to the PATS modems. GBS implements a worldwide high-capacity satellite broadcast information system to provide a continuous, one-way, high-speed, high-volume flow of classified and unclassified intelligence products (full motion video, imagery, data) to garrisoned, deployed or moving forces. This program element may include necessary civilian pay expenses required to manage, execute, and deliver AEHF and SMI capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:          PE 1206431SF / Advanced EHF MILSATCOM (SPACE) System Development & Demonstration (SDD)$$, NULL, 1053000, 0, 0, NULL, NULL, 29, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 981000, 13598000, 10157000, 10157000, 0, 10157000, 0, $$The Space Modernization Initiative (SMI) evolves current and future SATCOM systems to develop a more affordable and resilient integrated enterprise capable of meeting near-term and emerging requirements. SMI will demonstrate technologies and Concepts of Operations (CONOPS) supporting the Protected Anti-jam Tactical SATCOM (PATS) family-of-systems capability that provides tactical-level military SATCOM (MILSATCOM) users protected, anti-jam SATCOM while operating in a contested environment. PATS is an integrated approach that includes the Protected Tactical Satellite Communications (PTS) and Protected Tactical Enterprise Service (PTES) programs to mitigate adversarial jamming effects by using the Protected Tactical Waveform (PTW). For this effort, SMI includes the Air Force - Army Anti-Jam Modem (A3M) to develop PTW-capable modems, providing high throughput and enhanced anti-jam capability in benign and contested environments. Finally, Global Broadcast Service (GBS) functionality will be added to the PATS modems. GBS implements a worldwide high-capacity satellite broadcast information system to provide a continuous, one-way, high-speed, high-volume flow of classified and unclassified intelligence products (full motion video, imagery, data) to garrisoned, deployed or moving forces. This program falls within the Satellite Communications (SATCOM) mission area which provides the space and dedicated ground architecture required to securely transport wideband, narrowband, tactical, and strategic satellite communications, including USSF-funded SATCOM terminals and commercial SATCOM activities. Space Force investment program interdependencies include: RDT&E Budget Line Items: Advanced EHF MILSATCOM (1206431SF); Commercial SATCOM Integration (1206445SF); Evolved Strategic SATCOM (ESS) (1206855SF); Family of Adv BLoS Terminals (FAB-T) (1203001SF); Narrowband Satellite Communications (1203109SF); Protected Tactical Enterprise Service (1206760SF); Protected Tactical Service (1206761SF; Space Tech Development & Prototyping (1206410SF); Tech Transition (Space) (1206458SF); Wideband Global SATCOM (SPACE) (1206433SF); Data Transport and Networking (1203156SF); Space Data Network (1203636SF); and elements of Procurement Budget Line Items: Family of Beyond Line-of-Sight Terminals (FBLOST); Mobile User Objective System (MUOS00); MILSATCOM (MILSAT); Wideband SATCOM Operational Management Systems (WSOMS0); Auxiliary Payloads (AUX000); Proliferated Low Earth Orbit SATCOM (PLEO00); PTES HUB (PTES00); ESS (ESS000). This program element may include necessary civilian pay expenses required to manage, execute, and deliver AEHF and SMI capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                   Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:         PE 1206431SF / Advanced EHF MILSATCOM (SPACE) System Development & Demonstration (SDD) This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1206432SF$$, $$Polar MILSATCOM (SPACE)$$, $$rdte_sf_ba5$$, $$ssc_milcom$$, 2026, 0, 250856000, 0, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$This program element acquires the Polar Military Satellite Communications (MILSATCOM) system that provides protected communications (anti-jam and low probability of intercept and detection) for users in the North Polar Region. In FY 2006, the Department of Defense (DoD) began funding Enhanced Polar System (EPS). The host spacecraft and the polar communications packages took advantage of the Advanced Extremely High Frequency (AEHF) technology including the extended Data Rate (XDR) waveform. The EPS Capability Development Document (CDD), approved by the Joint Requirements Oversight Council in September 2006, is based on a two-package, hosted XDR program with operational availability in CY 2015 and CY 2017. EPS is comprised of four segments: Payload, Ground Control, Gateway, and Terminal (acquired by each Service's Terminal Program Office). Milestone B review was completed April 2, 2014. In FY 2019, the United States Air Force (USAF) and Norwegian Ministry of Defense signed the Arctic Memorandum of Agreement (MOA), which enforces the international collaboration with Norway to host two EPS-Recapitalization (EPS-R) payloads on Space Norway-procured spacecraft. EPS-R developed and acquired two Extremely High Frequency (EHF) payloads that are hosted on Space Norway-procured spacecraft and to upgrade/modify the existing EPS Ground Control and Gateway. This program element may include necessary civilian pay expenses required to manage, execute, and deliver Polar MILSATCOM weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                               Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:       PE 1206432SF / Polar MILSATCOM (SPACE) System Development & Demonstration (SDD)$$, NULL, NULL, NULL, NULL, NULL, NULL, 30, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1206433SF$$, $$Wideband Global SATCOM (SPACE)$$, $$rdte_sf_ba5$$, $$ssc_milcom$$, 2026, 29609000, 0, 0, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$The Wideband Global SATCOM (WGS) System provides the Department of Defense (DoD) with high data rate military satellite communication (MILSATCOM) services in accordance with the Joint Space Management Board-approved MILSATCOM architecture (August 1996), the Joint Requirements Oversight Council (JROC)-approved MILSATCOM Capstone Requirements Document (October 1997), and JROC-approved WGS Operational Requirements Document (May 2000). Dual-frequency WGS satellites augment, then replace the DoD's Defense Satellite Communications System X-band service and augment one-way Global Broadcast Service Ka-band capabilities. In addition, WGS provides a high capacity two-way Ka-band Service. This program was originally conceived to augment the near-term "bandwidth gap" in warfighter communications needs but it remains to be the DoD's primary wideband system. WGS has 10 operational legacy satellites and WGS-11 and WGS-12 (WGS-11 & 12) are in development as the first modern digital payloads using commercial technologies providing more coverage beams than their existing WGS predecessors combined and delivering twice the operational capacity than previous WGS analog satellites. Funding for this effort supports the advanced capabilities for WGS-11 & 12 under development for launch in FY 2026 and FY 2027, respectively. Project 657107, WGS Space Systems Resiliency Upgrade, enables the addition of WGS-12 to the constellation due to the increase in required capability on the core WGS ground system, Global SATCOM Configuration Control Element (GSCCE), to support both WGS-11 and 12 simultaneously from the same operational site. In May 2024, the DoD Chief Information Office endorsed re-direction of Beam Optimization & Operational Management (BOOM) funds towards GSCCE modernization. In FY2026 the program will restart WGS-BOOM. The objective of the WGS-BOOM effort is for the development, integration, and test of advanced beam management to enhance WGS-11 & 12 baseline beam management tools in support of rapid planning and control. This effort will develop and deploy capabilities across the WGS enterprise to provide WGS-11 & 12 management and control (M&C) ground enhancements with responsive end-to-end mission planning, protection, and terminal synchronized capabilities. WGS BOOM development includes upgrades to the WGS-11 & 12 payload control system, Global SATCOM Configuration Control Element (GSCCE), to decrease operational timelines to be able to better track and support airborne ISR missions as they move through the theater. The 10 operational legacy WGS satellites on-orbit were each developed by building on heritage WGS capabilities. Continually improving WGS capability and leveraging advances in Boeing commercial technology, in FY 2018 the DoD has procured a more advanced single WGS-11 satellite (previously referenced as WGS-11+ to designate meeting the Congressional intent of two satellites, herein referenced as WGS-11 with the new Congressional add of WGS-12) enhancing support to the US military, DoD, and allied nations with more flexibility and mission capacity to support dispersed users than previous WGS spacecraft. The new capabilities allow operators to create unique coverage anywhere within the satellite's field of view and custom designed for the mission at hand. In FY 2024, the DoD contracted for WGS-12, a clone of the WGS-11 spacecraft with the Protected Tactical SATCOM (PTS) as a hosted payload. WGS-12 was added to the WGS Block II Follow On Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                             Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:           PE 1206433SF / Wideband Global SATCOM (SPACE) System Development & Demonstration (SDD) (B2FO) contract. The advanced beam management capabilities of WGS-11 & 12 payloads will produce more coverage beams (over 1500) than the entire existing WGS constellation and deliver twice the mission capacity than WGS-10 can, thereby operationally increases the availability of military-grade communications. The objective of the GSCCE modernization effort is to integrate GSCCE architecture utilized to manage and control both the legacy 10 WGS satellites and additional WGS-11 & 12 satellites in production into the modern Wideband SATCOM Operational Management System (WSOMS) Mediated Interoperability Infrastructure (WMII) hardware. This effort will develop and deploy modern hardware and software capabilities across the WGS enterprise to provide payload management tools in support of planning and control to all WGS satellites, to include the advanced capabilities of WGS-11 & 12. This funding will also be utilized to integrate and deploy the full suite of Mitigation and Anti-Jam Enhancements (MAJE) nodes for WGS 1-10 X-band interference mitigation capabilities. WGS Block I consists of satellites 1-3, Block II consists of satellites 4-6 and Block II Follow On (B2FO) includes satellites 7-12. WGS satellites 1-10 have been funded, procured and launched in previous budget cycles. With the operation of WGS-5, the constellation provided global coverage and Full Operational Capability (FOC) was declared on 12 May 2014. In the Consolidated Appropriations Act, FY 2018, Congress added 600M Space Force Procurement in FY 2018 for "full funding for WGS-11 and WGS-12." A sole source Request for Proposal was released to Boeing in June 2018. A final decision was made to procure a single satellite (once designated as WGS-11+ but will herein forward be referenced as WGS-11) with twice the operational capacity of WGS-10 as the best approach to delivering the directed additional WGS capacity in a cost- effective manner. WGS-11 will host a PTS payload providing robust anti-jam capability to tactical warfighters, funded by the Protected Tactical SATCOM (PTS) program in PE 1206761SF. In the Consolidated Defense Appropriations Act, FY 2023, Congress added 442M Space Force Procurement in FY 2023 for "Protected Wideband Satellite" to procure a protected wideband satellite providing resilient, jam resistant tactical communications to support warfighter needs. The United States Space Force (USSF) has interpreted the Congressional add is intended to procure a WGS-12 satellite equipped with the tactical anti-jam capabilities identical with WGS-11 including the PTS hosted payload. The funding will cover costs for a WGS-12 spacecraft clone of the WGS-11 to include a PTS hosted payload. The current B2FO Acquisition Program Baseline (APB) allows for procurement of a WGS-12 and the acquisition is a Firm Fixed Price effort with integration of PTS in FY 2026 and launch in FY 2027. Since the Congressional add did not include funding for a launch vehicle, ground activities and other Government costs, the USSF is pursuing International Partner (IP) sources to cover additional funding required by FY 2025 these additional requirements. IPs receive constellation-wide WGS resources commensurate with their financial contributions to the WGS system. Investment from IPs to cooperatively enhance the system started in November 2007 through a bilateral Memorandum of Understanding (MOU) with Australia to fund WGS space vehicle (SV)-6, launch and launch services. Five countries (Canada, Denmark, Netherlands, Luxembourg, New Zealand) signed a new multilateral WGS MOU in CY 2012 and funded the procurement of WGS SV-9. In CY 2017, Amendment One to the WGS MOU leveraged additional funding for resiliency enhancements from two new IPs (Czech Republic and Norway). In CY 2022, nine countries signed Amendment Two to the multilateral MOU (adds Belgium and United Kingdom) to cover necessary ground upgrades and launch costs for WGS-11 not covered by the FY 2018 Congressional add, and extends the duration of the WGS MOU, as amended, through September 2039. There is an agreement in coordination via the State Department regarding IP collaboration with WGS-12. Space Systems Command (SSC) provides program management, engineering Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:            PE 1206433SF / Wideband Global SATCOM (SPACE) System Development & Demonstration (SDD) expertise through FY 2028. Discussions for potential future partnerships regarding the Wideband Global SATCOM (WGS) program continue in support of National Space Policy and improved operational efficiency. This program element may include necessary civilian pay expenses required to manage, execute, and deliver WGS-11 & 12 for weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, NULL, 0, 0, 0, NULL, NULL, 31, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 0, 19296000, 0, 0, 0, 0, 0, $$The Wideband Global SATCOM (WGS) System provides the Department of War (DoW) with high data rate military satellite communication (MILSATCOM) services in accordance with the Joint Space Management Board-approved MILSATCOM architecture (August 1996), the Joint Requirements Oversight Council (JROC)-approved MILSATCOM Capstone Requirements Document (October 1997), and JROC-approved WGS Operational Requirements Document (May 2000). Dual-frequency WGS satellites augment, then replace the DoW's Defense Satellite Communications System X-band service and augment one-way Global Broadcast Service Ka-band capabilities. In addition, WGS provides a high capacity two-way Ka-band Service. This program was originally conceived to augment the near-term "bandwidth gap" in warfighter communications needs but it remains to be the DoW's primary wideband system. WGS has 10 operational legacy satellites and WGS-11 and WGS-12 (WGS-11 & 12) are in development as the first modern digital payloads using commercial technologies providing more coverage beams than their existing WGS predecessors combined and delivering twice the operational capacity than previous WGS analog satellites. Funding for this effort supports the advanced capabilities for WGS-11 & 12 under development for launch in FY 2026 and FY 2027, respectively. Project 657107, WGS Space Systems Resiliency Upgrade, enables the WGS ground system, Global SATCOM Configuration Control Element (GSCCE), to control both WGS-11 and WGS-12 satellites from one control site, clearing the way for WGS-12 to join the constellation. In May 2024, the DoW Chief Information Office endorsed re-direction of Beam Optimization & Operational Management (BOOM) funds towards GSCCE modernization. In FY2026 the program will restart WGS-BOOM. The objective of the WGS-BOOM effort is for the development, integration, and test of advanced beam management to enhance WGS-11 & 12 baseline beam management tools in support of rapid planning and control. This effort will develop and deploy capabilities across the WGS enterprise to provide WGS-11 & 12 management and control (M&C) ground enhancements with responsive end-to-end mission planning, protection, and terminal synchronized capabilities. WGS BOOM development includes upgrades to the WGS-11 & 12 payload control system, Global SATCOM Configuration Control Element (GSCCE), to decrease operational timelines effectively and support airborne ISR missions as they move through the theater. This program falls within the Satellite Communications (SATCOM) mission area which provides the space and dedicated ground architecture required to securely transport wideband, narrowband, tactical, and strategic satellite communications, including USSF-funded SATCOM terminals and commercial SATCOM activities. Program interdependencies include: Advanced EHF MILSATCOM (1206431SF); Commercial SATCOM Integration (1206445SF); Evolved Strategic SATCOM (ESS) (1206855SF); Family of Adv BLoS Terminals (FAB-T) (1203001SF); MILSATCOM Terminals (1203601SF); Narrowband Satellite Communications (1203109SF); Polar MILSATCOM (SPACE)1206432SF); Protected Tactical Enterprise Service (1206760SF); Protected Tactical Service (1206761SF); SATCOM O&M (1203605SF); Space Tech Development & Prototyping (1206410SF); Tech Transition (Space) (1206458SF); Wideband Global SATCOM (SPACE) (1206433SF); Wideband Global System Satellites (1203600SF). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                             Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:              PE 1206433SF / Wideband Global SATCOM (SPACE) System Development & Demonstration (SDD) The 10 operational legacy WGS satellites on-orbit were each developed by building on heritage WGS capabilities. Continually improving WGS capability and leveraging advances in Boeing commercial technology, in FY 2018 the DoW procured a more advanced single WGS-11 satellite (previously referenced as WGS-11+ to designate meeting the Congressional intent of two satellites, herein referenced as WGS-11 with the new Congressional add of WGS-12) enhancing support to the US military, DoW, and allied nations with more flexibility and mission capacity to support dispersed users than previous WGS spacecraft. The new capabilities allow operators to create unique coverage anywhere within the satellite's field of view and custom designed for the mission at hand. In FY 2024, the DoW contracted for WGS-12, a clone of the WGS-11 spacecraft with the Protected Tactical SATCOM (PTS) as a hosted payload. WGS-12 was added to the WGS Block II Follow On (B2FO) contract. The advanced beam management capabilities of WGS-11 & 12 payloads will produce more coverage beams (over 1500) than the entire existing WGS constellation and deliver twice the mission capacity than WGS-10 can, thereby operationally increases the availability of military-grade communications. The objective of the GSCCE modernization effort is to integrate GSCCE architecture utilized to manage and control both the legacy 10 WGS satellites and additional WGS-11 & 12 satellites in production into the modern Wideband SATCOM Operational Management System (WSOMS) Mediated Interoperability Infrastructure (WMII) hardware. This effort will develop and deploy modern hardware and software capabilities across the WGS enterprise to provide payload management tools in support of planning and control to all WGS satellites, to include the advanced capabilities of WGS-11 & 12. This funding will also be utilized to integrate and deploy the full suite of Mitigation and Anti-Jam Enhancements (MAJE) nodes for WGS 1-10 X-band interference mitigation capabilities. WGS Block I consists of satellites 1-3, Block II consists of satellites 4-6 and Block II Follow On (B2FO) includes satellites 7-12. WGS satellites 1-10 have been funded, procured and launched in previous budget cycles. With the operation of WGS-5, the constellation provided global coverage and Full Operational Capability (FOC) was declared on 12 May 2014. In the Consolidated Appropriations Act, FY 2018, Congress added 600M Space Force Procurement in FY 2018 for "full funding for WGS-11 and WGS-12." A sole source Request for Proposal was released to Boeing in June 2018. A final decision was made to procure a single satellite (once designated as WGS-11+ but will herein forward be referenced as WGS-11) with twice the operational capacity of WGS-10 as the best approach to delivering the directed additional WGS capacity in a cost- effective manner. WGS-11 will host a PTS payload providing robust anti-jam capability to tactical warfighters, funded by the Protected Tactical SATCOM (PTS) program in PE 1206761SF. In the Consolidated Defense Appropriations Act, FY 2023, Congress added 442M Space Force Procurement in FY 2023 for "Protected Wideband Satellite" to procure a protected wideband satellite providing resilient, jam resistant tactical communications to support warfighter needs. The United States Space Force (USSF) has interpreted the Congressional add is intended to procure a WGS-12 satellite equipped with the tactical anti-jam capabilities identical with WGS-11 including the PTS hosted payload. The funding covered costs for a WGS-12 spacecraft clone of the WGS-11 to include a PTS hosted payload. The current B2FO Acquisition Program Baseline (APB) allows for procurement of a WGS-12, and the acquisition is a Firm Fixed Price effort with integration of PTS in FY 2026 and launch in FY 2027. Since the Congressional add did not include funding for a launch vehicle, ground activities and other Government costs, the USSF is pursuing International Partner (IP) sources to cover additional funding required by FY 2025 these additional requirements. IPs receive constellation-wide WGS resources commensurate with their financial contributions to the WGS system. Investment from IPs to cooperatively enhance the system started in November 2007 through a bilateral Memorandum of Understanding (MOU) with Australia to fund WGS space vehicle (SV)-6, launch and launch Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                   Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:              PE 1206433SF / Wideband Global SATCOM (SPACE) System Development & Demonstration (SDD) services. Five countries (Canada, Denmark, Netherlands, Luxembourg, New Zealand) signed a new multilateral WGS MOU in CY 2012 and funded the procurement of WGS SV-9. In CY 2017, Amendment One to the WGS MOU leveraged additional funding for resiliency enhancements from two new IPs (Czech Republic and Norway). In CY 2022, nine countries signed Amendment Two to the multilateral MOU (adds Belgium and United Kingdom) to cover necessary ground upgrades and launch costs for WGS-11 not covered by the FY 2018 Congressional add, and extends the duration of the WGS MOU, as amended, through September 2039. An updated MOU is in coordination to include WGS 12. Currently with International participants for signature, expected by end-of-February 2026. Space Systems Command (SSC) provides program management engineering expertise through FY 2028. Discussions for potential future partnerships regarding the Wideband Global SATCOM (WGS) program continue in support of National Space Policy and improved operational efficiency. This program element may include necessary civilian pay expenses required to manage, execute, and deliver WGS-11 & 12 for weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1206438SF$$, $$Space Control Technology$$, $$rdte_sf_ba4$$, $$ssc_sda$$, 2026, 60106000, 0, 62195000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$This program supports a range of activities including systems engineering, technology planning, development, demonstrations and prototyping, and testing, as well as modeling, simulations and exercises to support development and maturation of tactics and procedures for a responsive and resilient Space Control mission area. This includes technology development and prototyping for Defensive Counterspace (DCS) and Offensive Counterspace (OCS) and the necessary systems engineering for the warfighter to effectively employ such systems. Specifically supported are DCS and Space Domain Awareness (SDA) activities, which include developing threat warning payloads for monitoring, detecting, identifying, tracking, assessing, verifying, categorizing, and characterizing objects and events in space. Additionally, Integration and Technology Futures project supports the development of payload prototypes and space defense force packages for protecting U.S. space systems, resources, and operations from enemy attempts to negate, interfere, or destroy them. Specific OCS activities include disruption, denial, or degradation (and associated Electronic Support) of adversary space systems that may be used for purposes hostile to U.S. national security interests. Rapid Reaction Capabilities in response to immediate warfighter needs in the Space Control mission area are developed within the Rapid Reaction Branch (RRB). Depending on the magnitude of Combatant Command Urgent Operational Needs (UON), this program may not include necessary funding for all contingency deployments. As required, necessary funding will be requested through established Joint Urgent Operational Need (JUON) and Overseas Contingency Operations (OCO) processes. Joint Space Integration Technology leverages knowledge of the space environment and impacts on weapon systems to prototype, develop, test, and field joint multi- domain software and modeling solutions to fill capability gaps for Combatant Commanders. Military Application of the Space Environment (MASE) project consolidates and integrates current space environment science and technology advancements to provide capability for joint force systems in all domains to address immediate and evolving threats to U.S. forces operating in harm's way. The data provided supports rapid and agile demonstrations, exercises, and war games that provide essential validation of delivered capabilities to improve operational effectiveness. This program element may include necessary civilian pay expenses required to manage, execute, and deliver SCT weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 4:              PE 1206438SF / Space Control Technology Advanced Component Development & Prototypes (ACD&P) This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 59471000, 55555000, 53444000, NULL, NULL, 16, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 60027000, 59148000, 62031000, 62031000, 0, 62031000, 54393000, $$Space Systems Command (SSC) is developing, prototyping, and executing the Integration and Technology Futures Project, the Rapid Reaction Project, and the Space Force TENCAP Project (Program 642611) for Guardians across the combat power mission area. As a result, the Service will deter, neutralize, defeat and/or destroy counterspace threats and defend the space domain. These three projects fall within the Combat Power mission area which provides the systems required to protect and defend space-based capabilities and ensure space superiority by enabling and executing combat operations in space. Space Force investment program interdependencies include: RDT&E Budget Line Items: Space- Based Moving Target Indicator (1203155SF); Long Range Kill Chains (1203154SF); Counterspace systems (1206421SF); Space Superiority ISR (1203330SF) and elements of Procurement Budget Line Items: Space Mods (SPCMOD); Space Based Air Moving Target Indicator (AMTI00); Ground Moving Target Indicator (GMTI00); and Counterspace Systems (CTRSPC). The Space Control Technology program supports a range of activities including systems engineering, technology planning, development, demonstrations and prototyping, and testing, as well as modeling, simulations and exercises to support development and maturation of tactics and procedures for a responsive and resilient Space Control mission area. This includes technology development and prototyping for Defensive Counterspace (DCS) and Offensive Counterspace (OCS) and the necessary systems engineering for the warfighter to effectively employ such systems. Specifically supported are DCS and Space Domain Awareness (SDA) activities, which include developing threat warning payloads for monitoring, detecting, identifying, tracking, assessing, verifying, categorizing, and characterizing objects and events in space. Additionally, Integration and Technology Futures (I&TF) project supports requirements development of space enterprise kill chains integration, including the identification and assessment of risks and gaps in the current and future space control architecture. I&TF also provides engineering requirements and configuration management, Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                            R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 4:     PE 1206438SF / Space Control Technology Advanced Component Development & Prototypes (ACD&P) including development of governance documents, change management, risk management, and engineering reviews. I&TF provides functional analysis support critical to determining requirements for the future space control architecture. Specific OCS activities include disruption, denial, or degradation (and associated Electromagnetic Support) of adversary space systems that may be used for purposes hostile to U.S. national security interests. Rapid Reaction Capabilities in response to immediate warfighter needs in the Space Control mission area are developed within the Rapid Reaction Branch (RRB). Depending on the magnitude of Combatant Command Urgent Operational Needs (UON), this project may not include necessary funding for all contingency deployments. As required, necessary funding will be requested through established Joint Urgent Operational Need (JUON) and Overseas Contingency Operations (OCO) processes. SF TENCAP continues and expands efforts and increases space warfighter effectiveness, previously funded by AF TENCAP. SF TENCAP accomplishes this work through the exploitation of national capabilities and promotes cross- domain integration of these capabilities into Space Domain Awareness, Offensive Space Operations, and Defensive Space Operations. Develops these capabilities into operational prototypes delivered directly to the warfighter, intelligence community, and a program of record inside of two years. It is not a new start. Joint Space Integration Technology leverages knowledge of the space environment and impacts on weapon systems to prototype, develop, test, and field joint multi- domain software and modeling solutions to fill capability gaps for Combatant Commanders. Military Application of the Space Environment (MASE) project consolidates and integrates current space environment science and technology advancements to provide capability for joint force systems in all domains to address immediate and evolving threats to U.S. forces operating in harm's way. The data provided supports rapid and agile demonstrations, exercises, and war games that provide essential validation of delivered capabilities to improve operational effectiveness. MASE falls within the Weather mission area which provides mission-critical environmental intelligence to support global military operations and delivers essential meteorological and oceanographic data to joint forces across all domains and detects space-based environmental threats to protect vital U.S. and allied space assets. Space Force investment program interdependencies include: RDT&E Budget Line Items: EO/IR Weather Systems (1203710SF); Space Force Weather Services Research (0604002SF); Weather Satellite Follow-on (1206422SF); elements of Space Situation Awareness Operations (1203940SF); elements of Space Control Technology (1206438SF); and elements of Procurement Budget Line Item: Space Mods (SPCMOD). This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program element may include necessary civilian pay expenses required to manage, execute, and deliver SCT weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                    Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 4:        PE 1206438SF / Space Control Technology Advanced Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1206440SF$$, $$Next-Gen OPIR -- Ground$$, $$rdte_sf_ba5$$, $$ssc_sensing$$, 2026, 358330000, 0, 500395000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$Next-Generation Overhead Persistent Infrared (Next-Gen OPIR) Ground (Project 657106): Next-Gen OPIR Ground, also known as Future Operationally Resilient Ground Evolution (FORGE), consists of a modern Command and Control (C2) capability, modernization of Mission Data Processing (MDP) to implement an open framework and develop mission applications, required development and upgrades to Relay Ground Stations (RGS), to provide a modern survivable and endurable architecture to meet USSF current and future space domain needs. FORGE will provide the flexibility and scalability to integrate new satellites, sensors and capabilities more rapidly and efficiently in order to meet evolving threats and warfighter needs. The Next-Gen OPIR Ground efforts enable cyber enhancements for both space and ground systems. FORGE C2 will introduce infrastructure and common platform services, mission unique software such as Telemetry, Tracking, and Commanding (TT&C), and mission management to support initial Next-Gen OPIR Space satellite launches without driving risk into the FORGE development schedule. The program has established a risk reduction ground capability, Next-Gen OPIR Interim Operations (NIO), based on a limited Space Based Infrared System (SBIRS) Block 20 solution. The total cost of the FORGE Rapid Prototype Middle Tier of Acquisition (MTA) effort is 2,301.9 million. The RGS development and fielding is not contained in the MTA effort, as it consists of stand-alone Acquisition Category (ACAT) III efforts. The FORGE Rapid Prototype MTA is fully funded across the Future Years Defense Program. The FY 2026 request for Next-Gen OPIR -- Ground includes 358,330 thousand of discretionary and 194,600 thousand of mandatory (reconciliation) for a total of 552,930. The mandatory funds reinstate Next-Generation Polar (NGP) as part of the overall FORGE development. This ensures a modern, survivable, and enduring architecture that meets USSF's current and future domain needs. Further information for this reconciliation request is provided in Section 20003 (Missile Defense) of the Reconciliation Exhibit. This program element may include necessary civilian pay expenses required to manage, execute, and deliver Next-Gen OPIR Ground system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 126398SF This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:         PE 1206440SF / Next-Gen OPIR -- Ground System Development & Demonstration (SDD)$$, NULL, 669035000, 652239000, 536423000, NULL, NULL, 32, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 500395000, 348330000, 761425000, 761425000, 0, 761425000, 398181000, $$The program office is developing the Next-Generation Overhead Persistent Infrared (Next-Gen OPIR) Ground (Project 657106) for Guardians across Missile Warning and Missile Tracking (MW/MT) mission area. As a result, the Service will advance space-based technology associated with Golden Dome, and deter, neutralize, defeat and/or destroy counterspace threats and defend the homeland. Next-Gen OPIR Ground, also known as Future Operationally Resilient Ground Evolution (FORGE), consists of a modern Command and Control (C2) capability, modernization of Mission Data Processing (MDP) to implement an open framework and develop mission applications, required development and upgrades to Relay Ground Stations (RGS), to provide a modern survivable and endurable architecture to meet USSF current and future space domain needs. FORGE will provide the flexibility and scalability to integrate new satellites, sensors and capabilities more rapidly and efficiently in order to meet evolving threats and warfighter needs. The Next- Gen OPIR Ground efforts enable cyber enhancements for both space and ground systems. FORGE C2 will introduce infrastructure and common platform services, mission unique software such as Telemetry, Tracking, and Commanding (TT&C), and mission management to support initial Next-Gen OPIR Space satellite launches without driving risk into the FORGE development schedule. The program has established a risk reduction ground capability, Next-Gen OPIR Interim Operations (NIO), based on a limited Space Based Infrared System (SBIRS) Block 20 solution. The FORGE program was designated as a Software Acquisition Pathway (SWP) on 30 July 2025. The total cost of the FORGE SWP effort is 2,930.62 million. The RGS development and fielding is not contained in the SWP effort, as it consists of stand-alone Acquisition Category (ACAT). The FORGE SWP is fully funded across the Future Years Defense Program. Resilient Ground Architecture establishes a proliferated missile warning processing & data distribution ground architecture that holistically creates a robust day-today operation with predictable and graceful degradation to a Survivable & Endurable mission—providing increased resilience through all phases of conflict and threat spectrum. Fielding RGA capabilities meets/aligns with JROC-M 059-23, PPD-35/40, and CJCSI 3296. This program element may include necessary civilian pay expenses required to manage, execute, and deliver Next-Gen OPIR Ground system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 126398SF. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:           PE 1206440SF / Next-Gen OPIR -- Ground System Development & Demonstration (SDD) This program falls within the Missile Warning and Missile Tracking (MW/MT) mission area which provides the multi-orbit space and ground architecture required to detect and track missiles and hypersonic glide vehicles worldwide. Space Force investment program interdependencies include: RDT&E Budget Line Items: Missile Defense Radars (1203873SF); Ballistic Missile EW Systems (1203909SF); Joint Tactical Ground System (1208053SF); NCMC - TW/ AA System (1203906SF); Next - Generation OPIR (1206442SF); Next - Generation - GEO (1206443SF); Next - Generation - Ground (1206440SF); Next - Generation - Polar (1206444SF); NUDET Detection System (1203913SF); Resilient MW / MT - LEO (1206446SF); Resilient MW / MT - MEO (1206447SF) and elements of Procurement Budget Line Item: Space Mods (SPCMOD) This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1206442SF$$, $$Next Generation OPIR$$, $$rdte_sf_ba5$$, $$ssc_sensing$$, 2026, 189621000, 0, 190951000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$The Overhead Persistent Infrared (OPIR) program succeeds the current Space Based Infrared System (SBIRS) and will provide improved missile warning, missile defense, battlespace awareness, and technical intelligence collection capabilities that are more survivable against emerging adversary threats. The program will deliver prototypes and demonstrations of novel Missile Warning/Missile Tracking (MW/MT) approaches and technologies; invest in critical industrial base gaps to meet future production needs; mature advanced target tracking and typing concepts to meet emerging threats; and an integration effort will identify, plan, manage and execute integration activities at the enterprise level. Due to funding transfers to segregate Next-Gen OPIR into other Program Elements, PE 1206442SF is now comprised of two projects: 1. Next-Gen OPIR Space Modernization Initiative (SMI) and 2. Integration. 1. SMI (Project 657009/Program Element 1206442SF): To better enable response to emerging global missile threats, SMI advances capabilities and reduces risk through four major thrust areas: Demonstrations/Prototypes, Technology Maturation, Data Exploitation, and Wide Field of View (WFOV) On-Orbit Testbed Mission Integration, each with a flagship investment. Demonstrations mature technologies by delivering ground and on-orbit prototypes. These demonstrations advance OPIR capabilities for missile warning and tracking, ensuring low risk transition of advanced technology to future operational systems. Each year, Space Systems Command (SSC) conducts a review of all technical development needs for future OPIR systems across the stakeholder community to include the Missile Defense Agency (MDA), Space Development Agency (SDA), Air Force Research Lab (AFRL), and mission partners to analyze future capability gaps and shared technology development interests in order to identify and prioritize development projects to maximize utility of SMI funds. Technology Maturation focuses development on advanced infrared sensing optics and electronics, resiliency hardware and software, and on-board processing algorithms and on-board computers. The investments within the Technology Maturation portfolio are heavily focused on developments that will benefit programs across SSC, SDA, MDA, and the Intelligence Community. Data Exploitation provides return-on-investment aimed at ingestion and fusion of current and future proliferated sensor program data to enhance missile warning, missile tracking, missile defense, battlespace awareness and technical intelligence mission capabilities. This includes the processing and exploitation of legacy SBIRS wideband data and its fusion with Wide Field of View (WFOV) Geosynchronous Earth Orbit (GEO) wideband sensor data focused on dimmer threat targets and the Indo-Pacific Command (INDOPACOM). Subsequently, this work will expand to include ingestion and fusion of WFOV Low Earth Orbit (LEO), Resilient Missile Warning/Missile Tracking (MW/MT), Medium-Earth Orbit (MEO) and other data as it becomes available. The large volume of data and event detections expected from these proliferated OPIR sensors threaten to overwhelm the enterprise and operators. Data Exploitation will focus on incorporating automation and innovation to overcome these challenges. Initiatives include leveraging Artificial Intelligence and Machine Learning (AI/ML) to reduce cognitive workload on operators while maintaining full operator oversight. The Data Exploitation thrust area includes maintaining the Boulder Ground Innovation Facility (BGIF) as the host location for the OPIR Tool, Applications, and Processing Laboratory (TAP Lab) Information Technology (IT) infrastructure and DevSecOps Continuous Integration/Continuous Delivery (CI/CD) pipeline used by the OPIR TAP Lab to develop and field advanced software applications and algorithms. WFOV On-Orbit Testbed Mission Integration, brings new or enhanced capabilities to the operational community. SMI funds engineering activities to reduce both production and future system costs through manufacturing and producibility enhancements, and Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                             Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:            PE 1206442SF / Next Generation OPIR System Development & Demonstration (SDD) technology insertion. SMI includes risk reduction for Program of Record (PoR) to deliver capabilities on threat-relevant timelines to include Future Operationally Resilient Ground Evolution (FORGE), Next-Gen Geosynchronous Earth Orbit (GEO), and Resilient Missile Warning/Missile Tracking (MW/MT), Medium-Earth Orbit (MEO). 2. Integration (Project 657123/Program Element 1206442SF): The Next-Gen Overhead Persistent Infrared (OPIR) Integration project includes efforts associated with the Government's primary role in, and tasks necessary to accomplish, the critical lead system integration function between the OPIR enterprise segments (Next- Gen Geosynchronous Earth Orbit (GEO), Next-Gen Ground, and the Resilient MW/MT Medium Earth Orbit (MEO)/Low Earth Orbit (LEO) architecture). This includes Enterprise Systems Engineering and Integration (SE&I) activities, Modeling and Simulation activities, and Digital Engineering activities, to include Model Based System Engineering (MBSE). The focus of the Integration project is on system-level integration activities, between the Next-Gen OPIR segments, such as Space to Ground. This differs from integration within the individual program segments, which refers to subsystem-level integration between subsystems such as a spacecraft bus to the mission payload. The Government Integrator directs the Next-Gen OPIR current enterprise architecture and system definition, controls and validates interfaces, ensures compatibility of Next-Gen systems, and develops/manages plans for execution and fielding of the Next-Gen OPIR Enterprise. Further, the Integrator, through various Federally Funded Research and Development Centers (FFRDCs), government partners, and contractors, executes unique MBSE and integration requirements of each segment by providing modeling, simulation, and technical analyses of Government-directed enterprise level trades among the Next-Gen OPIR segments. These trades lead to definition, management, maintenance, and evolution of the Next-Gen OPIR Enterprise requirements and interface technical documents to ensure the integrity of the enterprise technical baseline. This program element may include necessary civilian pay expenses required to manage, execute, and deliver Next-Gen OPIR weapon system capabilities. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206389SF. This program is in Budget Activity 5, System Development and Demonstration (SDD) because the majority of Projects under PE 1206442SF have been declared Section 804 Rapid Prototype efforts conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, NULL, 221162000, 223360000, 228306000, NULL, NULL, 33, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 190951000, 189621000, 209851000, 209851000, 0, 209851000, 232871000, $$The program office is developing and prototyping the Resilient Next Generation OPIR (Projects 657009 & 657123) for Guardians across Missile Warning and Missile Tracking (MW/MT) mission area. As a result, the Service will deter, neutralize, defeat and/or destroy counterspace threats and defend the homeland. The Overhead Persistent Infrared (OPIR) program succeeds the current Space Based Infrared System (SBIRS) and will provide improved missile warning, missile defense, battlespace awareness, and technical intelligence collection capabilities that are more survivable against emerging adversary threats. The program will deliver prototypes and demonstrations of novel Missile Warning/Missile Tracking (MW/MT) approaches and technologies; invest in critical industrial base gaps to meet future production needs; mature advanced target tracking and typing concepts to meet emerging threats; and an integration effort will identify, plan, manage and execute integration activities at the enterprise level. Due to funding transfers to segregate Next-Gen OPIR into other Program Elements, PE 1206442SF is now comprised of two projects: 1. Next-Gen OPIR Space Modernization Initiative (SMI) and 2. Integration. 1. SMI (Project 657009/Program Element 1206442SF): To better enable response to emerging global missile threats, SMI advances capabilities and reduces risk through five major thrust areas: Demonstrations/Prototypes, Technology Maturation, Data Processing and Analytics, Wide Field of View (WFOV) On-Orbit Testbed Mission Integration, and Capability Exploitation each with a flagship investment. The use of demonstrations help mature technologies by delivering ground and on-orbit prototypes. These demonstrations advance OPIR capabilities for missile warning and tracking, ensuring low risk transition of advanced technology to future operational systems. Each year, Space Systems Command (SSC) conducts a review of all technical development needs for future OPIR systems across the stakeholder community to include the Missile Defense Agency (MDA), Space Development Agency (SDA), Air Force Research Lab (AFRL), and mission partners to analyze future capability gaps and shared technology development interests in order to identify and prioritize development projects to maximize utility of SMI funds. Technology Maturation focuses development on advanced infrared sensing optics and electronics, resiliency hardware and software, and on-board processing algorithms and on-board computers. The investments within the Technology Maturation portfolio are heavily focused on developments that will benefit programs across SSC, SDA, MDA, and the Intelligence Community. Data Processing & Analytics provides return-on-investment aimed at ingestion and fusion of current and future proliferated sensor program data to enhance missile warning, missile tracking, missile defense, battlespace awareness and technical intelligence mission capabilities. This includes the processing and exploitation of legacy SBIRS wideband data and its fusion with Wide Field of View (WFOV) Geosynchronous Earth Orbit (GEO) wideband sensor data focused on dimmer threat targets and the Indo-Pacific Command (INDOPACOM). Subsequently, this work will expand to include ingestion and fusion of WFOV Low Earth Orbit (LEO), Resilient Missile Warning/Missile Tracking (MW/MT), Medium-Earth Orbit (MEO) and other data as it becomes available. The large volume of data and event detections expected from these proliferated OPIR sensors threaten to overwhelm the enterprise and operators. Data Processing & Analytics will focus on incorporating Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:               PE 1206442SF / Next Generation OPIR System Development & Demonstration (SDD) automation and innovation to overcome these challenges. Initiatives include leveraging Artificial Intelligence and Machine Learning (AI/ML) to reduce cognitive workload on operators while maintaining full operator oversight. The Data Processing and Analytics thrust area includes maintaining the Boulder Ground Innovation Facility (BGIF) as the host location for the Overhead Persistent Infrared (OPIR) Tool, Applications, and Processing Laboratory (TAP Lab) Information Technology (IT) infrastructure and Development, Security, Operations (DevSecOps) Continuous Integration/Continuous Delivery (CI/CD) pipeline used by the OPIR TAP Lab to develop and field advanced software applications and algorithms. Wide Field of View (WFOV) On-Orbit Testbed Mission Integration, brings new or enhanced capabilities to the operational community. Capability Exploitation focuses on rapidly fielding, integrating, and operationally employing prototype capabilities derived from Space Modernization Initiative (SMI) investments, emphasizing speed, iteration, and real-world use to deliver residual operational capability, generate operational insight, reduce transition risk, and directly inform requirements, Concept of Operations (CONOPS), and future acquisition decisions. SMI funds engineering activities to reduce both production and future system costs through manufacturing and producibility enhancements, and technology insertion. SMI includes risk reduction for Program of Record (PoR) to deliver capabilities on threat-relevant timelines to include Future Operationally Resilient Ground Evolution (FORGE), Next-Gen Geosynchronous Earth Orbit (GEO), and Resilient Missile Warning/Missile Tracking (MW/MT), and Medium-Earth Orbit (MEO). 2. Integration (Project 657123/Program Element 1206442SF): The Next-Gen Overhead Persistent Infrared (OPIR) Integration project includes efforts associated with the Government's primary role in, and tasks necessary to accomplish, the critical lead system integration function between the OPIR enterprise segments (Next- Gen Geosynchronous Earth Orbit (GEO), Next-Gen Ground, and the Resilient MW/MT Medium Earth Orbit (MEO)/Low Earth Orbit (LEO) architecture). This includes Enterprise Systems Engineering and Integration (SE&I) activities, Modeling and Simulation activities, and Digital Engineering activities, to include Model Based System Engineering (MBSE). The focus of the Integration project is on system-level integration activities, between the Next-Gen OPIR segments, such as Space to Ground. This differs from integration within the individual program segments, which refers to subsystem-level integration between subsystems such as a spacecraft bus to the mission payload. The Government Integrator directs the Next-Gen OPIR current enterprise architecture and system definition, controls and validates interfaces, ensures compatibility of Next-Gen systems, and develops/manages plans for execution and fielding of the Next-Gen OPIR Enterprise. Further, the Integrator, through various Federally Funded Research and Development Centers (FFRDCs), government partners, and contractors, executes unique MBSE and integration requirements of each segment by providing modeling, simulation, and technical analyses of Government-directed enterprise level trades among the Next-Gen OPIR segments. These trades lead to definition, management, maintenance, and evolution of the Next-Gen OPIR Enterprise requirements and interface technical documents to ensure the integrity of the enterprise technical baseline. This program falls within the Missile Warning and Missile Tracking (MW/MT) mission area which provides the multi-orbit space and ground architecture required to detect and track missiles and hypersonic glide vehicles worldwide. Space Force investment program interdependencies include: RDT&E Budget Line Items: Missile Defense Radars (1203873SF); Ballistic Missile EW Systems (1203909SF); Joint Tactical Ground System (1208053SF); NCMC - TW/ AA System (1203906SF); Next - Generation OPIR (1206442SF); Next - Generation - GEO (1206443SF); Next - Generation - Ground (1206440SF); Next - Generation - Polar (1206444SF); NUDET Detection System (1203913SF); Resilient MW / MT - LEO (1206446SF); Resilient MW / MT - MEO (1206447SF) and elements of Procurement Budget Line Item: Space Mods (SPCMOD). This program element may include necessary civilian pay expenses required to manage, execute, and deliver Next-Gen OPIR weapon system capabilities. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206389SF. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                   Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:         PE 1206442SF / Next Generation OPIR System Development & Demonstration (SDD) This program is in Budget Activity 5, System Development and Demonstration (SDD) because the majority of Projects under PE 1206442SF have been declared Section 804 Rapid Prototype efforts conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1206443SF$$, $$Next-Gen OPIR -- GEO$$, $$rdte_sf_ba5$$, $$ssc_sensing$$, 2026, 432073000, 2854126000, 458727000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$Next-Generation Overhead Persistent Infrared (Next-Gen OPIR) Geosynchronous Earth Orbit (GEO) (Project 657120): The primary mission is to provide initial missile warning of a strategic missile attack on the US, deployed forces and allies. The Next-Gen OPIR GEO (NGG) missile warning satellites enhance detection and improve reporting of intercontinental ballistic missile launches, submarine ballistic missile launches, and tactical ballistic missile launches. Development consists of new payloads in a highly resilient bus, providing real-time persistent global infrared coverage to meet validated Joint Requirements Oversight Council (JROC) requirements on current and future space domain demands. The Program Office is acquiring the NGG capability in two contract actions. Phase 1 awarded in August 2018 encompasses requirements analysis, design/development, critical path flight hardware procurement, and risk reduction efforts leading to a System Critical Design Review (CDR) in October 2021. Phase 2 was awarded in January 2021 for the manufacturing, assembly, system integration and test, launch, and early on-orbit test through operational acceptance of NGG satellites 1-3. The Department has assessed the third Space Vehicle (SV) is not required as a result of continued positive performance of the Space-Based Infrared System (SBIRS) constellation and the anticipated full operational capability of the Medium Earth Orbit (MEO), Program Element 1206447SF/ Low Earth Orbit (LEO), Program Element 1206446SF missile tracking constellation. As a result, the program has removed the third satellite development efforts. NGG is now a 2 SV baseline. The NGG program has been designated as a Major Capability Acquisition. This program element may include necessary civilian pay expenses required to manage, execute, and deliver Next-Gen OPIR GEO system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:           PE 1206443SF / Next-Gen OPIR -- GEO System Development & Demonstration (SDD)$$, NULL, 366635000, 123126000, 95157000, NULL, NULL, 34, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 458727000, 422173000, 485703000, 485703000, 0, 485703000, 0, $$The program office is developing the Next-Generation Overhead Persistent Infrared (Next-Gen OPIR) Geosynchronous Earth Orbit (GEO) (Project 657120) for Guardians across Missile Warning and Missile Tracking (MW/MT) mission area. As a result, the Service will deter, neutralize, defeat and/or destroy counterspace threats and defend the homeland while providing resilient infrastructure, equipment and personnel. Next-Generation Overhead Persistent Infrared (Next-Gen OPIR) Geosynchronous Earth Orbit (GEO) (Project 657120): The primary mission is to provide initial missile warning of a strategic missile attack on the US, deployed forces and allies. The Next-Gen OPIR GEO (NGG) missile warning satellites enhance detection and improve reporting of intercontinental ballistic missile launches, submarine ballistic missile launches, and tactical ballistic missile launches. Development consists of new payloads in a highly resilient bus, providing real-time persistent global infrared coverage to meet validated Joint Requirements Oversight Council (JROC) requirements on current and future space domain demands. The Program Office is acquiring the NGG capability in two contract actions. Phase 1 awarded in August 2018 encompasses requirements analysis, design/development, critical path flight hardware procurement, and risk reduction efforts leading to a System Critical Design Review (CDR) in October 2021. Phase 2 was awarded in January 2021 for the manufacturing, assembly, system integration and test, launch, and early on-orbit test through operational acceptance of NGG satellites 1-3. The Department has assessed the third Space Vehicle (SV) is not required as a result of continued positive performance of the Space-Based Infrared System (SBIRS) constellation and the anticipated full operational capability of the Medium Earth Orbit (MEO), Program Element 1206447SF/ Low Earth Orbit (LEO), Program Element 1206446SF missile tracking constellation. As a result, the program has removed the third satellite development efforts. NGG is now a 2 SV baseline. The NGG program has been designated as a Major Capability Acquisition. This program falls within the Missile Warning and Missile Tracking (MW/MT) mission area which provides the multi-orbit space and ground architecture required to detect and track missiles and hypersonic glide vehicles worldwide. Space Force investment program interdependencies include: RDT&E Budget Line Items: Missile Defense Radars (1203873SF); Ballistic Missile EW Systems (1203909SF); Joint Tactical Ground System (1208053SF); NCMC - TW/ AA System (1203906SF); Next - Generation OPIR (1206442SF); Next - Generation - GEO (1206443SF); Next - Generation - Ground (1206440SF); Next - Generation - Polar (1206444SF); NUDET Detection System (1203913SF); Resilient MW / MT - LEO (1206446SF); Resilient MW / MT - MEO (1206447SF) and elements of Procurement Budget Line Item: Space Mods (SPCMOD). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                    Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:        PE 1206443SF / Next-Gen OPIR -- GEO System Development & Demonstration (SDD) The total cost of the NGG program is 9130.8 million which includes prior year costs from Program Element (PE) 1206442SF, Project 657120 of 1338.6 million and PE 1206442F, Project 657120 of 1704.2 million. This program element may include necessary civilian pay expenses required to manage, execute, and deliver Next-Gen OPIR GEO system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1206444SF$$, $$Next-Gen OPIR -- Polar$$, $$rdte_sf_ba5$$, $$ssc$$, 2026, 0, 1320594000, 769478000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$Next-Generation Overhead Persistent Infrared (OPIR) Space, Block 0 Polar (Project 657121): The primary mission is to provide initial missile warning of a ballistic missile attack on the US, its deployed forces, and its allies. Next-Gen OPIR Space enhances detection and improves reporting of intercontinental ballistic missile launches, submarine launched ballistic missile launches, and tactical ballistic missile launches. Development consists of the Next-Gen OPIR Polar (NGP) missile warning satellites with new payloads in a highly resilient bus, providing real-time persistent global infrared coverage to meet validated Joint Requirements Oversight Council (JROC) requirements on current and future space domain demands. The Program Office is acquiring the NGP capability through three contract phases. Phase 0, awarded in June 2018, encompassed system requirements analysis and risk reduction efforts, which led to a March 2020 System Requirements Review (SRR). Phase 1, awarded in May 2020, encompasses engineering design, unit hardware procurement, component and subsystem qualification and design, critical path flight hardware procurement, and risk reduction efforts, and culminated in a System Critical Design Review (CDR) in August 2024. Phase 2 was awarded in October 2024, encompassing manufacture, assembly, integration, test and launch of two satellites. The NGP program has been designated as a Major Capability Acquisition. This program element may include necessary civilian pay expenses required to manage, execute, and deliver Next-Gen OPIR Polar system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. The FY 2026 request for Next-Gen OPIR Polar (NGP) includes $0 of discretionary and $723,700 thousands of mandatory (reconciliation) for a total of $723,700 thousand. The mandatory funds fully fund NGP. Further information for this reconciliation request is provided in Section 20003 (Missile Defense) of the Reconciliation Exhibit. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                            Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:              PE 1206444SF / Next-Gen OPIR -- Polar System Development & Demonstration (SDD)$$, NULL, 0, 0, 0, NULL, NULL, 35, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 769478000, 436521000, 0, 0, 0, 0, 0, $$The program office is developing the Next-Generation Overhead Persistent Infrared (Next-Gen OPIR) Polar (Project 657121) for Guardians across Missile Warning and Missile Tracking (MW/MT) mission area. As a result, the Service will deter, neutralize, defeat, and/or destroy counterspace threats and defend the homeland while providing resilient infrastructure, and equipment. Next-Generation Overhead Persistent Infrared (Nex-Gen OPIR) Space, Block 0 Polar (Project 657121): The primary mission is to provide initial missile warning of a ballistic missile attack on the US, its deployed forces, and its allies. Next-Gen OPIR Space enhances detection and improves reporting of intercontinental ballistic missile launches, submarine launched ballistic missile launches, and tactical ballistic missile launches. Development consists of the Next-Gen OPIR Polar (NGP) missile warning satellites with new payloads in a highly resilient bus, providing real-time persistent global infrared coverage to meet validated Joint Requirements Oversight Council (JROC) requirements on current and future space domain demands. The program office is acquiring the NGP capability through three contract phases. Phase 0, awarded in June 2018, encompassed system requirements analysis and risk reduction efforts, which led to a March 2020 System Requirements Review (SRR). Phase 1, awarded in May 2020, encompasses engineering design, unit hardware procurement, component and subsystem qualification and design, critical path flight hardware procurement, and risk reduction efforts, and culminated in a System Critical Design Review (CDR) in August 2024. Phase 2 was awarded in October 2024, encompassing manufacture, assembly, integration, test and launch of two satellites. This program falls within the Missile Warning and Missile Tracking (MW/MT) mission area which provides the multi-orbit space and ground architecture required to detect and track missiles and hypersonic glide vehicles worldwide. Space Force investment program interdependencies include: RDT&E Budget Line Items: Missile Defense Radars (1203873SF); Ballistic Missile EW Systems (1203909SF); Joint Tactical Ground System (1208053SF); NCMC - TW/AA System (1203906SF); Next - Generation OPIR (1206442SF); Next - Generation - GEO (1206443SF); Next - Generation - Ground (1206440SF); Next - Generation - Polar (1206444SF); NUDET Detection System (1203913SF); Resilient MW / MT - LEO (1206446SF); Resilient MW / MT - MEO (1206447SF) and elements of Procurement Budget Line Item: Space Mods (SPCMOD). The NGP program had been designated as a Major Capability Acquisition. The total cost of the NGP program is 3,440.763 million which includes prior year costs from Program Element (PE) 1206442SF (Next-Gen OPIR), Project 657121 (Next-Gen OPIR Space, Block 0 Polar) of 330.136 million, and PE 1206442F (Mission OPIR), Project 657121 (Next-Gen OPIR Space, Block 0 Polar) of 153.742 million. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:            PE 1206444SF / Next-Gen OPIR -- Polar System Development & Demonstration (SDD) This program element may include necessary civilian pay expenses required to manage, execute, and deliver Next-Gen OPIR Polar system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1206445SF$$, $$Commercial SATCOM (COMSATCOM) Integration$$, $$rdte_sf_ba5$$, $$dw_disa$$, 2026, 132060000, 0, 134487000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$Commercial Satellite Communication (COMSATCOM) Integration develops, prototypes and demonstrates the capabilities required to fully leverage COMSATCOM as part of the Department of Defense's (DoD) SATCOM enterprise. The United States Space Force (USSF) has determined that an enterprise approach to the procurement, delivery and management of its SATCOM capabilities is the best means to create an environment that is responsive to Combatant Commanders and other users across the spectrum of conflict. In addition, an enterprise approach will improve affordability, Department purchasing power and mission assurance. Project 650140, COMSATCOM, will rapidly prototype and deliver Enterprise Management and Control (EM&C) integration tools and mission applications enabling warfighters to operate responsive and resilient SATCOM as a single enterprise. Project 651126, COMSATCOM Infrastructure, will develop and stand up COMSATCOM business and customer management tools, finalizing the Congressionally directed migration from Defense Information Systems Agency (DISA) systems to USSF systems. Development of enhanced COMSATCOM acquisition capabilities leverage enterprise innovation activities focused on transforming how DoD acquires, accesses and deploys COMSATCOM capabilities. The COMSATCOM Project 650140 includes an International Medium Earth Orbit (MEO) SATCOM for the USSF to partner, explore, prototype, and integrate an international commercial SATCOM service into the DoD SATCOM enterprise. Luxembourg (LUX) MEO establishes the baseline satellite capability in partnership with the LUX Ministry of Defense (MoD), leveraging the commercial satellite communications system in MEO. The funding in the International MEO SATCOM will be used to demonstrate the onboarding of MEO commercial SATCOM services into the SATCOM architecture and Space Data Transport Force Design. Demonstrations will include utilizing EM&C for provisioning and planning, usage of Protected Tactical Waveform (PTW) over MEO Commercial SATCOM and integration of Protected Tactical Enterprise Services (PTES) hubs into commercial SATCOM capable gateways. Early adaption of capability will also be used to prototype and demonstrate fiber resiliency for large gateway backhaul via space. Capacity will further be used to demonstrate platforms use of multi-orbital terminals for Airborne Intelligence, Surveillance, and Reconnaissance (AISR), maritime communications and ground force mobile communications. Luxembourg is also procuring commercial SATCOM services and will contribute to international demonstration and testing of integrated and interoperable ground and space architecture elements. This partnership will also enable additional international partners to join and demonstrate the ability to bulk buy future capacity together to drive cost savings. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:         PE 1206445SF / Commercial SATCOM (COMSATCOM) Integration System Development & Demonstration (SDD) This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, NULL, 70995000, 71975000, 73396000, NULL, NULL, 36, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 124117000, 127261000, 68554000, 68554000, 0, 68554000, 74979000, $$Commercial Satellite Communication (COMSATCOM) Integration is developing, prototyping, demonstrating, and executing Enterprise Management and Control (EM&C) integration tools and mission software applications (Project 650140) for Guardians across the Satellite Communications Mission Area; the Service Institutional Function: Operations; and the Operational Unit Force Structure: Warfighting, Operations Commands, and Combat Service Support. As a result, the Service will (1) streamline capabilities development through institutional processes, (2) improve readiness and operational reach of existing force structure, (3) augment, supplement, and/or integrate Allies, partners, and commercial space to USSF units, and (4) achieve resilient infrastructure, equipment, and personnel. COMSATCOM Integration develops, prototypes and demonstrates the capabilities required to fully leverage COMSATCOM as part of the Department of War's (DoW) SATCOM enterprise. The United States Space Force (USSF) has determined that an enterprise approach to the procurement, delivery and management of its SATCOM capabilities is the best means to create an environment that is responsive to Combatant Commanders and other users across the spectrum of conflict. In addition, an enterprise approach will improve affordability, Department purchasing power and mission assurance. Project 650140, COMSATCOM, will rapidly prototype and deliver EM&C integration tools and mission applications enabling warfighters to operate responsive and resilient SATCOM as a single enterprise. Project 651126, COMSATCOM Infrastructure, will develop and stand up COMSATCOM business and customer management tools, finalizing the Congressionally directed migration from Defense Information Systems Agency (DISA) systems to USSF systems. Development of enhanced COMSATCOM acquisition capabilities leverage enterprise innovation activities focused on transforming how DoW acquires, accesses and deploys COMSATCOM capabilities. The COMSATCOM Project 650140 includes an International Medium Earth Orbit (MEO) SATCOM for the USSF to partner, explore, prototype, and integrate an international commercial SATCOM service into the DoW SATCOM enterprise. Luxembourg (LUX) MEO establishes the baseline satellite capability in partnership with the LUX Ministry of Defense (MoD), leveraging the commercial satellite communications system in MEO. The funding in the International MEO SATCOM will be used to demonstrate the onboarding of MEO commercial SATCOM services into the SATCOM architecture and Space Data Transport Force Design. Demonstrations will include utilizing EM&C for provisioning and planning, usage of Protected Tactical Waveform (PTW) over MEO Commercial SATCOM and integration of Protected Tactical Enterprise Services (PTES) hubs into commercial SATCOM capable gateways. Early adaption of capability will also be used to prototype and demonstrate fiber resiliency for large gateway backhaul via space. Capacity will further be used to demonstrate platforms use of multi- orbital terminals for Airborne Intelligence, Surveillance, and Reconnaissance (AISR), maritime communications and ground force mobile communications. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                              Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:              PE 1206445SF / Commercial SATCOM (COMSATCOM) Integration System Development & Demonstration (SDD) Luxembourg is also procuring commercial SATCOM services and will contribute to international demonstration and testing of integrated and interoperable ground and space architecture elements. This partnership will also enable additional international partners to join and demonstrate the ability to bulk buy future capacity together to drive cost savings. This program falls within the Satellite Communications (SATCOM) mission area which provides the space and dedicated ground architecture required to securely transport wideband, narrowband, tactical, and strategic satellite communications, including USSF-funded SATCOM terminals and commercial SATCOM activities. Program interdependencies include: Advanced EHF MILSATCOM (1206431SF); Commercial SATCOM Integration (1206445SF); Evolved Strategic SATCOM (ESS) (1206855SF); Family of Adv BLoS Terminals (FAB-T) (1203001SF); MILSATCOM Terminals (1203601SF); Narrowband Satellite Communications (1203109SF); Polar MILSATCOM (SPACE) (1206432SF); Protected Tactical Enterprise Service (1206760SF); Protected Tactical Service (1206761SF); SATCOM O&M (1203605SF); Space Tech Development & Prototyping (1206410SF); Tech Transition (Space) (1206458SF); Wideband Global SATCOM (SPACE) (1206433SF); Wideband Global System Satellites (1203600SF). This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1206446SF$$, $$Resilient Missile Warning Missile Tracking - Low Earth Orbit (LEO)$$, $$rdte_sf_ba5$$, $$ssc_sensing$$, 2026, 1757354000, 0, 1697821000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$The Space Development Agency (SDA) is developing and demonstrating next generation space capabilities for the joint warfighter enabled by proliferation of satellites in Low Earth Orbit (LEO) and a new acquisition model utilizing rapid spiral development. SDA is developing capabilities to address a wide range of Department of Defense (DoD) space needs as stated in the National Defense Strategy and DoD Space Vision, including advanced missile tracking and global surveillance enabling beyond- line-of-sight targeting. SDA will orchestrate the rapid development and fielding of the Proliferated Warfighter Space Architecture (PWSA), a resilient military sensing and data transport capability via a proliferated space architecture in LEO. This program element funds the development and demonstration of space technologies to deliver Missile Warning, Missile Tracking and Missile Defense (MW/MT/MD) and Fire Control capabilities to U.S. joint warfighting forces in bi-annual tranches, which began in FY 2022. This program element may include necessary civilian pay expenses and contractor support required to support delivery of the MW/MT/MD capability. The FY 2026 cost of the Tranche 1 (T1) Tracking Layer Middle Tier of Acquisition effort is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify Future Years Defense Program funding in a future budget submission. The FY 2026 cost of the Tranche 2 (T2) Tracking Layer Middle Tier of Acquisition effort is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify Future Years Defense Program funding in a future budget submission. The FY 2026 cost of the Tranche 3 (T3) Tracking Layer Middle Tier of Acquisition effort is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify Future Years Defense Program funding in a future budget submission. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:             PE 1206446SF / Resilient Missile Warning Missile Tracking - Low Earth Orbit (LEO) System Development & Demonstration (SDD)$$, NULL, 2933204000, 3130564000, 2945565000, NULL, NULL, 37, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 1697821000, 1695454000, 3564176000, 3564176000, 0, 3564176000, 3010514000, $$The Space Development Agency (SDA) is developing and demonstrating the Proliferated Warfighter Space Architecture (PWSA) Tracking Layer (Project 657LEO) for Guardians across the Combat Support, Satellite Communications, Operations, and Warfighting mission areas. As a result, the Service will improve readiness and operational reach of existing force structure and continue to advance all near term effects. SDA is rapidly developing and demonstrating next generation space capabilities for the joint warfighter enabled by proliferation of satellites in Low Earth Orbit (LEO) and a new acquisition model utilizing rapid spiral development. SDA is advancing a proliferated space architecture to address a wide range of Department of War (DoW) space needs aligned with the United States Space Force Space Warfighting Framework, including advanced missile tracking and global surveillance enabling beyond- line-of-sight targeting. In coordination with Combatant Commands and other DoW Space stakeholders, SDA will orchestrate the rapid development and fielding of the Proliferated Warfighter Space Architecture (PWSA), a resilient military sensing and data transport capability via a proliferated space architecture in LEO. This program element funds the development and demonstration of space technologies to deliver Missile Warning, Missile Tracking and Missile Defense (MW/MT/MD) and Fire Control capabilities to U.S. joint warfighting forces in bi-annual tranches, which began in FY 2022. As part of the PWSA, SDA is building and fielding the Tracking Layer, using a proliferated constellation of satellites to provide resiliency through a layered sensor net to ensure space sensing necessary to respond to incoming threats. The PWSA Tracking Layer provides worldwide persistent visibility at fidelity levels which enable low- latency detection and real-time tracking to meet critical operational timelines. The total cost of the Tracking Layer Tranche 1 (TRKT1) Middle Tier of Acquisition effort is $2,841.700 million, including RDT&E and procurement of prototype units. The TRKT1 program is fully funded across the Future Years Defense Program. The total cost of the Tracking Layer Tranche 2 (TRKT2) Middle Tier of Acquisition effort is $3,965.900 million, including RDT&E and procurement of prototype units. The TRKT2 program is fully funded across the Future Years Defense Program. The total cost of the Tracking Layer Tranche 3 (TRKT3) Middle Tier of Acquisition effort is $5,249.800 million, including RDT&E and procurement of prototype units. The TRKT3 program is fully funded across the Future Years Defense Program. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:           PE 1206446SF / Resilient Missile Warning Missile Tracking - Low Earth Orbit (LEO) System Development & Demonstration (SDD) This program falls within the Missile Warning and Missile Tracking (MW/MT) mission area which provides the multi-orbit space and ground architecture required to detect and track missiles and hypersonic glide vehicles worldwide. Space Force investment program interdependencies include: RDT&E Budget Line Items: Missile Defense Radars (1203873SF); Ballistic Missile EW Systems (1203909SF); Joint Tactical Ground System (1208053SF); NCMC - TW/ AA System (1203906SF); Next - Generation OPIR (1206442SF); Next - Generation - GEO (1206443SF); Next - Generation - Ground (1206440SF); Next - Generation - Polar (1206444SF); NUDET Detection System (1203913SF); Resilient MW / MT - LEO (1206446SF); Resilient MW / MT - MEO (1206447SF) and elements of Procurement Budget Line Item: Space Mods (SPCMOD) This program element may include necessary civilian pay expenses and contractor support required to manage, execute, and deliver the MW/MT/MD capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 1201198SF. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1206447SF$$, $$Resilient Missile Warning Missile Tracking - Medium Earth Orbit (MEO)$$, $$rdte_sf_ba5$$, $$ssc_sensing$$, 2026, 686348000, 0, 756349000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$The United States Space Force Space Systems Command and Space Development Agency are collaborating to deliver Overhead Persistent Infrared capabilities, in concert with Department of Defense and Intelligence Community partners, to support a proliferated space architecture that is resilient by design and capable of operating through contested environments. Resilient Missile Warning/Missile Tracking - Medium Earth Orbit space and ground efforts pivot the Department of the Air Force's legacy missile warning force design to a more resilient multi-orbit approach to counter advanced missiles, hypersonic glide vehicles, and fractional orbital bombardment threats. Missile Warning, Missile Tracking Medium Earth Orbit was originally anchored in Missile Warning and Missile Defense Capability Development Document requirements validated by the Joint Requirements Oversight Council; there is now a Joint Requirement Oversight Council-approved Capability Development Document Annex with very specific Medium Earth Orbit and Low Earth Orbit requirements. Constellation resiliency is foundational to the Department of the Air Force's Resilient Missile Warning and Tracking force design, therefore, the Overhead Persistent Infrared Family of Systems, including Missile Warning, Missile Tracking Medium Earth Orbit, is designed to work cohesively to gain and maintain custody of a spectrum of missile threats. The Medium Earth Orbit program will deploy space assets in multiple Epochs to allow for incremental capability delivery and to ensure competition throughout the lifecycle of the program. Resilient Missile Warning, Missile Tracking Medium Earth Orbit will bolster legacy Space Based Infrared Satellite and Next-Gen Overhead Persistent Infrared capabilities and will independently satisfy mission area Capability Development Document requirements for missile tracking by as early as FY 2033. FY 2026 funding supports final build, test, and delivery of flight payloads and buses to support Epoch 1, space vehicle level assembly integration and test, and launch/early orbit operations. FY 2026 funding also includes ground activities previously captured in PE 1206448SF, Project 657124, that continue ground segment Mission Data Processing application development and integration, command and control software and facilities build and integration into the Medium Earth Orbit Space Operations Center, and ground entry point site construction to support on-orbit initialization in FY 2027. In order to preserve Epoch 1 schedule and avoid additional costs, the Program Executive Officer approved the transition of the space segment development to a single vendor as of September 2024. Space Systems Command, Space Development Agency, and the Missile Defense Agency will continue to use the Combined Program Office construct to develop and implement a system-of-systems integration strategy across for Missile Warning, Missile Tracking and Missile Defense constellations supporting Low Earth Orbit, Medium Earth Orbit, Geosynchronous Orbit and Polar Orbit regimes. Resilient Missile Warning, Missile Tracking Medium Earth Orbit Epoch 1 is now comprised of a single space vendor and multiple ground lines of effort to include the following: -Space vehicle development efforts are currently underway with Millennium Space Systems with the potential delivery of up to twelve space vehicles. -Delivery includes: design, build, hardware integration, testing, delivery, launch vehicle integration, space vehicle. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:                PE 1206447SF / Resilient Missile Warning Missile Tracking - Medium Earth Orbit (MEO) System Development & Demonstration (SDD) -Launch & early orbit operations, calibration, tuning, flying, and delivery of formatted two-dimensional tracks into the Real-Time Transfer Service for incorporation with other sensors data necessary for warning/tracking requirements and operations. -Mission Data Processing and unique ground software on contract as of December 2022. -Perform the integration of the space vehicles into the operations center for command and control at the Boulder Ground Innovation Facility (BGIF). -Develop integration command and control and Mission Data Processing software to operate constellation of Medium Earth Orbit space vehicles for supporting multiple collection layers. -Additional ground applications for ground resource management and sensor tasking will be included as part of the Operations and Integration contract and transition to the Ground Management and Integration contract in support of Epoch 2. -Acquire, build, install, test, and operate ground-based antennas for uplink/downlink of commands and mission data. At least two sites and six apertures are required for Epoch 1.The antennas for Epoch 1 are on contract as of December 2022 and will be located at Schriever Space Force Base, Colorado, and Al Udeid Air Base, Qatar. An additional antenna at Clear Space Force Station, Alaska will be modified to support Epoch 1 ground contacts. Additional overseas locations are being considered to ensure Ground Entry Point availability, communication diversity, and mission assurance. -Test, assess, and validate sensor performance on the ground and on-orbit to ensure track data is integrated by Program of Record data and fusion operational programs such as Future Operationally Resilient Ground Evolution (FORGE) (PE 1206440SF), Ballistic Missile Defense Overhead Persistent Infrared Architecture, other classified partners and missions, research and development multi-intelligence fusion (PE 1206442SF), and intelligence characterization. Space vehicle testing is on contract as of December 2022. Fusion software studies underway with FORGE program as of March 2023. Additional studies planned with Ballistic Missile Defense Overhead Persistent Infrared Architecture started in FY 2024. -Mature integrated digital model: support Space System Command's role as the mission area integrator, perform resiliency analyses, baseline future requirements, and assess performance against current and new targets. On contract as of May 2021. The Epoch 2 acquisition began in FY 2025 and will continue in FY 2026 with the acquisition of additional planes of missile warning and tracking space vehicle capability (total number of space vehicles depend on source selection); managing up to two prime vendors delivering space vehicles as well as Ground Command and Control and Mission Data Processing software. The program will leverage the FORGE framework and Boulder Ground Innovation Facility for both operations and underlying hardware and software framework services and will continue the tasking and fusion architecture that began in Epoch 1 for Epoch 2 acquisitions. Furthermore, Epoch 2 will continue to manage a ground management & integration contractor to assist with on boarding space craft and vendor operations into the BGIF. Epoch 2 will expand upon the current Ground Entry Points to procure additional antennas necessary to support space vehicle planes. Finally, Epoch 2 will also continue the use of model- based systems engineering and digital models to ease integration. FY 2024 35.000M Recission is not captured due to a database error. The FY 2026 cost of the Resilient Missile Warning/Missile Track - Medium Earth Orbit (MW/MT - MEO) Epoch 1 Middle Tier of Acquisition effort is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify Future Years Defense Program funding in a future budget request. The total cost of the MW/MT - MEO Epoch 2 Middle Tier of Acquisition effort is 3,846.5M, including RDT&E and procurement of prototype units. The MW/MT - MEO Epoch 2 program is fully funded across the Future Years Defense Program. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:          PE 1206447SF / Resilient Missile Warning Missile Tracking - Medium Earth Orbit (MEO) System Development & Demonstration (SDD) This program element may include necessary civilian pay expenses required to manage, execute, and deliver Missile Warning, Missile Tracking capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, NULL, 1589750000, 1591857000, 1749492000, NULL, NULL, 38, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 756349000, 675848000, 1413662000, 1413662000, 0, 1413662000, 2000070000, $$The program office is developing and prototyping the Resilient Missile Warning Tracking (MWT) MEO (Project 657MEO) for Guardians across Missile Warning and Missile Tracking (MW/MT) mission area. As a result, the Service will advance space-based technology associated with Golden Dome, and deter, neutralize, defeat and/ or destroy counterspace threats and defend the homeland. A new class of threat requires a new class of architecture. Since legacy systems alone cannot maintain custody of advanced, dim and maneuverable missile threats, Resilient MWT delivers a multi-orbit architecture designed to defeat new threats, support homeland defense, Combatant Command operations and the broader missile defense kill chain. The United States Space Force Space Systems Command and Space Development Agency are collaborating to deliver Overhead Persistent Infrared capabilities, in concert with Department of War and Intelligence Community partners, to support a proliferated space architecture that is resilient by design and capable of operating through contested environments. Resilient Missile Warning and Tracking - Medium Earth Orbit space and ground efforts pivot the Department of the Air Force's legacy missile warning force design to a more resilient multi-orbit approach to counter advanced missiles, hypersonic glide vehicles, and fractional orbital bombardment threats. Resilient Missile Warning and Tracking Medium Earth Orbit was originally anchored in Missile Warning and Missile Defense Capability Development Document requirements validated by the Joint Requirements Oversight Council; there is now a Joint Requirement Oversight Council-approved Capability Development Document Annex with very specific Medium Earth Orbit and Low Earth Orbit requirements. Constellation resiliency is foundational to the Department of the Air Force's Resilient Missile Warning and Tracking force design, therefore, the Overhead Persistent Infrared Family of Systems, including Missile Warning and Tracking Medium Earth Orbit, is designed to work cohesively to gain and maintain custody of a spectrum of missile threats. This program falls within the Missile Warning and Missile Tracking (MW/MT) mission area which provides the multi-orbit space and ground architecture required to detect and track missiles and hypersonic glide vehicles worldwide. Space Force investment program interdependencies include: RDT&E Budget Line Items: Missile Defense Radars (1203873SF); Ballistic Missile EW Systems (1203909SF); Joint Tactical Ground System (1208053SF); NCMC - TW/ AA System (1203906SF); Next - Generation OPIR (1206442SF); Next - Generation - GEO (1206443SF); Next - Generation - Ground (1206440SF); Next - Generation - Polar (1206444SF); NUDET Detection System (1203913SF); Resilient MW / MT - LEO (1206446SF); Resilient MW / MT - MEO (1206447SF) and elements of Procurement Budget Line Item: Space Mods (SPCMOD). The Medium Earth Orbit program will deploy space assets in multiple Epochs to allow for incremental capability delivery and to ensure competition throughout the lifecycle of the program. Resilient Missile Warning and Tracking Medium Earth Orbit will bolster legacy Space Based Infrared Satellite and Next-Gen Overhead Persistent Infrared capabilities and will independently satisfy mission area Capability Development Document requirements for missile tracking by as early as FY Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                            Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:               PE 1206447SF / Resilient Missile Warning Missile Tracking - Medium Earth Orbit (MEO) System Development & Demonstration (SDD) 2033. FY 2026 funding supports final build, test, and delivery of flight payloads and buses to support Epoch 1, space vehicle level assembly integration and test, and launch/early orbit operations. FY 2026 funding also includes ground activities previously captured in PE 1206448SF, Project 657124, that continue ground segment Mission Data Processing application development and integration, command and control software and facilities build and integration into the Medium Earth Orbit Space Operations Center, and ground entry point site construction to support on-orbit initialization in FY 2027. In order to preserve Epoch 1 schedule and avoid additional costs, the Program Executive Officer (PEO) approved the transition of the space segment development to a single vendor as of September 2024. Space Systems Command, Space Development Agency, and the Missile Defense Agency will continue to use the Combined Program Office construct to develop and implement a system-of-systems integration strategy across for Missile Warning and Tracking and Missile Defense constellations supporting Low Earth Orbit, Medium Earth Orbit, Geosynchronous Orbit and Polar Orbit regimes. Resilient Missile Warning and Tracking Medium Earth Orbit Epoch 1 is now comprised of a single space vendor and multiple ground lines of effort to include the following: -Space vehicle development efforts are currently underway with Millennium Space Systems for the delivery of twelve space vehicles. -Delivery includes: design, build, hardware integration, testing, delivery, launch vehicle integration, space vehicle. -Launch & early orbit operations, calibration, tuning, flying, and delivery of formatted two-dimensional tracks into the Real-Time Transfer Service for incorporation with other sensors data necessary for warning/tracking requirements and operations. -Mission Data Processing and unique ground software on contract as of December 2022. -Perform the integration of the space vehicles into the operations center for command and control at the Boulder Ground Innovation Facility (BGIF). -Develop integration command and control and Mission Data Processing software to operate constellation of Medium Earth Orbit space vehicles for supporting multiple collection layers. -Additional ground applications for ground resource management and sensor tasking will be included as part of the Operations and Integration contract and transition to the Ground Management and Integration contract in support of all Epochs. -Acquire, build, install, test, and operate ground-based antennas for uplink/downlink of commands and mission data. At least two sites and six apertures are required for Epoch 1. The antennas for Epoch 1 are on contract as of December 2022 and will be located at Schriever Space Force Base, Colorado, and Al Udeid Air Base, Qatar. An additional set of antennas at Clear Space Force Station, Alaska will be modified to support Epoch 1 ground contacts. Additional overseas locations are necessary to ensure Ground Entry Point (GEP) availability for future Epochs and will improve communication diversity, and mission assurance. -Test, assess, and validate sensor performance on the ground and on-orbit to ensure track data is integrated by Program of Record data and fusion operational programs such as Future Operationally Resilient Ground Evolution (FORGE) (PE 1206440SF), Ballistic Missile Defense Overhead Persistent Infrared Architecture (BOA), other classified partners and missions, research and development multi-intelligence fusion (PE 1206442SF), and intelligence characterization. Space vehicle testing is on contract as of December 2022. Fusion software studies underway with FORGE program as of March 2023, and with BOA as of 2024. -Mature integrated digital model: support Space System Command's role as the mission area integrator, perform resiliency analyses, baseline future requirements, and assess performance against current and new targets. On contract as of May 2021. The Epoch 2 acquisition began in FY 2025 and will continue in FY 2027 with the acquisition of additional planes of missile warning and tracking space vehicle capability (total number of space vehicles depend on source selection); managing up to two prime vendors delivering space vehicles as well as Ground Command and Control and Mission Data Processing software. The program will leverage the FORGE framework and BGIF for both operations and underlying hardware and software framework services and will continue the tasking and fusion architecture that began in Epoch 1 for Epoch 2 acquisitions. Furthermore, Epoch 2 will continue to manage a ground Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:           PE 1206447SF / Resilient Missile Warning Missile Tracking - Medium Earth Orbit (MEO) System Development & Demonstration (SDD) management & integration contractor to assist with on boarding space craft and vendor operations into the BGIF. Epoch 2 will expand upon the current GEPs to procure additional antennas necessary to support space vehicle planes. Finally, Epoch 2 will also continue the use of model-based systems engineering and digital models to ease integration. This program element may include necessary civilian pay expenses required to manage, execute, and deliver Missile Warning and Tracking capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1206458SF$$, $$Tech Transition (Space)$$, $$rdte_sf_ba4$$, $$sf$$, 2026, 326144000, 0, 209247000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$The Tech Transition (Space) Program addresses the gaps between USSF Force Design activities, initial system-level technology or concept development and demonstration, and successful acquisition and operational capability implementation. This program also matures new warfighting concepts to rapidly develop and experiment with fieldable prototypes to assess military utility of transition-ready weapon systems. Following the guidance in the National Defense Strategy, the Department of the Air Force has institutionalized Experimentation and Prototyping to achieve smarter, faster, and more efficient acquisitions that move technologies rapidly to support the most critical warfighting capabilities. Project 649493 eases and accelerates the architectural pivots required by the Space Warfighting Analysis Center's future force design recommendations through engagement with commercial and industry partners, prototyping and demonstration, test buys and contracts, warfighter engagement, and the capturing of lessons learned to feed back into Force Design analytics and forward into requirements and acquisition. Project 64S444, Experimentation (Space), explores new space-related concepts and their applications in potential future operating environments within a system-of-systems context, taking risks early in the acquisition process to drive a more optimized and efficient acquisition process and significantly reduce overall acquisitions costs. The Tech Transition Program allows acquisition program managers (the capability developers) and warfighters (the capability recipients and end users) to prototype, integrate, and demonstrate candidate technologies and assess them in an operational system-of-systems environment in partnership with Combatant Commanders, Major and Field Commands, Program Executive Officers, schoolhouses, simulation facilities, and development planning organizations. This Program is a parallel effort to United States Air Force Program Element (PE) 0604858F, Tech Transition Program, Project 645350, Experimentation, and continues space-related work executed in that Program in prior fiscal years. Through FY 2030, the Projects quantify the performance and resilience of a Hybrid SATCOM architecture in an operational environment by connecting flexible terminals (from multiple vendors) to multiple SATCOM paths spanning low, medium, and geosynchronous orbits. Each of these new SATCOM pathways offer unique attributes to the DOD. The terminal flexibility will allow rapid incorporation of new commercial SATCOM vendors as they emerge, thus ensuring low-cost SATCOM options for DOD in the foreseeable future. The Resilient Architecture Design and Evaluation project coupled with Hybrid SATCOM terminals will prototype and test techniques for dynamic networking, enhancing cybersecurity, and rapid switching capabilities between DoD and commercial paths, including broadband, narrowband and other mission services through both space-to-ground and space-to-space connectivity. The knowledge will transition to USSF to inform contract structures for operations that enable switching between DoD systems and multiple vendors at minimum cost. Together, these Projects will directly inform COCOMS, MAJCOMS, Field Commands, and PEOs in the acquisition and sustainment of Hybrid SATCOM capability for multiple Joint Force applications using commercial service level agreements and advanced cybersecurity architectures. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 4:             PE 1206458SF / Tech Transition (Space) Advanced Component Development & Prototypes (ACD&P) In order to manage, execute, and deliver science and technology capabilities, this program element may include: necessary civilian pay expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, administrative contractor services, etc. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 187239000, 160063000, 163028000, NULL, NULL, 17, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 196537000, 313678000, 241056000, 241056000, 0, 241056000, 166287000, $$The Air Force Research Laboratory (AFRL) is demonstrating and prototyping Tech Transition (Space) program (Projects 649493, 64S444) for Guardians across Satellite Communications enterprise. As a result, the Service will streamline capabilities development through institutional processes and improve readiness and operational reach of existing force structure. The Tech Transition (Space) Program addresses the gaps between United States Space Force (USSF) Force Design activities, initial system-level technology or concept development and demonstration, and successful acquisition and operational capability implementation. This program also matures new warfighting concepts to rapidly develop and experiment with fieldable prototypes to assess military utility of transition-ready weapon systems. Following the guidance in the National Defense Strategy, the Department of the Air Force (DAF) has institutionalized Experimentation and Prototyping to achieve smarter, faster, and more efficient acquisitions that move technologies rapidly to support the most critical warfighting capabilities. This program falls within the Satellite Communications (SATCOM) mission area which provides the space and dedicated ground architecture required to securely transport wideband, narrowband, tactical, and strategic satellite communications, including USSF-funded SATCOM terminals and commercial SATCOM activities. Space Force investment program interdependencies include: RDT&E Budget Line Items: Advanced EHF MILSATCOM (1206431SF); Commercial SATCOM Integration (1206445SF); Evolved Strategic SATCOM (ESS) (1206855SF); Family of Adv BLoS Terminals (FAB-T) (1203001SF); Narrowband Satellite Communications (1203109SF); Protected Tactical Enterprise Service (1206760SF); Protected Tactical Service (1206761SF; Space Tech Development & Prototyping (1206410SF); Wideband Global SATCOM (SPACE) (1206433SF); Data Transport and Networking (1203156SF); Space Data Network (1203636SF); and elements of Procurement Budget Line Items: Family of Beyond Line-of-Sight Terminals (FBLOST); Mobile User Objective System (MUOS00); MILSATCOM (MILSAT); Wideband SATCOM Operational Management Systems (WSOMS0); Auxiliary Payloads (AUX000); Proliferated Low Earth Orbit SATCOM (PLEO00); PTES HUB (PTES00); ESS (ESS000). Project 649493, Resilient Architecture Design and Evaluation, eases and accelerates the architectural pivots required by the Space Warfighting Analysis Center's Future Force design recommendations through engagement with commercial and industry partners, prototyping and demonstration, test buys and contracts, warfighter engagement, and the capturing of lessons learned to feed back into Force Design analytics and forward into requirements and acquisition. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                             Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 4:              PE 1206458SF / Tech Transition (Space) Advanced Component Development & Prototypes (ACD&P) Project 64S444, Experimentation (Space), explores new space-related concepts and their applications in potential future operating environments within a system-of- systems context, taking risks early in the acquisition process to drive a more optimized and efficient acquisition process and significantly reduce overall acquisitions costs. The Tech Transition Program allows acquisition program managers (the capability developers) and warfighters (the capability recipients and end users) to prototype, integrate, and demonstrate candidate technologies and assess them in an operational system-of-systems environment in partnership with Combatant Commanders, Major and Field Commands, Program Executive Officers, schoolhouses, simulation facilities, and development planning organizations. This Program is a parallel effort to United States Air Force RDT&E Program Element (PE) 0604858F/Tech Transition Program, Project 645350/Experimentation. The Projects quantify the performance and resilience of a Hybrid SATCOM architecture in an operational environment by connecting flexible terminals (from multiple vendors) to multiple SATCOM paths spanning low, medium, and geosynchronous orbits. Each of these new SATCOM pathways offer unique attributes to the Department of War (DoW). The terminal flexibility will allow rapid incorporation of new commercial SATCOM vendors as they emerge, thus ensuring low-cost SATCOM options for DoW in the foreseeable future. The Resilient Architecture Design and Evaluation project coupled with Hybrid SATCOM terminals will prototype and test techniques for dynamic networking, enhancing cybersecurity, and rapid switching capabilities between DoW and commercial paths, including broadband and narrowband, and other mission services for multi-domain sensing, position navigation and timing (PNT), space control among others, through both space-to-ground and space-to-space connectivity. The knowledge will transition to USSF to inform contract structures for operations that enable switching between DoW systems and multiple vendors at minimum cost. Together, these Projects will directly inform COCOMS, MAJCOMS, Field Commands, and PEOs in the acquisition and sustainment of Hybrid SATCOM capability for multiple Joint Force applications using commercial service level agreements and advanced cybersecurity architectures. The FY 2027 request was reduced by $0.078 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency" Cost Efficiency Initiative. In order to manage, execute, and deliver science and technology capabilities, this program element may include: necessary civilian pay expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, administrative contractor services, etc. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                    Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 4:         PE 1206458SF / Tech Transition (Space) Advanced Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1206601SF$$, $$Space Technology$$, $$rdte_sf_ba2$$, $$afrl_rv$$, 2026, 245497000, 0, 255964000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$This program focuses on seven major areas. First, the enterprise transformational applied research develops multidisciplinary applied research efforts to accelerate the technology pipeline of transformational capabilities. Efforts in this program have been coordinated through the Department of Defense Science and Technology Executive Committee process to harmonize efforts and eliminate duplication. Second, the Space Survivability and Surveillance area develops technologies to understand space weather and the geophysics environment for mitigation and exploitation of these effects to Department of Air Force (DAF) systems. Third, the spacecraft payload technologies area improves satellite payload operations by developing advanced materials/components, networking, analysis tools, and subsystem capabilities. Fourth, the rocket propulsion technology area develops rocket propulsion and associated technologies for space access, space maneuver, and strategic systems. Fifth, the lasers & imaging technology area conducts research supporting ground-based optical space situational awareness and ground-to-space laser- enabled communication. Sixth, the spacecraft protection area develops technologies for protecting United States space assets in potential hostile settings. The last major area, spacecraft vehicles, focuses on spacecraft platform and control technologies, operator effectiveness, and human-machine interactions. This program also secures National Unique Testing Assets, providing unmatched capabilities that underpin technological leadership and ensure the safety and security of our nation. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 2:          PE 1206601SF / Space Technology Applied Research This program is executed by the Air Force Research Laboratory (AFRL). AFRL is focused on high-impact, multi-domain science and technology (S&T) solutions that propel innovation today and support the Air and Space Force in securing dominance in future operational environments. AFRL effectively aligns the Department of the Air Force (DAF) S&T enterprise and workforce towards the most consequential DAF priorities to accelerate the delivery of game-changing S&T. This program includes funding for the requisite DAF Science & Engineering (S&E) and mission enabling civilian workforce with the necessary technical competencies to develop, manage, and deliver science & technology capabilities. The execution of Space Force S&T depends on AFRL support funded through DAF (Air and Space Force) RDT&E program elements: 1206601SF, 1206616SF, 0601102F, 0602020F, 0602102F, 0602202F, 0602203F, 0602204F, 0602298F, 0602336F, 0602602F, 0602605F, 0602788F, and 0603680F. In FY 2026, $90.095 million is budgeted in this program for 484 direct Full-Time Equivalent (FTE) civilians. The Air Force Research Laboratory (AFRL) utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the workforce strength, structure, positions, and compensation. In order to manage, execute, and deliver science and technology capabilities, this program element may include: expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, administrative contractor services, etc. This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters.$$, NULL, 239599000, 241767000, 247726000, NULL, NULL, 4, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 242170000, 276981000, 234190000, 234190000, 0, 234190000, 252764000, $$The Air Force Research Laboratory (AFRL) is researching, analyzing and developing Space Technology (Projects 620200, 621010, 624846, 624847, 624866, 625018, and 625809) to support Guardians across Science & Technology and Test & Evaluation. The effects of our efforts will ensure that future Science & Technology and Test & Evaluation have the necessary experimentation and analytic results for future USSF R&D activities. This program focuses on seven major areas. First, the enterprise transformational applied research develops multidisciplinary applied research efforts to accelerate the technology pipeline of transformational capabilities. Second, the Space Survivability and Surveillance area develops technologies to understand space weather and the geophysics environment for mitigation and exploitation of these effects to Department of Air Force (DAF) systems. Third, the spacecraft payload technologies area improves satellite payload operations by developing advanced materials/components, networking, analysis tools, and subsystem capabilities. Fourth, the rocket propulsion technology area develops rocket propulsion and associated technologies for space access, space maneuver, and strategic systems enabling dynamic space operations. Fifth, the lasers & imaging technology area conducts research supporting ground-based optical space situational awareness and ground-to-space laser- enabled communication. Sixth, the spacecraft protection area develops technologies for protecting United States space assets in potential hostile settings. The last major area, spacecraft vehicles technologies, focuses on spacecraft platform and control technologies; technology and algorithm development and transition for performing rendezvous & proximity operations and docking to enable dynamic space operations and in-orbit refueling activities; operator effectiveness, and human- Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 2:         PE 1206601SF / Space Technology Applied Research machine interactions. This program also secures National Unique Testing Assets, providing unmatched capabilities that underpin technological leadership and ensure the safety and security of our nation. This program includes funding for the requisite DAF Science & Engineering (S&E) and mission enabling civilian workforce with the necessary technical competencies to develop, manage, and deliver science & technology capabilities. The execution of Space Force S&T depends on AFRL support funded through DAF (Air and Space Force) RDT&E program elements: 1206616SF, 0601102F, 0602020F, 0602102F, 0602202F, 0602203F, 0602204F, 0602298F, 0602336F, 0602602F, 0602605F, 0602788F, and 0603680F. In FY 2027, 89.624 million is budgeted in this program for 484 direct Full-Time Equivalent (FTE) civilians. The Air Force Research Laboratory (AFRL) utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the workforce strength, structure, positions, and compensation. In order to manage, execute, and deliver science and technology capabilities, this program element may include: expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, administrative contractor services, etc. This program falls within the Science and Technology (S&T) and Test & Evaluation (T&E) mission area which provides the S&T initiatives, demonstrations, experiments, and studies towards developing next-generation space capabilities. The T&E mission area provides all efforts required to establish and operate the test infrastructure for USSF capabilities. Space Force investment program interdependencies include: RDT&E Budget Line Items: Defense Research Sciences (0601102SF); Major T&E Investments - Space (1206759SF); Small Business Innovation Research (1205502SF); Space Advanced Tech Dev / Demo (1206616SF); Space Innov Intg & Rapid Tech Dev (1203174SF); Space Rapid Capabilities Office (1206857SF); Space Science and Technology (1206310SF); Space Systems Prototype Transition (1206427SF); Space Technology (1206601SF); Space Test and Evaluation (1202051SF); Space Test Program (1206864SF); University Research Initiatives (0601103SF); Operational Test & Training Infrastructure (1206617SF) and elements of Procurement Budget Line Item: General Information Tech - Space (GNRLIT). The FY 2027 request was reduced by 0.471 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency” Cost Efficiency Initiative. This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                       Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 2:         PE 1206601SF / Space Technology Applied Research$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1206616SF$$, $$Space Advanced Technology Development/Demo$$, $$rdte_sf_ba3$$, $$afrl_rv$$, 2026, 128588000, 0, 261474000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$This program focuses on five major areas. First, Space Warfighter Technologist Capabilities, practices to accelerate moving emerging technologies into the hands of the warfighter. Second, the integrated space technology demonstrations project is a series of advanced technology demonstrations designed to address mission needs by applying emerging technologies from the Air Force Research Laboratory (AFRL), other United States government laboratories, and industry. This project also includes multi-domain enabling technologies such as modeling and simulation, agile software development, advanced materials and process, and manufacturing and processes to reduce transition risk. Third, the program focuses on ground-based optical space situational awareness technology development and demonstration at the Maui Space Surveillance System in Hawaii, as well as the operation and upgrade of the facility. Fourth, the program develops and demonstrates advanced and innovative low-cost high performance space access and satellite propulsion technologies and components. The last major area, spacecraft vehicles, focuses on developing Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 3:        PE 1206616SF / Space Advanced Technology Development/Demo Advanced Technology Development (ATD) technologies for next-generation space communications terminals and equipment. Efforts in this program have been coordinated through the Department of Defense Science and Technology Executive Committee process to harmonize efforts and eliminate duplication. This program is executed by the Air Force Research Laboratory (AFRL). AFRL is focused on high-impact, multi-domain science and technology (S&T) solutions that propel innovation today and support the Air and Space Force in securing dominance in future operational environments. AFRL effectively aligns the Department of the Air Force (DAF) S&T enterprise and workforce towards the most consequential DAF priorities to accelerate the delivery of game-changing S&T. This program includes funding for the requisite DAF Science & Engineering (S&E) and mission enabling civilian workforce with the necessary technical competencies to develop, manage, and deliver science & technology capabilities. The execution of Space Force S&T depends on AFRL support funded through DAF (Air and Space Force) RDT&E program elements: 1206601SF, 1206616SF, 0601102F, 0602020F, 0602102F, 0602202F, 0602203F, 0602204F, 0602298F, 0602336F, 0602602F, 0602605F, 0602788F, and 0603680F. In FY 2026, $5.328 million is budgeted in this program for 23 direct Full-Time Equivalent (FTE) civilians. The Air Force Research Laboratory (AFRL) utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the workforce strength, structure, positions, and compensation. In order to manage, execute, and deliver science and technology capabilities, this program element may include: necessary civilian pay expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, administrative contractor services, etc. This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment.$$, NULL, 109679000, 109816000, 112349000, NULL, NULL, 7, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 245989000, 155341000, 126427000, 126427000, 0, 126427000, 114597000, $$The Air Force Research Laboratory (AFRL) is developing and demonstrating Space Advanced Technology Development/Demo (Projects 630321, 633834, 634868, 634922, and 63682J) to support Guardians across Science & Technology and Test & Evaluation. The effects of our efforts will ensure that we have improved readiness across the force for Science & Technology and Test & Evaluation. This program focuses on five major areas. First, the Space Warfighter Technologist Capabilities area, practices to accelerate moving emerging technologies into the hands of the warfighter. Second, the Integrated Space Technology Demonstrations area is a series of advanced technology demonstrations designed to address mission needs by applying emerging technologies from the Air Force Research Laboratory (AFRL), other United States government laboratories, and industry. This area also includes multi-domain enabling technologies such as modeling and simulation, agile software development, advanced materials and process, and manufacturing and processes to reduce transition risk. Third, the Maui Space Surveillance System area focuses on ground-based optical space situational awareness technology development and demonstration at the Maui Space Surveillance System in Hawaii, as well as the operation and upgrade of the facility. Fourth, the Space & Missile Rocket Propulsion area develops and demonstrates advanced and innovative low-cost high performance space access and satellite propulsion technologies and components. The last major area, Spacecraft Vehicles, focuses on developing technologies for next-generation space communications terminals and equipment. This program includes funding for the requisite DAF Science & Engineering (S&E) and mission enabling civilian workforce with the necessary technical competencies to develop, manage, and deliver science & technology capabilities. The execution of Space Force S&T depends on AFRL support funded through DAF (Air and Space Force) RDT&E program elements: 1206601SF, 1206616SF, 0601102F, 0602020F, 0602102F, 0602202F, 0602203F, 0602204F, 0602298F, 0602336F, 0602602F, 0602605F, 0602788F, and 0603680F. In FY 2027, 4.509 million is budgeted in this program for 23 direct Full-Time Equivalent (FTE) civilians. The Air Force Research Laboratory (AFRL) utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the workforce strength, structure, positions, and compensation. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 3:                PE 1206616SF / Space Advanced Technology Development/Demo Advanced Technology Development (ATD) In order to manage, execute, and deliver science and technology capabilities, this program element may include: expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, administrative contractor services, etc. This program falls within the Science and Technology (S&T) and Test & Evaluation (T&E) mission area which provides the S&T initiatives, demonstrations, experiments, and studies towards developing next-generation space capabilities. The T&E mission area provides all efforts required to establish and operate the test infrastructure for USSF capabilities. Space Force investment program interdependencies include: RDT&E Budget Line Items: Defense Research Sciences (0601102SF); Major T&E Investments - Space (1206759SF); Small Business Innovation Research (1205502SF); Space Advanced Tech Dev / Demo (1206616SF); Space Innov Intg & Rapid Tech Dev (1203174SF); Space Rapid Capabilities Office (1206857SF); Space Science and Technology (1206310SF); Space Systems Prototype Transition (1206427SF); Space Technology (1206601SF); Space Test and Evaluation (1202051SF); Space Test Program (1206864SF); University Research Initiatives (0601103SF); Operational Test & Training Infrastructure (1206617SF) and elements of Procurement Budget Line Item: General Information Tech - Space (GNRLIT). The FY 2027 request was reduced by 0.442 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency” Cost Efficiency Initiative. This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1206730SF$$, $$Space Security and Defense Program$$, $$rdte_sf_ba4$$, $$ssc_sda$$, 2026, 45200000, 0, 53199000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$This Program Element (PE) 1206730SF, Space Security and Defense Program (SSDP) funds activities executed by the Joint Department of Defense (DoD) and Office of the Director of National Intelligence (ODNI) organization Space Security and Defense Program. The Program and organization were established to function as the center of excellence for options and strategies (materiel, non-materiel, cross-Title, cross-domain) leading to a more resilient National Security Space (NSS) Enterprise. The organization and its activities operate under the authority of the Deputy Secretary of Defense (DEPSECDEF) and Principal Deputy Director of National Intelligence (PDDNI). SSDP's unique position with both the DoD and ODNI, authorities from both the DEPSECDEF and PDDNI, and broad NSS-scoped mission-set provides a crucial and objective protection competency to advance the highest priority efforts to deliver economical, programmatically-executable, and operationally-relevant space protection solutions for the Nation. SSDP-funded activities support NSS stakeholders including the DoD, Intelligence Community (IC), civil, commercial, and international space entities/missions supporting current and future national security operations in both peacetime and throughout all phases of conflict. In this capacity, SSDP employs these funds to lead and collaborate on NSS susceptibility and vulnerability assessments, and threat mitigation processes. Its breadth of activities span the capability to conduct rigorous foundational analyses in order to understand red counterspace threat and blue operations environments, and to plan and execute projects to discover, analyze, and validate near-term and far-term options to detect, track, and mitigate and/or render these threats (including emerging space and transmedium threats) ineffective. SSDP analytic products to mitigate/defeat adversary counterspace threats either manifest themselves in validated materiel solution recommendations to corporate decision processes (including system and/or architectural requirements and potential investment opportunities), or as non-materiel recommendations such as Tactics, Techniques, and Procedures (TTP), Concepts of Operations (CONOPS), and/or space policy, or a combination of both. Regardless, SSDP threat analyses and models of all sorts are shared across the NSS enterprise to ensure efficiency and speed of analysis, and ultimately produce results in more resilient space effects for national security missions. This program element may include necessary emergent or unanticipated civilian pay expenses required to manage and execute SSDP and/or deliver products for emergent or unanticipated weapon system capabilities. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 4:           PE 1206730SF / Space Security and Defense Program Advanced Component Development & Prototypes (ACD&P)$$, NULL, 81606000, 82663000, 83275000, NULL, NULL, 18, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 53199000, 45200000, 102140000, 102140000, 0, 102140000, 84263000, $$The Space Security and Defense Program (SSDP) is a Joint Title-10/title 50 organization serving as the primary space survivability technical advisor to the DEPSECDEF and PDDNI. SSDP's focus and analysis is on USSF core and enterprise service operational functions (Space Control, Space Domain Awareness) with Title-10/Title 50 equities within the Space Protection Program (Project 64A025). Beginning in FY27, SSDP is also the USSF's designated agent for performing analytical activities, experimentation, and modeling & simulation (M&S), to deliver data-driven recommendations and carry-out other DoW efforts prescribed to the USSF in support of the Joint Assault Breaker II (ABII) Program (Project 645611). This Program Element (PE) 1206730SF, Space Security and Defense Program (SSDP) funds activities executed by the Joint Department of War (DoW) and Office of the Director of National Intelligence (ODNI) organization Space Security and Defense Program. The Program and organization were established to function as the center of excellence for options and strategies (materiel, non-materiel, cross-Title, cross-domain) leading to a more resilient National Security Space (NSS) Enterprise. The organization and its activities operate under the authority of the Deputy Secretary of War (DEPSECWAR) and Principal Deputy Director of National Intelligence (PDDNI). SSDP's unique position with both the DoW and ODNI, authorities from both the DEPSECWAR and PDDNI, and broad NSS-scoped mission-set provides a crucial and objective protection competency to advance the highest priority efforts to deliver economical, programmatically-executable, and operationally-relevant space protection solutions for the Nation. SSDP-funded activities support NSS stakeholders including the DoW, Intelligence Community (IC), civil, commercial, and international space entities/missions supporting current and future national security operations in both peacetime and throughout all phases of conflict. In this capacity, SSDP employs these funds to lead and collaborate on NSS susceptibility and vulnerability assessments, and threat mitigation processes. Its breadth of activities span the capability to conduct rigorous foundational analyses in order to understand red counterspace threat and blue operations environments, and to plan and execute projects to discover, analyze, and validate near-term and far-term options to detect, track, and mitigate and/or render these threats (including emerging space and transmedium threats) ineffective. SSDP analytic products to mitigate/defeat adversary counterspace threats either manifest themselves in validated materiel solution recommendations to corporate decision processes (including system and/or architectural requirements and potential investment opportunities), or as non-materiel recommendations such as Tactics, Techniques, and Procedures (TTP), Concepts of Operations (CONOPS), and/or space policy, or a combination of both. Regardless, SSDP threat analyses and models of all sorts are shared across the NSS enterprise to ensure efficiency and speed of analysis, and ultimately produce results in more resilient space effects for national security missions. Project 645611, Assault Breaker II (ABII), is classified, all-Service, USSOCOM, and USCYBERCOM, multi-year effort led by the Office of the Under Secretary of War for Research and Engineering (OUSW(R&E)) to analyze, research, and recommend material and non-material solutions, and incorporate ABII program analysis and recommendations into ongoing Joint Staff (JS) and Office of the Secretary of War (OSW) capability development processes to field a lethal, resilient, and rapidly adaptive Joint Force able to defeat and deter potential adversaries. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 4:             PE 1206730SF / Space Security and Defense Program Advanced Component Development & Prototypes (ACD&P) This program falls within the Enterprise Management & Information Technology mission area. Enterprise Management provides the personnel and infrastructure required to manage USSF headquarters functions at the service and field command levels, including the Space Service Acquisition Executive for Space Systems and Programs, Office of the Assistant Secretary for Space Acquisition and Integration, the Office of the Chief of Space Operations (OCSO), the Space Staff, and Secretariat. Information Technology includes the IT infrastructure required for the USSF to acquire, sustain, and operate its assets. Program interdependencies include: Acq and Management Support (Space) (1207804SF); Acq Workforce - Space & Missile Sys (1206392SF); Asst SecAF - Space Acq & Integration (1203924SF); Combat Support - Other Program (1203969SF); Commercial Services (1206771SF); Force Structure Deviation (0808722F); Headquarters U.S. Space Force (1209398SF); Management Headquarters - STARCOM (1209158SF); Mgt Headquarters - Space (Admin) (1205498SF); Operational Headquarters - Space (1203925SF); Permanent Change of Station Travel (0808731F); Service Support to OSW (0901503SF); Service Support to SDA - MHA (1201198SF); Space & Missile Systems Center - MHA (1206398SF); Space Planning and Operations Support (1201000SF); Space Security and Defense Program (1206730SF); Space Warfighting Analysis (1203622SF); Svc Spt to The Joint Staff (0901507SF) This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1206759SF$$, $$Major T&E Investment - Space$$, $$rdte_sf_ba6$$, $$starcom$$, 2026, 189083000, 0, 229665000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$This program funds the United States Space Force (USSF) Test Enterprise. Funds support enterprise-level, threat-relevant, and fully-integrated developmental and operational Space Test & Evaluation (T&E) activities and capabilities; the development of a professional space T&E workforce; and the organization, acquisitions, and operations of the National Space Test and Training Complex (NSTTC). Space T&E activities and capabilities include the USSF Integrated Test Force (ITF) structures, USSF Operational Test Agency (OTA) test execution campaigns, and the workforce and activities required to conduct T&E to adequately assess the performance and survivability of Department of Defense (DoD) space systems, tactics, and technologies in contested environments. Workforce development refers to the organizations, training, and activities required to develop a professional space T&E workforce including the development and operation of the Space Test Course at the United States Air Force (USAF) Test Pilot School (TPS). Space T&E infrastructure encompasses the organization, acquisitions, operations, and associated activities as part of the NSTTC to develop, integrate, operate, and sustain the minimum technical capabilities required to test and evaluate the performance and survivability of critical DoD space systems in contested environments. The NSTTC delivers realistic test and training environments to support capability development by incorporating a mix of live and virtual capabilities to conduct threat emulation, advanced training, tactics development, and integrated testing. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 6:         PE 1206759SF / Major T&E Investment - Space RDT&E Management Support$$, NULL, 63594000, 65312000, 66829000, NULL, NULL, 47, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 216282000, 195977000, 65731000, 65731000, 0, 65731000, 71595000, $$STARCOM is developing and operating the U.S. Space Force's Major Test and Evaluation (T&E) resources (Projects 660191, 664597, and 664598) to improve test for Guardians across the following mission areas: Science & Technology and Test & Evaluation; Space Domain Awareness; Position, Navigation, and Timing; Satellite Communications; Weather; Combat Power; and Launch. As a result, the Service will benefit from improved testing and validation of new capabilities across all Service Operational Functions, as well as streamlined capabilities development through improved institutional processes. This program funds the United States Space Force (USSF) Test Enterprise. Funds support enterprise-level, threat-relevant, and fully-integrated developmental and operational Space Test & Evaluation (T&E) activities and capabilities; the development of a professional space T&E workforce; and the organization and operations of the National Space Test and Training Complex (NSTTC) under the Space Training & Readiness Command (STARCOM) Field Command. Space T&E activities and capabilities include the USSF Integrated Test Force (ITF) structures, USSF Operational Test Agency (OTA) test execution campaigns, and the workforce and activities required to conduct T&E to adequately assess the performance and survivability of Department of War (DoW) space systems, tactics, and technologies in contested environments. Workforce development refers to the organizations, training, and activities required to develop a professional space T&E workforce including the development and operation of the Space Test Course at the United States Air Force (USAF) Test Pilot School (TPS). Space T&E infrastructure encompasses the organization, operations, and associated activities as part of the NSTTC to integrate, operate, and sustain the minimum technical capabilities required to test and evaluate the performance and survivability of critical DoW space systems in contested environments. The NSTTC delivers realistic test and training environments to support capability development by incorporating a mix of live and virtual capabilities to conduct threat emulation, advanced training, tactics development, and integrated testing. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                           Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 6:         PE 1206759SF / Major T&E Investment - Space RDT&E Management Support This program falls within the Science and Technology (S&T) and Test & Evaluation (T&E) mission area which provides the S&T initiatives, demonstrations, experiments, and studies towards developing next-generation space capabilities. The T&E mission area provides all efforts required to establish and operate the test infrastructure for USSF capabilities. Space Force investment program interdependencies include: RDT&E Budget Line Items: Defense Research Sciences (0601102SF); University Research Initiatives (0601103SF) ; Major T&E Investments - Space (1206759SF); Small Business Innovation Research (1205502SF); Space Advanced Tech Dev / Demo (1206616SF); Space Innov Intg & Rapid Tech Dev (1203174SF); Space Rapid Capabilities Office (1206857SF); Space Science and Technology (1206310SF); Space Systems Prototype Transition (1206427SF); Space Technology (1206601SF); Space Test and Evaluation (1202051SF); Space Test Program (1206864SF); University Research Initiatives (0601103SF); Operational Test & Training Infrastructure (1206617SF) and elements of Procurement Budget Line Item: General Information Tech - Space (GNRLIT) Beginning in FY 2027, Project 664598, National Space Test & Training Complex, has been moved into the new Project 644441, Operational Test & Training Infrastructure, within the new Program Element 1206617SF, Operational Test & Training Infrastructure. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1206760SF$$, $$Protected Tactical Enterprise Service (PTES)$$, $$rdte_sf_ba4$$, $$ssc_milcom$$, 2026, 114430000, 0, 77509000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$The global threat of electronic warfare attacks against space systems will expand in the coming years in both number and types of weapons. Threat development will include a focus on jamming capabilities against military satellite communications (SATCOM). To address this critical threat, the Space Force is developing the Protected Tactical Enterprise Service (PTES) ground system to provide worldwide, anti-jam, Low Probability of Intercept communications for tactical warfighters via the Protected Tactical Waveform (PTW). This Program Element also provides for a capacity increase of non-PTW SATCOM for joint warfighters. The PTES Program began as a Rapid Prototyping activity under the Middle Tier of Acquisition authority in June 2018. Upon a successful Operational Demonstration of PTW Over Wideband Global SATCOM (WGS) and satisfying MTA requirements, the program transitioned into the Software Acquisition Pathway in FY 2023. The PTES Program focused on getting PTW broadcasted over the WGS system, with a plan to later expand the capability over commercial satellites and the Protected Tactical SATCOM (PTS) system. PTES is comprised of these two efforts: Project 643726, PTW Over WGS (PTWoW) and Project 643733, PTW Over Commercial (PTWoC). The PTES Program developed a Mission Management System (MMS), Key Management System (KMS), and Joint Hub (JH) to enable transponded PTW over SATCOM. The JH is unmanned computing and communications hardware located at a SATCOM teleport that provides the PTW signal processing, reach-back network connectivity, and near real-time networked control to direct the connected terminals. Each JH requires site surveys, equipment purchases (modems, End Cryptographic Unit, etc.), equipment installation, and equipment testing. Production-representative PTW modems for user terminals were developed by the Protected Tactical Service Field Demonstration and will be separately acquired by each Service and by international partners. The Navy Wideband Anti-Jam Modem System, the Air Force-Army Anti-Jam Modem, and other stakeholders rely on PTES to provide PTW ground infrastructure. This program element may include necessary civilian pay expenses required to manage, execute, and deliver the PTES weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 4:          PE 1206760SF / Protected Tactical Enterprise Service (PTES) Advanced Component Development & Prototypes (ACD&P)$$, NULL, 87065000, 86103000, 87664000, NULL, NULL, 19, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 74849000, 96615000, 155885000, 155885000, 0, 155885000, 89417000, $$USSF is developing the Protected Tactical Enterprise Service (PTES) ground system for the United States and Allies within the mission area of Satellite Communications. As a result, the Service will improve battle management of all weapon systems, improve readiness and operational reach of existing force structure, augment, supplement, and/or integrate Allies, partners, and commercial space to USSF units, and improve resilience of infrastructure, equipment, and personnel. The global threat of electronic warfare attacks against space systems will expand in the coming years in both number and types of weapons. Threat development will include a focus on jamming capabilities against military satellite communications (SATCOM). To address this critical threat, the Space Force is developing the Protected Tactical Enterprise Service (PTES) ground system to provide worldwide, anti-jam, Low Probability of Intercept communications for tactical warfighters via the Protected Tactical Waveform (PTW). This Program Element also provides for a capacity increase of non-PTW SATCOM for joint warfighters. The PTES Program began as a Rapid Prototyping activity under the Middle Tier of Acquisition authority in June 2018. Upon a successful Operational Demonstration of PTW Over Wideband Global SATCOM (WGS) and satisfying MTA requirements, the program transitioned into the Software Acquisition Pathway in FY 2023. The PTES Program focused on getting PTW broadcasted over the WGS system, with a plan to later expand the capability over commercial satellites and the Protected Tactical SATCOM (PTS) system. PTES is comprised of these two efforts: Project 643726, PTW Over WGS (PTWoW) and Project 643733, PTW Over Commercial (PTWoC). The PTES Program developed a Mission Management System (MMS), Key Management System (KMS), and Joint Hub (JH) to enable transponded PTW over SATCOM. The JH is unmanned computing and communications hardware located at a SATCOM teleport that provides the PTW signal processing, reach-back network connectivity, and near real-time networked control to direct the connected terminals. Each JH requires site surveys, equipment purchases (modems, End Cryptographic Unit, etc.), equipment installation, and equipment testing. Production-representative PTW modems for user terminals were developed by the Protected Tactical Service Field Demonstration and will be separately acquired by each Service and by international partners. The Navy Wideband Anti-Jam Modem System, the Air Force-Army Anti-Jam Modem, and other stakeholders rely on PTES to provide PTW ground infrastructure. This program falls within the Satellite Communications (SATCOM) mission area which provides the space and dedicated ground architecture required to securely transport wideband, narrowband, tactical, and strategic satellite communications, including USSF-funded SATCOM terminals and commercial SATCOM activities. Space Force investment program interdependencies include: RDT&E Budget Line Items: Advanced EHF MILSATCOM (1206431SF); Commercial SATCOM Integration (1206445SF); Evolved Strategic SATCOM (ESS) (1206855SF); Family of Adv BLoS Terminals (FAB-T) (1203001SF); Narrowband Satellite Communications (1203109SF); Protected Tactical Enterprise Service Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 4:        PE 1206760SF / Protected Tactical Enterprise Service (PTES) Advanced Component Development & Prototypes (ACD&P) (1206760SF); Protected Tactical Service (1206761SF; Space Tech Development & Prototyping (1206410SF); Tech Transition (Space) (1206458SF); Wideband Global SATCOM (SPACE) (1206433SF); Data Transport and Networking (1203156SF); Space Data Network (1203636SF); and elements of Procurement Budget Line Items: Family of Beyond Line-of-Sight Terminals (FBLOST); Mobile User Objective System (MUOS00); MILSATCOM (MILSAT); Wideband SATCOM Operational Management Systems (WSOMS0); Auxiliary Payloads (AUX000); Proliferated Low Earth Orbit SATCOM (PLEO00); PTES HUB (PTES00); ESS (ESS000) This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1206761SF$$, $$Protected Tactical Service (PTS)$$, $$rdte_sf_ba4$$, $$ssc_milcom$$, 2026, 571921000, 0, 419996000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$The global threat of electronic warfare attacks against space systems will expand in the coming years in both number and types of weapons. Threat development will very likely focus on jamming capabilities against dedicated military satellite communications (SATCOM). To address this critical threat, and in pursuit of more precise solutions for disaggregated strategic and tactical SATCOM, U.S Strategic Command (USSTRATCOM) and Air Force Space Command (AFSPC) initiated the tactical SATCOM family-of-systems. This integrated approach includes the Protected Tactical Satellite Communications (PTS) and Protected Tactical Enterprise Service (PTES) programs to mitigate adversarial jamming effects by using the Protected Tactical Waveform (PTW). The PTS program is the disaggregated tactical communications follow-on to the Advanced Extremely High Frequency (AEHF) program. The United States Space Force (USSF) is developing the PTS system to provide tactical users increased protection with worldwide, beyond-line-of-sight, Anti-Jam (AJ), low-probability-of-intercept communications in benign and highly- contested anti-access/area denial environments utilizing the PTW. The PTS system's on-board payload/signal processing, antenna design, and advanced beam-forming using a distributed, diversified, and agile constellation of hostable payloads and high capacity free-flyers enables reliable tactical SATCOM within close proximities to adversarial jammers. The system also employs interfaces consistent with USSF's on-going resilience initiatives enhancing mission assurance and interoperability. The program's modular, flexible, scalable, and protected tactical payload constellation architecture will increase resiliency through distribution across a larger number of space platforms (e.g., hostable, free-flyer, international partnerships). The PTES program (PE 1206760SF, Project 643726) establishes the ground infrastructure for PTS, which operationalizes the PTW. For the initial PTS phase, USSF is utilizing FY 2016 National Defense Authorization Act (NDAA), Middle Tier of Acquisition (MTA) for Rapid Prototyping (RP) authority and Section 815, Other Transaction Authority (OTA), to achieve an affordable, rapid, operational capability for the tactical warfighter. This strategy employs rapid payload development to progressively and incrementally deploy prototypes with residual capabilities demonstrated in an operational environment. These prototyping payloads (PTS-P) demonstrate innovative AJ technologies with modular and scalable payloads to meet validated military needs for protected tactical communications. This includes technical baseline development, systems engineering trade analyses, internal/external system integration and development, candidate system architecture evaluations, risk reduction demonstrations, prototyping concepts development, system testing, and enabling technologies maturation. The PTS-Resilient (PTS-R) project will follow the PTS-P prototyping activity to develop purpose-built "hub in space” satellites with full signal processing and switching capability that allows direct connectivity between users. On June 13th 2024, the Milestone Decision Authority has designated PTS-R as an ACAT I, pre-Milestone B program in the Technology Maturation and Risk Reduction (TMRR) acquisition phase. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                             Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 4:               PE 1206761SF / Protected Tactical Service (PTS) Advanced Component Development & Prototypes (ACD&P) The PTS-P and PTS-R Phases include a Space Segment, Ground Segment, and Gateway Segment. For the Space Segment, the USSF strategy utilizes a payload- centric focus to enable an affordable, resilient space architecture. This enables hosting and rideshare opportunities with other US government, commercial, International Partner (IP) satellites or integration onto a commodity satellite bus. For the Ground Segment, PTS develops satellite command and control (C2) and leverages the Protected Tactical Enterprise Service (PTES) activity for mission and key management planning. The PTS Gateway Segment enables tactical warfighters reach back to global DoD Information Network. The PTS user Terminal Segment, not included in this PTS acquisition, will be procured by the military services utilizing low-cost Protected Tactical Waveform (PTW) modem upgrades enabled by the Air Force - Army Anti-Jam Modem (A3M) ACAT III program and the Navy Wideband Anti-Jam Modem System (WAMS) technology demonstration program. PTS also develops the National Security Agency (NSA)-certified and space-flight qualified production-ready Space Hub End Cryptographic Unit (ECU). Starting the ECU as a single, early risk reduction effort targets a high-risk area of the PTS development and enables PTS program success. In CY 2022 the Space Warfighting Analysis Center (SWAC) identified gaps in protected SATCOM capabilities relative to existing and planned capabilities against current and predicted user needs, with consideration of current and emerging challenges to both operating environments and system deployment. SWAC developed a Force Design (FD) to address these gaps, realigning capabilities and disaggregating mission sets. Protected Tactical SATCOM - Global (PTS-G) is a key and enabling capability of the USSF FD that bridges the gap between the more focused capabilities provided by PTS-R, and the broadly-available but also the lower assured access capabilities provided by existing / emerging MILSATCOM and commercial services. PTS-G also augments current and future warfighter capability with increased global capacity. PTS-G is a moderate degree of assured access communications across military Ka- band and X-band using a disaggregated and proliferated sets of lower-complexity satellites. Space Systems Command (SSC) will develop the PTS-G space and ground systems to provide worldwide assured-access communications for tactical warfighters. PTS-G will consist of two types of space vehicles (PTS-G-Ka and PTS-G-X), and ground infrastructure (system controller/hub with gateways), and will connect to existing Protected Tactical SATCOM Family of Systems ground infrastructure (mission management system and cryptographic key management system) developed under the PTES program. PTS-G will consist of multiple satellites that can provide either X-band or mil Ka-band transponded capability while also supporting the utilization of the PTW Waveform. PTW modems for user terminals will be acquired by each Service and by international partners. Initially, PTS-G will provide capabilities in select regions. PTS-G will target a solution that can provide worldwide coverage. PTS-G will be interoperable with the PTES program to perform management and cryptographic key management for PTW users, but PTS-G will procure and install the associated PTES Joint Hubs and other ground infrastructure to operate the satellites, anchor the data, and perform Operation and Support (O&S). In addition, the PTS-R system will be integrated with components of PTES and will be complementary to PTS-G. PTS-G addresses the gap in protected communications capability identified in the USSF FD and in the Joint Space Communications Layer (JSCL) Initial Capabilities Document (ICD). To meet the warfighter requirements for protected tactical MILSATCOM and the capability gaps identified in these studies in a timely and cost-effective Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 4:               PE 1206761SF / Protected Tactical Service (PTS) Advanced Component Development & Prototypes (ACD&P) manner, use and modification of existing capabilities and Commercial Off the Shelf (COTS) products will be leveraged to the maximum extent, to develop the PTS-G capabilities. SSC will strategically execute prototyping and risk reduction as needed to develop and deploy PTS-G capabilities. This program element may include necessary civilian pay expenses required to manage, execute, and deliver PTS weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 450808000, 326372000, 391236000, NULL, NULL, 20, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 390585000, 428697000, 449434000, 449434000, 0, 449434000, 389432000, $$The Protected Tactical Service (PTS) program is developing, demonstrating, prototyping, and operating beyond-line-of-sight, Anti-Jam (AJ), low-probability-of-intercept satellite communications and provides the space and dedicated ground architecture required to securely transport tactical satellite communications for warfighters across the Satellite Communications (SATCOM) mission area. As a result, the Service will improve readiness and operational reach of existing force structure and provide an enduring resilient Infrastructure, equipment, and personnel. The global threat of electronic warfare attacks against space systems will expand in the coming years in both number and types of weapons. Threat development will very likely focus on jamming capabilities against dedicated military satellite communications (SATCOM). To address this critical threat, and in pursuit of more precise solutions for disaggregated strategic and tactical SATCOM, U.S Strategic Command (USSTRATCOM) and Air Force Space Command (AFSPC) initiated the tactical SATCOM family-of-systems. This integrated approach includes the Protected Tactical Satellite Communications (PTS) and Protected Tactical Enterprise Service (PTES) programs to mitigate adversarial jamming effects by using the Protected Tactical Waveform (PTW). The PTS program is the disaggregated tactical communications follow-on to the Advanced Extremely High Frequency (AEHF) program. The United States Space Force (USSF) is developing the PTS system to provide tactical users increased protection with worldwide, beyond-line-of-sight, Anti-Jam (AJ), low-probability-of-intercept communications in benign and highly- contested anti-access/area denial environments utilizing the PTW. The PTS system's on-board payload/signal processing, antenna design, and advanced beam-forming using a distributed, diversified, and agile constellation of hostable payloads and high capacity free-flyers enables reliable tactical SATCOM within close proximities to adversarial jammers. The system also employs interfaces consistent with USSF's on-going resilience initiatives enhancing mission assurance and interoperability. The program's modular, flexible, scalable, and protected tactical payload constellation architecture will increase resiliency through distribution across a larger number of space platforms (e.g., hostable, free-flyer, international partnerships). The PTES program (PE 1206760SF, Project 643726) establishes the ground infrastructure for PTS, which operationalizes the PTW. This program falls within the Satellite Communications (SATCOM) mission area which provides the space and dedicated ground architecture required to securely transport wideband, narrowband, tactical, and strategic satellite communications, including USSF-funded SATCOM terminals and commercial SATCOM activities. Program interdependencies include: Advanced EHF MILSATCOM (1206431SF); Commercial SATCOM Integration (1206445SF); Evolved Strategic SATCOM (ESS) (1206855SF); Family of Adv BLoS Terminals (FAB-T) (1203001SF); MILSATCOM Terminals (1203601SF); Narrowband Satellite Communications (1203109SF); Polar MILSATCOM (SPACE) Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                              Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 4:         PE 1206761SF / Protected Tactical Service (PTS) Advanced Component Development & Prototypes (ACD&P) (1206432SF); Protected Tactical Enterprise Service (1206760SF); Protected Tactical Service (1206761SF); SATCOM O&M (1203605SF); Space Tech Development & Prototyping (1206410SF); Tech Transition (Space) (1206458SF); Wideband Global SATCOM (SPACE) (1206433SF); Wideband Global System Satellites (1203600SF). For the initial PTS phase, USSF is utilizing FY 2016 National Defense Authorization Act (NDAA), Middle Tier of Acquisition (MTA) for Rapid Prototyping (RP) authority and Section 815, Other Transaction Authority (OTA), to achieve an affordable, rapid, operational capability for the tactical warfighter. This strategy employs rapid payload development to progressively and incrementally deploy prototypes with residual capabilities demonstrated in an operational environment. These prototyping payloads (PTS-P) demonstrate innovative AJ technologies with modular and scalable payloads to meet validated military needs for protected tactical communications. This includes technical baseline development, systems engineering trade analyses, internal/external system integration and development, candidate system architecture evaluations, risk reduction demonstrations, prototyping concepts development, system testing, and enabling technologies maturation. The PTS-Resilient (PTS-R) project will follow the PTS-P prototyping activity to develop purpose-built "hub in space” satellites with full signal processing and switching capability that allows direct connectivity between users. On June 13th 2024, the Milestone Decision Authority has designated PTS-R as an ACAT I, pre-Milestone B program in the Technology Maturation and Risk Reduction (TMRR) acquisition phase. The PTS-P and PTS-R Phases include a Space Segment, Ground Segment, and Gateway Segment. For the Space Segment, the USSF strategy utilizes a payload- centric focus to enable an affordable, resilient space architecture. This enables hosting and rideshare opportunities with other US government, commercial, International Partner (IP) satellites or integration onto a commodity satellite bus. For the Ground Segment, PTS develops satellite command and control (C2) and leverages the Protected Tactical Enterprise Service (PTES) activity for mission and key management planning. The PTS Gateway Segment enables tactical warfighters reach back to global DoW Information Network. The PTS user Terminal Segment, not included in this PTS acquisition, will be procured by the military services utilizing low-cost Protected Tactical Waveform (PTW) modem upgrades enabled by the Air Force - Army Anti-Jam Modem (A3M) ACAT III program and the Navy Wideband Anti-Jam Modem System (WAMS) technology demonstration program. PTS also develops the National Security Agency (NSA)-certified and space-flight qualified production- ready Space Hub End Cryptographic Unit (ECU). Starting the ECU as a single, early risk reduction effort targets a high-risk area of the PTS development and enables PTS program success. In CY 2022 the Space Warfighting Analysis Center (SWAC) identified gaps in protected SATCOM capabilities relative to existing and planned capabilities against current and predicted user needs, with consideration of current and emerging challenges to both operating environments and system deployment. SWAC developed a Force Design (FD) to address these gaps, realigning capabilities and disaggregating mission sets. Protected Tactical SATCOM - Global (PTS-G) is a key and enabling capability of the USSF FD that bridges the gap between the more focused capabilities provided by PTS-R, and the broadly-available but also the lower assured access capabilities provided by existing / emerging MILSATCOM and commercial services. PTS-G also augments current and future warfighter capability with increased global capacity. PTS-G is a moderate degree of assured access communications across military Ka- band and X-band using a disaggregated and proliferated sets of lower-complexity satellites. Space Systems Command (SSC) will develop the PTS-G space and ground systems to provide worldwide assured-access communications for tactical warfighters. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                             Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 4:             PE 1206761SF / Protected Tactical Service (PTS) Advanced Component Development & Prototypes (ACD&P) PTS-G will consist of space vehicles utilizing military Ka band and X band payloads (PTS-G-Ka and PTS-G-X), and ground infrastructure (system controller/hub with gateways), and will connect to existing Protected Tactical SATCOM Family of Systems ground infrastructure (mission management system and cryptographic key management system) developed under the PTES program, as well as integrating legacy SATCOM waveforms. PTS-G will consist of multiple satellites that can provide either X-band and/or mil Ka-band transponded capability while also supporting the utilization of the PTW Waveform. PTW modems for user terminals will be acquired by each Service and by international partners. Initially, PTS-G will provide capabilities in select regions. PTS-G will target a solution that can provide worldwide coverage. PTS-G will be interoperable with the PTES program to perform management and cryptographic key management for PTW users, but PTS-G will procure and install the associated PTES Joint Hubs and other ground infrastructure to operate the satellites, anchor the data, and perform Operation and Support (O&S). In addition, the PTS-R system will be integrated with components of PTES and will be complementary to PTS-G. PTS-G addresses the gap in protected communications capability identified in the USSF FD and in the Joint Space Communications Layer (JSCL) Initial Capabilities Document (ICD). To meet the warfighter requirements for protected tactical MILSATCOM and the capability gaps identified in these studies in a timely and cost-effective manner, use and modification of existing capabilities and Commercial Off the Shelf (COTS) products will be leveraged to the maximum extent, to develop the PTS-G capabilities. SSC will strategically execute prototyping and risk reduction as needed to develop and deploy PTS-G capabilities. This program element may include necessary civilian pay expenses required to manage, execute, and deliver PTS weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1206770SF$$, $$Enterprise Ground Services$$, $$rdte_sf_ba7$$, $$sprco$$, 2026, 0, 0, 0, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$The Assistant Secretary of the Air Force for Space Acquisition and Integration directed the formation of a Combined Program Office (CPO) by merging Enterprise Ground Services (EGS) from Space Systems Command (SSC) and Ground Command, Control, and Communications (GC3) from the Space Rapid Capabilities Office (Space RCO). The CPO is called the Rapid Resilient Command and Control (R2C2) CPO and utilizes the Space RCO acquisition authorities under the Space RCO Program Executive Officer to execute funding in the EGS and GC3 program elements to develop an extensible, scalable, modular ground segment solution capable of supporting protect and defend missions of the United States Space Force. Combined EGS and GC3 funding will be used wholly and directly to support CPO activities. R2C2 will continue development and integration of the satellite operations ground segment solution (SatOps) to support the protect and defend mission set, including, but not limited to, capabilities and services needed to perform mission control. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:           PE 1206770SF / Enterprise Ground Services Operational Systems Development$$, NULL, NULL, NULL, NULL, NULL, NULL, 72, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1206771SF$$, $$Commercial Services$$, $$rdte_sf_ba5$$, $$dw_osd$$, 2026, 36628000, 0, 40000000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$Commercial Services delivers integrated, effective, efficient, and resilient commercial space capabilities to the warfighter in support of OSD's Commercial Space Integration Strategy and USSF's Commercial Space Strategy. It determines capability needs in USSF mission area architectures that can and should be fulfilled with commercial capabilities, identifies and integrates viable commercial solutions, and ensures the reliability, availability, resiliency, cybersecurity, operational utility and interoperability of the commercial capability to be presented to the space operators, military warfighters, and combatant commands. It ensures commercial capabilities will be available in peacetime and through the entire spectrum of conflict. The Commercial Space Office (COMSO) leads USSF efforts to develop sufficient and efficient capabilities by integrating commercial capabilities into hybrid (government, commercial, allied) architectures. Project 650008 funds Commercial Augmentation Space Reserve (CASR), a contractually managed framework for building relationships with industry during peacetime to ensure DoD access to commercial space capabilities throughout the spectrum of conflict. This funding supports the initial establishment and execution of the CASR program and activities to include contractual integration of commercial providers into CASR framework; threat sharing; wargaming/exercises; readiness and inspection program of CASR companies; Commercial Space Marketplace for Innovation and Collaboration (COSMIC); and other CASR incentives (security, cyber, protection measures, etc.). Project 650009 funds Commercial Capability Integration. With the commercial space industry innovating and developing capability at a record rate, COMSO will leverage the full force of this innovation by rapidly integrating commercial space capabilities to meet warfighter demand. The near-term focus of this effort is to expand commercial integration efforts where architecture gaps and current/emerging commercial capabilities match, in areas such as as space sensing and multi-domain awareness, Space-Based Environmental Monitoring (SBEM), alternate forms of Positioning, Navigation and Timing (alternate PNT), Space Domain Awareness (SDA), and Space Access, Mobility and Logistics (SAML). Commercial Capability Integration efforts will encompass all USSF mission areas to identify and integrate commercial capabilities necessary to meet warfighter needs. Leveraging commercial space will allow for cost efficiencies and will expedite delivery of space capabilities to the warfighter. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:            PE 1206771SF / Commercial Services System Development & Demonstration (SDD) This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, NULL, 26128000, 29008000, 31625000, NULL, NULL, 39, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 44699000, 168026000, 23752000, 23752000, 0, 23752000, 32258000, $$Commercial Services delivers integrated, effective, efficient, and resilient commercial space capabilities to the warfighter in support of OSW's Commercial Space Integration Strategy and USSF's Commercial Space Strategy. It determines capability needs in USSF mission area architectures that can and should be fulfilled with commercial capabilities, identifies and integrates viable commercial solutions, and ensures the reliability, availability, resiliency, cybersecurity, operational utility and interoperability of the commercial capability to be presented to the space operators, military warfighters, and combatant commands. It ensures commercial capabilities will be available in peacetime and through the entire spectrum of conflict. The Commercial Space Office (COMSO) leads USSF efforts to develop sufficient and efficient capabilities by integrating commercial capabilities into hybrid (government, commercial, allied) architectures. Project 650008 funds Commercial Augmentation Space Reserve (CASR), a contractually managed framework for building relationships with industry during peacetime to ensure DoW access to commercial space capabilities throughout the spectrum of conflict. This funding supports the initial establishment and execution of the CASR program and activities to include contractual integration of commercial providers into CASR framework; threat sharing; wargaming/exercises; readiness and inspection program of CASR companies; Commercial Space Marketplace for Innovation and Collaboration (COSMIC); and other CASR incentives (security, cyber, protection measures, etc.). Project 650009 funds Commercial Capability Integration. With the commercial space industry innovating and developing capability at a record rate, COMSO will leverage the full force of this innovation by rapidly integrating commercial space capabilities to meet warfighter demand. The near-term focus of this effort is to expand commercial integration efforts where architecture gaps and current/emerging commercial capabilities match, in areas such as as space sensing and multi-domain awareness, Space-Based Environmental Monitoring (SBEM), alternate forms of Positioning, Navigation and Timing (alternate PNT), Space Domain Awareness (SDA), and Space Access, Mobility and Logistics (SAML). Commercial Capability Integration efforts will encompass all USSF mission areas to identify and integrate commercial capabilities necessary to meet warfighter needs. Leveraging commercial space will allow for cost efficiencies and will expedite delivery of space capabilities to the warfighter. This program falls within the Multi-Mission mission area which provides the systems and efforts that evenly contribute to multiple mission areas across the space enterprise. Space Force investment program interdependencies include: Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                       Date: April 2026 Appropriation/Budget Activity                                             R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:      PE 1206771SF / Commercial Services System Development & Demonstration (SDD) RDT&E Budget Line Items: Defensive Cyber Operations - Space (1203040SF); Rapid Resilient Command and Control (1206772SF); Satellite Control Network (1203110SF); Space and Missile Test and Evaluation (1203173SF; Space Force IT, Data Analytics, Digital (1203010SF); and elements of Procurement Budget Line Items: AF Satellite Comm System (AFSCOM); Spaceborne Equip (Comsec) (MC0MSE); Spares and Repair Parts (SSPARE); Space Digital Integrated Network (SDN000)” The Commercial Space Office (COMSO) is developing the Commercial Services (PE 1206771SF) program for Guardians across all USSF Mission Areas. As a result, the Service will streamline capabilities development through institutional processes; improve readiness and operational reach of existing force structure; augment, supplement, and/or integrate Allies, partners, and commercial space to USSF units This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F, 0606392F. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1206853SF$$, $$National Security Space Launch Program (SPACE) - EMD$$, $$rdte_sf_ba5$$, $$ssc_assured_a$$, 2026, 6595000, 0, 103392000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$The National Security Space Launch (NSSL) program provides a space launch service that satisfies the government's National Launch Forecast (NLF) requirements to place National Security Space (NSS) space vehicles on orbit. NSSL is a launch service, not a weapon system, which is primarily funded with production funds. NSSL Phase 2 development, started late FY 2014, funds research and development activities and related studies, to include, but not limited to, investments in new and/ or upgraded launch systems and associated launch facilities to meet NSS launch needs leveraging domestic commercial launch providers. The Space Force continues to provide support to monitor and close out the remaining activities for the Launch Service Agreement (LSA) public-private partnership with United Launch Alliance Vulcan Centaur. Future development to capitalize on new technology and innovations developed by industry may continue to utilize public- private partnerships. The FY 2026 request was reduced by $0.065 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. In PY 2.246M was expended for civilian pay expenses in this program element, and in CY 2.650M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:           PE 1206853SF / National Security Space Launch Program (SPACE) - EMD System Development & Demonstration (SDD)$$, NULL, 3735000, 3707000, 3756000, NULL, NULL, 40, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 101138000, 6540000, 2748000, 2748000, 0, 2748000, 3831000, $$System Delta 80 is executing the National Security Space Launch program (Program Element NSSL00) for Guardians across Space Access. As a result, the Service will advance space-based technology associated with Golden Dome, deliver space domain awareness capabilities, improve readiness and operational reach of existing force structure, and ensure resilient infrastructure, equipment, and personnel. The National Security Space Launch (NSSL) program provides a space launch service that satisfies the government's National Launch Forecast (NLF) requirements to place National Security Space (NSS) space vehicles on orbit. NSSL is a launch service, not a weapon system, which is primarily funded with production funds. NSSL Phase 2 development, started late FY 2014, funds research and development activities and related studies, to include, but not limited to, investments in new and/ or upgraded launch systems and associated launch facilities to meet NSS launch needs leveraging domestic commercial launch providers. The Space Force continues to provide support to monitor and close out the remaining activities for the Launch Service Agreement (LSA) public-private partnership with United Launch Alliance Vulcan Centaur. Future development to capitalize on new technology and innovations developed by industry may continue to utilize public- private partnerships. This program falls within the Launch mission area which provides the launch systems and corresponding ground architecture required to provide assured access to space, the movement of payloads to and from the space domain, and provision a safe and secure range for space launch operations. Program interdependencies include: EELVP (Space) - EMD (1206853SF); National Security Space Launch Program (1203953SF); Rocket System Launch Program (1206860SF); SDA Launch Procurement (1203954SF); Space Access, Mobility & Logistics (1203955SF); Spacelift Range System (1203182SF); Tactically Responsive Launch (1206862SF). This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:           PE 1206853SF / National Security Space Launch Program (SPACE) - EMD System Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1206855SF$$, $$Evolved Strategic SATCOM (ESS)$$, $$rdte_sf_ba5$$, $$sf$$, 2026, 1229929000, 0, 918581000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$ESS is the backbone for Joint All Domain Nuclear Command, Control and Communications (NC3). The system will replace Advanced Extremely High Frequency (AEHF) Strategic Satellite Communications (SATCOM) services to provide global, integrated, survivable, resilient, and dynamic ground and satellite communications for assured strategic capabilities across the conflict continuum. The ESS program underwent a resiliency architecture shift to address emerging sophisticated threats and to ensure strategic SATCOM capabilities are available to the National Command Authority (NCA), Combatant Commanders, and joint warfighters in any potential future conflict. It will provide the only arctic DoD strategic communication capability across the joint enterprise, and will provide worldwide secure, jam-resistant communications for strategic ground, sea, and air assets. ESS will support existing strategic user terminals in all operational environments. ESS is acquired and developed in several parallel efforts to accelerate delivery of capability to warfighters by the strategic need date in FY 2032. The ESS System includes a Space Segment (ACAT-I), Ground, User, and Integration Segment (ACAT-I equiv), and a Crypto Segment (ACAT-III). The Space Segment is converting to a Major Capability Acquisition (MCA) from a Middle-Tier Acquisition (MTA) in FY 2025. The Ground Segment, also known as GRIFFON - Ground Resilient Integration & Framework for Operational NC3, is comprised of the Ground Integration and Framework (GIF), System of Systems Integration (SoSI), and Mission Software Applications. This enables a resilient and modular cybersecure architecture that bridges the gap between modern software best practices and legacy user terminal capability. The GIF/SoSI is leveraging Software Acquisition Pathway Other Transactional Authority for rapid prototyping of ground software. The ESS Ground Framework creates the cybersecure software development, integration, and operational environments utilizing agile Modular Open Systems Approach (MOSA) principles and onboards hosted external mission applications and services. The SoSI ensures all ESS segments that are acquired in parallel, in addition to external entities, work together to accomplish the mission. Additional mission-unique capabilities, like In-Band Command and Control (C2), Out-of-Band C2, Strategic Mission Planning, Test, Evaluation, Training, and other similar mission capabilities will be acquired modularly as applications that will be hosted on the ESS Ground Framework. The Crypto Segment is focused on the development, integration and testing of National Security Agency (NSA)-certified End-Cryptographic Units (ECUs) that are required for secure strategic communications encryption in the ESS payloads, bus, and test terminals. The modular acquisition approach allows the program to avoid "vendor lock” in all segments and creates opportunities for industry competition and teaming with small innovative non-traditional partners for the Ground Segment on the Space Enterprise Consortium (SpEC) Other Transactional Authority (OTA). SpEC requires ESS ground segment primary contractors that are developing software to utilize small businesses for a significant portion of the prototyping work, allowing the program to integrate innovative best practices, increase agility, reduce costs and development lifecycles, while also expanding the resilient and strategic SATCOM capabilities. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 4:            PE 1206855SF / Evolved Strategic SATCOM (ESS) Advanced Component Development & Prototypes (ACD&P) The ESS system adheres to NC3 classification requirements. ESS will meet the requirements for strategic communications and capability gaps identified in the Protected Satellite Communications Services (PSCS) Analysis of Alternatives (AoA), the Protected Follow-on for Resiliency (PAFR) Study and the Strategic Tiger Team. The ESS architecture and functionality will be designed in accordance with the United States Space Command's signed ESS Concept of Operations and the Joint Requirements Oversight Council's validated Capability Development Document (CDD) satisfying the legacy Advanced Extremely High Frequency (AEHF) strategic requirements and mission performance with enhancements for increased resiliency and cybersecurity. The ESS system will satisfy emerging requirements using modular open system approaches to support incremental enhancements. This program element may include necessary civilian pay expenses required to manage, execute, and deliver ESS weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF, 1206398SF. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 1682562000, 1017348000, 1172547000, NULL, NULL, 21, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 0, 0, 1838718000, 1838718000, 0, 1838718000, 951863000, $$This is not a new start. The Evolved Strategic SATCOM (ESS) Program office is developing the next-generation strategic SATCOM (Projects ESS000, 650014, 650015) for Guardians across the Satellite Communications Mission Area. As a result, the Service will improve readiness and operational reach of existing force structure, integrate Allies, partners, and commercial space to USSF units, and deliver resilient infrastructure, equipment, and personnel. ESS is the backbone for Joint All Domain Nuclear Command, Control and Communications (NC3). The system will replace Advanced Extremely High Frequency (AEHF) Strategic Satellite Communications (SATCOM) services to provide global, integrated, survivable, resilient, and dynamic ground and satellite communications for assured strategic capabilities across the conflict continuum. The ESS program underwent a resiliency architecture shift to address emerging sophisticated threats and to ensure strategic SATCOM capabilities are available to the National Command Authority (NCA), Combatant Commanders, and joint warfighters in any potential future conflict. ESS will provide the only arctic DoW strategic communication capability across the joint enterprise, and will provide worldwide secure, jam-resistant communications for strategic ground, sea, and air assets. ESS will support existing strategic user terminals in all operational environments. ESS is acquired and developed in several parallel efforts to accelerate delivery of capability to warfighters by the strategic need date in FY 2032. The ESS System includes a Space Segment (ACAT-I), Ground, User, and Integration Segment (ACAT-I equiv), and a Crypto Segment (ACAT-III). The Space Segment is a Major Capability Acquisition (MCA) program in the Engineering Manufacturing and Development (EMD) phase. The Ground Segment, also known as GRIFFON - Ground Resilient Integration & Framework for Operational NC3, is comprised of the Ground Integration and Framework (GIF), System of Systems Integration (SoSI), and Mission Software Applications. This enables a resilient and modular cybersecure architecture that bridges the gap between modern software practices and legacy user terminal capability. The GIF/SoSI and Mission Planning Software efforts are leveraging the Software Acquisition Pathway Other Transactional Authorities for rapid prototyping of ground software. The ESS Ground Framework creates cybersecure software development, integration, and operational environments utilizing agile Modular Open Systems Approach (MOSA) principles and onboards hosted external mission applications and services. SoSI ensures all ESS segments that are acquired in parallel, in addition to external entities, work together to accomplish the mission. Additional mission-unique capabilities, like In-Band Command and Control (C2); Out- of-Band C2; Mission Planning; Test, Evaluation, and Training; and other similar mission capabilities will be acquired modularly as applications that will be hosted on the ESS Ground Framework. ESS Ground is also pursuing alternative approaches to software applications and C2 Terminals to maintain competition and bolster the industrial base. The Crypto Segment is focused on the development, integration and testing of National Security Agency (NSA)-certified End-Cryptographic Units (ECUs) Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:       PE 1206855SF / Evolved Strategic SATCOM (ESS) System Development & Demonstration (SDD) and modernization of the Protected Key Management Architecture (PKMA), that are both required for secure strategic communications encryption in the ESS payloads, bus, and test terminals. The modular acquisition approach allows the program to avoid "vendor lock” in all segments and creates opportunities for industry competition and teaming with small innovative non-traditional partners for the Ground Segment using the Space Enterprise Consortium (SpEC) Other Transactional Authority (OTA). SpEC requires ESS ground segment primary contractors that are developing software to utilize small businesses for a significant portion of the prototyping work, allowing the program to integrate innovative practices, increase agility, and reduce costs and development lifecycles, while also expanding the resilient and strategic SATCOM capabilities. The ESS system adheres to NC3 classification requirements. ESS will meet the requirements for strategic communications and capability gaps identified in the Protected Satellite Communications Services (PSCS) Analysis of Alternatives (AoA), the PSCS AoA Follow-on for Resiliency (PAFR) Study and the Strategic Tiger Team. The ESS architecture and functionality will be designed in accordance with the United States Space Command's signed ESS Concept of Operations and the Joint Requirements Oversight Council's validated Capability Development Document (CDD) satisfying the legacy Advanced Extremely High Frequency (AEHF) strategic requirements and mission performance with enhancements for increased resiliency and cybersecurity. The ESS system will satisfy emerging requirements using modular open system approaches to support incremental enhancements. This program falls within the Satellite Communications (SATCOM) mission area which provides the space and dedicated ground architecture required to securely transport wideband, narrowband, tactical, and strategic satellite communications, including USSF-funded SATCOM terminals and commercial SATCOM activities. Space Force investment program interdependencies include: RDT&E Budget Line Items: Advanced EHF MILSATCOM (1206431SF); Commercial SATCOM Integration (1206445SF); Evolved Strategic SATCOM (ESS) (1206855SF); Family of Adv BLoS Terminals (FAB-T) (1203001SF); Narrowband Satellite Communications (1203109SF); Protected Tactical Enterprise Service (1206760SF); Protected Tactical Service (1206761SF; Space Tech Development & Prototyping (1206410SF); Tech Transition (Space) (1206458SF); Wideband Global SATCOM (SPACE) (1206433SF); Data Transport and Networking (1203156SF); Space Data Network (1203636SF); and elements of Procurement Budget Line Items: Family of Beyond Line-of-Sight Terminals (FBLOST); Mobile User Objective System (MUOS00); MILSATCOM (MILSAT); Wideband SATCOM Operational Management Systems (WSOMS0); Auxiliary Payloads (AUX000); Proliferated Low Earth Orbit SATCOM (PLEO00); PTES HUB (PTES00); ESS (ESS000) This program element may include necessary civilian pay expenses required to manage, execute, and deliver ESS weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF, 1206398SF. As of FY 2027, ESS has transitioned to Budget Activity 5. Previously, this effort was in Budget Activity 4 (Project 643725). This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                   Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 5:        PE 1206855SF / Evolved Strategic SATCOM (ESS) System Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1206857SF$$, $$Space Rapid Capabilities Office$$, $$rdte_sf_ba4$$, $$sprco$$, 2026, 9664000, 0, 107892000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$The Space Rapid Capabilities Office (Space RCO) mission is to expedite the development and fielding of operationally focused capabilities for immediate and near term needs as directed by the Space RCO Board of Directors (BoD). Key operating principles include a short and narrow chain of command, overarching programmatic insight, early and prominent war fighter involvement, and small integrated teams within a single office to rapidly augment existing space capabilities when needed, to expand operational capability, reconstitute/replenish/protect critical space capabilities to reserve "continuity of operations" capability, and exploit space technological or operational innovations to increase U.S. advantage. The Space RCO is ready to develop, test, train, and equip war fighter needs as they are identified at any time. First, the requirements must be validated by the commander U.S. Space Command; second, the project must be approved by the Space RCO BoD; third, the project will be executed by the Space RCO. If the effort is initiated during execution year, it will be described in the next year's budget exhibit. Space RCO is supporting the Rapid Resilient Command and Control (R2C2) Combined Program Office (CPO) in FY 2025. The R2C2 CPO utilizes the Space RCO acquisition authorities under the Space RCO Program Executive Officer to execute funding in the Enterprise Ground Services (EGS) and Ground Command, Control, and Communications (GC3) program elements to develop an extensible, scalable, modular ground segment solution capable of supporting protect and defend missions of the United States Space Force. Combined EGS and GC3 funding will be used wholly and directly to support CPO activities. R2C2 will continue development and integration of the satellite operations (SatOps) ground segment solution to support the protect and defend mission set, including, but not limited to, capabilities and services needed to perform mission control. Space RCO is supporting the Air Force Research Lab (AFRL) developed Space Solar Power project to collect solar energy and provide uninterrupted, assured, and logistically agile power to expeditionary forces operating in unimproved areas such as forward operating bases. AFRL formulated the Space Solar Power Incremental Demonstrations and Research (SSPIDR) project to rapidly demonstrate this innovative technology via a series of integrated demos and technology development/ maturation efforts. In addition, Space RCO will conduct studies and analyses for future programs to support the BoD. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 4:            PE 1206857SF / Space Rapid Capabilities Office Advanced Component Development & Prototypes (ACD&P) This program element may include necessary civilian pay expenses required to manage, execute, and deliver Space RCO weapon system capabilities. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 10301000, 10483000, 10680000, NULL, NULL, 22, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 104661000, 15582000, 9950000, 9950000, 0, 9950000, 10894000, $$The Space Rapid Capabilities Office (Space RCO) mission is to expedite the development and fielding of operationally focused capabilities for immediate and near term needs as directed by the Space RCO Board of Directors (BoD) for Guardians across Space Control, Operations, and Warfighting. Key operating principles include a short and narrow chain of command, overarching programmatic insight, early and prominent war fighter involvement, and small integrated teams within a single office to rapidly augment existing space capabilities when needed, to expand operational capability, reconstitute/replenish/protect critical space capabilities to reserve "continuity of operations" capability, and exploit space technological or operational innovations to increase U.S. advantage. As a result, the Service will deter, neutralize, defeat and/or destroy counterspace threats and defend the homeland. The Service will also augment, supplement, and/or integrate Allies, partners, and commercial space to USSF units. Furthermore, the Service will continue to advance all near term effects and provide resilient infrastructure, equipment, and personnel. The Space RCO is ready to develop, test, train, and equip war fighter needs as they are identified at any time. First, the requirements must be validated by the commander U.S. Space Command; second, the project must be approved by the Space RCO BoD; third, the project will be executed by the Space RCO. If the effort is initiated during execution year, it will be described in the next year's budget exhibit. Space RCO is supporting the Rapid Resilient Command and Control (R2C2) Combined Program Office (CPO) in FY 2025. The R2C2 CPO utilizes the Space RCO acquisition authorities under the Space RCO Program Executive Officer to execute funding in the Enterprise Ground Services (EGS) and Ground Command, Control, and Communications (GC3) program elements to develop an extensible, scalable, modular ground segment solution capable of supporting protect and defend missions of the United States Space Force. Combined EGS and GC3 funding will be used wholly and directly to support CPO activities. R2C2 will continue development and integration of the satellite operations (SatOps) ground segment solution to support the protect and defend mission set, including, but not limited to, capabilities and services needed to perform mission control. Space RCO is supporting the Air Force Research Lab (AFRL) developed Space Solar Power project to collect solar energy and provide uninterrupted, assured, and logistically agile power to expeditionary forces operating in unimproved areas such as forward operating bases. AFRL formulated the Space Solar Power Incremental Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 4:         PE 1206857SF / Space Rapid Capabilities Office Advanced Component Development & Prototypes (ACD&P) Demonstrations and Research (SSPIDR) project to rapidly demonstrate this innovative technology via a series of integrated demos and technology development/ maturation efforts. In addition, Space RCO will conduct studies and analyses for future programs to support the BoD. This program falls within the Science and Technology (S&T) and Test & Evaluation (T&E) mission area which provides the S&T initiatives, demonstrations, experiments, and studies towards developing next-generation space capabilities. The T&E mission area provides all efforts required to establish and operate the test infrastructure for USSF capabilities. Program interdependencies include: Defense Research Sciences (0601102SF); Major T&E Investments - Space (1206759SF); Small Business Innovation Research (1205502SF); Space Advanced Tech Dev / Demo (1206616SF); Space Innov Intg & Rapid Tech Dev (1203174SF); Space Science and Technology (1206310SF); Space Systems Prototype Transition (1206427SF); Space Technology (1206601SF); Space Test and Evaluation (1202051SF); Space Test Program (1206864SF); and University Research Initiatives (0601103SF). This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1206860SF$$, $$Rocket Systems Launch Program (SPACE)$$, $$rdte_sf_ba6$$, $$ssc_assured_a$$, 2026, 19857000, 0, 35134000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$Rocket Systems Launch Program (RSLP) provides responsive space and Research, Development, Test and Evaluation (RDT&E) launch vehicle support to DoD and other government agencies using commercial launch systems and excess ballistic missile assets. The RSLP mission was established by the Secretary of Defense in 1972. The small launch program complements the National Security Space Launch (NSSL) program with multiple options to acquire dedicated spacelift and rideshare services for developmental, demonstration, and small operational space vehicles. It provides mission planning, payload integration, vehicle acquisition, processing, launch operations, booster storage and disposition, aging surveillance, maintenance and logistics support for selected DoD responsive space and RDT&E launches. Costs directly attributable to a specific launch or program (e.g., reliability of flight testing, maintenance of launch vehicle processing infrastructure) are paid by non-Space Force users (Navy, Army, Missile Defense Agency (MDA), Defense Advanced Research Project Agency (DARPA), National Reconnaissance Office (NRO), etc.). RSLP maintains exclusive control of decommissioned Minuteman and Peacekeeper assets used in testing to include refurbishment, transportation and handling, storage, aging surveillance, and launch services. RSLP enhances capacity to provide mid-to-low & polar-to-high inclination orbits as a part of support for national security space programs through Spaceports that are commercially licensed by the Federal Aviation Administration and received funding from the local or State government. RSLP also funds general research, development, prototyping, integration, and supplemental reliability of flight testing efforts for launch to enhance the reliability of a variety of launch vehicles using RSLP motors for suborbital and orbital missions (e.g., updates to the Modular Mechanical Ordnance Destruct System). While the corresponding RSLP Procurement, Space Force line is set to $0 due to no planned procurements of Space Force funded missions, the activities funded by this RDT&E line are still required to safely store and maintain the RSLP inventory of launch assets. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. In PY $0.0M was expended for civilian pay expenses in this program element, and in CY $0.180M is forecasted for civilian pay expenses in this program element. The FY 2026 request was reduced by $0.195 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 6:          PE 1206860SF / Rocket Systems Launch Program (SPACE) RDT&E Management Support$$, NULL, 21163000, 21537000, 21943000, NULL, NULL, 48, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 34761000, 65031000, 19965000, 19965000, 0, 19965000, 22380000, $$System Delta 80 is developing, operating, prototyping, and executing the Rocket System Launch Program (RSLP) for Guardians across Space Access, Warfighting, and Combat Support. As a result, the Service will advance space-based technology associated with Golden Dome, deliver space domain awareness capabilities, improve readiness and operational reach of existing force structure, continue to advance all near term effects, and ensure resilient infrastructure, equipment, and personnel. RSLP provides responsive space and Research, Development, Test and Evaluation (RDT&E) launch vehicle support to the Department of War (DoW) and other government agencies using commercial launch systems and excess ballistic missile assets. The RSLP mission was established by the Secretary of Defense in 1972. The small launch program complements the National Security Space Launch (NSSL) program with multiple options to acquire dedicated spacelift and rideshare services for developmental, demonstration, and small operational space vehicles. It provides mission planning, payload integration, vehicle acquisition, processing, launch operations, booster storage and disposition, aging surveillance, maintenance and logistics support for selected DoW responsive space and RDT&E launches. Costs directly attributable to a specific launch or program (e.g., reliability of flight testing, maintenance of launch vehicle processing infrastructure) are paid by users (Navy, Army, Missile Defense Agency (MDA), Defense Advanced Research Project Agency (DARPA), National Reconnaissance Office (NRO), etc.). RSLP maintains exclusive control of decommissioned Minuteman and Peacekeeper assets used in testing to include refurbishment, transportation and handling, storage, aging surveillance, and launch services. RSLP enhances capacity to provide mid-to-low & polar-to-high inclination orbits as a part of support for national security space programs through Spaceports that are commercially licensed by the Federal Aviation Administration and received funding from the local or State government. RSLP also funds general research, development, prototyping, integration, and supplemental reliability of flight testing efforts for launch to enhance the reliability of a variety of launch vehicles using RSLP motors for suborbital and orbital missions (e.g., updates to the Modular Mechanical Ordnance Destruct System). While the corresponding RSLP Procurement, Space Force line is set to 0 due to no planned procurements of Space Force funded missions, the activities funded by this RDT&E line are still required to safely store and maintain the RSLP inventory of launch assets. This program falls within the Launch mission area which provides the launch systems and corresponding ground architecture required to provide assured access to space, the movement of payloads to and from the space domain, and provision a safe and secure range for space launch operations. Program interdependencies include: EELVP (Space) - EMD (1206853SF); National Security Space Launch Program (1203953SF); Space Test Program (1206864SF); SDA Launch Procurement (1203954SF); Space Access, Mobility & Logistics (1203955SF); Spacelift Range System (1203182SF); Tactically Responsive Space (1206862SF). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 6:              PE 1206860SF / Rocket Systems Launch Program (SPACE) RDT&E Management Support The FY 2026 spend plan amount for Research, Development, Test & Evaluation, Space Force, Rocket System Launch Program (RSLP) includes 65,031 thousand of discretionary and 60,000 thousand of mandatory (reconciliation) for a total of 125,031 thousand. The mandatory funds will be used to expand the capabilities at the Mid- Atlantic Regional Spaceport to provide a resilient and responsive launch enterprise. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1206862SF$$, $$Tactically Responsive Space$$, $$rdte_sf_ba4$$, $$ssc_sda$$, 2026, 33282000, 0, 40052000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$Tactically Responsive Space (TacRS) rapidly integrates and deploys space-based end-to-end capabilities in response to Combatant Commander (CCMD) urgent needs for power projection and characterization. TacRS missions will be capable of entering operations and generating effects on tactically relevant timelines. The near- term focus of TacRS is to establish these foundational concepts enabling the Space Force to establish the necessary capabilities, processes, concept of operations, and tactics, techniques and procedures to enable a rapid response. In FY 2026, funding will be used to finalize an early operational Space Domain Awareness (SDA) capability that will involve a rapid call-up, launch, and space vehicle operations. In addition, funding will be used to develop the maneuverable, prepositioned SDA TacRS missions. Furthermore, funding will be used to support follow-on SDA operational missions requiring both rapid launch and maneuverable, prepositioned capabilities. Finally, funding will be used to mature new TacRS concepts including, but not limited to, the ability to quickly utilize commercial capabilities. The FY 2026 request for TacRS includes $33,282 thousands of discretionary and $135,000 thousands of mandatory (reconciliation) for a total of $168,282 thousands. The mandatory funds additional TacRS space and launch vehicles in FY 2026. Further information for this reconciliation request is provided in Section 20009 (INDOPACOM Capabilities) of the Reconciliation Exhibit. This program element may include necessary civilian pay expenses required to manage, execute, and deliver Tactically Responsive Space weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                            Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 4:           PE 1206862SF / Tactically Responsive Space Advanced Component Development & Prototypes (ACD&P)$$, NULL, 54000000, 62700000, 48100000, NULL, NULL, 23, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 43635000, 29800000, 86306000, 86306000, 0, 86306000, 49000000, $$The Space Safari Office is developing, prototyping, and executing the Tactically Responsive Space (TacRS) (project 643835) to deliver space control functions to Guardians and Combatant Commands. As a result of these activities, the Service will deliver capabilities to augment, supplement, and integrate with Allies, partners, and commercial space companies to Space Force units. TacRS rapidly integrates and deploys space-based end-to-end capabilities in response to Combatant Commander (CCMD) urgent needs for power projection and characterization. TacRS missions will be capable of entering operations and generating effects on tactically relevant timelines. The near-term focus of TacRS is to establish these foundational concepts enabling the Space Force to establish the necessary capabilities, processes, concept of operations, and tactics, techniques and procedures to enable a rapid response. In FY 2026, funding will be used to finalize an early operational Space Domain Awareness (SDA) capability that will involve a rapid call-up, launch, and space vehicle operations. In addition, funding will be used to develop the maneuverable, prepositioned SDA TacRS missions. Furthermore, funding will be used to support follow-on SDA operational missions requiring both rapid launch and maneuverable, prepositioned capabilities. Finally, funding will be used to mature new TacRS concepts including, but not limited to, the ability to quickly utilize commercial capabilities. This program falls within the Combat Power mission area which provides the systems required to protect and defend space-based capabilities and ensure space superiority by enabling and executing combat operations in space. Program interdependencies include: Counterspace Operations (1203936SF); Counterspace Systems (1206421SF); Defense Recon Support Activities (1203159SF); National Space Defense Center (1203620SF); National Space Defense Center - MIP (1203621SF); Space Control Technology (1206438SF); Space Intelligence Activities (1203375SF); Space Superiority ISR (1203330SF); Rocket Systems Launch Program (1206860SF); and Rapid Resilient Command & Control (1206772SF). The FY 2026 spend plan amount for Research, Development, Test & Evaluation, Space Force, Tactically Responsive Space (TacRS) includes $29,800 thousand of discretionary and $135,000 thousand of mandatory (reconciliation) for a total of $164,800 thousand. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                       Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 4:         PE 1206862SF / Tactically Responsive Space Advanced Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1206864SF$$, $$Space Test Program (STP)$$, $$rdte_sf_ba6$$, $$saf_sp$$, 2026, 28787000, 0, 30279000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$America secures peace through strength, and that strength is built on an unyielding technological edge in space - an edge forged through strategic investments in the Department of Defense's (DoD) Space Test Program (STP). As the DoD's primary gateway for space experimentation to lead to space superiority, STP is a critical enabler of national security and a direct investment in deterring adversaries like China. The DoD Space Experiments Review Board (SERB) is central to STP's mission, conducting a rigorous annual review to evaluate and prioritize space experiment proposals. After being reviewed by the SERB, STP provides these cutting-edge technologies with rapid access to the demanding environment of space, accelerating their maturation into operational capabilities. This ensures our troops maintain a decisive advantage across all domains by: • Providing Access for Rigorous Testing and Evaluation: STP enables space access to test technologies, raise Technology Readiness Levels, and validate research. • Ensuring Warfighter Relevance: Through the DoD SERB prioritization, STP focuses on space technologies with direct military applications, benefiting warfighters across all domains. • Developing Future Operational Capabilities: STP matures promising space technologies into operational systems, strengthening the United States Space Force and ensuring its advantage. • Fostering Cross-Service Collaboration and Innovation: STP, DoD's space experimentation hub, fosters cross-service/agency collaboration, aligning tech priorities and minimizing redundancy. • Maximizing Value Through Collaboration: STP partners with government, commercial, and international entities to maximize taxpayer value, broaden space access, and optimize launch opportunities. STP adheres to Executive Orders 10521 and 13185, and the requirement from the Office of the Under Secretary of Defense for Research and Engineering (OUSD (R&E)) to support research, per DoD Instruction 3210.1, Administration and Support of Basic Research. In addition, the Deputy Secretary of Defense Space Test Program Management & Funding Policy, issued in July 2002, reaffirmed STP as the primary provider of spaceflight for the DoD space research community. The July 2002 policy statement also reaffirmed STP's role as the single manager for all DoD payloads on the International Space Station (ISS). This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 6:        PE 1206864SF / Space Test Program (STP) RDT&E Management Support The FY 2026 request was reduced by $0.283M for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, NULL, 30675000, 31102000, 31660000, NULL, NULL, 49, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 29568000, 28404000, 29598000, 29598000, 0, 29598000, 32294000, $$Space Systems Command is executing the Department of War (DoW) Space Test Program (Project 662617) through the Space Access and the Combat Power Enterprise. As a result, the United States Space Force will advance the Department's space capabilities development through institutional processes, principled public servants; space-minded warfighters; and bold and collaborative problem solvers. This program falls within the Science and Technology (S&T) and Test & Evaluation (T&E) mission area which provides the S&T initiatives, demonstrations, experiments, and studies towards developing next-generation space capabilities. The T&E mission area provides all efforts required to establish and operate the test infrastructure for USSF capabilities. Program interdependencies include: Defense Research Sciences (0601102SF); Major T&E Investments - Space (1206759SF); Small Business Innovation Research (1205502SF); Space Advanced Tech Dev / Demo (1206616SF); Space Innov Intg & Rapid Tech Dev (1203174SF); Space Rapid Capabilities Office (1206857SF); Space Science and Technology (1206310SF); Space Systems Prototype Transition (1206427SF); Space Technology (1206601SF); Space Test and Evaluation (1202051SF); University Research Initiatives (0601103SF). The Department of the Air Force (DAF), as the Department's designated Space Test Program (STP) Executive Agent (EA), provides a critical multi-user space program that is essential for national security. America secures peace through strength, and that strength is built on the unyielding technological edge in space forged by strategic investments in the STP. As the Department of War's (DoW) primary gateway for space experimentation, STP is a direct investment in deterring adversaries and ensuring the nation's space superiority. STP provides the primary spaceflight capability to demonstrate, evaluate, and accelerate risk-reducing and advanced technologies in operational space environments. STP is responsible for mission design, spacecraft acquisition, integration, launch, and on-orbit operations for emerging technologies from the entire DoW research community, including the Army, Navy, Air Force, Space Force, National Reconnaissance Office, and other agencies. By centrally financing these critical mission elements, STP offers the most cost-effective way to flight-test new space systems, technologies, and concepts. Central to STP's mission is the DoW Space Experiments Review Board (SERB), which conducts a rigorous annual review to evaluate and prioritize space experiment proposals to meet joint warfighter needs. This process ensures that STP focuses on cutting-edge technologies with direct military relevance, accelerating their maturation into operational capabilities and providing our troops with a decisive advantage. This strategic approach enables DoW space researchers to: •Demonstrate Feasibility: Prove the viability of new space systems and technologies through rigorous testing and evaluation, raising their Technology Readiness Levels. •Improve Operational Design: Characterize the space environment and sensor physics to enhance operational systems and future upgrades. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                             Date: April 2026 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 6:                PE 1206864SF / Space Test Program (STP) RDT&E Management Support •Develop Future Capabilities: Provide early operational capabilities to evaluate military utility, mature promising space technologies into operational systems, and quickly respond to new developments. •Foster Innovation and Collaboration: Offer first flight and high-risk tolerance opportunities for new space launch providers, leveraging diverse government, commercial, and international partners to maximize value and accelerate innovation. Furthermore, the DAF designates STP as the primary DoW program supporting human spaceflight. STP acts as the single manager for all DoW payloads on National Aeronautics and Space Administration (NASA) manned flights, including the International Space Station. In this role, STP performs or manages all crew training, payload integration, and operations for DoW experiments on NASA manned platforms. STP operates in accordance with Executive Orders 10521 and 13185, DoW Instruction 3210.1, and policy from the Office of the Under Secretary of War for Research and Engineering (OUSW(R&E)). STP's role as the primary provider of spaceflight for the DoW research community was reaffirmed by the Deputy Secretary of Defense in July 2002. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. The FY 2027 request was reduced by $0.278 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency" Cost Efficiency Initiative. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1206895C$$, $$Ballistic Missile Defense System Space Programs$$, $$rdte_dw_ba4$$, $$dw_mda$$, 2026, 97061000, 107597000, 119561000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 74, "original_pe": "1206895C", "page_header": "Defense-Wide"}$$::jsonb, $$SKA: The SKA project will deliver dedicated space sensors contributing to hit and kill assessment for Homeland Defense. Missile Defense Agency (MDA) Missile Defense System intercept testing experience provided a solid understanding of kill assessment physics to enable exploration of this critical capability. SKA incorporates Government Accountability Office (GAO) recommendations to examine the operational feasibility of disaggregating large satellites and to provide data for the business case for shared versus dedicated satellite control, including the ground antenna networks. The favorable cost and schedule performance on SKA is also consistent with the GAO's assessment of hosted payload programs. The SKA experiment utilizes a network of small infrared sensors integrated onto host satellites that while on orbit observe missile defense intercepts and deliver situational awareness hit and kill assessment declarations. Hypersonic & Ballistic Tracking Space Sensor (HBTSS): HBTSS will demonstrate a schedule-focused, cost-constrained capability to detect and track hypersonic threats and boosting conventional ballistic missiles. The key characteristic of the HBTSS prototype demonstration that sets it apart from other Overhead Persistent Infrared sensors is the requirement to provide fire-control quality tracking data. The enhanced tracking accuracy through missile burn out on ballistic threats and the enhanced tracking accuracy on hypersonic threats will provide the warfighter increased missile defense weapons systems engagement capability and higher accuracy impact predictions. The requirement for fire-control data necessitates that HBTSS be a highly sensitive, low-latency, high quality of service system. Following the successful demonstration of HBTSS capabilities, the responsibility for HBTSS operational fielding will be transferred to the United States Space Force and the MDA will continue the development of the next-generation of space-based fire control sensors for missile defense. Operationally, the HBTSS fire-control capability will be part of Space Development Agency's Proliferated Warfighter Space Architecture and will detect hypersonic, ballistic, and other advanced threats much sooner than terrestrial radars, providing hypersonic threat-tracking data for hand off through linked missile defense weapons. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Missile Defense Agency                                                                Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:             PE 1206895C / Ballistic Missile Defense System Space Programs Advanced Component Development & Prototypes (ACD&P) Space Applications for Missile Defense (SAMD): SAMD supports Golden Dome for America and Next-Generation Missile defense by providing systems-of-systems engineering, technology integration, global test (ground, flight and operational acceptance) and configuration of prototype and operational space capabilities internally and across agencies and service. Additionally, SAMD provides strategic planning, requirements development, program coordination and integration, acquisition, financial management, cost estimating, contracting, program protection, logistics, mission assurance, engineering, and program assessments for development and acquisition of space applications within MDA and jointly with the Agencies and Services. Beginning in FY 2026, SAMD will consolidate funding for the Missile Defense Space Enterprise Architecture to provide enterprise-level operations and sustainment in support of Missile Defense System Space Programs experimentation and testing. Individual programs will continue to fund mission unique requirements. Rapidly evolving rogue and peer missile threats have led to a change in national defense policy. The President's January 27, 2025, Executive Order established a goal of protecting the U.S. citizens, safeguarding critical infrastructure, and securing second-strike capability against missile attack from any adversary. MDA is responding with speed and intensity to deliver next-generation missile defenses to protect the U.S. against ballistic, hypersonic, cruise, and other advanced missile threats. This program submission reflects changes necessary to meet this evolving mission space. This Program Element (PE) also funds Cybersecurity efforts necessary to support Missile Defense System Space Programs.$$, NULL, 104060000, 53736000, 44109000, NULL, NULL, 139, $$RDTE_Vol2_MDA_RDTE_PB26_Justification_Book.pdf$$, $$MDA$$, FALSE, 115442000, 71263000, 95819000, 95819000, NULL, 95819000, 44404000, $$Space Applications for Missile Defense (SAMD): SAMD supports the President's Executive Order 14186 and Missile Defense System - Next by providing systems-of- systems engineering, space capabilities integration, prototyping, global test (ground, flight and operational acceptance) and configuration of prototype and operational space capabilities internally and across Agencies and Services. Additionally, SAMD provides strategic planning, requirements development, program coordination and integration, acquisition, financial management, cost estimating, contracting, program protection, logistics, mission assurance, engineering, and program assessments for development and acquisition of space applications within MDA and jointly with the Agencies and Services. Beginning in FY 2026, SAMD will consolidate funding for the Missile Defense Space Enterprise Architecture to provide enterprise-level operations and sustainment in support of Missile Defense System Space Programs experimentation and testing. Individual programs will continue to fund mission unique requirements. Hypersonic & Ballistic Tracking Space Sensor (HBTSS): HBTSS will demonstrate a schedule-focused, cost-constrained capability to detect and track hypersonic threats and boosting conventional ballistic missiles. The key characteristic of the HBTSS prototype demonstration that sets it apart from other Overhead Persistent Infrared sensors is the requirement to provide fire-control quality tracking data. The enhanced tracking accuracy through missile burn out on ballistic threats and the enhanced tracking accuracy on hypersonic threats will provide the warfighter increased missile defense weapons systems engagement capability and higher accuracy impact predictions. The requirement for fire-control data necessitates that HBTSS be a highly sensitive, low-latency, high quality of service system. Following the successful demonstration of HBTSS capabilities, the responsibility for HBTSS operational fielding will be transferred to the United States Space Force and the MDA will continue the development of the next-generation of space-based fire control sensors for missile defense. Operationally, the HBTSS fire-control capability will be part of Space Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Missile Defense Agency                                                               Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:              PE 1206895C / Ballistic Missile Defense System Space Programs Advanced Component Development & Prototypes (ACD&P) Development Agency's Proliferated Warfighting Space Architecture and will detect hypersonic, ballistic, and other advanced threats much sooner than terrestrial radars, providing hypersonic threat-tracking data for hand off through linked missile defense weapons. In FY 2026, MDA will complete disposition of the HBTSS satellites. Spacebased Kill Assessment (SKA): The SKA project delivered dedicated space sensors contributing to hit and kill assessment for Homeland Defense. Missile Defense Agency (MDA) Missile Defense System intercept testing experience provided a solid understanding of kill assessment physics to enable exploration of this critical capability. SKA incorporated Government Accountability Office (GAO) recommendations to examine the operational feasibility of disaggregating large satellites and to provide data for the business case for shared versus dedicated satellite control, including the ground antenna networks. The favorable cost and schedule performance on SKA was also consistent with the GAO's assessment of hosted payload programs. The SKA experiment utilized a network of small infrared sensors integrated onto host satellites that while on orbit observed missile defense intercepts and delivered situational awareness hit and kill assessment declarations. This PE also funds Cybersecurity efforts necessary to support Missile Defense System Space Programs. These activities are necessary to ensure compliance with the Federal Information Security Management Act. The funds requested in this PE provide both legacy and Global Missile Defense Capability development for the United States, its deployed forces, allies, and partners. The capabilities funded by this budget request are complementary to the architecture funded by the Golden Dome Program's separate budget request and together fulfill the President's Executive Order 14186. The President's January 27, 2025, Executive Order established a goal of protecting the U.S. citizens, safeguarding critical infrastructure, and securing second-strike capability against missile attack from any adversary. This program and budget in addition to the budget requested by the Golden Dome Program Office reflects the changes necessary to protect the U.S. against ballistic, hypersonic, cruise, and other advanced missile threats.$$, $$Budget J-Books/FY27/Remaining/RDTE_Vol2_MDA_RDTE_PB27_Justification_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1208053SF$$, $$Joint Tactical Ground System$$, $$rdte_sf_ba7$$, $$ssc$$, 2026, 6698000, 0, 6937000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$The Joint Tactical Ground Station (JTAGS) is a post-production, Acquisition Category (ACAT) III program. JTAGS provides missile warning message data for the Air and Missile Defense (AMD) architecture and improves performance for Integrated Air and Missile Defense Fire Control Systems/Composite Army Air and Missile Defense Brigades. JTAGS disseminates near real time warning, alerting, and cueing information on ballistic missile launches and other tactical events of interest throughout the theater using existing communication networks, providing critical support to Combatant Commanders in their Areas of Responsibility (AOR). JTAGS consist of two sheltered operation rooms, one equipment room, and three antennas. Four outside contiguous United States (OCONUS) deployed JTAGS units, which are deployed in three theaters (United States Pacific Command (PACOM), United States Central Command (CENTCOM), United States European Command (EUCOM)), constitute DoD's in-theater system providing space-based missile warning. The fifth contiguous United States (CONUS) system is used as an institutional trainer but is available as a deployable asset. JTAGS is designated as the in-theater element of the United States Strategic Command's Theater Event System (TES), supporting all Theater Missile Defense pillars, affording the shortest sensor-to-shooter connectivity. On 14 January 2016, the Army Acquisition Executive designated the JTAGS Pre-Planned Product Improvement (JTAGS P3I) program as a separate ACAT III modification program. The JTAGS Program Element (PE) supports development and testing of the JTAGS Block II P3I program based on the JTAGS Operational Requirements Document (ORD), additive Joint Requirements Oversight Council - Memorandum (JROC-M) requirements, and the formal JTAGS Block II Capability Development Document (CDD) thresholds. P3I upgraded JTAGS to a Block II configuration for operation with the next generation of Space Based Infrared System (SBIRS) satellites, and improved warning tactical parameters and timeliness. The JTAGS Block II P3I program based on the 2009 JTAGS ORD is on contract as a two-phase development effort. JTAGS Block II Phase 2 activities seek to develop and test capabilities identified in 2009 JTAGS ORD. Joint Requirements Oversight Council (JROC) Memos 197-12, 113-13, and 042-19 and PL 111-383(Ike Skelton National Defense Authorization Act for FY 2011) support the requirements to develop and field JTAGS Block II capabilities as soon as possible. JTAGS Block II Phase 2 Spiral 3 fielding was completed during FY 2024 and FY 2025. The continued JTAGS Block II CDD addresses evolving User-driven needs such as emerging threats and interface efforts that were not known at the time the JTAGS ORD was validated. Developmental efforts to achieve JTAGS Block II CDD threshold requirements continue through FY 2029. FY 2026 requests funds to continue development for cyber compliance, defense against emerging threats, Assured Positioning, Navigation and Timing (APNT) and M- code GPS compliance, addresses obsolescence mitigation with Commercial Off The Shelf (COTS) hardware/software upgrades, and research and develop prototypes for various system modifications for Red Hat Linux, the next generation Joint Tactical Terminals. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:          PE 1208053SF / Joint Tactical Ground System Operational Systems Development This program element may include necessary civilian pay expenses required to manage, execute, and deliver the Joint Tactical Ground Stations (JTAGS) system capability. The sue of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 147700000, 115640000, 57821000, NULL, NULL, 75, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 6937000, 6698000, 92731000, 92731000, 0, 92731000, 38750000, $$Detachments 1 through 4 are operating the Joint Tactical Ground Station (JTAGS) (Project 676760) WT-5 systems for Guardians across Missile Warning and Missile Tracking (MW/MT) mission area. As a result, the Service will improve readiness and operational reach of existing force structure. JTAGS is a post-production, Acquisition Category (ACAT) III program. The weapon system designator for JTAGS is WT-5. JTAGS provides missile warning message data for the Air and Missile Defense (AMD) architecture. JTAGS disseminates near real time warning, alerting, and cueing information on ballistic missile launches and events of interest throughout the theater using existing communication networks, providing critical support to Combatant Commanders in their Areas of Responsibility (AOR). Additionally, JTAGS supports the Strategic Missile Warning architecture. JTAGS consist of two sheltered operation rooms, one equipment room, and three antennas. Four outside contiguous United States (OCONUS) deployed JTAGS units, which are deployed in three theaters (United States Pacific Command (PACOM), United States Central Command (CENTCOM), United States European Command (EUCOM)), constitute Department of War's (DoW) in-theater system providing space-based missile warning. The fifth contiguous United States (CONUS) system is used as an institutional trainer but is available as a deployable asset. JTAGS is designated as the in-theater element of the United States Strategic Command's Theater Event System (TES), supporting all Theater Missile Defense pillars, affording the shortest sensor-to-shooter connectivity. The JTAGS Block II P3I program based on the 2009 JTAGS ORD is on contract as a two-phase development effort. Joint Requirements Oversight Council (JROC) Memos 197-12, 113-13, and 042-19 and PL 111-383 support the requirements to develop and field JTAGS Block II capabilities as soon as possible. Continued JTAGS Block II CDD addresses evolving User-driven needs such as emerging threats, resiliency, modernization, and expanding interfaces that were not known at the time the JTAGS ORD was validated. Developmental efforts to achieve JTAGS Block II CDD threshold requirements continue through FY 2032. Resilient Ground Architecture establishes a proliferated missile warning processing & data distribution ground architecture that holistically creates a robust day-to- day operation with predictable and graceful degradation to a Survivable & Endurable mission—providing increased resilience through all phases of conflict and threat spectrum. Fielding RGA capabilities meets/aligns with JROC-M 059-23, PPD-35/40, and CJCSI 3296. Resilient Ground Architecture is a new start with efforts beginning in FY 2027. Note that Resilient Ground Architecture funding is split between PE 1208053SF and PE 1206440SF. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:             PE 1208053SF / Joint Tactical Ground System Operational Systems Development This program element may include necessary civilian pay expenses required to manage, execute, and deliver the Joint Tactical Ground Stations (JTAGS) system capability. The sum of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program falls within the Missile Warning and Missile Tracking (MW/MT) mission area which provides the multi-orbit space and ground architecture required to detect and track missiles and hypersonic glide vehicles worldwide. Space Force investment program interdependencies include: RDT&E Budget Line Items: Missile Defense Radars (1203873SF); Ballistic Missile EW Systems (1203909SF); NCMC - TW/AA System (1203906SF); Next - Generation OPIR (1206442SF); Next - Generation - GEO (1206443SF); Next - Generation - Ground (1206440SF); Next - Generation - Polar (1206444SF); NUDET Detection System (1203913SF); Resilient MW / MT - LEO (1206446SF); Resilient MW / MT - MEO (1206447SF) and elements of Procurement Budget Line Item: Space Mods (SPCMOD) This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1208248SF$$, $$Space Domain Awareness/Planning/Tasking SW$$, $$rdte_sf_ba8$$, $$ssc_sda$$, 2026, 200968000, 0, 145665000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$The FY 2018 National Defense Authorization Act (Sections 873/874) directed the Office of the Secretary of Defense (OSD) to streamline software development. The Space Domain Awareness (SDA)/Planning/Tasking software program is an OSD pilot initiative in which all lifecycle funding is tracked under Budget Activity 08 (BA 08), Software and Digital Technology Pilot Programs, beginning in FY 2021. Pilot programs enable the execution of modern software development practices encompassing development, procurement, sustainment, modification, and maintenance activities within a single Research, Development, Test and Evaluation (RDT&E) appropriation in this Program Element (PE). The Space Force is developing SDA/Planning/Tasking functions for the United States Space Force (USSF) and U.S. Indo-Pacific Command (USINDOPACOM). Capabilities will initially be delivered to Space Operations Command (SpOC) and U.S. Space Forces - Space (S4S). The SDA/Planning/Tasking software program provides a collaborative environment that will enhance and modernize SDA and Battle Management Command and Control (BMC2) capabilities; create decision-relevant views of the space and multi-domain environment; rapidly detect, track, and characterize objects of interest; identify/exploit traditional and non-traditional sources; perform space threat analysis; and enable efficient distribution of data across the Space Surveillance Network (SSN). The program maintains enterprise infrastructure, platform, and data services, and develops mission applications to enable responsive, resilient operational-level SDA/Planning/Tasking capabilities for the National Space Defense Center (NSDC), Combined Space Operations Center (CSpOC), Mission Delta 2 (MD 2) and other Command and Control (C2) centers. Employing an agile-based Rapid Delivery Framework (RDF) with a 90-day Program Increment (PI) construct, fosters a collaborative and integrated environment for the community to effectively plan and deliver C2 capabilities. The enterprise-wide system provides a common government infrastructure and processes to allow C2 capabilities at USSF operational Deltas to rapidly address the evolving and dynamic threat. The program also identifies shared/common platform, infrastructure, and data layer solutions to support open frameworks and architectures across the enterprise ground portfolio. Funding includes technical studies, development, experimentation, integration, and related support costs. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program is in Budget Activity 8, Software and Digital Technology Pilot Program because this budget activity includes funding provided for expenses necessary for agile development, test and evaluation, procurement, production and modification, and the operation and maintenance of these programs. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                    Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 8:          PE 1208248SF / Space Domain Awareness/Planning/Tasking SW Software and Digital Technology Pilot Programs$$, NULL, 628329000, 621701000, 643829000, NULL, NULL, 76, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 140938000, 201991000, 617062000, 617062000, 0, 617062000, 659818000, $$This program falls within the Space Domain Awareness (SDA) mission area which provides the space-based and ground-based architecture required to detect, track, catalogue, and identify objects and activities in the space domain. As the foundation for space control, SDA encompasses surveillance of all space objects and activities; detailed surveillance of specific space assets; monitoring space environmental conditions; monitoring cooperative space assets; gathering indications and warning on adversary space operations; and conducting integrated command, control, communications, processing, analysis, dissemination, and archiving activities. Space Force investment program interdependencies include: RDT&E Budget Line Items: Space Domain Awareness/Planning/Tasking SW (1208248SF); Automate Sat C2 (1207440SF); Space Situational Awareness Operations (1203940SF); Space Situational Awareness Systems (1206425SF); and elements of Procurement Budget Line Item: Space Mods (SPCMOD). This is not a new start. Space Systems Command (SSC) System Delta (SYD) 85 and the Kronos Program Office are continuing to develop the Kronos Family of Systems for Guardians across Warfighting, Operational Command, and Combat Support units. As a result, the Service will improve battle management of all weapon systems and adjust force structure as required. Combat Forces Command (CFC) Mission Delta 2 (MD2) is developing, sustaining and modernizing SDA for Guardians across MD2, USSF and other users. As a result, the Service will deliver SDA capabilities, improve readiness and operational reach of the existing force structure, and integrate Allies, partners, and commercial space to USSF units. The Space Domain Awareness (SDA)/ Planning/ Tasking software program is an Office of the Secretary of War (OSW) pilot initiative in which all lifecycle funding is tracked under Budget Activity 8 (BA 8), Software and Digital Technology Pilot Programs, beginning in FY 2021. This pilot program enables the execution of modern software development practices encompassing development, procurement, sustainment, modification, and maintenance activities within a single Research, Development, Test and Evaluation (RDT&E) appropriation in this Program Element (PE). SDA/Planning/Tasking functions support United States Space Force (USSF) and U.S. Indo-Pacific Command (USINDOPACOM). Capabilities will initially be delivered to Combat Forces Command (CFC) and U.S. Space Forces - Space (S4S). The SDA/Planning/Tasking software program provides a collaborative environment that will enhance and modernize SDA and Battle Management Command and Control (BMC2) capabilities; create decision-relevant views of the space and multi-domain environment; rapidly detect, track, and characterize objects of interest; identify / exploit traditional and non-traditional sources; perform space threat analysis; and enable efficient distribution of data across the Space Surveillance Network (SSN). The program maintains enterprise infrastructure, platform, and data services, and develops mission applications to enable responsive, resilient operational-level SDA/Planning/Tasking capabilities for the National Space Defense Center (NSDC), Combined Space Operations Center (CSpOC), Mission Delta 2 (MD 2), other Command and Control (C2) centers, and Space Force Components within Combatant Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 8:             PE 1208248SF / Space Domain Awareness/Planning/Tasking SW Software and Digital Technology Pilot Programs Commands. The employment of an agile-based Rapid Delivery Framework (RDF) with a 120 day Program Increment (PI) construct fosters a collaborative and integrated environment for the community to effectively plan and deliver C2 capabilities. The enterprise-wide system provides a common government infrastructure and processes to allow C2 capabilities at USSF Mission and Combat Deltas to rapidly address the evolving and dynamic threat. The program also identifies shared/common platform, infrastructure, and data layer solutions to support open frameworks and architectures across the enterprise ground portfolio. Funding includes technical studies, development, experimentation, integration, and related support costs. For FY 2027, the Space Domain Awareness/Planning/Tasking SW Program Element increased $415.071 million from the FY 2026 funding level. For Project 68A035, FY 2027 funding reflects a significant increase to fully fund enterprise SDA development and sustainment, driven by USSPACECOM priorities and transfer of O&M funding for current SDA systems from PE 1203940SF to BA 8 RDT&E project 68A035 to support agile software development. Activities in Project 68A035 are continuing from FY 2026 and are not a new start. For Project 681018, funding was transferred from Project 68A035 to this project (also known as Kronos) and substantially increased for a total of $260.441 million in FY 2027 to expand development of BM and C2 scope previously in SDA. Activities in Project 681018 are not a new start. This is consistent with the direction and intent of the Under Secretary of War for Acquisition and Sustainment in splitting the Space Domain Awareness (SDA) and BMC2 programs out of the Space C2 program as documented in a 12 May 2025 Acquisition Decision Memorandum. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program is in Budget Activity 8, Software and Digital Technology Pilot Program because this budget activity includes funding provided for expenses necessary for agile development, test and evaluation, procurement, production and modification, and the operation and maintenance of these programs.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
