INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_0300_L111$$, $$Combatant Craft Systems$$, $$proc_dw_0300_ba2$$, $$dw_other$$, 2026, 55818000, 20412000, 20822000, NULL, $${"page": 170, "ba_num": "02", "source": "p1_fy26", "ba_name": "Special Operations Command", "line_no": "111", "service": "dw", "fy24_qty": null, "fy25_qty": null, "fy27_v27": {"ba": "02", "p1_li": 65}, "appr_code": "0300", "appr_name": "Procurement, Defense-Wide", "fy26_v181": {"li_num": 65, "source": "p1_master_fy26_v181", "source_pdf": "Budget J-Books/FY27/Remaining/FY2027_p1.pdf", "fy26_disc_K": 7000, "fy26_supp_K": 36440, "fy26_total_K": 43440, "name_partial": "Combatant Craft Systems"}, "fy26t_qty": null, "fy26d_cost": 30418000, "fy26r_cost": 25400000, "ident_code": ""}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 43440000, 33858000, 33858000, 0, 33858000, NULL, NULL, $$Budget J-Books/FY27/DW_Procurement/PROC_SOCOM_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1203182SF$$, $$Spacelift Range System (SPACE)$$, $$rdte_sf_ba7$$, $$ssc_assured_a$$, 2026, 54996000, 0, 45506000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$The Spacelift Range System (SLRS), also known as the Launch and Test Range System (LTRS), provides public safety and assured access to space. LTRS operates at the Eastern Range (ER) at Patrick SFB/Cape Canaveral SFS, FL and the Western Range (WR) at Vandenberg SFB, CA. LTRS provides tracking, telemetry, communications, flight safety, and other capabilities to support launch of national security space (NSS), civil and commercial space payloads, Intercontinental and Sea Launched ballistic missile and missile defense evaluations, and aeronautical and guided weapon tests. LTRS ensures ability to meet the national launch requirement, safely supports the launch cadence of ER/WR launch requirement holders and provides assured access to space for the nation. The ER and WR are designated as Department of Defense Major Range and Test Facility Bases (MRTFB). To meet evolving technological requirements and Spaceport of the Future guidance, LTRS rebalanced funding from a predominantly Procurement focused appropriation to a balanced appropriation mix of Procurement and RDT&E funding through a Zero Baseline Transfer FY 2025 and beyond. This realignment of appropriations ensures requirements expend against the appropriation most suited for the type of development work required for mission fulfillment. No requirements planned for Procurement obligations were sacrificed to achieve this shift in funding profile, but a large subset of these requirements to modernize Range Instrumentation and associated services were moved to the software acquisition pathway effort as core capabilities. LTRS is comprised of 12 subsystems that together provide this capability to the ranges. The Range Safety, Command Destruct, and Positive Control subsystems provide the capability to destroy an errant rocket, if necessary to protect public safety. These subsystems rely on the Telemetry, Radar, and Optics subsystems to provide tracking data. The Weather and Surveillance subsystems allow range operators and customers to determine if conditions are safe for launch. The Communications, Data Handling, and Timing & Sequencing subsystems ensure critical data is expeditiously routed from remote sensors (e.g., radars, optics) to range operators and customers. Finally, the Planning and Scheduling subsystem ensures all assets are available when needed for a launch or test operation. The shift from the LTRS program into the Spaceports of the Future (SOTF) will be accomplished over the coming years through capability transformation. The Space Force requires RDT&E funds to conduct LTRS Digital Transformation studies, prototype experimentation, and developmental test activities to meet evolving technological requirements. These activities will constitute the shift from Range systems alone, to integrated Spaceports while remaining operational. The Commander's SOTF vision supports the increased launch tempo and volume, while meeting technological demands of the Spaceport customer base. The transformation will entail data capability pathfinding, integrating existing systems to emerging technologies through prototype activities, and development of unique-fit solutions. Specifically, funds will provide engineering analyses for insertion of promising technology, provide opportunity to test Cloud infrastructure and software development strategies to drive state-of-the-art applications into LTRS development, validate pathfinder concepts to meet an accelerating launch capacity and cadence, improve system cyber Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:             PE 1203182SF / Spacelift Range System (SPACE) Operational Systems Development survivability and resilience, and continue to evaluate promising technology beyond current industry standards. Digital Transformation drives automation and system autonomy into LTRS operations for seamless launch and return operations and accelerates capability to Range users through adoption of modern systems, platforms and processes. This program element may include necessary civilian pay expenses required to manage, execute, and deliver LTRS Critical Space Operations capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 58342000, 59391000, 60467000, NULL, NULL, 60, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 43933000, 54300000, 56781000, 56781000, 0, 56781000, 61676000, $$System Delta 80 is developing and executing the Launch and Test Range System (LTRS) Modernization (aka Spacelift Range System) (Project 674157) for Guardians across Space Access, Command and Control, Operations, and Ops Commands. As a result, the Service will deliver space domain awareness capabilities, improve readiness and operational reach of existing force structure, deter, neutralize, defeat and/or destroy counterspace threats and defend the homeland, continue to advance all near term effects, and ensure resilient infrastructure, equipment, and personnel. The Spacelift Range System (SLRS), also known as the Launch and Test Range System (LTRS), provides public safety and assured access to space. LTRS operates at the Eastern Range (ER) at Patrick SFB/Cape Canaveral SFS, FL and the Western Range (WR) at Vandenberg SFB, CA. LTRS provides tracking, telemetry, communications, flight safety, and other capabilities to support launch of national security space (NSS), civil and commercial space payloads, Intercontinental and Sea Launched ballistic missile and missile defense evaluations, and aeronautical and guided weapon tests. LTRS ensures ability to meet the national launch requirement, safely supports the launch cadence of ER/WR launch requirement holders and provides assured access to space for the nation. The ER and WR are designated as Department of War Major Range and Test Facility Bases (MRTFB). To meet evolving technological requirements and Spaceport of the Future guidance, LTRS rebalanced funding from a predominantly Procurement focused appropriation to a balanced appropriation mix of Procurement and RDT&E funding through a Zero Baseline Transfer FY 2025 and beyond. This realignment of appropriations ensures requirements expend against the appropriation most suited for the type of development work required for mission fulfillment. No requirements planned for Procurement obligations were sacrificed to achieve this shift in funding profile, but a large subset of these requirements to modernize Range Instrumentation and associated services were moved to the software acquisition pathway effort as core capabilities. LTRS is comprised of 12 subsystems that together provide this capability to the ranges. The Range Safety, Command Destruct, and Positive Control subsystems provide the capability to destroy an errant rocket, if necessary to protect public safety. These subsystems rely on Telemetry, Radar, and Optics subsystems to provide tracking data. The Weather and Surveillance subsystems allow range operators and customers to determine if conditions are safe for launch. The Communications, Data Handling, and Timing & Sequencing subsystems ensure critical data is expeditiously routed from remote sensors (e.g., radars, optics) to range operators and customers. Finally, the Planning and Scheduling subsystem ensures all assets are available when needed for a launch or test operation. The shift from the LTRS program into the Spaceports of the Future (SOTF) will be accomplished over the coming years through capability transformation. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                           Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:              PE 1203182SF / Spacelift Range System (SPACE) Operational Systems Development The Space Force requires RDT&E funds to conduct LTRS Digital Transformation studies, prototype experimentation, and developmental test activities to meet evolving technological requirements. These activities will constitute the shift from Range systems alone, to integrated Spaceports while remaining operational. The Commander's SOTF vision supports the increased launch tempo and volume, while meeting technological demands of the Spaceport customer base. The transformation will entail data capability pathfinding, integrating existing systems into emerging technologies through prototype activities, and development of unique-fit solutions. Specifically, funds will provide engineering analyses for insertion of promising technology, provide opportunity to test Cloud infrastructure and software development strategies to drive state-of-the-art applications into LTRS development, validate pathfinder concepts to meet an accelerating launch capacity and cadence, improve system cyber survivability and resilience, and continue to evaluate promising technology beyond current industry standards. Digital Transformation drives automation and system autonomy into LTRS operations for seamless launch and return operations and accelerates capability to Range users through adoption of modern systems, platforms and processes. This program element may include necessary civilian pay expenses required to manage, execute, and deliver LTRS Critical Space Operations capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program falls within the Space Access mission area which provides the launch systems and corresponding ground architecture required to provide assured access to space, the movement of payloads to and from the space domain, and provision a safe and secure range for space launch operations. Program interdependencies include: EELVP (Space) - EMD (1206853SF); National Security Space Launch Program (1203953SF); Rocket System Launch Program (1206860SF); SDA Launch Procurement (1203954SF); Space Access, Mobility & Logistics (1203955SF); Tactically Responsive Space (1206862SF). This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
