INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1203330SF$$, $$Space Superiority ISR$$, $$rdte_sf_ba7$$, $$spoc$$, 2026, 24411000, 0, 28227000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$The Space Superiority Intelligence (SSI) program provides intelligence for key find, fix, track, target, engage, and assess requirements supporting Space Superiority activities meeting Combatant Command (CCMD) needs for Space Operations Command (SpOC). SSI funds developmental intelligence activities to support new space superiority capability acquisition and development. Funds associated developmental intelligence Planning and direction, Collection, Processing and exploitation, Analysis and production, Dissemination and integration (PCPAD) capabilities providing Battlespace Awareness and Space Domain Awareness (SDA) in support of Space Superiority and Space Control. This includes funding for fixed and transportable intelligence collection; Processing, Exploitation and Dissemination (PED); analysis and production capabilities that are modular (plug-and-play); meet Risk Management Framework Accreditation requirements and can keep pace with technological advances and emerging threats. It provides intelligence support systems for SDA activities that provide the requisite current and predictive knowledge of space events and threat conditions and intelligence support to the Space Security and Defense Program (SSDP) by providing architectural survivability analysis of critical mission assets for mission assurance, as well as network analysis. It also supports specialized/tailored, phased threat system analysis and studies (A&S), test support, lab equipment, and Material Acquisition and Exploitation (MAE) for system development, vulnerability, susceptibility assessments to support tactics, techniques and procedures (TTP) development, and future threat technology studies necessary for mission area success, achievement of space superiority, and to preserve the US space advantage across all domains. Space acquisition must respond with speed and agility to the proliferation of emerging space adversary threats and new technologies. In support of these nascent, cutting edge space acquisition capabilities, Space Superiority Intelligence provides exquisite, crucial cryptologic and other intelligence through transformational collection and production activities through the rapid development and fielding of fixed and transportable intelligence architectures capable of front-end collection and analysis of new technologies in near real time. Space Superiority and Space Control is only realized through Space Superiority Intelligence support on the front end of space acquisition, allowing increased innovation and resiliency in support of changing program/project priorities to respond and to operate in the contested space domain, as well as supporting lifecycle experimentation, prototyping, and risk reduction. Supports USSPACECOM Space Domain Awareness Initial Capabilities Document (ICD), February 2022. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                     Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:           PE 1203330SF / Space Superiority ISR Operational Systems Development$$, NULL, 59757000, 51767000, 48022000, NULL, NULL, 61, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 28227000, 24411000, 64290000, 64290000, 0, 64290000, 46028000, $$Combat Forces Command (CFC)/Intelligence Directorate (S2) is developing, operating, prototyping and executing terrestrially-based Space Superiority Intelligence collection, processing, exploitation, analysis and production capabilities in support of Combatant Commands (CCMD) and Combat Forces Command (CFC) requirements within the Combat Power mission to ensure space superiority over near-peer adversaries, enabling space combat operations and capability development. As a result, the Service will contribute to space domain awareness. The Space Superiority Intelligence, Surveillance and Reconnaissance (SSI) program provides intelligence for key find, fix, track, target, engage, and assess (F2T2EA) requirements supporting Space Superiority activities meeting Combatant Command (CCMD) and Combat Forces Command (CFC) needs. SSI develops intelligence capabilities supporting Space Force operations and space superiority capability acquisition and development. Funds development of intelligence Planning and direction, Collection, Processing and exploitation, Analysis and production, Dissemination and integration (PCPAD) capabilities providing Battlespace Awareness and Space Domain Awareness (SDA) in support of Space Superiority and Space Control. This includes funding for fixed-site and transportable intelligence collection; Processing, Exploitation and Dissemination (PED); analysis and production capabilities; and targeting capabilities; while meeting Risk Management Framework (RMF) accreditation requirements in order keep pace with technological advances and emerging threats. It provides intelligence support systems for SDA activities that provide the requisite current and predictive knowledge of space events, threat conditions, and networks. It also supports specialized/tailored, phased threat system analysis and studies (A&S), test support, lab equipment, and Material Acquisition and Exploitation (MAE) for system development, vulnerability, susceptibility assessments to support tactics, techniques and procedures (TTP) development, and future threat technology studies necessary for mission area success, achievement of space superiority, and to preserve the US space advantage across all domains. Funding expands three 73 ISRS collection sites in three Areas of Responsibility (AORs) to eight collection sites in five AORs, with the full complement of sites being called Orion's Belt. Orion's Belt will be supplemented by five deployable 72 ISRS UTCs of small form factor capabilities constituting its CONUS-based Deployable ISR Support Cells (DISCs) to meet USSF Service-retained and CCMD intelligence collection requirements. Funding initiates USSF continuation of Congressional adds to fully develop a Space Joint Munitions Effectiveness Manual (JMEM) in support of targeting-related Tactics, Techniques, and Procedures (TTPs) which will drive operational engagement. CFC will partner with Space Systems Command, OSW DOT&E's Joint Technical Coordination Group for Munitions Effectiveness (JTCG-ME), National Laboratories, and FFRDCs to develop all required models, simulations, and advanced user tools. Space acquisition must respond with speed and agility to the proliferation of emerging space adversary threats and new technologies. In support of these nascent, cutting-edge space acquisition capabilities, Space Superiority Intelligence provides exquisite, crucial cryptologic and other intelligence through transformational collection and production activities through the rapid development and fielding of fixed and transportable intelligence architectures capable of front-end collection and analysis Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                           Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:              PE 1203330SF / Space Superiority ISR Operational Systems Development of new technologies in near real time. Space Superiority and Space Control is only realized through Space Superiority Intelligence support on the front end of space acquisition, allowing increased innovation and resiliency in support of changing program/project priorities to respond and to operate in the contested space domain, as well as supporting lifecycle experimentation, prototyping, and risk reduction. Supports USSPACECOM Space Domain Awareness Initial Capabilities Document (ICD), February 2022. Fulfills USSPACECOM FY26-30 Integrated Priorities List (IPLs) regarding Persistent and Resilient ISR and Operational Intelligence. This program falls within the Combat Power mission area which provides the systems required to protect and defend space-based capabilities and ensure space superiority by enabling and executing combat operations in space. Space Force investment program interdependencies include: RDT&E Budget Line Items: Counterspace Systems (1206421SF); Space-Based Moving Target Indicator (1203155SF); Long Range Kill Chains (1203154SF); Space Control Technology (1206438SF); and elements of Procurement Budget Line Items: Space Mods (SPCMOD); Space Based Air Moving Target Indicator (AMTI00); Ground Moving Target Indicator (GMTI00); Counterspace Systems (CTRSPC) The FY 2027 request for RDT&E includes $64,290 thousand of discretionary and $0 thousand of mandatory (reconciliation) for a total of $64,290 thousand. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
