INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603199F$$, $$Sustainment Science and Technology (S&T)$$, $$rdte_af_ba3$$, $$afrl_rx$$, 2026, 12915000, 9710000, 5668000, NULL, $${"ba_raw": "6.3", "source": "af_r1_fy26", "original_pe": "0603199F"}$$::jsonb, $$The Air Force Research Laboratory (AFRL) is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. This program develops and transitions AFRL readiness technologies for fielded and future Department of the Air Force systems. These technologies include corrosion/ erosion prevention, maintenance/repair techniques, state awareness/non-destructive inspection, and health management and life prediction. Matured and demonstrated technologies increase lethality and readiness by improving the affordability and availability of aerospace weapon systems. This is achieved by reducing sustainment costs, extending service life, and maintaining mission readiness and capability. Studies are conducted to analyze processes and methodologies for applying these technologies to address sustainment issues across the force. These studies identify cross-cutting applications for fielded systems and opportunities for building sustainability into future weapon systems. This program also develops and demonstrates affordable advanced composites and specialty materials for current and future weapon systems. Funds in this PE may be used to investigate specified technology advancements in air, space and/or cyber domains. In order to manage, execute, and deliver science and technology capabilities, this program element may include: necessary civilian pay expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, administrative contractor services, etc. This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0603199F / Sustainment Science and Technology (S&T) Technology Development (ATD)$$, NULL, 13751000, 14025000, 14309000, NULL, NULL, 18, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, 5358000, 27791000, 13277000, 13277000, 0, 13277000, 14599000, $$This program develops and transitions AFRL readiness technologies for fielded and future Department of the Air Force systems. These technologies include corrosion/ erosion prevention, maintenance/repair techniques, state awareness/non-destructive inspection, and health management and life prediction. Matured and demonstrated technologies increase lethality and readiness by improving the affordability and availability of aerospace weapon systems. This is achieved by reducing sustainment costs, extending service life, and maintaining mission readiness and capability. Studies are conducted to analyze processes and methodologies for applying these technologies to address sustainment issues across the force. These studies identify cross-cutting applications for fielded systems and opportunities for building sustainability into future weapon systems. This program also develops and demonstrates affordable advanced composites and specialty materials for current and future weapon systems. This program is accomplished by the Air Force Research Laboratory (AFRL). AFRL is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. Funds in this PE may be used to investigate specified technology advancements in air, space, and/or cyber domains. In order to manage, execute, and deliver science and technology capabilities, this program element may include: necessary civilian pay expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, etc. This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0603199F / Sustainment Science and Technology (S&T) Technology Development (ATD)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume I.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603203F$$, $$Advanced Aerospace Sensors$$, $$rdte_af_ba3$$, $$afrl_ry$$, 2026, 69652000, 51051000, 37935000, NULL, $${"ba_raw": "6.3", "source": "af_r1_fy26", "original_pe": "0603203F"}$$::jsonb, $$The Air Force Research Laboratory is focused on high-impact, multi-domain science & technology solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force science & technology enterprise and workforce to align towards the most consequential Department of the Air Force priorities and accelerate the delivery of game-changing science & technology. This program develops and demonstrates technologies for electro-optical sensors, multifunction radio frequency sensors, precision navigation and timing, and electronic countermeasures, as well as associated technologies, critical components and algorithms to support Department of the Air Force surveillance, targeting, and electronic combat warfighting capabilities. The program develops and demonstrates technologies for integrating sensors, precision timing and navigation, and electronic combat sensors and systems into a fused and seamless technology capability to demonstrate capabilities for rapid fielding. This program creates and applies artificial intelligence toolsets to ensure an asymmetric advantage for the Department of the Air Force. The program demonstrates artificial intelligence enabled autonomy to augment cognitive capabilities of our Airmen and Guardians so they can keep up with the faster pace and increased complexity of modern warfare. This program has been coordinated through the Department of Defense Science and Technology Executive Committee process to harmonize efforts and eliminate duplication. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0603203F / Advanced Aerospace Sensors Technology Development (ATD) The Department of the Air Force technologies in this program are both enabling and enduring as we invest in maturing emerging technologies that address established mission gaps, and transformational technologies that address integrated enterprise capabilities intended to reshape the future force across warfighting domains. Development of transformational operational capabilities through advanced technology solutions focuses on five strategic capabilities: Global Persistent Awareness; Resilient Information Sharing; Rapid, Effective Decision-Making; Complexity, Unpredictability, and Mass; and Speed and Reach of Disruption and Lethality. In order to manage, execute, and deliver science and technology capabilities, this program element may include: necessary civilian pay expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, administrative contractor services, etc. This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment.$$, NULL, 73208000, 86761000, 88629000, NULL, NULL, 19, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, 35088000, 69098000, 72149000, 72149000, 0, 72149000, 90382000, $$This program develops and demonstrates technologies for electro-optical sensors, multifunction radio frequency sensors, precision navigation and timing, and electronic countermeasures, as well as associated technologies, critical components and algorithms to support Department of the Air Force surveillance, targeting, and electronic combat warfighting capabilities. The program develops and demonstrates technologies for integrating sensors, precision timing and navigation, and electronic combat sensors and systems into a fused and seamless technology capability to demonstrate capabilities for rapid fielding. This program creates and applies artificial intelligence toolsets to ensure an asymmetric advantage for the Department of the Air Force. The program demonstrates artificial intelligence enabled autonomy to augment cognitive capabilities of our Airmen and Guardians so they can keep up with the faster pace and increased complexity of modern warfare. This program has been coordinated through the Department of War Science and Technology Executive Committee process to harmonize efforts and eliminate duplication. The Department of the Air Force technologies in this program are both enabling and enduring as we invest in maturing emerging technologies that address established mission gaps, and transformational technologies that address integrated enterprise capabilities intended to reshape the future force across warfighting domains. Development of transformational operational capabilities through advanced technology solutions focuses on five strategic capabilities: Global Persistent Awareness; Resilient Information Sharing; Rapid, Effective Decision-Making; Complexity, Unpredictability, and Mass; and Speed and Reach of Disruption and Lethality. The Air Force Research Laboratory (AFRL) is focused on high-impact, multi-domain science & technology solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force science & technology enterprise and workforce to align towards the most consequential Department of the Air Force priorities and accelerate the delivery of game-changing science & technology. Funds in this PE may be used to investigate specified technology advancements in air, space and/or cyber domains. In order to manage, execute, and deliver science and technology capabilities, this program element may include: necessary civilian pay expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, information technology hardware, software and support, administrative contractor services, etc. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                    Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0603203F / Advanced Aerospace Sensors Technology Development (ATD) This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume I.pdf$$) ON CONFLICT DO NOTHING;
