INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0601102F$$, $$Defense Research Sciences$$, $$rdte_af_ba1$$, $$afrl_afosr$$, 2026, 302716000, 347393000, 361930000, NULL, $${"ba_raw": "6.1", "source": "af_r1_fy26", "original_pe": "0601102F"}$$::jsonb, $$Defense Research Sciences consists of basic research activities in academia and industry along with research performed in the Department of the Air Force, including the Air Force Research Laboratory, Air Force Institute of Technology, and the United States Air Force Academy. This program supports basic broad-based scientific and engineering research in areas critical to Department of the Air Force weapon, sensor, and support systems. All research areas are subject to long-range planning and technical review by both Department of the Air Force and tri-Service scientific planning groups. Efforts in this program have been coordinated through the Department of Defense Science and Technology Executive Committee process to harmonize efforts and eliminate duplication. The Air Force Research Laboratory (AFRL) is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. This program includes funding for the requisite DAF Science & Engineering (S&E) and mission enabling civilian workforce with the necessary technical competencies to develop, manage, and deliver science & technology capabilities. The use of program funds in this program element is in conjunction with the civilian pay expenses budgeted in the following program elements: 1206601SF, 0602020F, 0602102F, 0602202F, 0602203F, 0602204F, 0602298F, 0602336F, 0602602F, 0602605F, 0602788F, and 0603680F. In FY 2026, $33.376 million is budgeted in this program for 145 direct Full-Time Equivalent (FTE) civilians. The Air Force Research Laboratory (AFRL) utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the workforce strength, structure, positions, and compensation without regard to any limitation on appointments, positions, or funding in a manner consistent with the budget. This program element may include necessary expenses to support the operation and maintenance of facilities to manage, execute, and deliver science and technology capabilities. Funds in this program element may be used to investigate specified science advancements in air, space and/or cyber domains. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 1: Basic        PE 0601102F / Defense Research Sciences Research This program is in Budget Activity 1, Basic Research because this budget activity includes scientific study and experimentation directed toward increasing fundamental knowledge and understanding in those fields of the physical, engineering, environmental, and life sciences related to long-term national security needs.$$, NULL, 305818000, 345890000, 356458000, NULL, NULL, 1, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, 324773000, 307645000, 296535000, 296535000, 0, 296535000, 363767000, $$Defense Research Sciences consists of basic research activities in academia and industry along with research performed in the Department of the Air Force (DAF), including the Air Force Research Laboratory (AFRL), Air Force Institute of Technology, and the United States Air Force Academy. This program supports basic broad- based scientific and engineering research in areas critical to DAF weapon, sensor, and support systems. All research areas are subject to long-range planning and technical review by both DAF and tri-Service scientific planning groups. This program is accomplished by AFRL. AFRL is focused on high-impact, multi-domain S&T solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the DAF S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. This program includes funding for the requisite DAF Science & Engineering (S&E) and mission enabling civilian workforce with the necessary technical competencies to develop, manage, and deliver science & technology capabilities. The use of program funds in this program element is in conjunction with the civilian pay expenses budgeted in the following program elements: 1206601SF, 1206616SF, 0602020F, 0602102F, 0602202F, 0602203F, 0602204F, 0602298F, 0602336F, 0602602F, 0602605F, 0602788F, and 0603680F. In FY 2027, $29.223 million is budgeted in this program for 139 direct Full-Time Equivalent (FTE) civilians. The AFRL utilizes Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                           Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 1: Basic         PE 0601102F / Defense Research Sciences Research 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the workforce strength, structure, positions, and compensation without regard to any limitation on appointments, positions, or funding in a manner consistent with the budget. Funds in this program element may be used to investigate specified science advancements in air, space, and/or cyber domains. This program is in Budget Activity 1, Basic Research because this budget activity includes scientific study and experimentation directed toward increasing fundamental knowledge and understanding in those fields of the physical, engineering, environmental, and life sciences related to long-term national security needs.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume I.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0601103F$$, $$University Research Initiatives$$, $$rdte_af_ba1$$, $$afrl_afosr$$, 2026, 94121000, 172154000, 146372000, NULL, $${"ba_raw": "6.1", "source": "af_r1_fy26", "original_pe": "0601103F"}$$::jsonb, $$This program supports defense-related basic research in a wide range of scientific and engineering disciplines relevant to maintaining U.S. military technological superiority. Research topics include, but are not limited to, transformational and high-priority technologies such as nanotechnology, sensor networks, artificial intelligence and information fusion, smart materials and structures, quantum materials and processes for sensing, communication and computing, efficient energy and power conversion, and high-energy materials for propulsion and control. The program also enhances and promotes the education of U.S. scientists and engineers in disciplines critical to maintaining, advancing, and enabling future U.S. defense technologies. For example, the National Defense Science and Engineering Graduate (NDSEG) program awards fellowships to train U.S. citizens in science and engineering disciplines of military importance under a joint tri-Service and Office of the Under Secretary of Defense for Research and Engineering competitive scholarship program. Finally, this program assists universities in establishing superior instrumentation capabilities needed to improve the quality of defense-related research and education. A fundamental component of this program is the recognition that future technologies and technology exploitations require highly coordinated and concerted multi- and interdisciplinary efforts. Efforts in this program have been coordinated through the Department of Defense Science and Technology Executive Committee process to harmonize efforts and eliminate duplication. This program is executed by the Air Force Research Laboratory (AFRL). AFRL is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. In order to manage, execute, and deliver S&T capabilities, this program element may include: necessary civilian expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, administrative contractor services, etc. Funds in this program element may be used to investigate specified science advancements in air, space and/or cyber domains. This program is in Budget Activity 1, Basic Research because this budget activity includes scientific study and experimentation directed toward increasing fundamental knowledge and understanding in those fields of the physical, engineering, environmental, and life sciences related to long-term national security needs. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 1: Basic       PE 0601103F / University Research Initiatives Research$$, NULL, 94281000, 107705000, 110996000, NULL, NULL, 2, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, 128783000, 99908000, 91394000, 91394000, 0, 91394000, 113275000, $$This program supports defense-related basic research in a wide range of scientific and engineering disciplines relevant to maintaining U.S. military technological superiority. Research topics include, but are not limited to, transformational and high-priority technologies such as nanotechnology, sensor networks, artificial intelligence and information fusion, smart materials and structures, quantum materials and processes for sensing, communication and computing, efficient energy and power conversion, and high-energy materials for propulsion and control. The program also enhances and promotes the education of U.S. scientists and engineers in disciplines critical to maintaining, advancing, and enabling future U.S. defense technologies. For example, the National Defense Science and Engineering Graduate (NDSEG) program awards fellowships to train U.S. citizens in science and engineering disciplines of military importance under a joint tri-Service and Office of the Under Secretary of War for Research and Engineering competitive scholarship program. Finally, this program assists universities in establishing superior instrumentation capabilities needed to improve the quality of defense-related research and education. A fundamental component of this program is the recognition that future technologies and technology exploitations require highly coordinated and concerted multi- and interdisciplinary efforts. This program is accomplished by the Air Force Research Laboratory (AFRL). AFRL is focused on high-impact, multi-domain S&T solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the DAF S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T In order to manage, execute, and deliver S&T capabilities, this program element may include: necessary civilian expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, etc. Funds in this program element may be used to investigate specified science advancements in air, space, and/or cyber domains. This program is in Budget Activity 1, Basic Research because this budget activity includes scientific study and experimentation directed toward increasing fundamental knowledge and understanding in those fields of the physical, engineering, environmental, and life sciences related to long-term national security needs. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                       Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 1: Basic     PE 0601103F / University Research Initiatives Research$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume I.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602020F$$, $$Future AF Capabilities Applied Research$$, $$rdte_af_ba2$$, $$afrl$$, 2026, 78214000, 77903000, 70277000, NULL, $${"ba_raw": "6.2", "source": "af_r1_fy26", "original_pe": "0602020F"}$$::jsonb, $$This program element develops multidisciplinary applied research efforts to accelerate the technology pipeline of transformational capabilities by reducing risk and maturing technologies so they can transition in support of larger advanced technology development capability investments. These activities are selected to enable solutions to the Department of the Air Force's (DAF's) highest priorities. The Explore effort creates investments to buy-down risk and accelerate enabling technologies to understand feasibility for future integration into 6.3 Future AF Integrated Technology Demo program. The Seedlings for Disruptive Capabilities Program (SDCP) facilitates Air Force Research Laboratory (AFRL) cross-disciplinary applied research to provide leap-ahead, high-risk high-payoff technology development. Modeling, simulation, and analysis activities will continue to explore transformational research into analytic technologies to validate capabilities and provide solid foundations for future efforts. These activities focus on predicting future outcomes and technology needs, as well as looking for more seedlings to feed the transformational capability pipeline. Efforts advance future workforce development projects and broaden partnerships to deepen and expand the scientific and technology enterprise. Applied research efforts span a broad spectrum of activities, and established processes allow agility and flexibility to meet higher demand signals while ensuring proper technical and financial execution metrics are met. AFRL plans and manages these funds at the enterprise level to achieve high levels of collaboration executed across all the applicable Technology Directorates and applies the research toward disruptive capabilities. Building from the technology competencies and ecosystems of the Technology Directorates brings together the needed diverse expertise and components to develop the transformational capabilities. In FY 2026, $9.077 million is budgeted in this program for 27 direct Full-Time Equivalent (FTE) civilians. The Air Force Research Laboratory (AFRL) utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the workforce strength, structure, positions, and compensation. The use of program funds in this program element would be executed in the Technology Directorates in addition to the civilian pay expenses budgeted in program elements 0601102F, 0602102F, 0602202F, 0602203F, 0602204F, 0602602F, 0602605F, 0602788F, and 0602298F. This program element may include necessary expenses to support the operation and maintenance of facilities to manage, execute, and deliver science and technology capabilities. The FY 2026 request was reduced by $0.163 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied      PE 0602020F / Future AF Capabilities Applied Research Research The FY 2026 request was reduced by $0.946 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative.” This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters.$$, NULL, 47321000, 66960000, 65284000, NULL, NULL, 3, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, 65619000, 77367000, 44029000, 44029000, 0, 44029000, 65977000, $$This program element develops multidisciplinary applied research efforts to accelerate the technology pipeline of transformational capabilities by reducing risk and maturing technologies so they can transition in support of larger advanced technology development capability investments. These activities are selected to enable solutions to the Department of the Air Force's (DAF's) highest priorities. The Explore effort creates investments to buy-down risk and accelerate enabling technologies to understand feasibility for future integration into 6.3 Future AF Integrated Technology Demo program. The Seedlings for Disruptive Capabilities Program (SDCP) facilitates Air Force Research Laboratory (AFRL) cross-disciplinary applied research to provide leap-ahead, high-risk high-payoff technology development. Modeling, simulation, and analysis activities will continue to explore transformational research into analytic technologies to validate capabilities and provide solid foundations for future efforts. These activities focus on predicting future outcomes and technology needs, as well as looking for more seedlings to feed the transformational capability pipeline. Efforts advance future workforce development projects and broaden partnerships to deepen and expand the scientific and technology enterprise. Applied research efforts span a broad spectrum of activities, and established processes allow agility and flexibility to meet higher demand signals while ensuring proper technical and financial execution metrics are met. AFRL plans and manages these funds at the enterprise level to achieve high levels of collaboration executed across all the applicable Technology Directorates and applies the research toward disruptive capabilities. Building from the technology competencies and ecosystems of the Technology Directorates brings together the needed diverse expertise and components to develop the transformational capabilities. This program includes funding for the requisite DAF Science & Engineering (S&E) and mission enabling civilian workforce with the necessary technical competencies to develop, manage, and deliver science & technology capabilities. The use of program funds in this program element is in conjunction with the civilian pay expenses budgeted in the following program elements: 1206601SF, 1206616SF, 0601102F, 0602102F, 0602202F, 0602203F, 0602204F, 0602298F, 0602336F, 0602602F, 0602605F, 0602788F, and 0603680F. In FY 2027, $5.891 million is budgeted in this program for 27 direct Full-Time Equivalent (FTE) civilians. The Air Force Research Laboratory (AFRL) utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the workforce strength, structure, positions, and compensation. This program is accomplished by the Air Force Research Laboratory (AFRL). AFRL is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. Funds in this PE may be used to investigate specified technology advancements in air, space, and/or cyber domains. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                           Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied        PE 0602020F / Future AF Capabilities Applied Research Research In order to manage, execute, and deliver science and technology capabilities, this program element may include: expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, administrative contractor services, etc. This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume I.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603036F$$, $$Modular Advanced Missile$$, $$rdte_af_ba4$$, $$aflcmc_ww$$, 2027, 0, 0, 0, NULL, $${}$$::jsonb, NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 0, 15099000, 15099000, 0, 15099000, 0, $$This program, BA 4, PE 0603036F, Modular Advanced Missile (MAM) is not a new start. The Modular Advanced Missile Program Element provides linkage between Research & Development and fielding of weapons capabilities. It will analyze, develop, mature, and demonstrate new or emerging armament technologies, processes, interfaces, mission planning, special test equipment, and resources. This program invests in analytical, data management, digital environments, networks, facilities, and security infrastructure upgrades supporting development of this program's capabilities, while leveraging the Department of War (DoW) and the Department of the Air Force (DAF) enterprise IT solutions. Expands program office staff, facilities, and security infrastructure to support the required classification levels for this program's activities. Engages with DoW, DAF, and industry stakeholders to refine threat analysis, refine inventory requirements, and plan upgrade requirements. Capitalizes on and incorporates successful laboratory research and development efforts applicable to this program's capability. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. Project was previously funded in PE 0207325F, Joint Air-to-Surface Standoff Missile (JASSM), Project 675356, JASSM Extended Range (JASSM-ER) in FY2026 and prior. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                    Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0603036F / Modular Advanced Missile Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604005F$$, $$NC3 Commercial Development & Prototyping$$, $$rdte_af_ba4$$, $$afnwc_nc$$, 2026, 67081000, 66406000, 52524000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0604005F"}$$::jsonb, $$The DAF nuclear enterprise has historically used unique closed systems to provide the high degree of mission assurance and security needed for this mission. Furthermore, the rapid development of the nuclear enterprise required the fielding of the most advanced technology of that time, and in most cases utilized technology that was well ahead of the commercial sector. Today the technological world is very different and in cases such as satellite communications and information technology (IT) systems the commercial sector has raced ahead of government unique systems. Commercial Leveraging for the nuclear enterprise will explore a range of key technologies that are either commercial, or commercial entwined with government system to quantitatively determine whether these capabilities provide increased resilience, improved reconstitution, or lower cost for applications within the DOD nuclear enterprise. It is not intended to replace baseline systems but rather will be prototypes to augment existing capabilities. The program will reduce risk in leveraging emerging commercial-based technologies by partnering with industry while providing access to Government analysis, testing and certification capabilities. Prime investments focus on Government-Industry partnerships to influence and militarize emerging commercial capabilities to ensure US competitive advantage in key technology areas. Experimentation efforts will be employed to explore new concepts and their applications in future operating environments within a system-of-systems context taking risks early in the acquisition process to drive a more optimized and efficient acquisition approach significantly reducing overall acquisitions costs. Prototyping of commercially derived technologies into government systems, followed by operational experimentation of the performance and security, will enable these candidate technologies to move into warfighting capability faster and at a lower cost, based on demonstrated low-risk prototypes. Efforts include a focus on communications, secure data flow, and incorporating commercial approaches for a coarse navigation capability. Communications will focus primarily on satellite links by prototyping terminals that can gain access and switch across multiple commercial and government links from a common terminal. Multiple commercial vendors will be competitively awarded contracts for these prototypes and will work with the government partners to interface with selected platforms across the enterprise. Secure data flow will test various techniques across commercial and DOD partners to smartly utilize multiple communications paths to increase Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                            Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604005F / NC3 Commercial Development & Prototyping Component Development & Prototypes (ACD&P) resilience, and to integrate with hybrid architectures under USSF and across terrestrial networks. Coarse navigation will explore, test and prototype commercially derived approaches to resiliently provide a very coarse navigation capability to disadvantaged users. This capability does not replace GPS or other advanced precision DOD Position-Navigation-Timing capabilities or approach their exquisite capabilities but will instead provide a back-up option for a coarse capability for a scenario when no other options are available to the DOD user. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F, 0605831F, and/or 0606017F. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 0, 0, 0, NULL, NULL, 39, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 50702000, 66249000, 61355000, 61355000, 0, 61355000, 0, $$A. Mission Description and Budget Item Justification The Department of the Air Force (DAF) nuclear enterprise has historically used unique closed systems to provide the high degree of mission assurance and security needed for this mission. Furthermore, the rapid development of the nuclear enterprise required the fielding of the most advanced technology of that time, and in most cases utilized technology that was well ahead of the commercial sector. Today's technological world is very different and, in cases such as satellite communications and information technology (IT) systems, the commercial sector has raced ahead of government unique systems. Commercial leveraging for the nuclear enterprise will explore a range of key technologies that are either commercial, or commercial entwined with government system to quantitatively determine whether these capabilities provide increased resilience, improved reconstitution, or lower cost for applications within the Department of War (DoW) nuclear enterprise. It is not intended to replace baseline systems but rather will be prototypes to augment existing capabilities. The program will reduce risk in leveraging emerging commercial-based technologies by partnering with industry while providing access to Government analysis, testing and certification capabilities. Prime investments focus on Government-industry partnerships to influence and militarize emerging commercial capabilities to ensure US competitive advantage in key technology areas. Experimentation efforts will be employed to explore new concepts and their applications in future operating environments within a system-of-systems context, taking risks early in the acquisition process to drive a more optimized and efficient acquisition approach significantly reducing overall acquisitions costs. Prototyping of commercially derived technologies into government systems, followed by operational experimentation of the performance and security, will enable these candidate technologies to move into warfighting capability faster and at a lower cost, based on demonstrated low-risk prototypes. Efforts include a focus on communications, secure data flow, and incorporating commercial approaches for a coarse navigation capability. Communications will focus primarily on satellite links by prototyping terminals that can gain access and switch across multiple commercial and government links from a common terminal. Multiple commercial vendors will be competitively awarded contracts for these prototypes and will work with the Government partners to interface with selected platforms across the enterprise. Secure data flow will test various techniques across commercial and DoW partners to appropriately utilize multiple communications paths to increase resilience, and to integrate with hybrid architectures under the United States Space Force (USSF) and across terrestrial networks. Coarse navigation will explore, test and prototype commercially derived approaches to resiliently provide a very coarse navigation capability to disadvantaged users. This capability does not replace the Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604005F / NC3 Commercial Development & Prototyping Component Development & Prototypes (ACD&P) Global Positioning System (GPS) or other advanced precision DoW Position-Navigation-Timing capabilities or approach their exquisite capabilities but will instead provide a back-up option for a coarse capability for a scenario when no other options are available to the DoW user. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F, 0605831F, and/or 0606017F. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604007F$$, $$E-7$$, $$rdte_af_ba4$$, $$aflcmc_hb$$, 2026, 199676000, 849565000, 607413000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0604007F"}$$::jsonb, $$Funds the E-7 program. The E-7 program replaces the unsustainable E-3 Airborne Warning and Control System (AWACS). The E-3 AWACS, first fielded in the 1970s, is at the end of its service life, and costly to maintain. The E-7 will serve as the USAF's principal airborne platform for airborne command and control and airborne moving target indicator, providing a reliable, persistent critical node in the long range kill chain for the Joint Force Air Component Commander (JFACC). The E-7 will provide increased capabilities to the USAF and the Joint Services to include the ability to detect and track highly maneuverable, small radar cross-section airborne targets (modern and emerging threats), the ability to real-time process and create a precise air picture, and the ability to battle manage (e.g. command and control) under a wide range of operational conditions. The E-7A is a highly modified Airborne Battle Management and Command and Control aircraft integrating a Boeing 737-700 Next Generation (737NG) airframe with a reinforced fuselage Section 46, a Northrop Grumman Multi-Role Electronically Scanned Array (MESA) Radar mounted on the aircraft's Section 46, and two 180-kVA generators added to commercial CFM-56 engines mounted beneath each wing. The E-7 will provide a reliable, operationally available, maintainable, and sustainable capability. E-7A consists of completing end items and modification components for aircraft to support test and evaluation; hardware and software modernization development efforts to ensure compliance with US cybersecurity and program protection standards; development efforts to ensure navigation and communication systems comply with GPS M-Code and Narrowband SATCOM mandates; development efforts to design and build flight planning terminals, deployable mission support systems, and mission crew trainers; design and build-out contractor and government System Integration Laboratories supporting development, integration, and test activities; and provide analysis and products supporting future requirements and airworthiness certification. E-7 Command and Control, Intelligence, Surveillance, and Reconnaissance (C2ISR): C2ISR system improvements investigate and develop future capabilities of the E-7 weapon system. These efforts also include but are not limited to advanced sensors, advanced communications, self-protection, enhanced cyber protection, the staffing and studying of cooperative development capabilities, and obsolescence resolution to ensure that the E-7 successfully integrates with joint and coalition forces in a net- centric environment. C2ISR primarily supports pre-systems acquisition in the areas of materiel solution analysis and technology development. This is accomplished by prototyping and demonstrating capabilities required by the warfighter. C2ISR also supports an analytical comparison of suitability, life-cycle cost, and system capabilities of alternative materiel solutions beyond the current E-7A that satisfy an established capability need identified in a User Requirements Document. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604007F / E-7 Component Development & Prototypes (ACD&P) This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, or 0606398F. In FY 2024 $4.970M was expended for civilian pay expenses in this program element, and in FY 2025 $8.059M is forecast for civilian pay expenses in this program element. The FY 2026 cost of the E-7A Middle Tier of Acquisition effort is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 0, 0, 0, NULL, NULL, 40, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 586729000, 1097263000, 0, 0, 0, 0, 0, $$Funds the E-7A program. The E-7A program is intended to replace the unsustainable E-3 Airborne Warning and Control System (AWACS). The E-3 AWACS, first fielded in the 1970s, is at the end of its service life, and costly to maintain. The E-7A will serve as the USAF's principal airborne platform for airborne command and control and airborne moving target indicator, providing a reliable, persistent critical node in the long-range kill chain for the Joint Force Air Component Commander (JFACC). The E-7A is intended to provide increased capabilities to the USAF and the Joint Services to include the ability to detect and track highly maneuverable, small radar cross-section airborne targets (modern and emerging threats), the ability to real-time process and create a precise air picture, and the ability to battle manage (e.g. command and control) under a wide range of operational conditions. The E-7A is a highly modified Airborne Battle Management and Command and Control aircraft integrating a Boeing 737-700 Next Generation (737NG) airframe with a reinforced fuselage Section 46, a Northrop Grumman Multi-Role Electronically Scanned Array (MESA) Radar mounted on the aircraft's Section 46, and two 180-kVA generators added to commercial CFM-56 engines mounted beneath each wing. The E-7A will provide a reliable, operationally available, maintainable, and sustainable capability. E-7A RDT&E efforts include: end item completion and component modification for aircraft to support test and evaluation; hardware and software modernization development efforts to ensure compliance with US cybersecurity and program protection standards; development efforts to ensure navigation and communication systems comply with GPS M-Code and Narrowband SATCOM mandates; development efforts to design and build flight planning terminals, deployable mission support systems, and mission crew trainers; design and build-out contractor and government System Integration Laboratories supporting development, integration, and test activities; and analysis and to support future requirements and airworthiness certification. E-7A Command and Control, Intelligence, Surveillance, and Reconnaissance (C2ISR): C2ISR system improvements investigate and develop future capabilities of the E-7 weapon system. These efforts also include but are not limited to advanced sensors, advanced communications, self-protection, enhanced cyber protection, the staffing and studying of cooperative development capabilities, and obsolescence resolution to ensure that the E-7A successfully integrates with joint and coalition forces in a net-centric environment. C2ISR primarily supports pre-systems acquisition in the areas of materiel solution analysis and technology development. This is accomplished by prototyping and demonstrating capabilities required by the warfighter. C2ISR also supports an analytical comparison of suitability, life-cycle cost, and system capabilities of alternative materiel solutions beyond the current E-7A that satisfy an established capability need identified in a User Requirements Document. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                                        R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604007F / E-7 Component Development & Prototypes (ACD&P) The total cost of the E-7A Middle Tier of Acquisition effort is 8,237.566 million, including RDT&E and procurement of prototype/Engineering and Manufacturing Development units. This program received FY26 200M RDT&E in the FY26CR 119-4 Sec 129 for the purpose of rapid prototyping activities to maintain program schedule and transition to production for the E-7 Wedgetail. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. In FY 2025 8.692 million was expended for civilian pay expenses in this program element, and in FY 2026 7.930 million is forecast for civilian pay expenses in this program element. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_2031_L046$$, $$Common Infrared Countermeasures (CIRCM)$$, $$proc_army_2031_ba4$$, $$peo_aviation$$, 2026, 0, 6526000, 0, NULL, $${"page": 13, "ba_num": "04", "source": "p1_fy26", "ba_name": "Support equipment and facilities", "line_no": "46", "service": "army", "fy24_qty": null, "fy25_qty": null, "appr_code": "2031", "appr_name": "Aircraft Procurement, Army", "fy26_v178": {"disc_K": 38419, "li_num": 28, "source": "p40_fy26_v178", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Army/Aircraft_Procurement_Army.txt"}, "fy26t_qty": null, "fy26d_cost": 0, "fy26r_cost": 0, "ident_code": ""}$$::jsonb, NULL, NULL, NULL, NULL, NULL, 1160780000, 3604816000, NULL, NULL, NULL, FALSE, 257854000, 225647000, 21511000, 21511000, 0, 21511000, NULL, NULL, $$Budget J-Books/FY27/Army/Aircraft_Procurement_Army.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604060F$$, $$NORAD & USNORTHCOM (N&NC) Experimentation$$, $$rdte_af_ba4$$, $$aflcmc$$, 2027, 0, 0, 0, NULL, $${}$$::jsonb, NULL, NULL, 31186000, 31172000, 31181000, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 0, 39257000, 39257000, 0, 39257000, 31189000, $$To maintain decision superiority and execute Homeland Defense (HD) missions aligned with the National Defense Strategy (NDS), the Department is modernizing existing data centers to support Artificial Intelligence (AI) capabilities. This strategy maximizes current infrastructure investments to deliver advanced data analytics and autonomous planning tools across all classification networks, actively avoiding the high costs and extended timelines associated with existing time-intensive tasks such as drafting operation plans, summarizing intelligence, and integrating cross domain data. This approach focuses on improving on-premises infrastructure to support DoW scalable environments, data analytics, and AI tool suites to support the integration of intelligence, planning, and operations data to address immediate mission needs. For example, this capability provides analysts with instant access to AI driven dashboards and alerts that fuse sensor feeds, logistics, and mission plans to rapidly enhance border monitoring, illicit trafficking detection, and domain awareness which significantly reduces analytic workloads, accelerates operational planning, and drives decision superiority in direct support of Homeland Defense (HD) and the Unified Command Plan (UCP). Under the Unified Command Plan, USNORTHCOM must maintain decision superiority by delivering timely, data-driven insights to protect the homeland. The current manual analytic workloads and extended planning cycles severely limit the response time to emerging threats. This AI implementation directly addresses limiting factors by streamlining analytic workloads, shrinking plan-drafting cycles, and drastically boosting real-time warning accuracy for border incursions, missile launches, and illicit trafficking. Embedding agentic AI directly into staff processes and coordination workflows accelerates situational awareness and tightens critical decision timelines, unlocking additional capacity for high-value decision support. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604060F / NORAD & USNORTHCOM (N&NC) Experimentation Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207110F$$, $$F-47$$, $$rdte_af_ba5$$, $$aflcmc_wa$$, 2026, 2579362000, 0, 0, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$F-47 enables Air Superiority for the Joint Force in the most challenging operational environments. Key F-47 attributes include enhancements to survivability, lethality, persistence, crewed/uncrewed teaming and interoperability across a range of military operations. Program activities include the employment of digital acquisitions through the application of digital engineering, agile software development, open systems architectures and digital systems infrastructure as well as the design, build, and test of full weapon systems with supporting elements. Funding provides for operational concept exploration, technology studies, multi-domain integration assessments, operational and system architecture development, maturation/risk reduction, prototyping, and Engineering and Manufacturing Development (EMD) of F-47 and related technologies. These technologies include autonomy, weapon systems, mission systems, government referenced architectures for standards and interfaces, terrestrial systems, training, product support, integrated system concept development and demonstration, as well as activities for full weapon system design, build, test, and program management support. Program management support costs include, but are not limited to, contractor support services, civilian pay, supplies, and facility related expenses. F-47 technologies are available to other DoD systems based on emerging threats, AF priorities, and development capacity. The FY 2026 request for F-47 includes 2,579,362 thousand of discretionary and 900,000 thousand of mandatory (reconciliation) for a total of 3,479,632 thousand. The mandatory funds address Air Superiority in FY 2026. Further information for this reconciliation request is provided in Section 20007 (Air Superiority) of the Reconciliation Exhibit. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                            Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System          PE 0207110F / F-47 Development & Demonstration (SDD)$$, NULL, 5253098000, 4122692000, 3293908000, NULL, NULL, 107, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 0, 3053053000, 5037904000, 5037904000, 0, 5037904000, 2952590000, $$F-47 enables Air Superiority for the Joint Force in the most challenging operational environments. Key F-47 attributes include enhancements to survivability, lethality, persistence, crewed/uncrewed teaming and interoperability across a range of military operations. Program activities include the employment of digital acquisitions through the application of digital engineering, agile software development, open systems architectures and digital systems infrastructure as well as the design, build, and test of full weapon systems with supporting elements. Funding provides for operational concept exploration, technology studies, multi-domain integration assessments, operational and system architecture development, maturation/risk reduction, prototyping, and Engineering and Manufacturing Development (EMD) of F-47 and related technologies. These technologies include autonomy, weapon systems, mission systems, government reference architectures for standards and interfaces, terrestrial systems, training, product support, integrated system concept development and demonstration, as well as activities for full weapon system design, build, test, and program management support. Program management support costs include, but are not limited to, contractor support services, civilian pay, supplies, and facility related expenses. F-47 technologies are available to other Department of War (DoW) systems based on emerging threats, AF priorities, and development capacity. The FY 2026 spend plan amount for Research, Development, Test, and Evaluation includes $3,053,053 thousand of discretionary and $400,000 thousand of mandatory (reconciliation) for a total of $3,453,053 thousand. Funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes. Funding may be used to resolve Diminishing Manufacturing Sources and Material Shortages (DMSMS) and/or obsolescence issues. DMSMS activities may include, but are not limited to, bridge buys, life of type buys, buys to protect schedule, and engineering efforts. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System     PE 0207110F / F-47 Development & Demonstration (SDD) This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, or 0605898F. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604200F$$, $$Future Advanced Weapon Analysis & Programs$$, $$rdte_af_ba5$$, $$aflcmc$$, 2026, 36125000, 9589000, 7205000, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0604200F"}$$::jsonb, $$Future Advanced Weapon Analysis & Programs enables Air Force enterprise weapons capability planning through the generation and execution of new and emerging requirements and trade space analysis. Inclusively, this necessitates the studies of emerging weapons system gaps and technology insertion for legacy and future systems, responsive design and development engineering, and emerging weapon system gaps and technology insertion for legacy and future systems. These studies also support the determination, exploration, and execution of feasible solutions through advanced technology prototype development and rapid fielding. Additionally, projects in this program element implement the Digital Acquisition tenants of Open, Agile, and Digital in support of all Air Force weapons by conducting high fidelity Modeling, Simulation and Analysis (MS&A) to support the development, testing, and evaluation of future concept and legacy weapons. Efforts under this program element explore new and future concept developments and analyses in response to stakeholder engagements, technology transitions and common enterprise needs, experimentation, air to ground, ground to launch, and air to air fieldable demonstrations and solutions, and the delivery of quick reaction material solutions. The overall objective is to identify methods to improve weapon system performance, develop potential future designs, mitigate evolving threats, pursue low-cost/affordable weapons solutions, and reduce life cycle costs. These projects will also develop and expand MS&A and experimental platforms for weapon qualification activities, improve safety, identify technology gaps, and ensure viability and durability of future weapons programs. This effort includes design, development, test, integration, and implementation of appropriate modular open systems approach, related components, and efforts, such as, but not limited to electrical, logical, and physical interfaces defined in current and future updates to the Weapon Open System Architecture (WOSA) standard. This approach allows modular and severable subsystems, to include those that are software-defined, at the appropriate level to be incrementally added, removed, or replaced throughout the life cycle. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 $101 thousand was expended for civilian pay expenses in this program element, and in FY 2025 $134 thousand is forecast for civilian pay expenses in this program element. The FY 2026 request was reduced by $570 thousand for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                             Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System     PE 0604200F / Future Advanced Weapon Analysis & Programs Development & Demonstration (SDD) This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, NULL, 26247000, 29473000, 30143000, NULL, NULL, 84, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 8290000, 52398000, 35142000, 35142000, 0, 35142000, 30755000, $$Future Advanced Weapon Analysis & Programs (FAWAP) enables Air Force enterprise weapons capability planning through the generation and execution of new and emerging requirements and trade space analysis. This encompasses studies of emerging weapons system gaps and the operational analysis of technology insertion for legacy and future systems. The outcomes of these studies drive responsive design and development engineering to support the determination, exploration, and execution of feasible solutions through advanced technology prototype development and rapid fielding. Efforts under this program element explore: new and future concept developments and analyses in response to stakeholder engagements; technology transitions and common enterprise needs; air-to-ground, ground-to-launch, and air-to-air fieldable demonstrations and solutions; and the delivery of quick-reaction materiel solutions. The overall objective is to identify methods to improve weapon system performance, develop potential future designs, mitigate evolving threats, pursue low-cost/ affordable weapons solutions, and reduce life cycle costs. These projects will also develop and expand Modeling, Simulation and Analysis (MS&A) and experimental platforms for weapon qualification activities; improve safety; identify technology gaps; and ensure viability and durability of future weapons programs. Projects in this program element implement the Digital Acquisition tenets of Open, Agile, and Digital in support of all Air Force weapons by conducting high fidelity MS&A to support the development, testing, and evaluation of future concept and legacy weapons. Projects under this program element utilize design, development, test, integration, and implementation of appropriate modular open systems approaches, related components, and efforts, including, but not limited to, logical and physical interfaces defined in Weapon Open System Architecture (WOSA). This approach allows modular and severable subsystems, to include those that are software-defined, at the appropriate level to be incrementally added, removed, or replaced throughout the life cycle. The FY2026 spend plan amount for Research, Development, Test & Evaluation, Air Force, includes $52,398 thousand of discretionary and $80,000 thousand of mandatory (reconciliation) for a total of $132,398 thousand. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System         PE 0604200F / Future Advanced Weapon Analysis & Programs Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604201F$$, $$PNT Resiliency, Mods, and Improvements$$, $$rdte_af_ba5$$, $$ssc_milcom$$, 2026, 125663000, 0, 214900000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$Positioning, Navigation, and Timing (PNT) solutions are critical to offensive and defensive operations, enabling delivery of precision fires, safe aerial navigation, and time coordination across multiple platforms and subsystems. PNT must be maintained in the face of emerging and continuously evolving adversarial electronic and cyber threats, requiring increased system resiliency and rapid adaptability. Evolving threats will drive upgrades such as Global Positioning System (GPS) receiver modernization, development of standard navigational system formats/interfaces, increased use of open system architecture design principles, incorporation of alternative navigation sources into navigational solutions, advanced anti-jam antennas, antenna electronics, radio frequency monitoring/locating/reporting capabilities, and precision clock improvements to maintain current and future force capabilities. Project 651030 includes Embedded GPS/Inertial Navigation System (INS) Modernized (EGI-M), Miniaturized Airborne GPS Receiver 2000 Modernization (MAGR-2K-M), Resilient GPS (R-EGI) development, PNT Software Defined User Equipment (PNT SDUE), anti-jam antenna/antenna electronics development, situational awareness devices, and other advanced/non-GPS PNT solutions. Activities also include, but are not limited to, current program planning, rapid prototyping/advanced technology and concept development, execution, and future program planning and support to other GPS enabled systems as required, covered within Budget Activities 6.3, 6.4, and 6.5. The PNT Resiliency, Mods, and Improvements (RMI) effort provides rapidly re-programmable application space for Alternate Satellite Navigation Systems User Equipment (UE), enabling agile and resilient response to GPS threat environments. Funds may be used to address emerging and short-notice Diminishing Manufacturing and Material Shortage (DMSMS) issues. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY2024 5.122M was expended for civilian pay expenses in this program element, in FY2024 6.001M was expended for civilian pay expenses in this program element, and in FY25, 10.899M is forecasted for civilian pay expenses in this program element. The FY 2026 cost of Middle Tier of Acquisition (MTA) effort PNT is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify Future Years Defense Program (FYDP) funding in a future budget submission. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System     PE 0604201F / PNT Resiliency, Mods, and Improvements Development & Demonstration (SDD) This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, NULL, 471574000, 425502000, 303872000, NULL, NULL, 85, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 224017000, 124199000, 710780000, 710780000, 0, 710780000, 315765000, $$Positioning, Navigation, and Timing (PNT) solutions are critical to offensive and defensive operations, enabling delivery of precision fires, safe aerial navigation, and time coordination across multiple platforms and subsystems. PNT must be maintained in the face of emerging and continuously evolving adversarial electronic and cyber threats, requiring increased system resiliency and rapid adaptability. Evolving threats will drive upgrades such as Global Positioning System (GPS) receiver modernization, development of standard navigational system formats/interfaces, increased use of open system architecture design principles, incorporation of alternative navigation sources into navigational solutions, advanced anti-jam antennas, antenna electronics, radio frequency monitoring/locating/reporting capabilities, and precision clock improvements to maintain current and future force capabilities. GPS Receiver Development includes Embedded GPS/Inertial Navigation System (INS) Modernized (EGI-M), Miniaturized Airborne GPS Receiver 2000 Modernization (MAGR-2K-M), Resilient GPS (R-EGI) development, PNT Software Defined User Equipment (PNT SDUE), anti-jam antenna/antenna electronics development, situational awareness devices, and other advanced/non-GPS PNT solutions. Activities also include, but are not limited to, current program planning, rapid prototyping/ advanced technology and concept development, execution, and future program planning and support to other GPS enabled systems as required. The PNT Resiliency, Mods, and Improvements (RMI) effort provides rapidly re-programmable application space for Alternate Satellite Navigation Systems User Equipment (UE), enabling agile and resilient response to GPS threat environments. Funds may be used to address emerging and short-notice Diminishing Manufacturing and Material Shortage (DMSMS) issues. Beginning in FY 2027, GPS Receiver Development project will include MGUE Inc 1 and Inc 2 efforts. MGUE Inc 1 program leverages technology to the maximum extent while addressing the production of M-Code integrated circuits far into the future. MGUE Inc 1 efforts encompass TECHEVAL and Follow-on Operational Test & Evaluation (FOT&E) test events for the Maritime Domain lead platform and expansion of Military-Code (M- Code) receiver technology into additional applications (precision guided munitions) and develop a Joint Modernized Handheld (JMHH) device and Aviation/Maritime receiver to meet Service requirements and address obsolescence. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System        PE 0604201F / PNT Resiliency, Mods, and Improvements Development & Demonstration (SDD) MGUE Inc 2 will be accomplished in four stages: 1) Risk Reduction Activities, 2) Miniature Serial Interface (MSI) Receiver Card Middle Tier Acquisition (MTA) rapid prototyping followed by 3) Software Acquisition Pathway (SWP) and 4) Joint Modernized GPS HH Receiver Middle Tier Acquisition (MTA) rapid prototyping effort. The total cost of the Positioning, Navigation, and Timing Software Defined User Equipment (PNT SDUE) Rapid Prototyping Middle Tier of Acquisition (RP MTA) effort is $551.300 million, including RDT&E and procurement of prototype units. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604281F$$, $$Tactical Data Networks Enterprise$$, $$rdte_af_ba5$$, $$aflcmc_hn$$, 2026, 77170000, 82369000, 78480000, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0604281F"}$$::jsonb, $$Air Force operations rely on secure communications capability for Command-and-Control messages, threat messages, target updates, etc. Adversaries continually attempt to detect, intercept, decrypt, defeat, disrupt, deny or degrade these communications capabilities--driving the Air Force to continuously upgrade its systems with enhanced encryption, increased technology for low probability of detection (LPD), low probability of interception (LPI), anti-jamming (AJ), increased security and performance engineering, and enhanced throughput and interoperability. These efforts ensure life-saving data can be transmitted before, during and after operations without adversary hostile intervention via secure and reliable communication paths. The communications paths utilized are often referred to as datalinks over which are transmitted messages via specific waveforms through radios, multi-function processors and affiliated and associated technologies in accordance with specifications and standards. The Tactical Data Networks Enterprise (TDNE) program element analyzes and evaluates requirements, designs, develops, enhances, and fields prospective or needed systems. The TDNE focuses on the research, analysis, design, development, test, evaluation and fielding or other capability development of Tactical Datalink (TDL), gateway, radio, multi-function processor, antenna, multi-function aperture, license, waveform and other associated equipment, technology or capabilities. TDNE develops, enhances and fields technologies, architectures, documentation, tactics, techniques, procedures and capabilities. These efforts enhance Air Force communications capacity, efficiency, affordability, integration and optimization. TDNE supports interoperability of Air Force to: Air Force, Joint, Coalition, and NATO (Allied), and other partner platforms and systems; supports releasability engineering, cyber engineering, digital engineering, encryption and safety compliance, et al. Tactical Data Links (TDL) System Integration provides for the study, analysis, enhancement, development, integration, demonstration, joint/coalition/NATO interoperability exercises, costing, test, trials, and evaluation of TDL as a subset of the broader aerial layer network. Products include interoperability standards and reports, waveform standards, and hardware/software technical solutions. The number of Air Force platforms hosting TDLs has expanded from C2 aircraft to the fighter, bomber, intelligence, surveillance, and reconnaissance (ISR), tanker, airlift and other tactical fleets as well as precision guided munitions. Utilization of TDLs in joint and international environments requires the integration of terminals into host platforms and interoperability of TDL networks across all deployed joint/Coalition/NATO platforms. USAF mandates require additional studies and analysis to meet frequency reprogramming and cryptographic requirements. To deliver TDL capabilities to required platforms and users, Tactical Data Links (TDL) Networks Enterprise is broken into four main thrusts of Tactical Data Links and Gateways (TDL&G) Integration, Advanced Aerial Communication Technology (AACT), the Common Tactical Edge Network (CTEN) program (which evolved from and includes prior Agile Communications efforts), and Second-Generation Anti-Jam Tactical UHF Radio for NATO (SATURN) waveform sponsor activities. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                                Date: June 2025 Appropriation/Budget Activity                                                         R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System              PE 0604281F / Tactical Data Networks Enterprise Development & Demonstration (SDD) Tactical Data Links and Gateways (TDL&G) Integration activities consist of TDL integration and waveform management to ensure host platforms and users have current TDL waveforms, network access, and interoperability. This includes enabling and supporting Joint Interoperability of Tactical Command and Control Systems (JINTACCS), joint/Coalition/NATO Interoperability, Link 16 enhancements, cybersecurity and performance testing, requirements analysis and fleet roadmapping efforts. In addition to integration efforts for new and existing TDLs, these activities require funding for test units and facilities, interoperability management systems, and assessment tools to implement waveform standards to meet system information exchange requirements. Advanced Aerial Communication Technology (AACT) activities consist of developing and demonstrating new technologies to enable host platforms and users. This includes but is not limited to the development of capabilities to reduce the effects of advanced jamming in Anti-Access/Area Denial environments and increase communications resiliency for platforms and users. Technical solutions developed under this effort include, but are not limited to, Small Form Factor (SFF)/Digitally Assisted Close Air Support (DACAS), SPOC and Link 16 Enhancements. The Common Tactical Edge Network (CTEN) program evolved from and incorporates prior Agile Communications efforts to enhance interoperability. It includes the capability to share tactically significant information within/to/from highly contested environments in support of the Air Superiority 2030 Flight Plan. It supports the application of open standards and advanced apertures over an Enterprise-wide Aerial Network, enabling all platforms to share combat-relevant data/info to, from and within the Highly Contested Environment (HCE). The CTEN program is primarily a software (SW) overlay network that routes data within and between permissive, contested, and highly contested environments through content routing to establish connections between heterogeneous networks across different media and domains. CTEN is considered a core enabling program for the DAF Battle Network and is a key enabler of the Advanced Battle Management System (ABMS). The CTEN efforts include the prior classified and unclassified Agile Communications efforts, along with their interoperability with affiliated cross-Service and Joint capabilities and efforts such as the Joint Tactical Edge Network (JTEN). Second-Generation Anti-Jam Tactical UHF Radio for NATO (SATURN) activities in this PE consists of executing the Waveform Sponsor role for SATURN. Each role consists of several distinct engineering and development responsibilities, to include, but not limited to leading and overseeing the development, refinement, updating, and US interoperability of the SATURN Waveform and its associated development efforts such as, for example, the SATURN Enhanced Data Rate (SEDR) program. DoD Instruction 4630.09, "Communications Waveform Management and Standardization” outlines the roles of a Waveform Sponsor that will be pursued via the funds in the program element. To note, DoDI 4630.09 identifies specific roles for a "Lead Service” and a "Waveform Sponsor”. "Lead Service” activities are unique and provided for in a separate program element 0303008F. Family of Gateways provides for the study (acquisitions current and proposed), analysis, enhancement, development, integration, costing, demonstration, test, and evaluation efforts that will allow joint combat forces to exchange information quickly and accurately by bridging discrete airborne, terrestrial, maritime, and space- based C4ISR networks producing operational effects not possible within individual networks. Gateway functions include enabling interoperability between data formats, protocols, and communication mediums. Additionally, gateway functions extend the connectivity range, consolidate data from multiple networks into high-capacity links for transmission to key C2ISR nodes, route information between disadvantaged users, and fuse/correlate data from multiple sources to improve accuracy. Gateway functions also provide application hosting, shared data storage, on-demand information access, smart data forwarding, and system monitoring and network management. Family of Gateways will support to enhance existing TDL performance, through upgrades and engineering analysis of system designs. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System     PE 0604281F / Tactical Data Networks Enterprise Development & Demonstration (SDD) Efforts within this PE align with USAF investment in ABMS (0604003F) and Tech Transition - Air (0604858F) to deliver beyond line of sight communications for the Department of the Air force Battle Network (DAF Battle Network). The FY 2026 request was reduced by 3.525M for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative" This program element may include necessary civilian pay expenses required to support, manage, execute, and deliver weapon system capabilities across the BACN platforms, aerial network, and tactical data network enterprise. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024, 0.903M was expended for civilian pay expenses in this program element. In FY 2025, 1.715M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, NULL, 106739000, 108311000, 110028000, NULL, NULL, 88, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 76188000, 76418000, 110151000, 110151000, 0, 110151000, 111461000, $$Air Force operations rely on secure communications capability for Command-and-Control messages, threat messages, target updates, etc. Adversaries continually attempt to detect, intercept, decrypt, defeat, disrupt, deny or degrade these communications capabilities--driving the Air Force to continuously upgrade its systems with enhanced encryption, increased technology for low probability of detection (LPD), low probability of interception (LPI), anti-jamming (AJ), increased security and performance engineering, and enhanced throughput and interoperability. These efforts enable the transmission of life-saving data before, during, and after operations without adversary hostile intervention via secure and reliable communication paths. The communications paths utilized are often referred to as datalinks over which are transmitted messages via specific waveforms through radios, multi-function processors and affiliated and associated technologies in accordance with specifications and standards. The Tactical Data Networks Enterprise (TDNE) program element analyzes and evaluates requirements, designs, develops, enhances, and fields prospective or needed systems. The TDNE focuses on the research, analysis, design, development, test, evaluation and fielding or other capability development of tactical datalinks (TDLs), gateway, radio, multi-function processor, antenna, multi-function aperture, license, waveform and other associated equipment, technology or capabilities. TDNE develops, enhances and fields technologies, architectures, documentation, tactics, techniques, procedures and capabilities. These efforts enhance Air Force communications capacity, efficiency, affordability, integration and optimization. TDNE supports interoperability of Air Force to: Air Force, Joint, Coalition, and NATO (Allied), and other partner platforms and systems; supports releasability engineering, cyber engineering, digital engineering, encryption and safety compliance, et al. Tactical Data Links (TDL) System Integration provides for the study, analysis, enhancement, development, integration, demonstration, joint/coalition/NATO interoperability exercises, costing, test, trials, and evaluation of TDL as a subset of the broader aerial layer network. Products include interoperability standards and reports, waveform standards, and hardware/software technical solutions. The number of Air Force platforms hosting TDLs has expanded from C2 aircraft to the fighter, bomber, intelligence, surveillance, and reconnaissance (ISR), tanker, airlift and other tactical fleets as well as precision guided munitions. Utilization of TDLs in joint and international environments requires the integration of terminals into host platforms and interoperability of TDL networks across all deployed joint/ Coalition/NATO platforms. USAF mandates require additional studies and analysis to meet frequency reprogramming and cryptographic requirements. To deliver TDL capabilities to required platforms and users, Tactical Data Links (TDL) Networks Enterprise is broken into six main thrusts of Tactical Data Links and Gateways (TDL&G) Integration, Advanced Aerial Communication Technology (AACT), the Common Tactical Edge Network (CTEN) program (which evolved from and includes prior Agile Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                                Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System   PE 0604281F / Tactical Data Networks Enterprise Development & Demonstration (SDD) Communications efforts), and Second-Generation Anti-Jam Tactical UHF Radio for NATO (SATURN) waveform sponsor activities, Advanced Tactical Datalinks, and Link 22. Tactical Data Links and Gateways (TDL&G) Integration activities consist of TDL integration and waveform management to ensure host platforms and users have current TDL waveforms, network access, and interoperability. This includes enabling and supporting Joint Interoperability of Tactical Command and Control Systems (JINTACCS), joint/Coalition/NATO Interoperability, Link 16 enhancements, Link 16 & MIDS-J improvements as needed, cybersecurity and performance testing, requirements analysis and fleet road mapping efforts. In addition to integration efforts for new and existing TDLs, these activities require funding for test units and facilities, interoperability management systems, and assessment tools to implement waveform standards to meet system information exchange requirements. Advanced Aerial Communication Technology (AACT) activities consist of developing and demonstrating new technologies to enable host platforms and users. This includes but is not limited to the development of capabilities to reduce the effects of advanced jamming in Anti-Access/Area Denial environments and increase communications resiliency for platforms and users, or could include radio, antenna, aperture, multifunction processor development or other such technological conception, development, prototyping and demonstration. Prior technical solutions developed under this effort include, but are not limited to, Small Form Factor (SFF)/ Digitally Assisted Close Air Support (DACAS), SPOC and Link 16 Enhancements. The Common Tactical Edge Network (CTEN) program evolved from and incorporates prior Agile Communications efforts to enhance interoperability. It includes the capability to share tactically significant information within/to/from highly contested environments in support of the Air Superiority 2030 Flight Plan. It supports the application of open standards and advanced apertures over an Enterprise-wide Aerial Network, enabling all platforms to share combat-relevant data/info to, from and within the Highly Contested Environment (HCE). The CTEN program is primarily a software (SW) overlay network that routes data within and between permissive, contested, and highly contested environments through content routing to establish connections between heterogeneous networks across different media and domains. CTEN is considered a core enabling program for the DAF Battle Network and is a key enabler of the Advanced Battle Management System (ABMS). The CTEN efforts include the prior classified and unclassified Agile Communications efforts, along with their interoperability with affiliated cross-Service and Joint capabilities and efforts such as the Joint Tactical Edge Network (JTEN). Second-Generation Anti-Jam Tactical UHF Radio for NATO (SATURN) activities in this PE consists of executing the Waveform Sponsor role for SATURN. Each role consists of several distinct engineering and development responsibilities, to include, but not limited to leading and overseeing the development, refinement, updating, and US interoperability of the SATURN Waveform and its associated development efforts such as, for example, the SATURN Enhanced Data Rate (SEDR) program. DoD Instruction 4630.09, "Communications Waveform Management and Standardization” outlines the roles of a Waveform Sponsor that will be pursued via the funds in the program element. To note, DoDI 4630.09 identifies specific roles for a "Lead Service” and a "Waveform Sponsor”. "Lead Service” activities are unique and provided for in a separate program element 0303008F. The Advanced Tactical Datalinks thrust evolves existing and develops new waveforms to keep pace with the evolving operational environment. One sample capability being developed is the Direct Line of Sight (DLOS) capability whose initiation commenced in another PE and which will transfer into this PE from in FY 2027. Funds will continue development to support current and future warfighter needs in evolving threat landscapes. DLOS and other ATDLs will enable mission success against adversary capabilities that deny Link 16 operations as well as other waveforms. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System        PE 0604281F / Tactical Data Networks Enterprise Development & Demonstration (SDD) Link 22 provides a long range surveillance Beyond Line of Sight (BLOS) datalink where SATCOM or alternate connectivity is not available. Link 22 provides tactical interoperability between air, surface, subsurface, and ground-based tactical data systems currently fielded to the U.S. Navy, NATO, and non-Link 16 coalition partners. Per DoD CIO, the replacement for Link-11 is Link-22. Family of Gateways provides for the study (acquisitions current and proposed), analysis, enhancement, development, integration, costing, demonstration, test, and evaluation efforts that will allow joint combat forces to exchange information quickly and accurately by bridging discrete airborne, terrestrial, maritime, and space- based C4ISR networks producing operational effects not possible within individual networks. Gateway functions include enabling interoperability between data formats, protocols, and communication mediums. Additionally, gateway functions extend the connectivity range, consolidate data from multiple networks into high-capacity links for transmission to key C2ISR nodes, route information between disadvantaged users, and fuse/correlate data from multiple sources to improve accuracy. Gateway functions also provide application hosting, shared data storage, on-demand information access, smart data forwarding, and system monitoring and network management. Family of Gateways will support to enhance existing TDL performance, through upgrades and engineering analysis of system designs. Efforts within this PE align with USAF investment in ABMS (0604003F) and Tech Transition - Air (0604858F) to deliver beyond line of sight communications for the Department of the Air force Battle Network (DAF Battle Network). This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. Program RDT&E funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Program RDT&E funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Program RDT&E funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                   Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System     PE 0604281F / Tactical Data Networks Enterprise Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604287F$$, $$Physical Security Equipment$$, $$rdte_af_ba5$$, $$aflcmc$$, 2026, 10589000, 9836000, 10569000, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0604287F"}$$::jsonb, $$The Physical Security Equipment (PSE) program provides for Air Force (AF) Integrated Base Defense Security Systems (IBDSS) improvements and enhancements, to include the demonstration and testing of PSE systems related to Force Protection. This program supports the protection of tactical, fixed, and nuclear weapons systems, AF personnel and AF facilities in the homeland and overseas. The PSE program includes spectrum planning for radio frequency (RF), communication security (cyber), information assurance requirements, integration and interoperability Command Control & Communication (C3) platform & components and Tactical Sensor System to support the Force Protection implementation of expeditionary/AFFORGEN concept. This Program Element also includes funding for Force Protection Commercial Off the Shelf (COTS) equipment, market research, integration, evaluation and testing. Force Protection programs are inherently subject to rapid changes in the operational environment and will retain sufficient program flexibility to meet changes in location, scope and capability in order to protect AF people, facilities and warfighting assets. The Defender Multi-Domain Command, Control and Communications (DMDC3) is an initiative developing the foundational structure of IBDSS to provide a platform that integrates the computing power, the means of communication, and the tools for situational awareness. PSE efforts support Modular Open Source Architecture (MOSA) standards to enable faster installations and greater interoperability to address the Chief of Staff of the AF 'Fight the Base' goals. IBDSS FY2026 developmental efforts will continue to evaluate and test state-of-the-art technology to support integrated based defense systems installations worldwide, continue to improve and integrate COTS efforts into IBDSS physical security equipment, and further develop, integrate and test Defender Multi-Domain Command, Control and Communications (DMDC3) software applications. IBDSS-4 expands upon and scales IBDSS modernization efforts first developed under IBDSS-2. Capability improvements include zero-trust architecture, Machine Language (ML)/Artificial Intelligence (AI) integration, expanded sensor capabilities, Unmanned Aerial System(UAS)/Unmanned Ground Vehicle (UGV) integration, and improved mobile C3. The FY 2026 request was reduced by 0.490 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2024 1.118M forecasted for civilian pay expenses in this program element, and in FY2025 1.430M is forecasted for civilian pay expenses in this program element. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System     PE 0604287F / Physical Security Equipment Development & Demonstration (SDD) This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, NULL, 9122000, 9319000, 9493000, NULL, NULL, 89, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 7720000, 15005000, 8743000, 8743000, 0, 8743000, 9686000, $$The Physical Security Equipment (PSE) program provides for Air Force (AF) Integrated Base Defense Security Systems (IBDSS) improvements and enhancements, to include the demonstration and testing of PSE systems related to Force Protection. This program supports the protection of tactical, fixed, and nuclear weapons systems, AF personnel and AF facilities in the homeland and overseas. The PSE program includes spectrum planning for radio frequency (RF), communication security (cyber), information assurance requirements, integration and interoperability Command Control & Communication (C3) platform & components and Tactical Sensor System to support the Force Protection implementation of expeditionary/AFFORGEN concept. This Program Element also includes funding for Force Protection Commercial Off the Shelf (COTS) equipment, market research, integration, evaluation and testing. Force Protection programs are inherently subject to rapid changes in the operational environment and will retain sufficient program flexibility to meet changes in location, scope and capability in order to protect AF people, facilities and warfighting assets. The Defender Multi-Domain Command, Control and Communications (DMDC3) is an initiative developing the foundational structure of IBDSS to provide a platform that integrates the computing power, the means of communication, and the tools for situational awareness. PSE efforts support Modular Open Source Architecture (MOSA) standards to enable faster installations and greater interoperability to address the Chief of Staff of the AF 'Fight the Base' goals. IBDSS FY2027 developmental efforts will continue to evaluate and test state-of-the-art technology to support integrated based defense systems installations worldwide, continue to improve and integrate COTS efforts into IBDSS physical security equipment, and further develop, integrate and test Defender Multi-Domain Command, Control and Communications (DMDC3) software applications. IBDSS-4 expands upon and scales IBDSS modernization efforts first developed under IBDSS-2. Capability improvements include zero-trust architecture, Machine Language (ML)/Artificial Intelligence (AI) integration, expanded sensor capabilities, Unmanned Aerial System (UAS)/Unmanned Ground Vehicle (UGV) integration, and improved mobile C3. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System       PE 0604287F / Physical Security Equipment Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0101125F$$, $$Nuclear Weapons Modernization$$, $$rdte_af_ba5$$, $$afnwc$$, 2027, 0, 0, 0, NULL, $${}$$::jsonb, NULL, NULL, 22000000, 10000000, 1000000, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 0, 23066000, 23066000, 0, 23066000, 0, $$The purpose of this program element is to conduct and support United States Air Force (USAF) and Joint Department of War (DoW) / Department of Energy (DOE) acquisition activities for the modernization of nuclear weapons. B61 Life Extension Program (LEP): The B61 LEP will integrate DOE efforts to extend the service life of the warhead with DoW efforts to develop a guided Tail Kit Assembly (TKA) required to maintain current B61 mission characteristics. Programmatic integration of the Air Force-led, joint DoW-DOE program is accomplished through the B61 LEP Project Officers Group (POG) and its subgroups. In accordance with Air Force Materiel Command mission assignment memo (dated 17 Feb 2011) and National Nuclear Security Administration (NNSA)-Air Force Nuclear Weapons Center (AFNWC) Memorandum of Understanding (MOU dated 28 Jun 2012), the USAF is responsible for development, acquisition and delivery of a guided TKA and All Up Round (AUR) technical integration, system qualification and fielding of the B61 variant on multiple platforms. On 27 Oct 23, the Department of War announced the United States will pursue a modern variant of the B61 nuclear gravity bomb, designated the B61-13. In a 2023 classified memorandum the Nuclear Weapons Council authorized programmatic planning for production of that modern variant. The System Program Office expects Congressional authorization and appropriation in Fiscal Year 2027 (FY27). The B61-13 will strengthen deterrence of adversaries and assurance of allies and partners by providing the President with additional options against certain harder and large-area military targets. The B61-13 will replace some of the B61-7s in the current stockpile. The B61-13 will have a yield similar to B61-7, which is higher than the B61-12. The B61-13 will include modern safety, security, and accuracy features of the B61-12. The B61-13 will not increase the overall number of weapons in the U.S. stockpile. The number of B61-12s to be produced will be lowered by the same amount as the number of B61-13s produced. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                     Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System        PE 0101125F / Nuclear Weapons Modernization Development & Demonstration (SDD) Funds may be used to address emerging and short-notice Diminishing Manufacturing and Material Shortage (DMSMS) issues. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 5, System Development and Demonstration (SDD), because it is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full-rate production. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0303267F$$, $$Auctioned Spectrum Relocation Fund$$, $$rdte_af_ba5$$, $$aflcmc$$, 2026, 0, 21667000, 0, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0303267F"}$$::jsonb, NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, FALSE, 9695000, 0, 0, 0, 0, 0, 0, $$Funding supports Spectrum relocation and sharing activities. In FY 2025, Project 658062 was completed. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0308602F$$, $$ENTEPRISE INFORMATION SERVICES (EIS)$$, $$rdte_af_ba6$$, $$afrl_ri$$, 2026, 101779000, 96912000, 104133000, NULL, $${"ba_raw": "6.6", "source": "af_r1_fy26", "original_pe": "0308602F"}$$::jsonb, $$Enterprise Information Services (EIS) is a portfolio of integrated programs/technologies/services that enables and sustains Air Force Information Management, Knowledge Operations and Development, Security and Operations (DevSecOps) initiatives. EIS provides Air Force personnel access to, and management of, timely, accurate, and trusted mission data, information, and knowledge supporting information/decision superiority. EIS is comprised of Platform One (P1) and Enterprise Resource Planning Common Services (ERP-CS). P1 and ERP-CS provide common platforms, common application support services, data center migration to the cloud options, and security services for AF mission applications. P1 provides access to a cyber-secure software supply chain and an existing, accredited DevSecOps infrastructure reusable by DoD programs that accelerate widespread adoption of DevSecOps methodologies IAW DoD Digital Modernization strategy. ERP-CS provides the common services for Enterprise Resource Planning (ERP) applications in the target DAF Cloud environment for Department of the Air Force (DAF) ERP systems. P1 and ERP-CS acquisitions are critical to provide common services across multiple hosting environments leveraging DoD and DAF brokered commercial cloud capabilities that comply with the Air Force Information Technology (AF IT) baselines. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24 1.169M was expended for civilian pay expenses in this program element; and in FY25 2.710M is forecasted for civilian pay expenses in this program element. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E     PE 0308602F / ENTEPRISE INFORMATION SERVICES (EIS) Management Support FY26 request was reduced by $.891M for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, implementing the President's Department of Government Efficiency Cost Efficiency Initiatives. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, NULL, 104946000, 107426000, 109909000, NULL, NULL, 144, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 104232000, 115119000, 80342000, 80342000, 0, 80342000, 112554000, $$Enterprise Information Services (EIS) is a portfolio of integrated programs/technologies/services that enables and sustains Air Force Information Management, Knowledge Operations and Development, and Security and Operations (DevSecOps) initiatives. EIS provides Air Force personnel access to, and management of, timely, accurate, and trusted mission data, information, and knowledge to support information/decision superiority. EIS is comprised of Platform One (P1) and Enterprise Resource Planning Common Services (ERP-CS). P1 and ERP-CS provide common platforms, common application support services, data center migration to the cloud options, and security services for Air Force mission applications. P1 provides access to a cyber-secure software supply chain and an existing, accredited DevSecOps infrastructure reusable by Department of War (DoW) programs that accelerate widespread adoption of DevSecOps methodologies in accordance with DoW Digital Modernization strategy. ERP-CS provides the common services for Enterprise Resource Planning (ERP) applications in the target Department of the Air Force (DAF) Cloud environment for DAF ERP systems. P1 and ERP- CS acquisitions are critical to provide common services across multiple hosting environments leveraging DoW and DAF brokered commercial cloud capabilities that comply with the Air Force Information Technology (AF IT) baselines. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F FY2026 request was reduced by 0.891 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, implementing the President's Department of Government Efficiency Cost Efficiency Initiatives. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E       PE 0308602F / ENTEPRISE INFORMATION SERVICES (EIS) Management Support$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604735F$$, $$Combat Training Ranges$$, $$rdte_af_ba5$$, $$aflcmc_wa$$, 2026, 139499000, 56609000, 160783000, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0604735F"}$$::jsonb, $$COMBAT TRAINING RANGES (CTR): Portfolio provides electronic warfare equipment and support to Air Force combat training ranges for training, testing, and evaluation of aircrews. Development and integration efforts include: aircraft pods, radar emitters, advanced radar emitters, communication jammers, command and control and debrief capability, and instrumentation equipment. All development efforts support USAF aircraft for Joint, Coalition, and Live Virtual Constructive (LVC) training events. This program leverages digital acquisition tenets of open, agile, and digital. This program will develop Common component in collaboration with other weapon systems, to reduce redundant costs between systems with similar subsystems requirements. It will also invest in analytical, information management, data management, digital environments, networks, facilities, and security infrastructure upgrades directly supporting development and sustainment of this program's capabilities, while leveraging DoD and DAF enterprise IT solutions. ADVANCED RADAR THREAT SYSTEM (ARTS): ADVANCED RADAR THREAT SYSTEM (ARTS): The ARTS family of systems program is currently focused on the ARTS-V1 and ARTS-V3 variants. ARTS-V1 is currently in the Production Phase, having achieved IOC with its Production Representative Article (PRA) at Nellis Test and Training Range, and is preparing to enter into full sustainment in FY28 following delivery of the 2 production units. ARTS-V3 is a software defined digital radar currently in the Engineering and Manufacturing Development Phase. ARTS-V3 is developing a state-of-the-art digital active electronically scanned radar system that will be used to simulate the latest foreign Surface-to-Air Missile (SAM) radar and Electronic Warfare (EW) threat systems. ARTS-V3 systems are a critical part of the Operational Training and Test Infrastructure (OTTI) plan for developing future Tactics, Techniques and Procedures (TTPs) for potential conflicts. These systems are also a critical component of the DoD's testing capabilities for validation of advanced airpower capabilities against threat-representative radar systems. Efforts include, but are not limited to: anechoic chamber research, digital twin, and open-air testing technology development, software development, and collaborative test and development infrastructures. ARTS V3 will validate open-air characteristics of advanced threat systems to develop realistic physics-based threat models for virtual high- end training environments including the Joint Synthetic Environment. MODERNIZATION RANGE THREATS SYSTEMS (RTS): The RTS program supports upgrading and modifying legacy range threat systems to provide combat training relevancy and enhanced systems capabilities. Legacy systems include Multiple Threat Emitter System (MUTES), Miniature Multiple Threat Emitter System (Mini- MUTES), Modular Threat Emitter (MTE) system, Tactical Radar Threat Generator (TRTG) system, Band Simulator, Unmanned Modular Threat Emitter (UMTE) system, and Joint Threat Emitter (JTE) system. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                            Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System          PE 0604735F / Combat Training Ranges Development & Demonstration (SDD) LIVE MISSION OPERATIONS CAPABILITY (LMOC): LMOC is an effort to modernize range control centers with common hardware and software that can support live- synthetic training missions. LMOC will provide a node-based enterprise that integrates all range system capabilities, including pre/post mission coordination, in a multi- level secure environment to enable blended live-synthetic training for 4th/5th generation aircraft and aircrew. P6 Combat Training Systems (P6CTS) will resolve existing critical training capability gaps and will enable comprehensive, realistic air combat training. Key upgrades include a trusted operating system, Multiple Level Security (MLS) architecture, Type 1 encryption of over-air data, and increased processing capability. P6CTS investment will support a robust Air-to-Air and Air-to-Ground combat training environment and provide a growth path to Blended Training capability. The P6CTS is comprised of airborne participant subsystem, ground system/subsystem and ancillary range communication infrastructure. P6CTS Initial Operating Capability (IOC) on F-15 at Nevada Test and Training Range (NTTR) is targeted for FY27. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24 3.8M was expended for civilian pay expenses in this program element, and in FY25 4.775M is forecasted for civilian pay expenses in this program element. The programs in the civilian pay requirement are ARTS-V3, P6CTS and LMOC. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, NULL, 46743000, 50422000, 42347000, NULL, NULL, 95, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 154258000, 147587000, 132783000, 132783000, 0, 132783000, 43206000, $$COMBAT TRAINING RANGES (CTR): Portfolio provides electronic warfare equipment and support to Air Force combat training ranges for training, testing, and evaluation of aircrews. Development and integration efforts include aircraft pods, radar emitters, advanced training radars, communication jammers, command and control and debrief capability, and instrumentation equipment. The portfolio will also research and develop analytical and information management, data management, digital environments, networks, facilities, and security infrastructure. All development efforts support USAF aircraft for Joint, Coalition, and Live Virtual Constructive (LVC) training events. ADVANCED RADAR THREAT SYSTEM Variant 3 (ARTS- V3): ARTS-V3 is developing the most advanced ground-based radars in the US inventory using digital active electronically scanned radar technology used to simulate the latest foreign peer adversary Surface-to-Air Missile (SAM) radar and Electronic Warfare (EW) threat systems. ARTS-V3 systems are a critical part of the Operational Training and Test Infrastructure (OTTI) plan for developing future Tactics, Techniques and Procedures (TTPs) for 5th/6th generation aircraft (F-35, B-21, F-47). ARTS- V3 systems are critical for Department of the Air Force test capabilities for validation of advanced airpower capabilities against threat-representative radar systems and validation of models used for the Joint Simulation Environment (JSE). ARTS Technology Development: Address the affordability training gap with government-owned, software-defined mobile emitters that increase threat density and realism of an integrated air defense network. Efforts include developing a technical data package, building prototypes, maturing production capabilities, and transitioning items for production. LIVE MISSION OPERATIONS CAPABILITY (LMOC): LMOC is a government-owned command system serving as the training range equivalent of an Air Operations Center (AOC). Connecting all CAF ranges through a secure, dedicated network backbone, LMOC utilizes a long-term, modular, and scalable architecture to enable real- time mission planning, execution, and debriefing. This multi-domain, multi-security level environment facilitates the integration of 4th/5th/6th generation live-synthetic training by supporting blue/red/white force cells from pre-event preparations through live monitoring to post-event debriefing and data storage. LMOC features provisions for future Live, Virtual, and Constructive (LVC)/Blended and Joint interoperability test and training requirements enhancing warfighter capabilities. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                           Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System        PE 0604735F / Combat Training Ranges Development & Demonstration (SDD) P6 Combat Training Systems (P6CTS) will resolve existing critical training capability gaps and will enable comprehensive, realistic air combat training. Key upgrades include a trusted operating system, Multiple Independent Levels of Security (MILS) architecture, Type 1 encryption of over-air data, and increased processing capability. P6CTS investment will support a robust Air-to-Air and Air-to-Ground combat training environment and provide a growth path to Blended Training capability. The P6CTS is comprised of airborne participant subsystem, ground system/subsystem and ancillary range communication infrastructure. P6CTS Initial Operating Capability (IOC) on F-15 at Nevada Test and Training Range (NTTR) is targeted for FY28. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207039F$$, $$Cognitive Electromagnetic Warfare$$, $$rdte_af_ba5$$, $$aflcmc$$, 2026, 44267000, 0, 0, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0207039F"}$$::jsonb, $$Cognitive Electromagnetic Warfare is an Air Force capability to analyze adversaries' use of the electromagnetic spectrum (EMS), make real-time decisions assisted by machine learning/artificial intelligence, preform effective electromagnetic attack (EA), and share EA techniques and identification/targeting criteria to the joint warfighting force. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 060531F, 0605833F, 0605898F, 0606398F. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System        PE 0207039F / Cognitive Electromagnetic Warfare Development & Demonstration (SDD)$$, NULL, 62453000, 99915000, 100828000, NULL, NULL, 106, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 0, 23933000, 50496000, 50496000, 0, 50496000, 103100000, $$This program integrates multiple projects to achieve massed non-kinetic warfare dominance for the Department of War (DoW) Counter Long Range Kill Chain (C-LRKC) and Counter-Command, Control, Communications, Computers, Cyber, Intelligence, Surveillance, & Reconnaissance (C-C5ISR) constructs. It includes three initial interrelated activities that capture and exploit EW effectiveness improvements/synergies in contested/congested battlespaces. These activities include: 1) Algorithm and Applications (Algo & Apps) 2) EW Dev Env and 3) MEAP. The Alg & Apps project continues efforts initiated under PE 64270F in FY2024 (as Cog EW) and extends those actions to identify/discover, investigate, and nominate potential advanced algorithms that can fill gaps in our abilities to automatically sense the electromagnetic environment, employ machine learning (ML) to understand it, and adapt or create new electromagnetic countermeasures in real-time to defeat adversary capabilities. This provides agile and adaptive responses to novel, ambiguous, and complex adversary radar and communication systems. The EW Dev Env project ties together several on-going AF, other service, and commercial activities by building and utilizing an evolving digital infrastructure to advance promising algorithms through an integrated disciplined maturation/validation process constituting the front end of an ""EW Application Pipeline” as the entry point of an AF standard methodology for producing and delivering advanced capabilities to rapidly meet operational requirements and transition advanced technologies to fielded capabilities in collaboration with weapon system program offices and ACC's 350th Spectrum Warfare Wing (SWW). It leverages work done under AFRL's E-Gon and the AF Open Architecture Test Pipeline (AOATP) efforts. This process will ultimately be used to implement Cog EW attributes into fieldable and supportable warfighting capabilities. The Mod EA Payloads (MEAP) project is a use case exemplar exercising the Algo & Apps and EW Dev Env processes to produce fieldable supportable advanced EA capabilities for applications in multiple crewed and uncrewed platforms. It will produce various form factor payloads for integration into Open Architecture hardware/ software platforms providing both offensive and defensive EA for host and other airborne entities in contested/congested environments. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                       Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System        PE 0207039F / Cognitive Electromagnetic Warfare Development & Demonstration (SDD) This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, & 0606398F. This program is in Budget Activity 5, System Development and Demonstration (SDD)as most of its elements have passed Milestone B, it's equivalent, or there is enough evidence that there is low risk in pursuing SDD type activities in pursuit of engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production." This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0303867F$$, $$AMBIT - Post-Auctioned SRF$$, $$rdte_af_ba5$$, $$aflcmc$$, 2026, 0, 19057000, 0, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0303867F"}$$::jsonb, NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, FALSE, 19453000, 0, 0, 0, 0, 0, 0, $$This program pays for relocation or sharing costs related to relocating from and/or sharing a frequency that has been auctioned off to the commercial sector, that was previously used by DoD. No FY27 funding is requested This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0401221F$$, $$KC-46A Tanker Squadrons$$, $$rdte_af_ba5$$, $$aflcmc_aa$$, 2026, 145434000, 78704000, 77804000, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0401221F"}$$::jsonb, $$Replacement of the legacy tanker fleet will take place in several stages. The initial tanker replacement increment of KC-46As will replace roughly a third of the current capability. Future programs will ultimately recapitalize the entire tanker fleet over a period of more than 30 years. The Air Force completed an Analysis of Alternatives (AoA) in Apr 2006 to determine the most appropriate strategy to recapitalize the aging fleet of aerial refueling aircraft. Based on this analysis, the Air Force concluded a strategy of full and open competition to select a commercial derivative replacement tanker aircraft would result in a best value tanker contract. To initiate the first phase of the tanker replacement, the KC-46A program released a final Request for Proposal (RFP) on 24 Feb 2010, and entered source selection on 9 Jul 2010. The KC-46A program held a Milestone B (MS B) Defense Acquisition Board (DAB) on 23 Feb 2011, received approval to enter Engineering and Manufacturing Development (EMD) from the Undersecretary of Defense (Acquisition, Technology and Logistics) (USD(AT&L)) on 24 Feb 2011, and awarded the KC-46A EMD contract to Boeing on 24 Feb 2011 to develop and procure 179 KC-46A aircraft. The program is procuring four RDT&E aircraft for integration and demonstration of capability which will ultimately be operationally fielded. During production and with the recent program of record increase, the program plans to procure 179 production aircraft through 13 lots (+ 4 EMD aircraft) for a total of 183 aircraft. The KC-46A program held a MS C DAB on 12 Aug 2016 and received approval to enter Low Rate Initial Production (LRIP). The program has awarded LRIP lots 1-11 with lot 11 put on contract 21 Nov 2024 bringing total number of aircraft to 154 on the production contract. The first DD250 was signed on 10 Jan 2019. The Air Force delivered the first KC-46A to McConnell Air Force Base on 25 Jan 2019. As of 18 Jun 2025, 94 aircraft have been delivered to the Air Force via DD250. Initial sustainment effort is provided via Interim Contractor Support (ICS) as the program is transitioning to organic sustainment. KC-46A funding also supports Training Systems, Support Equipment, Operational Site Activation, Depot Stand-Up, Alternate Mission Equipment (AME), Direct Mission Support, Program Support Costs (PSC) Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                              Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System       PE 0401221F / KC-46A Tanker Squadrons Development & Demonstration (SDD) activities, Other Government Costs (OGC), various studies and analyses, future tanker planning activities, long lead items, and potential Diminishing Manufacturing Sources (DMS) and obsolescence planning activities. In addition to its air refueling capability, the KC-46 is planned to be a key joint and coalition communications node. The KC-46A will provide the capability to fuel joint and coalition receivers via a boom or drogue system on every mission and will also augment the airlift fleet with cargo, passenger, and aeromedical evacuation capabilities. The KC-46A will operate in day, night, and adverse weather conditions to enable deployment, employment, sustainment, and redeployment of U.S. joint, allied, and coalition forces. The KC-46A will have communication, navigation, and surveillance equipment for world-wide operations; the capability to perform missions in chemical and biological environments; the ability to operate in up to medium threat environments with self-defense/protection (both active and passive) capabilities; and the necessary battle space awareness to mitigate survivability threats. Mobility Air Forces (MAF) Connectivity is a requirement for Line-of-Sight (LOS) and Beyond-Line-of-Sight (BLOS) connectivity capability on the KC-46A to provide the communications resiliency and bandwidth via integration of Multi-band, Multi-orbit SATCOM terminal and array installation to allow the selective movement between satellite constellations, resulting in over 20 Mbps required for the data rate pace needed for C2 in a near-peer fight. This will enable maximum MAF connectivity and real- time secure command and control for aircrew situational awareness. The Aircrew Training System (ATS) and Maintenance Training System (MTS) provide critical capabilities for KC-46A aircrew. The ATS contract will provide Aircrew Training Devices (ATDs), to include Weapon System Trainers (WSTs), Boom Operator Trainers (BOTs), Fuselage Trainers (FuTs), Part-Task Trainers (PTTs), and emerging technologies to meet validated Air Mobility Command (AMC) aircrew training requirements at each Main Operating Base (MOB) and the Formal Training Unit (FTU). The ATS contract will also support Distributed Mission Operations (DMO), provide aircrew instruction, develop courseware, provide logistics support, acquire a technical data package to support future competition efforts, and manage training device/courseware concurrency with the aircraft. Option year nine was put on Un- definitized Contract Action (UCA) 10 Oct 2023. Option year nine definitized in March 2024. Option 10 was awarded on 14 Aug 2024. The MTS focus is on designing, developing, testing, producing, and fielding an optimized training system for KC-46A maintainers by integrating various forms of training media and Maintenance Training Devices (MTDs) into a "blended" solution. This blended solution includes the appropriate mix of hardware and software, "high-fidelity" Augmented Hardware Training Devices (AHTDs), Part Task Trainers (PTTs), Interactive Multimedia Instruction (IMI), and emerging technologies to meet validated AMC maintenance training requirements. Tanker Production Extension initiates planning, risk reduction, Request for Proposal (RFP) Development, and other pre-production activities (including obsolescence mitigation) to acquire additional aircraft upon completion of on-going KC-46 production. This requirement supports performance of a full financial audit as required by U.S.C. Title 10, Subtitle A, Part I, Chapter 9A, Sec 240-D, Financial Improvement and Audit Remediation (FIAR) Plan. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System     PE 0401221F / KC-46A Tanker Squadrons Development & Demonstration (SDD) 0606398F. In FY 2024 $3.058 million was expended for civilian pay expenses in this program element, and in FY 2025 $3.823 million is forecast for civilian pay expenses in this program element. The FY 2026 request was reduced by $1.681 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, NULL, 334249000, 92265000, 14378000, NULL, NULL, 120, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 76296000, 130175000, 543788000, 543788000, 0, 543788000, 10000000, $$Replacement of the legacy tanker fleet will take place in several stages. The initial tanker replacement increment of KC-46As will replace roughly a third of the current capability. Future programs will ultimately recapitalize the entire tanker fleet over a period of more than 30 years. The Air Force completed an Analysis of Alternatives (AoA) in Apr 2006 to determine the most appropriate strategy to recapitalize the aging fleet of aerial refueling aircraft. Based on this analysis, the Air Force concluded a strategy of full and open competition to select a commercial derivative replacement tanker aircraft would result in a best value tanker contract. To initiate the first phase of the tanker replacement, the KC-46A program released a final Request for Proposal (RFP) on 24 Feb 2010, and entered source selection on 9 Jul 2010. The KC-46A program held a Milestone B (MS B) Defense Acquisition Board (DAB) on 23 Feb 2011, received approval to enter Engineering and Manufacturing Development (EMD) from the Undersecretary of War (Acquisition and Sustainment) (USD[A&S]) on 24 Feb 2011, and awarded the KC-46A EMD contract to Boeing on 24 Feb 2011 to develop and procure 179 KC-46A aircraft. The program procured four RDT&E aircraft for integration and demonstration of capability which will ultimately be operationally fielded. The KC-46A program held a MS C DAB on 12 Aug 2016 and received approval to enter Low Rate Initial Production (LRIP). With the recent program of record increase, the program plans to procure 184 production aircraft through 13 lots (+ 4 EMD aircraft) for a total of 188 aircraft. The program has awarded LRIP lots 1-12 with lot 12 put on contract 25 Nov 2025 bringing total number of aircraft to 169 on the production contract. The first DD250 was signed on 10 Jan 2019, and the Air Force delivered the first KC-46A to McConnell Air Force Base on 25 Jan 2019. As of 3 April 2026, 105 aircraft have been delivered to the Air Force via DD250. Initial sustainment effort is provided via Interim Contractor Support (ICS) as the program is transitioning to organic sustainment. KC-46A funding also supports Training Systems, Support Equipment, Operational Site Activation, Depot Stand-Up, Alternate Mission Equipment (AME), Direct Mission Support, Program Support Costs (PSC) activities, Other Government Costs (OGC), various studies and analyses, future tanker planning activities, long lead items, and potential Diminishing Manufacturing Sources (DMS) and obsolescence planning activities. In addition to its air refueling capability, the KC-46 is planned to be a key joint and coalition communications node. The KC-46A will provide the capability to fuel joint and coalition receivers via a boom or drogue system on every mission and will also augment the airlift fleet with cargo, passenger, and aeromedical evacuation capabilities. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                           Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System          PE 0401221F / KC-46A Tanker Squadrons Development & Demonstration (SDD) The KC-46A will operate in day, night, and adverse weather conditions to enable deployment, employment, sustainment, and redeployment of U.S. joint, allied, and coalition forces. The KC-46A will have communication, navigation, and surveillance equipment for world-wide operations; the capability to perform missions in chemical and biological environments; the ability to operate in up to medium threat environments with self-defense/protection (both active and passive) capabilities; and the necessary battle space awareness to mitigate survivability threats. Mobility Air Forces (MAF) Connectivity is a requirement for Line-of-Sight (LOS) and Beyond-Line-of-Sight (BLOS) connectivity capability on the KC-46A to provide the communications resiliency and bandwidth via integration of Multi-band, Multi-orbit SATCOM terminal and array installation to allow the selective movement between satellite constellations, resulting in higher Mbps required for the data rate pace needed for C2 in a near-peer fight. This will enable maximum MAF connectivity and real- time secure command and control for aircrew situational awareness. The Aircrew Training System (ATS) and Maintenance Training System (MTS) provide critical capabilities for KC-46A aircrew. The ATS contract will provide Aircrew Training Devices (ATDs), to include Weapon System Trainers (WSTs), Boom Operator Trainers (BOTs), Fuselage Trainers (FuTs), Part-Task Trainers (PTTs), and emerging technologies to meet validated Air Mobility Command (AMC) aircrew training requirements at each Main Operating Base (MOB) and the Formal Training Unit (FTU). The ATS contract will also support Distributed Mission Operations (DMO), provide aircrew instruction, develop courseware, provide logistics support, acquire a technical data package to support future competition efforts, and manage training device/courseware concurrency with the aircraft. Option year nine was put on Un- definitized Contract Action (UCA) on 10 Oct 2023 and definitized in March 2024. Option 10 was awarded on 14 Aug 2024. The MTS focus is on designing, developing, testing, producing, and fielding an optimized training system for KC-46A maintainers by integrating various forms of training media and Maintenance Training Devices (MTDs) into a "blended" solution. This blended solution includes the appropriate mix of hardware and software, "high-fidelity" Augmented Hardware Training Devices (AHTDs), Part Task Trainers (PTTs), Interactive Multimedia Instruction (IMI), and emerging technologies to meet validated AMC maintenance training requirements. Project 651120, Pegasus Capability Improvement efforts include KC-46A Block 1 Pegasus Advanced Communications Suite (PACS) program will satisfy Department of War (DoW), National Security Agency (NSA), Department of Transportation (DoT), and USAF mandates by upgrading legacy Tactical Data Link 16, Beyond Line- of-Sight (BLOS) Ultra High Frequency (UHF) Line- of-Sight (LOS) capabilities with next-generation Link 16 terminals and UHF secure, global, BLOS and anti-jam LOS satellite voice communications capabilities for the KC-46A weapon system. Project 650013, KC-46 Tanker Production Extension (PEx) efforts include but are not limited to planning, risk reduction, Request for Proposal (RFP) Development, and other pre-production activities (including obsolescence mitigation) to acquire additional KC-46A aircraft upon completion of current KC-46 production. Project 655271, KC-46 RDT&E efforts will provide the capability to fuel joint and coalition receivers via a boom or drogue system on every mission and will also augment the airlift fleet with cargo, passenger, and aeromedical evacuation capabilities. The KC-46A will operate in day, night, and adverse weather conditions to enable deployment, employment, sustainment, and redeployment of U.S. joint, allied, and coalition forces. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                           Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System         PE 0401221F / KC-46A Tanker Squadrons Development & Demonstration (SDD) This requirement supports performance of a full financial audit as required by U.S.C. Title 10, Subtitle A, Part I, Chapter 9A, Sec 240-D, Financial Improvement and Audit Remediation (FIAR) Plan. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605018F$$, $$AF Integrated Personnel and Pay System (AF-IPPS)$$, $$rdte_af_ba7$$, $$af_ng$$, 2026, 64050000, 63451000, 49739000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0605018F"}$$::jsonb, $$The Air Force Integrated Personnel and Pay System (AFIPPS) is a web-enabled, Enterprise Resource Planning (ERP) solution that integrates existing personnel and pay processes into one self-service system. AFIPPS supports how the Department of the Air Force (DAF) owns and operates the Human Resource Management domain and is a component of the AF/A1 digital transformation journey, currently underway. AFIPPS continues the transformation by providing an accurate and single authoritative source of personnel data to ensure timely delivery of pay, entitlements, allowances, and benefits to all Active Duty Air and Space Forces, Air National Guard (ANG), and Reserve (USAFR) components. AFIPPS represents the DAF's commitment to modernize business practices and provide enhanced support to service members and their families by integrating personnel and pay systems. AFIPPS will eliminate DAF reliance on the unsustainable Defense Finance and Accounting System (DFAS) and the Defense Joint Military Pay System (DJMS) for payroll processing and ensures improved auditability of service member pay. The AFIPPS program directly increases readiness for total force service members, human resources and financial management specialists, and DAF Commanders. AFIPPS will improve the DAF community's experience by allowing members to self-initiate pay/personnel actions, decreasing pay errors, and providing accurate personnel/pay data for leadership decision-making. AFIPPS modernizes the existing Military Personnel Data System (MilPDS) and adds pay and leave capability. In Jan 2021, the DAF leveraged a MilPDS self-service capability deployment to verify the baseline system had the infrastructure for the new pay and leave capability in place. The self-service capability allowed DAF Airmen and Guardians to initiate self-registration, validate member data and verify operational performance. AFIPPS revised the original deployment strategy from a single Go-Live deployment in January 2025 to a HR Deployment in second quarter fiscal year 2025 that will subsume MilPDS, a Limited Deployment to a low-risk population with no prior service in the fourth quarter fiscal year 2025 to continue HR activities with the inclusion of payroll capabilities with an additional Limited Deployment prior to Full Deployment (FD), and a FD to all DAF military personnel in second quarter fiscal year 2027 for continued HR activities with payroll capabilities. This requirement supports performance of a full financial audit as required by title 10 U.S.C Chapter 9A, Sec 240-D. Reduces civilian personnel full-time equivalents and funding in the amount of 0.196M to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0605018F / AF Integrated Personnel and Pay System (AF-IPPS) Operational Systems Development This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability; The use of such programs funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, 0605898F. In FY 2024 0.000M was expended for civilian pay expenses in this program element, and in FY 2025 0.388M is forecasted for civilian pay expenses in this program element. The FY 2026 request for AFIPPS includes 64,050 thousand of discretionary and 0 thousand of mandatory (reconciliation) for a total of 64,050 thousand. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 31777000, 27350000, 22535000, NULL, NULL, 154, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 48523000, 63172000, 31777000, 31777000, 0, 31777000, 23098000, $$The Air Force Integrated Personnel and Pay System (AFIPPS) is an Enterprise Resource Planning (ERP) program based on Oracle e-Business Suite (EBS), a commercial-off-the-shelf (COTS) solution, that contains both the Human Resources (HR) and Payroll modules. In alignment with a Department of War (DoW) directive to pursue a DoW-wide military pay solution, the Department of the Air Force (DAF) has halted development of AFIPPS. The Services have been instructed to align their Human Resource (HR) systems to the Defense Finance and Accounting Service's (DFAS) requirements once they are released. In Q2FY2026, the Program Executive Officer (PEO) was directed to terminate the Air Force Integrated Personnel and Pay System (AFIPPS) program and begin the orderly and expeditious shutdown of program activities while preserving the Military Personnel Data System (MilPDS) for capability support. The Office of the Under Secretary of War for Personnel & Readiness OUSW(P&R) instructed the Air Force to posture the legacy MilPDS system to support the Department of War (DoW) efforts to transform military pay. Post termination activities in FY2027, PE 0605018F, Project 676003, HRM Structural Development, efforts are planned to transfer to PE 1201212SF, project 670220, Datalake and UI/UX Development, in order to fund critical initiative activity to implement Personnel Management Act (PMA) Human Resource (HR) Information Technology (IT) Automation and develop a data layer within the existing Air Force Human Resources structure that can be utilized to meet current and future Space Force needs. These efforts will support the DoW requirement for updated HR systems in preparation for their DoW wide military pay initiative. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0605018F / AF Integrated Personnel and Pay System (AF-IPPS) Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605024F$$, $$Anti-Tamper Technology Executive Agency$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 62965000, 49311000, 65792000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0605024F"}$$::jsonb, $$The Anti-Tamper (AT) Technology Executive Agency budget funds activities related to the DoD Executive Agent for AT (ATEA) responsibilities required by DoD Directive 5200.47E, "Anti-Tamper (AT).” These responsibilities are unique to the DoD ATEA and the Air Force Component Office of Primary Responsibility (OPR) for AT. The DoD ATEA is responsible for developing and enforcing AT policy and guidance, assessing AT technologies (hardware and software), maintaining and developing new AT technology products and assessment capabilities, maintaining and maturing AT laboratory equipment and infrastructure, establishing and maintaining a library of AT technologies, providing security guidance and support mechanisms, providing outreach and education to the DoD AT community, providing intelligence support, and evaluating AT implementations across all DoD acquisition programs, foreign military sales (FMS), and direct commercial sales (DCS). The AF OPR for AT evaluates AT on applicable AF acquisition programs, FMS, and DCS as well as manages AF AT technology development. AT directly enables CPI resilience. AT protects critical program information (CPI), in U.S. weapon systems that are no longer under U.S. control (e.g., lost/left on the battlefield or sold to a foreign government) from hands-on, reverse engineering (RE) attacks. AT protections enable the U.S. to preserve its technological advantage and the combat capabilities of critical weapons systems while supporting the warfighters' mission requirements. Furthermore, AT adds longevity to DoD weapon systems by deterring or delaying RE attacks, and thus reducing an adversaries' ability to obtain the CPI and/or develop weapon countermeasures against the system. All DoD acquisition programs, FMS, and DCS with CPI require a validated AT Plan. The AT program includes resources required for subject matter experts (SMEs) to evaluate AT Plans and conduct AT validation on all DoD Weapon Systems. Additionally, the AT program provides resources for SMEs to perform AT assessments of both commercial off the shelf (COTS), contractor funded government only use (CFGO) and government off the shelf (GOTS) products. As the COTS, CFGO and GOTS technologies advance, the AT program includes the resources required to mature AT hardware/software assessment capabilities. These capabilities include the acquisition of specialized equipment, maintenance and/or renovations to support the integration of this equipment, and modifications to new and/or existing laboratory facilities to meet equipment and security requirements. The DoD ATEA coordinates technology development among the DoD Services/Agencies, National Laboratories, and Industry. These technology development efforts fund development of new AT technology, as well as enhance existing AT technology efforts to increase the technology readiness level (TRL) and facilitate transition for programs to implement. The AT technology development and enhancement efforts include: advanced AT sensor hardware, secure processing, crypto-analysis, tamper penalties, modifying and developing technology to address vulnerability and susceptibility of fielded parts, and other AT enablers. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0605024F / Anti-Tamper Technology Executive Agency Operational Systems Development The Air Force AT OPR conducts AT technology and product development to meet Air Force service needs to mature promising AT technologies to transition to Air Force weapons systems. Technology and product development priorities are given to those technologies/products that most benefit AF acquisition programs while aligning to the overall DoD ATEA technology and product development strategy. These activities are coordinated through the ATEA as a part of the ATEA technology and product development roadmap and to coordinate with Navy and Army AT technology development efforts. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, 0605898F. In FY24 $2.906M was expended for civilian pay expenses in this program element, and in FY25 $4.544M is forecast for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 172320000, 142894000, 117132000, NULL, NULL, 155, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 65434000, 62803000, 130610000, 130610000, 0, 130610000, 117632000, $$The Anti-Tamper (AT) Technology Executive Agency budget funds activities related to the DoD Executive Agent for AT (ATEA) responsibilities required by DoD Directive 5200.47E, "Anti-Tamper (AT).” These responsibilities are unique to the DoD ATEA and the Air Force Component Office of Primary Responsibility (OPR) for AT. The DoD ATEA is responsible for developing and enforcing AT policy and guidance, assessing AT technologies (hardware and software), maintaining and developing new AT technology products and assessment capabilities, maintaining and maturing AT laboratory equipment and infrastructure, establishing and maintaining a library of AT technologies, providing security guidance and support mechanisms, providing outreach and education to the DoD AT community, providing intelligence support, and evaluating AT implementations across all DoD acquisition programs, foreign military sales (FMS), and direct commercial sales (DCS). The AF OPR for AT evaluates AT on applicable AF acquisition programs, FMS, and DCS as well as manages AF AT technology development. AT directly enables critical program information (CPI) resilience. AT protects CPI, in Weapon Systems that are no longer under U.S. control (e.g., lost/left on the battlefield or sold to a foreign government) from hands-on, reverse engineering (RE) attacks. AT protections enable the U.S. to preserve its technological advantage and the combat capabilities of critical weapons systems while supporting the warfighters' mission requirements. Furthermore, AT adds longevity to DoD weapon systems by deterring or delaying RE attacks, and thus reducing an adversaries' ability to obtain the CPI and/or develop weapon countermeasures against the system. All DoD acquisition programs, FMS, and DCS with CPI require a validated AT Plan. The AT program includes resources required for subject matter experts (SMEs) to evaluate AT Plans and conduct AT validation on all DoD Weapon Systems. Additionally, the AT program provides resources for SMEs to perform AT assessments of both commercial off the shelf (COTS), contractor funded government only use (CFGO) and government off the shelf (GOTS) products. As the COTS, CFGO and GOTS technologies advance, the AT program includes the resources required to mature AT hardware/software assessment capabilities. These capabilities include the acquisition of specialized equipment, maintenance and/or renovations to support the integration of this equipment, and modifications to new and/or existing laboratory facilities to meet equipment and security requirements. The DoD ATEA coordinates technology development among the DoD Services/Agencies, National Laboratories, and Industry. These technology development efforts fund development of new AT technology, as well as enhance existing AT technology efforts to increase the technology readiness level (TRL) and facilitate transition for programs to implement. The AT technology development and enhancement efforts include but are not limited to: advanced AT sensor hardware, secure processing, crypto-analysis, tamper penalties, modifying and developing technology to address vulnerability and susceptibility of fielded parts, and other AT enablers. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0605024F / Anti-Tamper Technology Executive Agency Operational Systems Development The Air Force AT OPR conducts AT technology and product development to meet Air Force service needs to mature promising AT technologies to transition to Air Force weapons systems. Technology and product development priorities are given to those technologies/products that most benefit AF acquisition programs while aligning to the overall DoD ATEA technology and product development strategy. These activities are coordinated through the ATEA as a part of the ATEA technology and product development roadmap and to coordinate with Navy and Army AT technology development efforts. Program RDT&E funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Program RDT&E funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Program RDT&E funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, 0605898F. In FY24 2.909M was expended for civilian pay expenses in this program element, in FY25 3.858M was expended for civilian pay expenses in this program element, and in FY26 3.280M is forecast for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0101122F$$, $$Air-Launched Cruise Missile (ALCM)$$, $$rdte_af_ba7$$, $$afnwc_nd$$, 2026, 555000, 279000, 542000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0101122F"}$$::jsonb, $$The AGM-86B, Air Launched Cruise Missile (ALCM), is a subsonic, air-to-surface strategic nuclear missile, operational since 1982. Armed with a W-80 warhead, it is designed to evade air and ground-based defenses in order to strike targets at any location within any enemy's territory. The ALCM is designed for B-52H internal and external carriage. RDT&E funds support development of new test and evaluation procedures, software, and equipment. RDT&E funds also provide sustainment solutions for Line Replaceable Units (LRU) and technology insertion to ensure ALCM sustainability supports Air Force strategic nuclear deterrence and Global Strike mission requirements until the capability is replaced by the Long Range Stand Off (LRSO) cruise missile. Additionally, RDT&E funds support aging and surveillance analysis to pro-actively identify components which will degrade system reliability. The ALCM Test Plan Development and Evaluation program develops plans and procedures for testing nuclear systems, and implements those procedures as directed by the Chairman, Joint Chiefs of Staff (CJCS) and to satisfy the recurring requirements to test Chemical, Biological, Radiological, and Nuclear (CBRN) susceptibility. An extensive Service Life Extension Program (SLEP) is in place to address age related issues and to ensure reliability and sustainability until replaced by the Long Range Stand Off (LRSO) cruise missile. Technology insertion is anticipated to address serviceability of components at or near end of life. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $0.0M was expended for civilian pay expenses in this program element, and in FY 2025 $0.0M is forecast for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                     Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0101122F / Air-Launched Cruise Missile (ALCM) Operational Systems Development$$, NULL, 591000, 601000, 613000, NULL, NULL, 161, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 527000, 555000, 570000, 570000, 0, 570000, 625000, $$The AGM-86B, Air Launched Cruise Missile (ALCM), is a subsonic, air-to-surface strategic nuclear missile, operational since 1982. Armed with a W-80 warhead, it is designed to evade air and ground-based defenses in order to strike targets at any location within any enemy's territory. The ALCM is designed for B-52H internal and external carriage. RDT&E funds support development of new test and evaluation procedures, software, and equipment. RDT&E funds also provide sustainment solutions for Line Replaceable Units (LRU) and technology insertion to ensure ALCM sustainability supports Air Force strategic nuclear deterrence and Global Strike mission requirements until the capability is replaced by the Long Range Stand Off (LRSO) cruise missile. Additionally, RDT&E funds support aging and surveillance analysis to pro-actively identify components which will degrade system reliability. The ALCM Test Plan Development and Evaluation program develops plans and procedures for testing nuclear systems, and implements those procedures as directed by the Chairman, Joint Chiefs of Staff (CJCS) and to satisfy the recurring requirements to test Chemical, Biological, Radiological, and Nuclear (CBRN) susceptibility. An extensive Service Life Extension Program (SLEP) is in place to address age related issues and to ensure reliability and sustainability until replaced by the Long Range Stand Off (LRSO) cruise missile. Technology insertion is anticipated to address serviceability of components at or near end of life. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                     Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0101122F / Air-Launched Cruise Missile (ALCM) Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0101126F$$, $$B-1B Squadrons$$, $$rdte_af_ba7$$, $$afgsc$$, 2026, 116589000, 12291000, 17939000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0101126F"}$$::jsonb, $$The B-1B Lancer is a swing-wing, supersonic, long-range conventional bomber. It carries the largest payload of both guided and unguided weapons in the AF inventory. The multi-mission B-1B is the backbone of America's long-range conventional bomber force and can rapidly deliver massive quantities of precision (and non-precision) weapons against any adversary, anywhere in the world, at any time. The B-1B modernization projects alleviate aircraft obsolescence issues due to Diminishing Manufacturing Sources and Material Shortages (DMSMS) while at the same time providing improved capabilities to the B-1B weapon system that require significant hardware and software development and testing. RADIO-CRYPTO MODERNIZATION: The B-1B Radio Crypto program originates from JROCM 040-11, VACM Cease Key CED-026-11, UHF SATCOM (Ultra-High Frequency Satellite Communication) Decommission and Cease Key for Demand Assigned Multi Access (DAMA) Orderwire, HAVE QUICK II Cease use date, and DoD CIO Mobile User Objective System (MUOS) transition directive. If the requirements/directives are not met, B-1B will lose its secure line of sight, beyond line of sight, and anti-jam communication with ground and air forces. The initiative will replace the existing ARC-210 (Gen 3/4) with ARC-210 (Gen 6) next generation radios. Additionally, the program will provide MUOS Satellite Communication capability that supports the DoD Chief Information Officer (CIO) directive to move all DoD assets to MUOS constellation (70% by FY26). This effort will lay in Ethernet cable required by MUOS Data (J-REAP C), install MUOS ancillaries High Power Amplifier/Low Noise Amplifier (HPA/LNA) and additional software to execute MUOS capability on the aircraft. The B-1B Radio Crypto program received an updated Acquisition Decision Memorandum (ADM) in March 2023 approving an updated acquisition strategy that combined the program increments into one technical baseline and accelerated the schedule. A further updated ADM signed January 2024 accelerated the full production lot buys. Preliminary Design Review (PDR) was completed in Q4 FY23, Critical Design Review (CDR) approval was completed Q1 FY24, and Ground / Flight Testing is currently ongoing and is expected to conclude Q3 FY25. EXTERNAL HEAVY-STORES PYLON: This is a FY26 New Start. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                              Date: June 2025 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                   PE 0101126F / B-1B Squadrons Operational Systems Development External Heavy-Stores Pylon program expands on the accomplishments of the Hypersonic Integration Program, a Congressional Add, by providing increased carriage capacity of standoff munition on B-1B aircraft. Maximum carriage of existing standoff munitions on the B-1B provides near-term increased volume of fires from standoff ranges and serves to mitigate transition risk of the Air Force bomber fleet prior to the emergence of the B-21 as a combat bomber. - HYPERSONIC INTEGRATION: -- The FY22 and FY23 Conference Appropriations, detailed in the Congressional Conference Reports of Interest, added 20.0M (10.0M in FY22 and 10.0M in FY23) RTD&E appropriation for B-1B hypersonic weapon integration. This funding developed an external carry-enabled testbed facilitating rapid integration of priority hypersonic weapons in support of national security objectives, leading to potential investment opportunities for weapon programs. This program provides an opportunity to significantly reduce risk for an operational external carry capability on the B-1B if directed. The Hypersonic Integration Program successfully demonstrated the B-1's ability to execute a captive carry of a 5,000-pound class store and the release of a proven weapon shape from a Load Adaptable Modular (LAM) pylon. LONG-RANGE ANTI-SHIP MISSILE (LRASM) C-3 INTEGRATION: This is a FY26 New Start. The Long-Range Anti-Ship Missile (LRASM) C-3 is increment 1 of the Offensive Anti-Surface Warfare (OASuW) weapon development program. LRASM (AGM-158C-3) addresses an air-launch capability gap by providing flexible, long-range, advanced, anti-surface capability against high-threat maritime targets. The LRASM AGM-158C-3 variant will be a forward fit Engineering Change Proposal (ECP) to the AGM-158C, to enhance long range strike and existing OASuW capability. Beginning in FY26 through the outyears, the USAF will procure AGM-158C-3 missiles only until the missile inventory objective is met. The first USAF LRASM C-3 missile deliveries are targeted in Q4 CY27. LRASM is highly leveraged on the design of the Joint Air-to-Surface Standoff Missile-Extended Range (JASSM-ER, AGM-158B). LRASM and JASSM-ER have over 70% hardware commonality and share the same production assembly line. The USN is the lead service for the LRASM program, and the B-1 is a threshold platform. The USAF and USN jointly procure LRASMs via a USAF contract that benefits from cost savings when aligned with JASSM-ER procurements. B-1B HYBRID SATCOM: This is a FY26 New Start. Hybrid-SATCOM provides resilient pLEO in contested environments. INDOPACOM has an urgent requirement to interface and exchange classified data with B-1 in support of INDOPACOM activities in CY26. Securing alternate network connectivity and pathways will restore long-range integration capability and increase combat effectiveness through a modern, resilient, and reliable construct. Without this capability, there is a risk of isolating combat air forces from the Air Operations Center and the Combatant Commander. B-1B TEST JET MAINTENANCE (MX): Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                               Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                 PE 0101126F / B-1B Squadrons Operational Systems Development This is a FY26 New Start. The B-1B AFMC Test Jet maintenance project will provide funding for the test aircraft, manpower, and facilities at the Air Force Test Center located at Edwards Air Force Base (AFB), California. This will support the developmental testing and sustainment needs of the B-1B weapon system. It funds support for maintenance activities for test aircraft, which is performed at Tinker AFB, Oklahoma. Funds also support analysis, documentation, and related activities necessary to establish a program of record and support the B-1B weapon system. Additionally, other costs include Program Management Administration (PMA) and centralized support as well as initiatives for anticipated weapon system enhancements (to include efforts to improve weapon system operational capabilities, safety, supportability, maintainability, reliability, digital engineering and total cost of ownership). GAP AND INTEGRATION ANALYSIS: Program funds cover engineering/planning studies, related engineering efforts, and the auxiliary equipment needed for development projects that have not yet been fielded. Funds may be used to resolve emerging safety of flight and DMSMS issues, accommodate technology insertion, and fulfill FAA (or other) mandates necessary to ensure continued aircrew safety and mission effectiveness. Costs include PMA costs, total ownership cost, as well as initiatives for anticipated weapon system enhancements (to include efforts for improving weapon system operational capabilities, safety, supportability, maintainability, reliability, digital engineering and total cost of ownership). B-1B funding also supports innovation activities to include studies, analyses, requirements definition, digital engineering initiatives and quick-reaction capability prototypes/demonstrations to accelerate planning for technology transition, technology insertion, and future acquisition programs. Funds may be used to resolve emerging safety of flight and DMSMS accommodating technology insertion and fulfilling FAA or other mandates necessary to ensure continued aircrew safety and mission effectiveness. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 1.4 million was expended for civilian pay expenses in this program element, and in FY 2025 0.8 million is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                                 Date: June 2025 Appropriation/Budget Activity                                                        R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                    PE 0101126F / B-1B Squadrons Operational Systems Development$$, NULL, 330619000, 166428000, 69399000, NULL, NULL, 162, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 17316000, 150566000, 273552000, 273552000, 0, 273552000, 83712000, $$The B-1B Lancer is a swing-wing, supersonic, long-range conventional bomber. It carries the largest payload of both guided and unguided weapons in the Air Force inventory. The multi-mission B-1B is the backbone of America's long-range conventional bomber force and can rapidly deliver massive quantities of precision and non- precision weapons against any adversary, anywhere in the world, at any time. The B-1B modernization projects alleviate aircraft obsolescence issues due to Diminishing Manufacturing Sources and Material Shortages (DMSMS) while at the same time providing improved capabilities to the B-1B weapon system that require significant hardware and software development and testing. The FY 2027 President's Budget Request for the B-1B Lancer is a direct investment in the strategic imperatives outlined in the 2026 National Defense Strategy. Following the reversal of its planned retirement, the B-1B's role as the backbone of America's long-range conventional strike force is more critical than ever. As demonstrated recently in Operation Absolute Resolve and Operation Epic Fury, the B-1B is an indispensable tool for achieving national security objectives. This request provides the necessary funding to modernize the platform, ensuring its lethality and relevance through the mid 2030's by directly supporting the three pillars of the 2026 National Defense Strategy: Integrated Deterrence, Campaigning, and Building a Resilient and Lethal Joint Force. LONG-RANGE ANTI-SHIP MISSILE (LRASM) C-3 INTEGRATION: The Long-Range Anti-Ship Missile (LRASM) C-3 is increment 1 of the Offensive Anti-Surface Warfare (OASuW) weapon development program. LRASM Air to Ground Missile (AGM-158C-3) addresses an air-launch capability gap by providing flexible, long-range, advanced, anti-surface capability against high-threat maritime targets. The LRASM AGM-158C-3 variant will be a forward fit Engineering Change Proposal (ECP) to the AGM-158C to enhance long range strike and existing Offensive Anti- Surface Warfare (OASuW) capability. Beginning in FY 2026, the United States Air Force (USAF) will procure AGM-158C-3 missiles only until the missile inventory objective is met. The first USAF LRASM C-3 missile deliveries are targeted in Q1 FY 2028. LRASM is highly leveraged on the design of the Joint Air-to-Surface Standoff Missile-Extended Range (JASSM-ER, AGM-158B). LRASM and JASSM-ER have over 70% hardware commonality and share the same production assembly line. The United States Navy (USN) is the lead service for the LRASM program; the USAF and USN jointly procure LRASMs via a USAF contract that benefits from cost savings when aligned with JASSM-ER procurements. HYBRID SATELLITE COMMUNICATIONS (SATCOM): Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                            Date: April 2026 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                   PE 0101126F / B-1B Squadrons Operational Systems Development Air Force Global Strike Command requirement document 1067 23-075, signed Q3 FY 2024, amended Q4 FY 2025 identified a need for a critical upgrade to Bombers beyond-line-of-sight (BLOS) communication capabilities. The current legacy data network is outdated and unreliable, leading to connectivity issues that hinder effective command and control (C2) and isolate combat air forces from the Air Operations Center (AOC) and the Combatant Commander. This degradation of situational awareness and communication negatively impacts mission execution and the ability to process information at the tactical edge. To address this capability gap, a modern, resilient, and reliable BLOS networking capability is required. This will support the transition to a Joint Fires Network (JFN) and the broader Joint All-Domain Command and Control (JADC2) concept. The solution will provide robust cyber defense, optimize aircraft weapons and routing, and enable the transfer of J-series messages and digital files via Transmission Control Protocol / Internet Protocol (TCP/IP) interfaces. The system must be fully integrated with existing aircraft power, cooling, and data bus systems, while also considering open architecture for future technological advancements. HYBRID Satellite Communications (SATCOM) provides resilient communication using Proliferated Low Earth Orbit (pLEO) satellites, providing the B-1B communication in contested environments. Securing alternate network connectivity and pathways will ensure long-range re-targeting capability and increase combat effectiveness through a modern, resilient, and reliable construct. Without this capability, there is a risk of isolating combat air forces from the Air Operations Center and the Combatant Commander. Urgent operational requirement identified Q2 FY 2026 to field initial capability utilizing Tactical Airborne Communication Kit (TACKit) within one year. TACKit will provide network connectivity for Beyond Line of Sight (BLOS) secure data until the Hybrid SATCOM solution is fully fielded in 2030. EXTERNAL HEAVY-STORES PYLON: Air Force Global Strike Command requirement document 1067 23-85, signed Q2 FY 2024 identified a need to Maximize carriage of existing standoff munitions on the B-1B. The B-1B is the premiere standoff weapon employment platform, carrying more AGM-158B/C Joint Air-to-Surface Standoff Missile (JASSM) and Long-Range Anti- Ship Missile (LRASM) than any other Combat Air Force (CAF) Asset. The B-1B provides mass, maneuver, and economy of force to combatant commanders. AFGSC, as the force provider of long-range strike and lead-Major Command (MAJCOM) for standoff attack weapons, provided guidance to pursue external carry on the B-1B. During the stand-up of the future bomber force (B-21 emergence and B-52 upgrades), the B-1B will be the primary bomber available to combatant commanders. External Heavy-Stores Pylon program builds on the accomplishments of the Hypersonic Integration Program, a Congressional Add, by providing increased carriage capacity of external stores on the B-1B aircraft. Maximum carriage of external weapons on the B-1B provides near-term increased volume of fires and serves to mitigate transition risk of the Air Force bomber fleet prior to the emergence of the B-21 as a combat bomber. HYPERSONIC INTEGRATION: The FY 2022 and FY 2023 Conference Appropriations, detailed in the Congressional Conference Reports of Interest, added 20.0 million (10.0 million in FY 2022 and 10.0 million in FY 2023) Research Testing Development and Evaluation (RTD&E) appropriation for B-1B hypersonic weapon integration. This funding developed an external carry-enabled testbed facilitating rapid integration of priority hypersonic weapons in support of national security objectives, leading to potential investment opportunities for weapon programs. This program provides an opportunity to significantly reduce risk for an operational external carry capability on the B-1B if directed. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                           Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0101126F / B-1B Squadrons Operational Systems Development The Hypersonic Integration Program successfully demonstrated the B-1B's ability to execute a captive carry of a 5,000-pound class store and the release of a proven weapon shape from a Load Adaptable Modular (LAM) pylon. EXPANDED WEAPONS INTEGRATION: This funding supports the B-1B Expanded Weapons Integration (EWI) program, a Continuous Improvement Program (CIP) essential for maintaining the platform's combat relevance against sophisticated adversaries, providing B-1B the ability to counter pacing and future threats. The primary objective of EWI is to advance the B-1B's ability to deliver a diverse range of standoff munitions, a critical capability for executing missions in contested anti-access/area denial (A2/AD) environments. Current efforts focus on expanding the overall external carriage arsenal, including but not limited to: Guided Bomb Unit (GBU)-72, multiple Joint Air-to-Surface Standoff Missile (JASSM) and Long-Range Anti-Ship Missile (LRASM), Joint Direct Attack Munition (JDAM), Air Launched Rapid Response Weapon (ARRW) and Air to Ground Missile (AGM-183). New Start FY 2027. This program will integrate advanced weapon systems, including hypersonic missiles, by funding the requisite engineering, software development, and comprehensive testing to certify new weapon systems for safe carriage and employment. By expanding the B-1B's payload and mission flexibility, this program significantly enhances its contribution to the nation's long-range strike portfolio, ensures it remains a formidable asset capable of meeting future mission demands, and improves overall combat readiness. New Start FY 2027. RESILIENT POSITIONING, NAVIGATION AND TIMING (PNT) GLOBAL POSITIONING SYSTEM (GPS) MILITARY CODE (M-CODE) AND DIGITAL ANTENNA ELECTRONICS (DAE): Resilient PNT using GPS M-Code enables the B-1B to accomplish its missions in the face of increasingly adverse GPS environments and conditions. GPS anti-jam and anti-spoofing capability provided by GPS M-Code supported by DAE improves the B-1B's ability to operate in an adverse GPS threat environment. New Start FY 2027. RADIO-CRYPTO MODERNIZATION: The B-1B Radio Crypto program originates from Joint Requirements Oversight Council Memorandum (JROCM) 040-11, Very High Frequency and Ultra High Frequency Wideband Tactical Secure Voice System Cryptographic Equipment (VACM) Cease Key CED-026-11, Ultra High Frequency (UHF) Satellite Communication (SATCOM) Decommission and Cease Key for Demand Assigned Multi Access (DAMA) Orderwire, HAVE QUICK II Cease use date, and Department of War (DoW) Chief Information Officer (CIO) Mobile User Objective System (MUOS) transition directive. If the requirements/directives are not met, B-1B will lose its secure line of sight (SLOS), beyond line of sight (BLOS), and anti-jam communication with ground and air forces. The initiative will replace the existing Airborne Radio Communications system Army-Navy Airborne Electronic Device for Radio Communications Equipment (ARC-210) (Generation 3/4) with ARC-210 (Generation 6) next generation radios. Additionally, the program will provide MUOS Satellite Communication capability that supports the DoW Chief Information Officer (CIO) directive to move all DoW assets to MUOS constellation (70% by FY 2026). This effort will lay in Ethernet cable required by MUOS Data (Joint Range Extension Applications Protocol (JREAP) C), install MUOS ancillaries High Power Amplifier/Low Noise Amplifier (HPA/LNA) and additional software to execute MUOS capability on the aircraft. The B-1B Radio Crypto program received an updated Acquisition Decision Memorandum (ADM) in Q2 FY 2023 approving an updated acquisition strategy that combined the program Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                           Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0101126F / B-1B Squadrons Operational Systems Development increments into one technical baseline and accelerated the schedule. A further updated ADM signed Q2 2024 accelerated the full production lot buys. Preliminary Design Review (PDR) was completed in Q4 FY 2023, Critical Design Review (CDR) approval was completed Q1 FY 2024, Ground Testing was completed in Q2 FY 2025, Flight Testing was completed Q4 FY 2025. Program is on track to reach Milestone (C) Q3 FY 2026. No FY 2027 funding requested for this program. B-1B TEST JET MAINTENANCE (MX): The B-1B Air Force Materiel Command (AFMC) Test Jet maintenance project will provide funding for the test aircraft, manpower, and facilities at the Air Force Test Center located at Edwards Air Force Base (AFB), California. This will support the developmental testing and sustainment needs of the B-1B weapon system. It funds support for maintenance activities of test aircraft at Tinker AFB, Oklahoma. Funds also support analysis, documentation, and related activities necessary to establish a program of record and support the B-1B weapon system. Additionally, other costs include Program Management Administration (PMA) and centralized support as well as initiatives for anticipated weapon system enhancements (to include efforts to improve weapon system operational capabilities, safety, supportability, maintainability, reliability, digital engineering and total cost of ownership). GAP AND INTEGRATION ANALYSIS: Program funds cover engineering/planning studies, related engineering efforts, and the auxiliary equipment needed for development projects that have not yet been fielded. Funds may be used to resolve emerging safety of flight and Diminishing Manufacturing Sources and Material Shortages (DMSMS) accommodating technology insertion and fulfilling Federal Aviation Administration (FAA) or other mandates necessary to ensure continued aircrew safety and mission effectiveness. Costs include program management and administrative costs, total ownership cost, as well as initiatives for anticipated weapon system enhancements (to include efforts for improving weapon system operational capabilities, safety, supportability, maintainability, reliability, digital engineering and total cost of ownership). B-1B funding also supports innovation activities to include studies, analyses, requirements definition, digital engineering initiatives and quick-reaction capability prototypes/demonstrations to accelerate planning for technology transition, technology insertion, and future acquisition programs. This program element may include necessary direct cite authority civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0101126F / B-1B Squadrons Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0101127F$$, $$B-2 Squadrons$$, $$rdte_af_ba7$$, $$afnwc$$, 2026, 12519000, 83010000, 37862000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0101127F"}$$::jsonb, $$The B-2 Program Office's mission is to modernize and sustain the nation's only long-range penetrable strike bomber serving both the nuclear and conventional missions. The B-2 must remain ready, effective, and survivable every time the nation calls and cannot relax on modernization or sustainment efforts until its replacement is fully operational - a moving goal that continues to slip into the future. The Air Force must continue to modernize the B-2 to ensure its mission effectiveness exceeds the pacing threat, which continues to advance in technology and capabilities. The B-2 Program Office's portfolio includes projects that sustain weapon system effectiveness while seeking opportunities to lower life-cycle costs; incrementally improve subsystem capabilities across a range of sustainment and modernization efforts; combine existing technologies with innovative processes to solve supportability challenges; and integrate novel technologies to ensure our warfighters' can outpace the threat, while at the same time reducing integration risk for future platforms. The B-2 is continuing modernization efforts to improve its avionics, communications systems, cockpit displays, armament systems, low observable components, core training system components, aircraft supportability improvements, and support equipment development. The Air Force will also study, prototype, and demonstrate, multiple structural, avionics, and engine modifications, as well as advanced weapons capabilities, carriage systems integration, and communications, that could improve the performance of the aircraft and engines and reduce maintenance man-hours and the logistics footprint of the fleet. Focus of the studies, prototypes, and demonstrations will be on non-mission capable (maintenance) drivers, safety issues, and obsolescence issues through modernization of key components in the airframe, avionics, and engines resulting in improved aircraft availability of a high demand/low density fleet. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $0.0M was expended for civilian pay expenses in this program element, and in FY 2025 $0.0M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                  Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0101127F / B-2 Squadrons Operational Systems Development$$, NULL, 572048000, 667383000, 409514000, NULL, NULL, 163, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 44020000, 72351000, 418178000, 418178000, 0, 418178000, 212024000, $$The B-2 Program Office's mission is to modernize and sustain the nation's only long-range penetrable strike bomber serving both the nuclear and conventional missions. The B-2 must remain ready, effective, and survivable every time the nation calls and cannot relax on modernization or sustainment efforts. The Air Force must continue to modernize the B-2 to ensure its mission effectiveness exceeds the pacing threat, which continues to advance in technology and capabilities. The B-2 Program Office's portfolio includes projects that sustain weapon system effectiveness while seeking opportunities to lower life-cycle costs; incrementally improve subsystem capabilities across a range of sustainment and modernization efforts; combine existing technologies with innovative processes to solve supportability challenges; and integrate novel technologies to ensure our warfighters' can outpace the threat, while at the same time reducing integration risk for future platforms. The B-2 is continuing modernization efforts to improve its avionics, communications systems, cockpit displays, armament systems, low observable components, core training system components, aircraft supportability improvements, radar capabilities, testing, and support equipment development. The Air Force will also study, prototype and demonstrate, multiple structural, avionics, engine modifications, as well as advanced weapons capabilities, carriage systems integration and communications, that could improve the performance of the aircraft, engines, reduce maintenance man-hours and the logistics footprint of the fleet. Focus of the studies, prototypes, and demonstrations will be on non-mission capable (maintenance) drivers, safety issues, obsolescence issues through modernization of key components in the airframe, avionics, and engines resulting in improved aircraft availability of a high demand/low density fleet. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0101127F / B-2 Squadrons Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0101213F$$, $$Minuteman Squadrons$$, $$rdte_af_ba7$$, $$afgsc$$, 2026, 106032000, 41732000, 59320000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0101213F"}$$::jsonb, $$The Minuteman (MM) Ground and Communication Equipment program replaces obsolete/unsupportable ground-based weapon system equipment located at 45 Launch Control Centers (LCCs) and 450 Launch Facilities (LFs) necessary to continue Minuteman III (MM III) operations until replaced by Sentinel. Current efforts include development, qualification, integration, and testing of replacement equipment for the LGM-30G Fast Rising B-Plug Energy Storage System-Replacement (FRBP ESS- R). MM III Baseline Support program replaces or upgrades obsolete/unsupportable flight test unique equipment installed on the missile during flight test, used to test MM III systems on the ground, or located at test facilities to collect, process, and analyze test data. Flight test equipment supports test and evaluation of MM III capabilities and MM III Operational Test Launches (OTLs) to determine ICBM force readiness, reliability, and capability shortfalls. Efforts include development, qualification, integration, and testing of replacement equipment such as: LGM-30G Flight Test, Telemetry, and Termination System (FT3); LGM-30G Higher Authority Communication Test System (HACTS) 2.0; LGM-30G Stage 1 Battery Replacement (SOBR); LGM-30G Depot Reentry Support Equipment Replacement Program (DRSERP); Arm/Disarm Switch Replacement (ADSR); and Little Mountain Test Facility (LMTF). These programs will also implement processes, procedures, and data systems to mitigate the transition risk from MM III to Sentinel. As other similar equipment is identified for replacement, it will be added to this program. MM III Baseline Support also provides for other MM III unique government costs, studies of system performance, contract closeout costs, cost trades and acquisition planning activities, up to and including proposal preparation, to meet Capability Development Document requirements in an evolving threat landscape by leveraging advanced technologies. Efforts also include any minor needs required to prepare for full acquisition purposes. MM Support Equipment program designs, develops, and tests replacement of obsolete/non-serviceable weapon system support equipment. These programs will also implement processes, procedures, and data systems to mitigate the transition risk from MM III to Sentinel. Efforts include design, development, and testing of support equipment such as MM III Acquisition of Transportation and Handling (MATH), MM III Acquisition of Transportation and Handling Support Equipment (MATH SE) effort, and Missile Transporter Acquisition Program (MTAP). Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0101213F / Minuteman Squadrons Operational Systems Development MM Crypto Mods executes United States Strategic Command, Air Force Global Strike Command, and Air Force Safety Center requirements by implementing the KS-60 capabilities and addresses Nuclear Weapon System Safety Group Operational Safety Review requirements 98-2, 00-1, and 02-2. It also incorporates continuous signal lockout capabilities to prevent the widespread loss of status monitoring. These features will greatly increase security during code changes by reducing the frequency of open sites by 75 days annually and will reduce associated resource costs for 450 LFs and 45 LCCs. MM III also includes unforeseen costs arising for various reasons for programs from prior President's Budgets. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2024, 0.000M was expended for civilian pay expenses. 0.000M is forecasted in FY2025 for civilian pay expenses. The FY 2026 request was reduced by $1.864 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 126059000, 129266000, 112665000, NULL, NULL, 164, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 57201000, 69110000, 79313000, 79313000, 0, 79313000, 91819000, $$The Minuteman (MM) Ground and Communication Equipment program replaces obsolete/unsupportable ground-based weapon system equipment located at 45 Launch Control Centers (LCCs) and 450 Launch Facilities (LFs) necessary to continue Minuteman III (MM III) operations until replaced by Sentinel. Current efforts include development, qualification, integration, and testing of replacement equipment for the LGM-30G Fast Rising B-Plug Energy Storage System-Replacement (FRBP ESS- R). MM III Baseline Support program replaces or upgrades obsolete/unsupportable MM III equipment critical for continued system operations. Program includes flight test unique equipment installed on the missile during flight test, MM III ground test systems, test facilities used to collect, process, and analyze test data, and missile, launch facility, and control center parts and equipment. Flight test equipment supports test and evaluation of MM III capabilities and MM III Operational Test Launches (OTLs) to determine ICBM force readiness, reliability, and capability shortfalls. Efforts include development, qualification, integration, and testing of replacement equipment such as: LGM-30G Flight Test, Telemetry, and Termination System (FT3). MM III ground test systems and facilities include LGM-30G Higher Authority Communication Test System (HACTS) 2.0; Little Mountain Test Facility (LMTF); and Depot Reentry Support Equipment Replacement Program (DRSERP). Missile, launch facility, and control center parts and equipment include LGM-30G Stage 1 Battery Replacement (SOBR); Arm/Disarm Switch Replacement (ADSR); and LGM-30G Environmental Control System Replacement (ECS-R). These programs will also implement processes, procedures, and data systems to mitigate the transition risk from MM III to Sentinel. As other similar equipment is identified for replacement, it will be added to this program. MM III Baseline Support also provides for other MM III unique government costs, studies of system performance, contract closeout costs, cost trades and acquisition planning activities, up to and including proposal preparation, to meet Capability Development Document requirements in an evolving threat landscape by leveraging advanced technologies. Efforts also include any minor needs required to prepare for full acquisition purposes. MM Support Equipment program designs, develops, and tests replacement of obsolete/non-serviceable weapon system support equipment. These programs will also implement processes, procedures, and data systems to mitigate the transition risk from MM III to Sentinel. Efforts include design, development, and testing of support equipment such as MM III Acquisition of Transportation and Handling (MATH), MM III Acquisition of Transportation and Handling Support Equipment (MATH SE) effort, Missile Transporter Acquisition Program (MTAP) and Fourth Generation Transporter Erector (TE4). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0101213F / Minuteman Squadrons Operational Systems Development MM Crypto Mods executes United States Strategic Command, Air Force Global Strike Command, and Air Force Safety Center requirements by implementing the KS-60 capabilities in LGM-30G ICBM Cryptography Upgrade II (ICU II) of remote key/code change and irreversible transformation as mandated in the approved Capabilities Development Document (dated 4 Jan 05) and addresses Nuclear Weapon System Safety Group Operational Safety Review requirements 98-2, 00-1 and 02-2. It also incorporates Continuous Signal Lockout capabilities to prevent the widespread loss of status monitoring. These features will greatly increase security during code changes by reducing the frequency of open sites by 75 days annually and will reduce associated resource costs for 450 Launch Facilities (LFs) and 45 Launch Control Centers (LCCs). MM III also includes unforeseen costs arising for various reasons for programs from prior President's Budgets. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207461F$$, $$Flight Operations Systems$$, $$rdte_af_ba7$$, $$acc$$, 2027, 0, 0, 0, NULL, $${}$$::jsonb, NULL, NULL, 16997000, 16067000, 19233000, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 0, 15978000, 15978000, 0, 15978000, 19235000, $$Kessel Run Flight Operations (KR Flight Ops) continues to develop and support software-based capabilities that optimize operational unit resource allocation, maximize the value of each mission or sortie, optimize fuel usage, and increase total force readiness. This program is required to enhance the Department of the Air Forces's ability to deliver mission-ready forces to meet global wartime and peacetime operations. Funding supports the development and fielding of the Aerospace Enterprise Readiness System (ARES), which is a cloud-based, modernized, and resilient application to support current and upcoming mission sets by providing operators with a single solution for tracking and monitoring schedules, training currency, stan/eval information, and resource allocation optimization. ARES provides real-time visibility into aircraft status, enabling informed decisions on sortie generation and readiness. Future capabilities may include data analytics and AI-driven scheduling and integration with Collaborative Combat Aircraft (CCA) and autonomous air vehicles. The ARES application will allow for the deprecation of three legacy systems (Patriot Excalibur (PEX), Puckboard, and Graduate Training Integration Management System (G/TIMS)). These capabilities support Air Mobility Command (AMC), Air Combat Command (ACC), Air Force Global Strike Command (AFGSC), Air National Guard Bureau (ANGB), Air Force Special Operations Command (AFSOC), Air Force Reserve Command (AFRC), and United States Space Force (USSF) requirements. Efforts within this program align with and depend upon United State Air Force investment in Mission Planning Systems (PE 0208006F), Air Operations Center (PE 0207410F), All Domain Common Platform (0303248F), Command and Control Incident Management Emergency Response Application (C2IMERA) (0305836F), and Advanced Battle Management System (ABMS) (0604003F) to deliver the Theater Air Planning System of Systems (TAP-SoS) architecture for the DAF BATTLE NETWORK. This program's efforts directly provide the development, infrastructure, and support necessary for each of these programs and TAP-SoS interdependencies, which provides the capabilities necessary for deliberate planning, dynamic mission replanning, friendly order of battle management, and mission tasking and execution. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0207461F / Flight Operations Systems Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1203155SF$$, $$Space-Based Moving Target Indicator$$, $$rdte_sf_ba7$$, $$ssc$$, 2026, 1063384000, 0, 256000000, NULL, $${"source": "jbook_fy26", "fy27_mand_k": 803000, "fy27_mand_v157": "2026-05-08", "fy27_mand_source": "DoW_FY2027_Mandatory_Funding_Overview.txt Appendix B", "fy27_mand_section": "Space Superiority"}$$::jsonb, $$The space-based Ground Moving Target Indicator (GMTI) project provides resources to acquire the next generation radar satellite system, providing resilient day-night, all weather detection, tracking, and imagery of ground and maritime targets. The GMTI project focuses on improving target detection, custody, and sensor-to-shooter timelines necessary for dynamic targeting and long-range strike within highly contested and non-permissive environments. The Space Force is working collaboratively with the military services, Combatant Commands, and the Intelligence Community to deliver and field the GMTI project. Additional details can be provided under separate cover. Note: this effort was previously completed under 1203154SF. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 883710000, 519953000, 484288000, NULL, NULL, 57, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 256000000, 719384000, 253355000, 253355000, 803000000, 1056355000, 1032319000, $$The program office is developing the space-based Ground Moving Target Indicator (Project 671120) for Guardians across Global Mission Operations. As a result, the Service will improve battle management of all weapon systems and deter, neutralize, defeat and/or destroy counterspace threats and defend the homeland while providing principled public servants, space-minded warfighters, and bold and collaborative problem solvers. The space-based Ground Moving Target Indicator (GMTI) project provides resources to acquire the next generation radar satellite system, providing resilient day-night, all weather detection, tracking, and imagery of ground and maritime targets. The GMTI project focuses on improving target detection, custody, and sensor-to-shooter timelines necessary for dynamic targeting and long-range strike within highly contested and non-permissive environments. The Space Force is working collaboratively with the military services, Combatant Commands, and the Intelligence Community to deliver and field the GMTI project. The FY 2027 budget for Space-Based Moving Target Indicator includes $803,000 thousand of mandatory and $0 of discretionary for a total of 803,000 thousands for Airborne Moving Target Indicator requirements. The FY 2026 value for ground moving target indicator includes 135,000 thousand of mandatory (reconciliation) funds and 719,384 thousand of discretionary for a total of 854,384 thousand. Additional details are located in the classified exhibits. This program falls within the Combat Power mission area which provides the systems required to protect and defend space-based capabilities and ensure space superiority by enabling and executing combat operations in space. Space Force investment program interdependencies include: RDT&E Budget Line Items: Counterspace Systems (1206421SF); Space-Based Moving Target Indicator (1203155SF); Long Range Kill Chains (1203154SF); Space Control Technology (1206438SF); Space Superiority ISR (1203330SF) and elements of Procurement Budget Line Items: Space Mods (SPCMOD); Space Based Air Moving Target Indicator (AMTI00); Ground Moving Target Indicator (GMTI00); Counterspace Systems (CTRSPC) This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:             PE 1203155SF / Space-Based Moving Target Indicator Operational Systems Development$$, $$Budget J-Books/FY27/Remaining/DoW_FY2027_Mandatory_Funding_Overview.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1206617SF$$, $$Operational Test & Training Infrastructure$$, $$rdte_sf_ba4$$, $$ssc_sda$$, 2027, 0, 0, 0, NULL, $${}$$::jsonb, NULL, NULL, 272596000, 295157000, 307890000, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 0, 265215000, 265215000, 0, 265215000, 306746000, $$SYD 81 is developing, operating and sustaining Operational Test & Training Infrastructure (OTTI) (Project 64441) for Guardians to improve test and training across the following mission areas: Combat Power, Missile Warning & Tracking, Space Domain Awareness, Launch, Position Navigation and Timing, Satellite Communications, Weather, Science & Technology and Test & Evaluation. As a result, the Service will improve readiness and operational reach of existing force structure through the resilient Infrastructure, equipment, and personnel training. This program continues funding United States Space Force (USSF) OTTI as the service-level effort to test, train, and build combat credibility for National Security Space weapon systems and joint force space capabilities. OTTI is primarily a portfolio of systems being developed with intended delivery to the National Space Test and Training Complex (NSTTC) under the command of Space Training & Readiness Command (STARCOM). OTTI has 4 lines of effort (LOEs): the Physical/Live Test and Training Range LOE, the Digital Test & Training Range LOE, a Test & Training Infrastructure LOE that supports the first two LOEs, and a Space Force Operational Readiness LOE focused on operation and sustainment of delivered systems. These efforts encompass the acquisition, development, integration, and sustainment activities to test and evaluate the performance of Department of War (DoW) space systems; train space operators for combat operations in, from, and through space; and develop and validate the tactics, techniques and procedures to support combat operations. This program falls within the Science & Technology (S&T) and Test & Evaluation (T&E) mission area which provides for the validation of combat credibility for Combat Power space systems and the validation of Tactics, Techniques, and Procedures (TTPs) for space superiority. In addition, the program develops advanced training systems and networks to improve the readiness of all mission area combat units. Space Force investment program interdependencies include: RDT&E Budget Line Items: Defense Research Sciences (0601102SF); Major T&E Investments - Space (1206759SF); Small Business Innovation Research (1205502SF); Space Advanced Tech Dev / Demo (1206616SF); Space Innov Intg & Rapid Tech Dev (1203174SF); Space Rapid Capabilities Office (1206857SF); Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                            Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 4:        PE 1206617SF / Operational Test & Training Infrastructure Advanced Component Development & Prototypes (ACD&P) Space Science and Technology (1206310SF); Space Systems Prototype Transition (1206427SF); Space Technology (1206601SF); Space Test and Evaluation (1202051SF); Space Test Program (1206864SF); University Research Initiatives (0601103SF); and elements of Procurement Budget Line Item: General Information Tech - Space (GNRLIT). OTTI funding is used to develop and deliver realistic low, medium, and High-End Advanced Test, Training and Tactics Development (HEAT3) environments. The live, virtual, and constructive (LVC) capabilities consist of platforms, networks, models, simulations, tools, and associated physical and digital infrastructure across space, terrestrial, and virtual domains in support of all DoW space mission areas. Low to medium fidelity models and training environments include unit-level and distributed training systems that facilitate Guardian home-station mission combat training and distributed exercises. HEAT3 higher fidelity models are required for test, advanced training scenarios, and warfighting tactics development and validation. OTTI delivers enterprise capabilities and solutions to field combat-ready forces and ensure space domain superiority in an evolving threat environment. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0601104A$$, $$University and Industry Research Centers$$, $$rdte_army_ba1$$, $$afc$$, 2026, 69391000, 117872000, 113476000, NULL, $${"act": "01", "ba_raw": "6.1", "source": "r1_fy26", "service": "army", "page_num": 10, "original_pe": "0601104A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) fosters university and industry based research to provide a scientific foundation for enabling technologies for future force capabilities. Broadly, the work in this PE falls into the categories of Collaborative Technology Alliances / Collaborative Research Alliances (CTAs/CRAs), University Centers of Excellence (COE), University Affiliated Research Centers (UARCs), Army-sponsored educational outreach, and Army investments at international academic and industrial partners. The Army formed CTAs to leverage large investments by the commercial sector in basic research areas that are of great interest to the Army. CTAs are industry-led partnerships between industry, academia, and the Army Futures Command to incorporate the practicality of industry, the expansion of the boundaries of knowledge from universities, and Army scientists to shape, mature, and transition technology relevant to the Army mission. CRAs are academia-led partnerships, which leverage the cutting-edge innovation found in the academic environment. The COEs focus on expanding the frontiers of knowledge in research areas where the Army has enduring needs, and couples state-of-the-art research programs at academic institutions with broad-based graduate education programs to increase the supply of scientists and engineers in automotive and rotary wing technology. Also included are Army Educational Outreach Program (AEOP) and activities to stimulate interest in science, math, and technology among middle and high school students. This PE includes support for basic research at three Army UARCs, which have been created to exploit opportunities to advance new capabilities through a sustained long- term multidisciplinary effort. The Institute for Soldier Nanotechnologies focuses on Soldier protection by emphasizing revolutionary materials research for advanced Soldier protection and survivability. The Institute for Collaborative Biotechnologies focuses on enabling network centric-technologies, and broadening the Army's use of biotechnology for the development of bio-inspired materials, sensors, and information processing. The Institute for Creative Technologies is a partnership with academia and the entertainment and gaming industries to leverage innovative research and concepts for training and simulation. Examples of specific research of mutual interest to the entertainment industry and the Army are technologies for realistic immersion in synthetic environments, networked simulation, standards for interoperability, and tools for creating simulated environments. This PE also includes the Historically Black Colleges and Universities and Minority Institutions (HBCU/MI) Centers of Excellence that address critical research areas for Army Transformation. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 1: Basic           PE 0601104A / University and Industry Research Centers Research The FY 2026 request was reduced by $0.091 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.257 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 53631000, 54847000, 55571000, NULL, NULL, 3, $$RDTE - Vol 1 - Budget Activity 1.pdf$$, NULL, FALSE, 109728000, 72391000, 53598000, 53598000, NULL, 53598000, 59986000, $$This Program Element (PE) fosters university and industry based research to provide a scientific foundation for enabling technologies for future force capabilities. Broadly, the work in this PE falls into the categories of Collaborative Technology Alliances / Collaborative Research Alliances (CTAs/CRAs), University Centers of Excellence (COE), University Affiliated Research Centers (UARCs), Army-sponsored educational outreach, and Army investments at international academic and industrial partners. The Army formed CTAs to leverage large investments by the commercial sector in basic research areas that are of great interest to the Army. CTAs are industry-led partnerships between industry, academia, and the Army Futures Command to incorporate the practicality of industry, the expansion of the boundaries of knowledge from universities, and Army scientists to shape, mature, and transition technology relevant to the Army mission. CRAs are academia-led partnerships, which leverage the cutting-edge innovation found in the academic environment. The COEs focus on expanding the frontiers of knowledge in research areas where the Army has enduring needs, and couples state-of-the-art research programs at academic institutions with broad-based graduate education programs to increase the supply of scientists and engineers in automotive and rotary wing technology. Also included are Army Educational Outreach Program (AEOP) and activities to stimulate interest in science, math, and technology among middle and high school students. This PE includes support for basic research at three Army UARCs, which have been created to exploit opportunities to advance new capabilities through a sustained long- term multidisciplinary effort. The Institute for Soldier Nanotechnologies focuses on Soldier protection by emphasizing revolutionary materials research for advanced Soldier protection and survivability. The Institute for Collaborative Biotechnologies focuses on enabling network centric-technologies, and broadening the Army's use of biotechnology for the development of bio-inspired materials, sensors, and information processing. The Institute for Creative Technologies is a partnership with academia and the entertainment and gaming industries to leverage innovative research and concepts for training and simulation. Examples of specific research of mutual interest to the entertainment industry and the Army are technologies for realistic immersion in synthetic environments, networked simulation, standards for interoperability, and tools for creating simulated environments. This PE also includes the Historically Black Colleges and Universities and Minority Institutions (HBCU/MI) Centers of Excellence that address critical research areas for Army Transformation. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 1: Basic             PE 0601104A / University and Industry Research Centers Research$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 1.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1203940SF$$, $$Space Situation Awareness Operations$$, $$rdte_sf_ba7$$, $$ssc_sda$$, 2026, 182377000, 0, 115660000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$In FY 2026, Project 673942, Joint Commercial Operations (JCO) efforts were transferred from Project 673940, Space Data Fusion to increase transparency. In FY 2026, Project 673943, Space Domain Awareness Network (SDANet) efforts were transferred from Project 673940, Space Data Fusion to increase transparency. Space Domain Awareness (SDA) is one of four U.S. Space Force Enterprise Functions and is defined as the ability to detect, characterize, attribute, predict, and target activities in the space domain to inform decision making. SDA is comprised of the following Enterprise Activities: Reconnaissance, Surveillance, Conjunction Assessment, Collision on Launch Assessment, Breakups, and Rendezvous and Proximity Operations Support. As the foundation for space control, SDA encompasses surveillance of all space objects and activities; detailed surveillance of specific space assets; monitoring space environmental conditions; monitoring cooperative space assets; gathering indications and warning on adversary space operations; and conducting integrated command and control (C2), communications, processing, analysis, dissemination, and archiving activities. Space Situation Awareness Operations (SSAO, 1203940SF) fields, upgrades, operationalizes, operates, and maintains Space Force sensors and information/data integration capabilities within the SDA network while companion program element Space Situational Awareness Systems (1206425SF) develops new network sensors and associated information integration capabilities across the network. Activities funded in this program (1203940SF) focus on surveillance of objects in earth orbit and beyond to aid tasks including satellite tracking; space object identification; tracking and cataloging; satellite attack warning; notification of satellite flyovers to U.S. forces; space treaty monitoring; and technical intelligence gathering. As a whole, this program upgrades, modifies, modernizes, operationalizes, fields, operates, and maintains sensors and information integration capabilities for an integrated, end-to-end SDA architecture that provides critical national security space solutions on tactical operational timelines. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                            Date: June 2025 Appropriation/Budget Activity                                                         R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:                  PE 1203940SF / Space Situation Awareness Operations Operational Systems Development The Space Data Fusion (SDF) project (673940) includes the Global Sensor Watch (GSW) program, which develops and/or upgrades Space Domain Awareness (SDA) data collection and exploitation capabilities, including artificial intelligence/machine learning (AI/ML), as modernization and improvement efforts to operational SDA capability. GSW prototypes and provides initial operational capabilities enabling an integrated, end-to-end, SDA tip and cue capability that implements a resilient architecture providing overlapping, assured, and viable surveillance options for executing event response; SDA data processing at multiple classification levels; and automated, worldwide, cross-sensor tipping and cueing. The SCU Lighthouse project is a partnership effort with the Missile Defense Agency (MDA) for targeted sensor upgrades providing dynamic tasking integration and tactical data exposure to MDA systems focused on closure of specific near-earth SDA kill chains. The Space Domain Awareness Network (SDANet) project (673943) was declared a Middle Tier Acquisition (MTA) rapid fielding program of record in FY 2024. It is deploying a modern end-to-end data delivery capability via resilient, distributed mesh network capability for the Space Surveillance Network (SSN) and other associated sensor, Command and Control (C2) and data nodes. SDANet supports existing capabilities through improvements to end-to-end architecture and data delivery efficiency and resiliency to enable modern C2 and Al/ML initiatives. SDANet enables Sensor-to-Sensor, Sensor-to-C2, and Sensor-to-Unified Data Library (UDL) end-to-end data flows revolutionizing the traditional vertical Sensor-to-C2 data flows to incorporate the ability to send and receive data laterally enabling space domain operations. The Joint Commercial Operations (673942) effort supports the Joint Commercial Operations (JCO) cell. The JCO's mission is to provide persistent and rapid SDA coverage to maximize decision making space and reduce reaction time in support of Protect & Defend missions. Commercial SDA executes commercial data buys beyond protect and defend missions and supports existing capabilities through improvements to architecture and system efficiency, cybersecurity, migration to cloud computing, building on artificial intelligence and machine learning (Al/ML) initiatives, and expanding agile software development, delivery, and integration practices. The Unified Data Library project (UDL 673941) supports integration, exploitation, and delivery of data sources for command and control and battle management of space forces. UDL will continue to develop the library by on-boarding new data sets, directly connecting to SDA sensors, expanding data services, expanding defensive cyber operations capabilities, adding non-metric data to the SDA marketplace, continuing to expand local area network capability to share SSN data in a cyber-secure manner, allow optimized data flow for use of existing SDA capability and provide access to new commercial SDA innovations that will enable the broader SDA mission. The SF Weather Services Research project (67A018) funds the operational development necessary to acquire, sustain, and modernize Air Force Weather Service (AFWS) capabilities in support of the 2022 National Defense Strategy. AFWS provides timely, accurate, resilient, and relevant environmental information to enable global battlespace situational awareness for Air Force (AF), Army, Special Operations Forces (SOF), Space Force (USSF), combatant commands, the Intelligence Community (IC), and other government agencies. AFWS provides climate impacts and assessments, as well as space and terrestrial weather sensing, forecasting, and weather analytic capabilities, at home station and deployed, in order to deliver critical environmental intelligence in support of decision makers to gain the asymmetric advantage during the full spectrum of air and space combat operations. The FY 2026 cost of the Middle Tier of Acquisition is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify Future Years Defense Program funding in a future budget submission. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:          PE 1203940SF / Space Situation Awareness Operations Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 227570000, 219699000, 227521000, NULL, NULL, 67, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 111855000, 179365000, 294902000, 294902000, 0, 294902000, 233889000, $$Space Domain Awareness (SDA) is one of four U.S. Space Force Enterprise Functions and is defined as the ability to detect, characterize, attribute, predict, and target activities in the space domain to inform decision making. SDA is comprised of the following Enterprise Activities: Reconnaissance, Surveillance, Conjunction Assessment, Collision on Launch Assessment, Breakups, and Rendezvous and Proximity Operations Support. As the foundation for space control, SDA encompasses surveillance of all space objects and activities; detailed surveillance of specific space assets; monitoring space environmental conditions; monitoring cooperative space assets; gathering indications and warning on adversary space operations; and conducting integrated command and control (C2), communications, processing, analysis, dissemination, and archiving activities. Space Situation Awareness Operations (SSAO, 1203940SF) fields, upgrades, operationalizes, operates, and maintains Space Force sensors and information/data integration capabilities within the SDA network while companion program element Space Situational Awareness Systems (1206425SF) develops new network sensors and associated information integration capabilities across the network. Activities funded in this program (1203940SF) focus on surveillance of objects in earth orbit and beyond to aid tasks including satellite tracking; space object identification; tracking and cataloging; satellite attack warning; notification of satellite flyovers to U.S. forces; space treaty monitoring; and technical intelligence gathering. As a whole, this program upgrades, modifies, modernizes, operationalizes, fields, operates, and maintains sensors and information integration capabilities for an integrated, end-to-end SDA architecture that provides critical national security space solutions on tactical operational timelines. The Space Data Fusion (SDF) project (673940) includes the Global Sensor Watch (GSW) program, which develops and/or upgrades SDA data collection and exploitation capabilities, including artificial intelligence/machine learning (AI/ML), as modernization and improvement efforts to operational SDA capability. GSW prototypes and provides initial operational capabilities enabling an integrated, end-to-end, SDA tip and cue capability that implements a resilient architecture providing overlapping, assured, and viable surveillance options for executing event response; SDA data processing at multiple classification levels; and automated, worldwide, Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                             Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:               PE 1203940SF / Space Situation Awareness Operations Operational Systems Development cross-sensor tipping and cueing. Battlespace Intelligence integrates with this capability to provide enhanced autonomous and semi-autonomous collection and assessment capabilities to rapidly deliver decision-quality information to the warfighter within operational timelines. The SCU Lighthouse project is a partnership effort with the Missile Defense Agency (MDA) for targeted sensor upgrades providing dynamic tasking integration and tactical data exposure to MDA systems focused on closure of specific near-earth SDA kill chains. The Space Domain Awareness Network (SDANet) project (673943) was declared a Middle Tier Acquisition (MTA) rapid fielding program of record in FY 2024. It is deploying a modern end-to-end data delivery capability via resilient, distributed mesh network capability for the Space Surveillance Network (SSN) and other associated sensor, Command and Control (C2) and data nodes. SDANet supports existing capabilities through improvements to end-to-end architecture and data delivery efficiency and resiliency to enable modern C2 and Al/ML initiatives. SDANet enables Sensor-to-Sensor, Sensor-to-C2, and Sensor-to-Unified Data Library (UDL) end-to-end data flows revolutionizing the traditional vertical Sensor-to-C2 data flows to incorporate the ability to send and receive data laterally enabling space domain operations. Through a Mission Data Integration (MDI) initiative, SDANet seeks to expand message format capabilities to enhance functionality and provide sensor-agnostic data flows to improve Space Domain Awareness by expanding the available sensor population beyond the existing government-owned SSN. Joint Commercial Operations (JCO) project (673942) rapidly contributes across the full Find, Fix, Track, Target, Engage, and Assess (F2T2EA) kill chain by delivering near-persistent, low-latency commercial sensing, data fusion, and analysis at operational speed. Through a proliferated network of commercial optical, radar, and passive RF sensors, the JCO enables rapid detection, identification, and custody of targets across Orbital Warfare and Electronic Warfare mission sets. JCO-generated state vectors, covariances, and pattern-of-life analysis directly support targeting decisions and engagement planning while significantly compressing decision timelines compared to legacy architectures. During engagement and assessment, JCO capabilities provide combat identification support, maneuver and behavior change detection, and battle damage assessment through optical, radar, and RF monitoring. The Commercial Integration Cell (CIC) is not a new start as it was previously funded in appropriation 3620, RDT&E, Space Force, PE 1206445S, Commercial SATCOM (COMSATCOM) Integration and consolidated within the commercial operations lines under JCO. The Commercial Integration Cell (CIC) project (673942) integrates prominent US industry partners within the Combined Space Operations Center (CSpOC). It focuses on capabilities & TS/SCI threat sharing, day-to-day operations & crisis action planning from competition through conflict, responsive communication & information sharing - increasing transparency and shared understanding & unity of effort. CIC is key in ensuring mission impact mitigation; thereby, addressing friction within the geopolitical landscape by maintaining close relationships with partners. CIC improves information sharing and collaboration in the operational domain, between entities providing space related services to the US Government and ultimately reduce risk to Combatant Command missions. The SDF, SDANet, and JCO projects fall within the Space Domain Awareness (SDA) mission area which provides the space-based and ground-based architecture required to detect, track, catalogue, and identify objects and activities in the space domain. As the foundation for space control, SDA encompasses surveillance of all space objects and activities; detailed surveillance of specific space assets; monitoring space environmental conditions; monitoring cooperative space assets; gathering indications and warning on adversary space operations; and conducting integrated command, control, communications, processing, analysis, dissemination, and archiving activities. Space Force investment program interdependencies include: RDT&E Budget Line Items: Space Domain Awareness/Planning/Tasking SW Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                            Date: April 2026 Appropriation/Budget Activity                                            R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:     PE 1203940SF / Space Situation Awareness Operations Operational Systems Development (1208248SF); Automate Sat C2 (1207440SF); Space Situational Awareness Systems (1206425SF); and elements of Procurement Budget Line Item: Space Mods (SPCMOD). The USSF is executing the SDF, SDANet, and JCO projects for Guardians across warfighting, operational commands, and combat support units. As a result, the Service will deliver SDA capabilities and deter, neutralize, defeat, and/or destroy counterspace threats and defend the homeland. The Unified Data Library project (UDL 673941) supports integration, exploitation, and delivery of data sources for command and control and battle management of space forces. UDL will continue to develop the library by on-boarding new data sets, directly connecting to SDA sensors, expanding data services, expanding defensive cyber operations capabilities, adding non-metric data to the SDA marketplace, continuing to expand local area network capability to share SSN data in a cyber-secure manner, allowing optimized data flow for use of existing SDA capability and providing access to new commercial SDA innovations that will enable the broader SDA mission. The SF Weather Services Research project (67A018) funds the operational development necessary to acquire, sustain, and modernize Air Force Weather Service (AFWS) capabilities in support of the 2022 National Defense Strategy. AFWS provides timely, accurate, resilient, and relevant environmental information to enable global battlespace situational awareness for Air Force (AF), Army, Special Operations Forces (SOF), Space Force (USSF), combatant commands, the Intelligence Community (IC), and other government agencies. AFWS provides climate impacts and assessments, as well as space and terrestrial weather sensing, forecasting, and weather analytic capabilities, at home station and deployed, in order to deliver critical environmental intelligence in support of decision makers to gain the asymmetric advantage during the full spectrum of air and space combat operations. The SF Weather Services Research project falls within the Weather mission area which provides mission-critical environmental intelligence to support global military operations and delivers essential meteorological and oceanographic data to joint forces across all domains and detects space-based environmental threats to protect vital U.S. and allied space assets. Space Force investment program interdependencies include: RDT&E Budget Line Items: EO/IR Weather Systems (1203710SF); Space Force Weather Services Research (0604002SF); Weather Satellite Follow-on (1206422SF); elements of Space Situation Awareness Operations (1203940SF); elements of Space Control Technology (1206438SF); and elements of Procurement Budget Line Item: Space Mods (SPCMOD) The FY 2026 spend plan amount for RDT&E includes 179,365 thousand of discretionary and 31,100 thousand of mandatory (reconciliation) for a total of 210,465 thousand. In FY26, a sum total of 3.446M was erroneously programmed between the five projects in this program element. This includes Congressional marks of -5.353M for "Space Data Fusion previously funded” and -5.622M for "Space Domain Awareness mesh network insufficient justification” as well as Congressional adds for 3.0M "AI satellite health monitoring” and 7.50M for "Collaborative sensor network.” In the year of execution, funding will be realigned internally to properly represent the Congressional marks, adds and SBIR/STTR reductions in their correct projects. Project 673940, Space Data Fusion will be increased by 4.095M to total 57.162M; project 673941, Unified Data Library will be decreased by 0.703M to total 41.533M; Project 673942, JCO will be decreased by 0.438M to total 33.250M; and Project 67A018, Space Based Environmental Monitoring will be decreased by 0.052M to total 2.992M. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:           PE 1203940SF / Space Situation Awareness Operations Operational Systems Development This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program falls within the Space Domain Awareness (SDA) mission area which provides the space-based and ground-based architecture required to detect, track, catalogue, and identify objects and activities in the space domain. As the foundation for space control, SDA encompasses surveillance of all space objects and activities; detailed surveillance of specific space assets; monitoring space environmental conditions; monitoring cooperative space assets; gathering indications and warning on adversary space operations; and conducting integrated command, control, communications, processing, analysis, dissemination, and archiving activities. Program interdependencies include: SC&C Software Pilot Program (1208248SF); Space Defense Interface Network (1203904SF); Space Situational Awareness Operations (1203940SF); Space Situational Awareness Systems (1206425SF)” This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1206423SF$$, $$Global Positioning System III - Operational Control Segment$$, $$rdte_sf_ba7$$, $$ssc_milcom$$, 2026, 190484000, 1007896000, 272224000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$The Global Positioning System (GPS) is a space based Positioning, Navigation and Timing (PNT) distribution system which operates through all weather. GPS supports both civil and military users in air, space, sea and land operations. GPS is a satellite-based radio navigation system that serves military and civil users worldwide. GPS users process satellite signals to determine accurate position, velocity and time. GPS must comply with Title 10 United States Code (USC) Sec 2281 which requires that the Secretary of Defense (SECDEF) ensures the continued sustainment and operation of GPS for military and civilian purposes, and 51 USC Sec 50112, which requires that GPS complies with certain standards and facilitates international cooperation. GPS also includes the Nuclear Detonation (NUDET) Detection System (NDS). The Government is responsible for the integration of the GPS Segments such that they provide worldwide GPS capability to support the warfighter and over four billion national security, civil, Allied, and commercial GPS users. Program Element (PE) 1206423SF funds Research, Development, Test and Evaluation (RDT&E) for the Next Generation Operational Control System (OCX), which includes OCX Blocks 0, 1, and 2, and the upgrade to OCX called OCX Block 3F (OCX 3F), which incorporates Regional Military Protection (RMP) and command and control functionality for GPS III Follow-on (GPS IIIF) satellites. OCX acquisition was established to 1) provide command and control of legacy and GPS III satellites, 2) incorporate situational awareness to support Navigation Warfare (NAVWAR) and signal monitoring, 3) enable mission capability upgrades to support a warfighter effects-based approach to operations, and 4) integrate Department of Defense (DoD) information assurance and cybersecurity controls and capabilities. OCX 3F will upgrade OCX to provide RMP, a high-powered military signal which strengthens U.S. and allied forces' GPS resiliency in contested on tested environments to mitigate future jamming threats. OCX 3F also provides the ability to rapidly reconfigure GPS IIIF satellites to create time-critical warfighter effects. OCX and OCX 3F funds support efforts such as engineering studies and analyses, architectural engineering studies, trade studies, technology needs forecasting, modernization initiatives, systems engineering, system development, resolving obsolescence issues, test and evaluation efforts, pre-operational support activities, and interim contractor support. These activities support upgrades and product improvements for military and civil applications necessary to enable efforts to protect the United States Military and Allies' use of GPS. Additionally, funds ensure OCX and OCX Block 3F efforts meet Joint Requirements Oversight Council (JROC) approved required capabilities. OCX Block 1 and 2 primary development concludes at system acceptance executed via DoD Form DD 250 (planned for 3rd Quarter FY 2025). Pre-Operational Support (pre-ops acceptance) and Interim Contractor Support (ICS) (post-ops acceptance) is the final contract phase that completes development, achieves the program's final Acquisition Program Baseline (APB) milestone Ready to Transition to Operations (RTO), supports Operational Acceptance (OA), and transitions OCX to long-term Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:             PE 1206423SF / Global Positioning System III - Operational Control Segment Operational Systems Development sustainment. Specifically, Interim Contract Support (ICS) provides contractor support services to sustain and provide capability insertions, maintain system performance requirements, and participate in government led events such as maintenance, integrated supply support, security, and launch activities. Research, Development, Test, and Evaluation (RDT&E) funded government activities include Development Test and Evaluation (DT&E), GPS Constellation Transfer (CTX), Operational Test and Evaluation (OT&E), and OA. Upon completion of those activities, OCX will prepare for, and transition to O&M funded Contractor Logistics Support (CLS). In FY 2024, the contractor conducted ICS proposal activities and the definitized contract was awarded in May 2025. OCX 3F, which achieved Milestone B May 2022, is required to launch and operationally command and control GPS IIIF space vehicles. OCX 3F will upgrade OCX with new capabilities to synchronize with GPS IIIF Space Segment and Military GPS User Equipment (MGUE) Increment 2 capabilities. This includes master control station development, GPS system simulator modification, launch and mission planning development, training simulators, integrated logistics support products, test resources, systems engineering required to meet the Government's obligations to the international, military and civil communities, and system requirements verification. OCX 3F will maintain backward compatibility to support the legacy constellation develop solutions necessary to command, control and monitor GPS IIIF, to include integration of RMP (Regional Military Protection) high power regional M-code signals, rapid warfighter effects and support to GPS auxiliary payloads. This PE may include necessary civilian pay expenses required to manage, execute, and deliver OCX and OCX 3F weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in PEs 1206392SF and 1206398SF. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 73675000, 29606000, 16927000, NULL, NULL, 68, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 263380000, 260168000, 332313000, 332313000, 0, 332313000, 7030000, $$Mission Delta 31 is developing the Next Generation Operational Control System (OCX) and OCX 3F (Project 67A021, 67A023) for Guardians across Position, Navigation, and Timing. As a result, the Service will improve readiness and operational reach of existing force structure. Program Element (PE) 1206423SF funds Research, Development, Test and Evaluation (RDT&E) for the Next Generation Operational Control System (OCX), which includes OCX Blocks 0, 1, and 2, and the upgrade to OCX called OCX Block 3F (OCX 3F), which incorporates Regional Military Protection (RMP) and command and control functionality for GPS III Follow-on (GPS IIIF) satellites. OCX acquisition was established to 1) provide command and control of legacy and GPS III satellites, 2) incorporate situational awareness to support Navigation Warfare (NAVWAR) and signal monitoring, 3) enable mission capability upgrades to support a warfighter effects-based approach to operations, and 4) integrate Department of War (DoW) information assurance and cybersecurity controls and capabilities. OCX 3F will upgrade OCX to provide RMP, a high-powered military signal which strengthens U.S. and allied forces' GPS resiliency in contested on tested environments to mitigate future jamming threats. OCX 3F also provides the ability to rapidly reconfigure GPS IIIF satellites to create time-critical warfighter effects. OCX and OCX 3F funds support efforts such as engineering studies and analyses, architectural engineering studies, trade studies, technology needs forecasting, modernization initiatives, systems engineering, system development, resolving obsolescence issues, test and evaluation efforts, pre-operational support activities, and interim contractor support. These activities support upgrades and product improvements for military and civil applications necessary to enable efforts to protect the United States Military and Allies' use of GPS. Additionally, funds ensure OCX and OCX Block 3F efforts meet Joint Requirements Oversight Council (JROC) approved required capabilities. Develop upgrades to modernize the current operational Architecture Evolution Plan (AEP) ground control segment system to deliver OCX Capability Development Document (CDD) requirements. Upgrades include GPS IIIF Launch and GPS IIIF Command and Control (C2). Additional upgrades to system interface tools are planned to support development and fielding of Civil Navigation (CNAV) signal monitoring to meet CDD requirements and other projects to ensure uninterrupted monitoring for all Signals in Space. Other modernization projects include changes to the hardware or software of the operational baseline by removing or adding a capability or function. OCX 3F, which achieved Milestone B May 2022, is required to launch and operationally command and control GPS IIIF space vehicles. OCX 3F will deliver with new capabilities to synchronize with GPS IIIF Space Segment and Military GPS User Equipment (MGUE) Increment 2 capabilities. This includes master control station development, GPS system simulator modification, launch and mission planning development, training simulators, integrated logistics support products, test resources, Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:             PE 1206423SF / Global Positioning System III - Operational Control Segment Operational Systems Development systems engineering required to meet the Government's obligations to the international, military and civil communities, and system requirements verification. OCX 3F will maintain backward compatibility to support the legacy constellation develop solutions necessary to command, control and monitor GPS IIIF, to include integration of RMP (Regional Military Protection) high power regional M-code signals, rapid warfighter effects and support to GPS auxiliary payloads. This program falls within the Positioning, Navigation, and Timing (PNT) mission area which provides the space and dedicated ground architecture and associated user equipment required to provide PNT services to civil and military users. Program interdependencies include: GPS III - Operational (1206423SF); GPS III Follow-on (1203269SF); GPS III Space Segment (1203265SF); GPS Ops Control Segment - Next (1203365SF); NAVSTAR GPS (Space & Control Seg) (1203165SF); NAVSTAR GPS (User Equipment) (1203164SF) This PE may include necessary civilian pay expenses required to manage, execute, and deliver OCX and OCX 3F weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in PEs 1206392SF and 1206398SF. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1206772SF$$, $$Rapid Resilient Command and Control (R2C2)$$, $$rdte_sf_ba7$$, $$sprco$$, 2026, 106220000, 0, 0, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$The Assistant Secretary of the Air Force for Space Acquisition and Integration directed the formation of a Combined Program Office (CPO) by merging Enterprise Ground Services (EGS) from Space Systems Command (SSC) and Ground Command, Control, and Communications (GC3) from the Space Rapid Capabilities Office (Space RCO). The CPO is called the Rapid Resilient Command and Control (R2C2) CPO and utilizes the Space RCO acquisition authorities under the Space RCO Program Executive Officer to execute funding in the EGS and GC3 program elements to develop an extensible, scalable, modular ground segment solution capable of supporting protect and defend missions of the United States Space Force. Combined EGS and GC3 funding will be used wholly and directly to support CPO activities. R2C2 will continue development and integration of the satellite operations ground segment solution (SatOps) to support the protect and defend mission set, including, but not limited to, capabilities and services needed to perform mission control. In FY 2026, Program Element (PE) 1206770SF, Enterprise Ground Services (EGS), efforts transferred to PE 1206772SF, Rapid Resilient Command and Control (R2C2), to consolidate functions for efficiency and improve transparency. There was a one-time technical adjustment in FY 2025 approved by Congress that moved EGS funding from PE 1206770SF to PE 1206857SF, Space Rapid Capabilities Office, which improved funding execution in FY 2025. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:          PE 1206772SF / Rapid Resilient Command and Control (R2C2) Operational Systems Development$$, NULL, 114134000, 116741000, 118937000, NULL, NULL, 73, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 0, 118034000, 109190000, 109190000, 0, 109190000, 121315000, $$The Space Rapid Capabilities Office (Space RCO) Rapid Resilient Command and Control (R2C2) Combined Program Office (CPO) is developing and demonstrating SatOps command and control (C2) services and infrastructure for Guardians across the space enterprise. As a result, the Service will improve and prepare infrastructure, improve battle management of weapon systems, and be able to deter, neutralize, defeat and/or destroy counterspace threats and defend the homeland. This program falls within the Multi-Mission Support mission area which provides the systems and efforts that evenly contribute to multiple mission areas across the space enterprise. Space Force Investment program interdependencies include: RDT&E Budget Line Items: Defensive Cyber Operations - Space (1203040SF); Rapid Resilient Command and Control (1206772SF); Satellite Control Network (1203110SF); Space and Missile Test and Evaluation (1203173SF; Space Force IT, Data Analytics, Digital (1203010SF); and elements of Procurement Budget Line Items: AF Satellite Comm System (AFSCOM); Spaceborne Equip (Comsec) (MC0MSE); Spares and Repair Parts (SSPARE); and Space Digital Integrated Network (SDN000). The Assistant Secretary of the Air Force for Space Acquisition and Integration directed the formation of a CPO by merging Enterprise Ground Services (EGS) from Space Systems Command (SSC) and Ground Command, Control, and Communications (GC3) from Space RCO. This CPO was named the R2C2 CPO and utilizes the Space RCO acquisition authorities under the Space RCO Program Executive Officer to execute funding in the EGS and GC3 program elements to develop an extensible, scalable, modular ground segment solution capable of supporting protect and defend missions of the United States Space Force. Combined EGS and GC3 funding will be used wholly and directly to support CPO activities. R2C2 will continue development and integration of the satellite operations ground segment solution (SatOps) to support the orbital warfare mission set, including, but not limited to, capabilities and services needed to perform mission control. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:           PE 1206772SF / Rapid Resilient Command and Control (R2C2) Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1207440SF$$, $$Automate Sat C2$$, $$rdte_sf_ba7$$, $$sf$$, 2027, 0, 0, 0, NULL, $${}$$::jsonb, NULL, NULL, 1554000000, 1493600000, 1368700000, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 0, 1524300000, 1524300000, 0, 1524300000, 918000000, $$Autonomous Tactical Fabric (ATF) delivers "Space Operations of the Future” by fundamentally changing how Guardians interact with the battlespace. ATF consists of transformational Infrastructure Modernization to create a deliberate, resilient architecture where physical location does not limit space operations, Fabric to enable cross- mission data accessibility for autonomy and analytics, and Mission Operations where health and status data integrates with the Fabric along with path-independent communication for Fleet Operations and Artificial Intelligence (AI)/Machine Learning (ML) is applied to reduce repetitive functions and data overload while implementing. Additionally, Integration will perform the technical, hands-on integration needed to connect intra-program technical areas as well as USSF and DAF stakeholders to the Infrastructure and Fabric. ATF will enable future Space Force operations to be conducted from diverse locations, using any sensor or system, while also autonomously harmonizing data across various echelons at speed and scale. ATF will increase resilience, automation, and connectivity to operate throughout the conflict spectrum by creating an ecosystem for weapon systems to connect in order to share data needed to elevate decisions. The program will implement autonomous sensor orchestration, path-agnostic meshed networking, and a common, shared, distributed data plane to fundamentally pivot space operations with next generation of software to accelerate decision making. ATF is not replacing existing programs or projects, but building the underlying ecosystem and framework needed to interconnect systems and data. USSF Space Systems Command is developing the Autonomous Tactical Fabric for Guardians across warfighting, ops commands, and combat support organizations. As a result, the Service will improve battle management of all weapon systems; deliver SDA capabilities; and deter, neutralize, defeat and/or destroy counterspace threats and defend the homeland; and continue to advance all near term effects. This program falls within the Space Domain Awareness (SDA) mission area which provides the space-based and ground-based architecture required to detect, track, catalogue, and identify objects and activities in the space domain. As the foundation for space control, SDA encompasses surveillance of all space objects and activities; detailed surveillance of specific space assets; monitoring space environmental conditions; monitoring cooperative space assets; gathering indications and warning on adversary space operations; and conducting integrated command, control, communications, processing, analysis, dissemination, and archiving activities. Space Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                             Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:       PE 1207440SF / Automate Sat C2 Operational Systems Development Force investment program interdependencies include: RDT&E Budget Line Items: Space Domain Awareness/Planning/Tasking SW (1208248SF); Space Situational Awareness Operations (1203940SF); Space Situational Awareness Systems (1206425SF); and elements of Procurement Budget Line Item: Space Mods (SPCMOD). This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602182A$$, $$C3I Applied Research$$, $$rdte_army_ba2$$, $$dw_osd$$, 2026, 22317000, 31635000, 25839000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "army", "page_num": 11, "original_pe": "0602182A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) investigates, designs, validates, and conducts experimentation to establish technical solutions for creating integrated future equipment and systems that improve resiliency, survivability, operational effectiveness, mobility, sustainability, and readiness of ground forces. This PE provides mid-to-long term tactical Command, Control, Communications and Intelligence (C3I) capabilities (e.g., networking, cyber, electronic warfare, Positioning, Navigation and Timing (PNT), space, persistent surveillance) based upon promising technologies that address emerging and future threats and includes research critical and unique to the Army and DoD (e.g., atmospheric modeling and meteorological technologies). Applied research investments focus on the design and investigation of materials, processes, technologies, methodologies, and models to establish architectures, systems, and interfaces that enhance and optimize performance on the future battlefield. The outputs of these efforts inform and transition to advanced research efforts that demonstrate improved C3I capabilities. The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. The FY 2026 request was reduced by $1.039 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.023 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                              Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 2: Applied         PE 0602182A / C3I Applied Research Research$$, NULL, NULL, NULL, NULL, NULL, NULL, 21, $$RDTE - Vol 1 - Budget Activity 2.pdf$$, NULL, FALSE, 25281000, 26317000, NULL, NULL, NULL, NULL, NULL, $$This PE investigates, designs, validates, and conducts experimentation to establish technical solutions for creating integrated future equipment and systems that improve resiliency, survivability, operational effectiveness, mobility, sustainability, and readiness of ground forces. This PE provides mid-to-long term tactical Command, Control, Communications and Intelligence (C3I) capabilities (e.g., networking, cyber, electronic warfare, Positioning, Navigation and Timing (PNT), space, persistent surveillance) based upon promising technologies that address emerging and future threats and includes research critical and unique to the Army and DoW (e.g., atmospheric modeling and meteorological technologies). Applied research investments focus on the design and investigation of materials, processes, technologies, methodologies, and models to establish architectures, systems, and interfaces that enhance and optimize performance on the future battlefield. The outputs of these efforts inform and transition to advanced research efforts that demonstrate improved C3I capabilities. The cited research is consistent with the Under Secretary of War for Research and Engineering priority focus areas and the Army Modernization Strategy.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 2.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603043A$$, $$Air Platform Advanced Technology$$, $$rdte_army_ba3$$, $$cft_fvl$$, 2026, 41266000, 13648000, 17076000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "army", "page_num": 12, "original_pe": "0603043A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) undertakes advanced technology efforts that support and enable the overall Army Aviation portfolio in general, and the Army's modernization priority for Future Vertical Lift (FVL). Vital and enduring research into advanced technologies is conducted pertinent to the air portfolio that supports mid-to-long term requirements in contested operational environments and technologies that have broad application to FVL modernization, as well as overall Army and specific Department of Defense (DoD) aviation needs. Research in this PE contributes to the Army Science and Technology (S&T) air systems portfolio and is fully coordinated with efforts in PE 0602148A (Future Vertical Lift Technology), PE 0603465A (Future Vertical Lift Advanced Technology) and PE 0602183A (Air Platform Applied Research). The cited research is consistent with the Under Secretary of Defense for Research and Engineering S&T focus areas and the Army Modernization Strategy. Research in this PE is performed by the Army Research Laboratory (ARL), Aviation and Missiles Center (AvMC) and Information Technology Laboratory. The FY 2026 request was reduced by $0.592 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                            Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced          PE 0603043A / Air Platform Advanced Technology Technology Development (ATD) The FY 2026 request was reduced by $0.096 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 49755000, 45716000, 42096000, NULL, NULL, 38, $$RDTE - Vol 1 - Budget Activity 3.pdf$$, NULL, FALSE, 16596000, 51266000, 23471000, 23471000, NULL, 23471000, 38408000, $$This PE undertakes advanced technology efforts that support and enable the overall Army Aviation portfolio in general, and the Army's modernization priority for Future Vertical Lift (FVL). Vital and enduring research into advanced technologies is conducted pertinent to the air portfolio that supports mid-to-long term requirements in contested operational environments and technologies that have broad application to FVL modernization, as well as overall Army and specific DoW aviation needs. Research in this PE contributes to the Army Science and Technology (S&T) air systems portfolio and is fully coordinated with efforts in PE 0602148A (Future Vertical Lift Technology), PE 0603465A (Future Vertical Lift Advanced Technology) and PE 0602183A (Air Platform Applied Research). The cited research is consistent with the Under Secretary of War (Research and Engineering) S&T focus areas and the Army modernization strategy. Research in this PE is performed by the Army Research Laboratory (ARL), Aviation and Missiles Center (AvMC) and Information Technology Laboratory. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced          PE 0603043A / Air Platform Advanced Technology Technology Development (ATD)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 3.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603118A$$, $$Soldier Lethality Advanced Technology$$, $$rdte_army_ba3$$, $$peo_stri$$, 2026, 95186000, 125951000, 98032000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "army", "page_num": 12, "original_pe": "0603118A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) matures and demonstrates Soldier Lethality technologies that improve Soldier operational performance by increasing lethality, mobility, protection, and optimizing situational awareness across the spectrum of operating environments and missions. This PE matures Soldier weapons and enabling components / subsystems, demonstrates lethal weapons systems with potential to provide greater lethality, target acquisition, fire control, and range at a significantly reduced weight for optimized Soldier and Small Unit system performance. The major focus areas for Soldier Lethality Science and Technology are Soldier weapons and ammunition technologies, protection technologies, cognitive and physical performance measures, training in synthetic training environments, and mission support capabilities such as situational awareness sensors and displays, dismounted power and energy technologies, and Soldier and Small Unit sustainment capabilities. This technology diverse PE also matures and demonstrates sensor technologies that increase Warfighter situational understanding, survivability, and lethality by providing sensor capabilities to acquire and engage all targets and threats at longer ranges in complex environments and operational conditions (e.g. day/night, obscured, smoke, adverse weather, and other degraded visual environments), and for advancing live training technologies that accurately replicate and realistically represent the effects of current and future weapons systems during force-on-force and force-on-target training. This PE matures and demonstrates effective technology in personal combat clothing, protective equipment such as personal armor, helmets, and eyewear, combat rations, shelters, logistical support items for aerial delivery of personnel and cargo, and energy systems to power current and emerging Soldier-born Intelligence, Surveillance, and Reconnaissance (ISR), sensor, optical, and communication systems with the least weight and sustainment burden on the Soldiers and Small Combat Units. This PE also matures and demonstrates technologies supporting the Army's Synthetic Training Environment (STE), a single, interconnected synthetic training system that will enable Army units and leaders to conduct realistic multi- echelon / multi-domain combined arms maneuver and mission command training, increasing proficiency through repetition. A specific research thrust area is applying systems-based practices to mature and demonstrate scientific and tailored knowledge of Soldiers' physical and cognitive architecture to facilitate rapid and efficient designs, assessments and trade-off analyses of technology insertions on the Soldier. Significant science and technology (S&T) investments are directed to improve the effectiveness of the technologies a Soldier utilizes while reducing the size and weight of the form factor of the equipment. Research in this PE complements PE 0602143A (Soldier Lethality Technology). The FY 2026 request was reduced by $3.181 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.568 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                           Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced        PE 0603118A / Soldier Lethality Advanced Technology Technology Development (ATD)$$, NULL, 146706000, 151371000, 154120000, NULL, NULL, 42, $$RDTE - Vol 1 - Budget Activity 3.pdf$$, NULL, FALSE, 100309000, 166186000, 125121000, 125121000, NULL, 125121000, 154350000, $$This Program Element (PE) matures and demonstrates Soldier Lethality technologies that improve Soldier operational performance by increasing lethality, mobility, protection, and optimizing situational awareness across the spectrum of operating environments and missions. This PE matures Soldier weapons and enabling components / subsystems, demonstrates lethal weapons systems with potential to provide greater lethality, target acquisition, fire control, and range at a significantly reduced weight for optimized Soldier and Small Unit system performance. The major focus areas for Soldier Lethality Science and Technology are Soldier weapons and ammunition technologies, protection technologies, cognitive and physical performance measures, training in synthetic training environments, and mission support capabilities such as situational awareness sensors and displays, dismounted power and energy technologies, and Soldier and Small Unit sustainment capabilities. This Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                               Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced             PE 0603118A / Soldier Lethality Advanced Technology Technology Development (ATD) technology diverse PE also matures and demonstrates sensor technologies that increase Warfighter situational understanding, survivability, and lethality by providing sensor capabilities to acquire and engage all targets and threats at longer ranges in complex environments and operational conditions (e.g. day/night, obscured, smoke, adverse weather, and other degraded visual environments), and for advancing live training technologies that accurately replicate and realistically represent the effects of current and future weapons systems during force-on-force and force-on-target training. This PE matures and demonstrates effective technology in personal combat clothing, protective equipment such as personal armor, helmets, and eyewear, combat rations, shelters, logistical support items for aerial delivery of personnel and cargo, and energy systems to power current and emerging Soldier-born Intelligence, Surveillance, and Reconnaissance (ISR), sensor, optical, and communication systems with the least weight and sustainment burden on the Soldiers and Small Combat Units. This PE also matures and demonstrates technologies supporting the Army's Synthetic Training Environment (STE), a single, interconnected synthetic training system that will enable Army units and leaders to conduct realistic multi- echelon / multi-domain combined arms maneuver and mission command training, increasing proficiency through repetition. A specific research thrust area is applying systems-based practices to mature and demonstrate scientific and tailored knowledge of Soldiers' physical and cognitive architecture to facilitate rapid and efficient designs, assessments and trade-off analyses of technology insertions on the Soldier. Significant science and technology (S&T) investments are directed to improve the effectiveness of the technologies a Soldier utilizes while reducing the size and weight of the form factor of the equipment. Research in this PE complements PE 0602143A (Soldier Lethality Technology).$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 3.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603461A$$, $$High Performance Computing Modernization Program$$, $$rdte_army_ba3$$, $$devcom$$, 2026, 241855000, 246739000, 239597000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "army", "page_num": 13, "original_pe": "0603461A", "page_header": "Department of the Army"}$$::jsonb, $$The High Performance Computing Modernization Program (HPCMP) addresses the supercomputing requirements of Department of Defense (DoD) scientists and engineers by: (1) demonstrating and maturing the most advanced, leading-edge computational architectures while exploiting the resulting systems by employing complementary specialized expertise; (2) demonstrating and maturing the Defense Research and Engineering Network (DREN), which investigates, demonstrates, and matures leading-edge digital networking and security technologies to securely deliver computational capabilities to the distributed DoD Research, Development, Test, and Evaluation (RDTE) community; and (3) leveraging specialized expertise from DoD, other federal departments and agencies, industry, and academia to demonstrate and mature leading-edge software application codes. DoD Supercomputing Resource Centers (DSRCs) provide extensive computational capabilities to demonstrate and mature emerging technologies that address the supercomputing requirements of the DoD RDTE community in the areas of hardware, software, and programming environments. All HPCMP sites are interconnected to each other, the DoD High Performance Computing (HPC) RDTE community, and other major defense sites via the DREN, a research network which investigates, demonstrates, and matures (a) state-of-the-art digital networking technologies to ensure a robust distributed environment and (b) the most advanced digital security capabilities to protect the intellectual property of the DoD and its contract entities as they employ HPCMP capabilities. The HPCMP's software application effort (a) optimizes, enhances, demonstrates, and matures critical DoD physics-based and engineering software to allow scientists and engineers to execute calculations with precision and efficiency on leading-edge supercomputers, (b) demonstrates and matures immersive collaborative programming environments to improve science and engineering workflows, and (c) demonstrates and matures leading-edge computational technology from academia and industry. These synergistic activities collectively demonstrate and mature horizontal technologies that are exploited across the DoD RDTE community, ensuring the DoD maintains the most advanced research and development ecosystem in computationally-intensive modeling and design. The research cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. The FY 2026 request was reduced by $0.104 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $1.425 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced         PE 0603461A / High Performance Computing Modernization Program Technology Development (ATD)$$, NULL, 241446000, 249071000, 249920000, NULL, NULL, 51, $$RDTE - Vol 1 - Budget Activity 3.pdf$$, NULL, FALSE, 231168000, 236609000, 215090000, 215090000, NULL, 215090000, 252958000, $$The High Performance Computing Modernization Program (HPCMP) addresses the supercomputing requirements of DoW scientists and engineers by: (1) demonstrating and maturing the most advanced, leading-edge computational architectures while exploiting the resulting systems by employing complementary specialized expertise; (2) demonstrating and maturing the Defense Research and Engineering Network (DREN), which investigates, demonstrates, and matures leading-edge digital networking and security technologies to securely deliver computational capabilities to the distributed DoW RDT& community; and (3) leveraging specialized expertise from DoW, other federal departments and agencies, industry, and academia to demonstrate and mature leading-edge software application codes. DoW Supercomputing Resource Centers (DSRCs) provide extensive computational capabilities to demonstrate and mature emerging technologies that address the supercomputing requirements of the DoW RDTE community in the areas of hardware, software, and programming environments. All HPCMP sites are interconnected to each other, the DoW High Performance Computing (HPC) RDTE community, and other major defense sites via the DREN, a research network which investigates, demonstrates, and matures (a) state-of-the-art digital networking technologies to ensure a robust distributed environment and (b) the most advanced digital security capabilities to protect the intellectual property of the DoW and its contract entities as they employ HPCMP capabilities. The HPCMP's software application effort (a) optimizes, enhances, demonstrates, and matures critical DoW physics-based and engineering software to allow scientists and engineers to execute calculations with precision and efficiency on leading-edge supercomputers, (b) demonstrates and matures immersive collaborative programming environments to improve science and engineering workflows, and (c) demonstrates and matures leading-edge computational technology from academia and industry. These synergistic activities collectively demonstrate and mature horizontal technologies that are exploited across the DoW RDTE community, ensuring the DoW maintains the most advanced research and development ecosystem in computationally intensive modeling and design. The research cited is consistent with the Under Secretary of War for Research and Engineering priority focus areas and the Army Modernization Strategy. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced          PE 0603461A / High Performance Computing Modernization Program Technology Development (ATD)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 3.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603305A$$, $$Army Missle Defense Systems Integration$$, $$rdte_army_ba4$$, $$smdc$$, 2026, 8141000, 48763000, 20031000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 13, "original_pe": "0603305A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) funds missile defense systems integration efforts for the US Army Space and Missile Defense Command in its role as the Army Service Component Command (ASCC) to USSTRATCOM and USSPACECOM. USASMDC: Headquarters, Department of the Army General Order 37, dated 16 October 2006, designated USASMDC as the Army proponent for ground-based midcourse defense (GMD), the Army integrator for global missile defense, and the ASCC of the U.S. Strategic Command (USSTRATCOM). Upon its establishment, USASMDC became the Army Service Component Command of the United States Space Command (USSPACECOM). Army Regulation (AR) 10-87 Army Commands, Army Service Component Commands, and Direct Reporting Units dated 4 September 2007, and AR 5-22 The Army Force Modernization Proponent System dated 19 August 2009 designate USASMDC as the Army specified proponent for Global Missile Defense (GMD) capabilities. As the Army proponent for GMD, USASMDC is responsible for developing warfighting concepts, conducting warfighting experiments to validate those concepts, identifying capabilities needed to implement the validated concepts, and developing Doctrine, Organizations, Training, Material, Leadership & Education, Personnel, Facilities and Policy (DOTMLPF-P) solutions to realize GMD capabilities. As the Army integrator for global missile defense, USASMDC is responsible for reviewing programs managed by the Army, other Services, Defense agencies and National agencies to ensure that they are correctly synchronized and will ultimately provide the capabilities required by USSTRATCOM and USSPACECOM to execute their global missile defense responsibilities to provide protection of the homeland and regional/theater missile defense. The FY 2026 request was reduced by $3.551 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.076 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                 Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced          PE 0603305A / Army Missle Defense Systems Integration Component Development & Prototypes (ACD&P)$$, NULL, 10494000, 11444000, 10833000, NULL, NULL, 60, $$RDTE - Vol 2 - Budget Activity 4A.pdf$$, NULL, FALSE, 19886000, 17641000, 8367000, 8367000, NULL, 8367000, 10938000, $$This Program Element (PE) funds missile defense systems integration efforts for the US Army Space and Missile Defense Command in its role as the Army Service Component Command (ASCC) to U.S. Strategic Command (USSTRATCOM) and United States Space Command (USSPACECOM). USASMDC: Headquarters, Department of the Army General Order 37, dated 16 October 2006, designated USASMDC as the Army proponent for ground-based midcourse defense (GMD), the Army integrator for global missile defense, and the ASCC to USSTRATCOM. Upon its establishment, USASMDC became the Army Service Component Command to USSPACECOM. Army Regulation (AR) 10-87 Army Commands, Army Service Component Commands, and Direct Reporting Units dated 4 September 2007, and AR 5-22 The Army Force Modernization Proponent System dated 19 August 2009 designate USASMDC as the Army specified proponent for Global Missile Defense (GMD) capabilities. As the Army proponent for GMD, USASMDC is responsible for developing warfighting concepts, conducting warfighting experiments to validate those concepts, identifying capabilities needed to implement the validated concepts, and developing Doctrine, Organizations, Training, Material, Leadership & Education, Personnel, Facilities and Policy (DOTMLPF-P) solutions to realize GMD capabilities. As the Army integrator for global missile defense, USASMDC is responsible for reviewing programs managed by the Army, other Services, Defense agencies and National agencies to ensure that they are correctly synchronized and will ultimately provide the capabilities required by USSTRATCOM and USSPACECOM to execute their global missile defense responsibilities to provide protection of the homeland and regional/theater missile defense.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603920A$$, $$Humanitarian Demining$$, $$rdte_army_ba3$$, $$devcom$$, 2026, 9349000, 22737000, 23272000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "army", "page_num": 13, "original_pe": "0603920A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) develops, demonstrates and validates cost-effective technologies for use in humanitarian demining via Outside Continental United States (OCONUS) operational field evaluations. This PE's low-cost and highly effective technology reduces the landmine and unexploded ordnance (UXO) / improvised explosive devise (IED) threat to deployed United States (US) forces and the local population. This PE coordinates with the Department of State's Weapons Removal and Abatement Program, the Department of Defense (DoD) Humanitarian Mine Action (HMA) programs of the Combatant Commands (CCMDs), and international mine action organizations and foreign militaries. New technology requirements and areas of emphasis are identified and validated at annual Requirements Workshop and UXO/IED Working Group Meetings. Technology investments are prioritized using the results of these meetings and CCMD security cooperation and theater campaign plan HMA objectives. This PE advances the state-of-the-art of demining technologies and evaluates these technologies utilizing host nation humanitarian demining partners. This PE supports and bolsters the CCMD stability operations mission as directed under Department of Defense Instruction (DODI) 3000.05 to foster mil-to-mil engagement, and bolster economic security and development with partner nations worldwide. Additionally, this PE fosters nations' mine action capacity while improving DoD's visibility and access, generating long-term positive perceptions of DoD and the US, and fostering collaborative relationships with host nation governments. It also directly supports the National Defense Strategy through ensuring common domains remain open and free. This PE utilizes a research and development plan based on operational test data gained through Operational Field Evaluations (OFEs). These OFEs provide this PE a unique capability to collect this data against live mines/UXO in actual minefields around the world. This data is unavailable to any other DoD organization. This OFE data drives future humanitarian demining investment decisions and is shared and leveraged by the U.S. Army's Army Futures Command programs to further improve U.S. forces' technologies. In addition, this PE provides mine and UXO detector training to the CCMDs at the Humanitarian Demining Training Center (HDTC) in support of Military to Military training and partnerships. This PE supports the DoD's strategic guidance to address instability and reduce the demand for significant US force commitments to stability operations; with DODI 3000.05 (Stability Operations) and Chairman of the Joint Chiefs of Staff Instruction (CJCSI) 3207.01C (Department of Defense Support to Humanitarian Mine Action) to reduce the social, economic and environmental impact of landmines and unexploded ordnance. This PE will be executed by the Army Futures Command (AFC). Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                           Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced         PE 0603920A / Humanitarian Demining Technology Development (ATD)$$, NULL, 6510000, 6589000, 6688000, NULL, NULL, 58, $$RDTE - Vol 1 - Budget Activity 3.pdf$$, NULL, FALSE, 22934000, 36349000, 7619000, 7619000, NULL, 7619000, 6784000, $$This Program Element (PE) develops, demonstrates and validates cost-effective technologies for use in humanitarian demining via Outside Continental United States (OCONUS) operational field evaluations. This PE's low-cost and highly effective technology reduces the landmine and unexploded ordnance (UXO) / improvised explosive devise (IED) threat to deployed United States (US) forces and the local population. This PE coordinates with the Department of State's Weapons Removal and Abatement Program, the Department of War (DoW) Humanitarian Mine Action (HMA) programs of the Combatant Commands (CCMDs), and international mine action organizations and foreign militaries. New technology requirements and areas of emphasis are identified and validated at annual Requirements Workshop and UXO/IED Working Group Meetings. Technology investments are prioritized using the results of these meetings and CCMD security cooperation and theater campaign plan HMA objectives. This PE advances the state-of-the-art of demining technologies and evaluates these technologies utilizing host nation humanitarian demining partners. This PE supports and bolsters the CCMD stability operations mission as directed under Department of Defense Instruction (DODI) 3000.05 to foster mil-to-mil engagement, and bolster economic security and development with partner nations worldwide. Additionally, this PE fosters nations' mine action capacity while improving DoW's visibility and access, generating long-term positive perceptions of DoW and the US, and fostering collaborative relationships with host nation governments. It also directly supports the National Defense Strategy through ensuring common domains remain open and free. This PE utilizes a research and development plan based on operational test data gained through Operational Field Evaluations (OFEs). These OFEs provide this PE a unique capability to collect this data against live mines/UXO in actual minefields around the world. This data is unavailable to any other DoW organization. This OFE data drives future humanitarian demining investment decisions and is shared and leveraged by the U.S. Army's Army Futures Command programs to further improve U.S. forces' technologies. In addition, this PE provides mine and UXO detector training to the CCMDs at the Humanitarian Demining Training Center (HDTC) in support of Military to Military training and partnerships. This PE supports the DoW's strategic guidance to address instability and reduce the demand for significant US force commitments to stability operations; with DODI 3000.05 (Stability Operations) and Chairman of the Joint Chiefs of Staff Instruction (CJCSI) 3207.01C (Department of Defense Support to Humanitarian Mine Action) to reduce the social, economic and environmental impact of landmines and unexploded ordnance. This PE will be executed by the Transformation & Training Command (T2COM). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 3: Advanced          PE 0603920A / Humanitarian Demining Technology Development (ATD)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 1 - Budget Activity 3.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_2031_L047$$, $$CMWS$$, $$proc_army_2031_ba4$$, $$peo_aviation$$, 2026, 38419000, 71964000, 51646000, NULL, $${"page": 13, "ba_num": "04", "source": "p1_fy26", "ba_name": "Support equipment and facilities", "line_no": "47", "service": "army", "fy24_qty": null, "fy25_qty": null, "appr_code": "2031", "appr_name": "Aircraft Procurement, Army", "fy26_v178": {"disc_K": 225647, "li_num": 29, "source": "p40_fy26_v178", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Army/Aircraft_Procurement_Army.txt"}, "fy26t_qty": null, "fy26d_cost": 38419000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, 29323000, 1849719000, NULL, NULL, NULL, FALSE, 51646000, 38419000, 140636000, 140636000, 0, 140636000, NULL, NULL, $$Budget J-Books/FY27/Army/Aircraft_Procurement_Army.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603804A$$, $$Logistics and Engineer Equipment - Adv Dev$$, $$rdte_army_ba4$$, $$asa_alt$$, 2026, 15435000, 22846000, 19995000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 14, "original_pe": "0603804A", "page_header": "Department of the Army", "fy26_v182_disc_K": 40435, "fy26_v182_supp_K": 10000, "fy26_v182_total_K": 50435, "fy26_v182_note_name": "Logistics and Engineer Equipment - Adv Dev", "fy26_v182_source_file": "RDTE - Vol 2 - Budget Activity 4A.txt", "fy26_v182_source_line": 7871}$$::jsonb, $$This Program Element (PE) supports advanced component development and prototypes of new and improved technologies for combat support and combat service support equipment essential to sustaining combat operations. Advancements in bridging, armored engineer vehicles to include development of a robotic capability Remote Control System for the Assault Breacher Vehicle, electric power generators, material-handling, environmental control, shelter systems, cargo aerial delivery, field service systems, mortuary affairs equipment and petroleum equipment are necessary to improve safety and increase the tactical mobility, operational capability, lethality and survivability on the digital battlefield and to provide for greater sustainment while reducing the logistics support burden. Army Watercraft funding supports initiatives to enhance the seaworthiness, safety, survivability, supportability, energy efficiency, environmental, bulk fuel, water generation, regulatory compliance and reliability of existing systems. FY 2026 Base dollars in the amount of $9.942 million supports Assault Breacher Vehicle Remote Control System (ABV RCS) which adds remote control capability to the ABV, allowing Soldiers to conduct minefield breaching operations remotely, removing Soldiers from the breach where 50% casualty rates are expected. FY 2026 Base dollars support engineering and logistics development, developmental testing and program support. FY 2026 RDTE dollars in the amount of $2.716 million supports modernization of the current Army Watercraft fleet by investigating technology insertions, including, but not limited to: force protection, prognostics & preventative maintenance, vessel electronics, autonomous operations and other emerging technologies. Funding also supports developing initial prototypes to enable refinement of operational requirements and early user feedback to support future sustainment and operational movement operating concepts. All Army Watercraft modernization efforts will incorporate Predictive Logistics which includes digital updates across commercial solutions which will improve readiness, predictive maintenance, unplanned emergency repairs. FY 2026 RDTE dollars in the amount of $2.777 million supports technology maturation efforts for advanced power technology (i.e, energy storage and power conversion) through Universal Power Gateway (UPG) development. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced        PE 0603804A / Logistics and Engineer Equipment - Adv Dev Component Development & Prototypes (ACD&P) The FY 2026 request was reduced by $0.2 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.067 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 5793000, 5807000, 5811000, NULL, NULL, 72, $$RDTE - Vol 2 - Budget Activity 4A.pdf$$, NULL, FALSE, 20946000, 50435000, 12822000, 12822000, NULL, 12822000, 5869000, $$This Program Element (PE) supports advanced component development and prototypes of new and improved technologies for combat support and combat service support equipment essential to sustaining combat operations. Advancements in bridging, armored engineer vehicles to include development of a robotic capability Remote Control System for the Assault Breacher Vehicle, electric power generators, material-handling, environmental control, shelter systems, cargo aerial delivery, field service systems, mortuary affairs equipment and petroleum equipment are necessary to improve safety and increase the tactical mobility, operational capability, lethality and survivability on the digital battlefield and to provide for greater sustainment while reducing the logistics support burden. Army Watercraft funding supports initiatives to enhance the seaworthiness, safety, survivability, supportability, energy efficiency, environmental, bulk fuel, water generation, regulatory compliance and reliability of existing systems. FY 2027 Armored Engineer Vehicles funding supports the Assault Breacher Vehicle Remote Control System (ABV RCS) which adds remote control capability to the ABV, allowing Soldiers to conduct minefield breaching operations remotely, removing Soldiers from the breach where 50% casualty rates are expected. FY 2027 Base dollars support engineering and logistics development, developmental testing and program support. FY 2027 Marine Orien Log Eq Ad funding supports modernization of the current Army Watercraft fleet by investigating technology insertions, including, but not limited to: force protection, survivability, prognostics & preventative maintenance, vessel electronics, autonomous operations and other emerging technologies. Funding also supports developing initial prototypes to enable refinement of operational requirements and early user feedback to support future sustainment and operational movement operating concepts. All Army Watercraft modernization efforts will incorporate Predictive Logistics which includes digital updates across commercial solutions which will improve readiness, predictive maintenance, unplanned emergency repairs. FY 2027 Adv Elec Energy Con Add funding supports technology maturation efforts for advanced power technology (i.e, energy storage and power conversion) through Universal Power Gateway (UPG) development and for continued analysis of transitioning micro-reactor technology to the Army. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced          PE 0603804A / Logistics and Engineer Equipment - Adv Dev Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603827A$$, $$Soldier Systems - Advanced Development$$, $$rdte_army_ba4$$, $$asa_alt$$, 2026, 41856000, 41551000, 24284000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 14, "original_pe": "0603827A", "page_header": "Department of the Army"}$$::jsonb, $$A portion of this funding line is directly aligned to the Soldier Lethality Army Modernization Priority. This Program Element (PE), Soldier Systems - Advanced Development, manages the Soldier as a system to increase combat effectiveness, test and deliver tangible products that save Soldiers lives and improve combat capability. The PE provides funding for evaluating, developing, and testing emerging technologies and critical Soldier support systems to reduce technology risk. Project CF2: Develop a long-term Soldier/Squad as a System integration platform ICW the Close Combat Integration Enterprise (CCIE) to ensure interoperability as part of the integrated Joint Forces. Verify and develop prototype digital engineering tools that provide Systems Engineering, Configuration Management, and Evaluation in a virtual and physical environment. Using enhancements to the Adaptive Squad Architecture (ASA) digital tools verify development of interface controls documents, and connection points to support the rapid integration of the CCIE programs with all other dismounted Soldier equipment. Prototype capabilities for evaluation and integration include new measurements and methodologies from S&T programs and future requirements. Funding for this program aligns with the Army's priorities in support of Digital Engineering and Transformation and is a Soldier Lethality Cross Functional Team priority. Project ET8: Personnel Airdrop System improves Low Altitude and High-Altitude personnel parachutes and associated equipment to include canopy improvement based on integration of new technology with the goal of enhancing the insertion capability and safety of the airborne Soldier and increasing the performance, reliability, and durability of personnel airdrop equipment. Project S53: Funding is used to evaluate and integrate technologies and representative or prototype systems that help expedite Soldier Clothing and Individual Equipment technology transition from the laboratory to operational use. Efforts focus on proving out commonality across as broad a spectrum of users as possible to provide a modular, integrated uniform/clothing system from skin out and head-to-toe. It funds efforts to transition new technologies and domestically available fabrics with Flame Resistant (FR), moisture wicking, insect protection and camouflage technologies, including integration of fabrics appropriate for uniforms and equipment used Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                  Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced            PE 0603827A / Soldier Systems - Advanced Development Component Development & Prototypes (ACD&P) in jungle/tropical and arctic environments. New technologies are identified to monitor health and improve Soldier survivability, reduce weight, and improve affordability, mobility and comfort in combat and training/administrative environments. Includes integration and interface on the Soldier system. Project S54: Small and medium arm weapon systems include weapons ranging up to 40 millimeter in caliber. Funding is used to support Small Arms Improvement and other domestic and foreign sources of small arms weapon systems to demonstrate, test and evaluate capability near or at planned operational requirements. These efforts focus on improvements designed to enhance lethality, target acquisition and tracking, fire control, usability, training effectiveness and reliability of weapons to include ammunition and counter UAS technologies when developing and/or evaluating standard and non-standard weapons. Focus areas include the maturing of technology through testing and evaluation of sub-system or system prototypes which demonstrates lightweight materials, thermal solutions, passive range finders, observation/situational awareness improvements, human-systems integration, robotic armament capability, non-lethal capability, advanced laser protection for optics, and equipment enhancements. Benefits include continuous improvements to small arms weapon systems, remote weapon systems, fire control equipment, optics, gun barrels, training devices, suppressors, component mounts, weapon mounts, ancillary items and weapon/ammunition interface. Project VS4: Supports efforts to evaluate integrated technologies and representative or prototype systems that help expedite Personal Protective Equipment (PPE) technology transition from the laboratory to operational use. The FY 2026 request was reduced by $1.74 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, NULL, 32680000, 32298000, 31166000, NULL, NULL, 74, $$RDTE - Vol 2 - Budget Activity 4A.pdf$$, NULL, FALSE, 23398000, 49356000, 56122000, 56122000, NULL, 56122000, 31476000, $$This Program Element (PE), Soldier Systems - Advanced Development, manages the Soldier as a system to increase combat effectiveness, test and deliver tangible products that save Soldiers lives and improve combat capability. The PE provides funding for evaluating, developing, and testing emerging technologies and critical Soldier support systems to reduce technology risk. Project CF2: Develop a long-term Soldier/Squad as a System integration platform ICW the Close Combat Integration Enterprise (CCIE) to ensure interoperability as part of the integrated Joint Forces. Verify and develop prototype digital engineering tools that provide Systems Engineering, Configuration Management, and Evaluation in a virtual and physical environment. Using enhancements to the Adaptive Squad Architecture (ASA) digital tools verify development of interface controls documents, and connection points to support the rapid integration of the CCIE programs with all other dismounted Soldier equipment. Prototype capabilities for evaluation and integration include new measurements and methodologies from S&T programs and future requirements. Funding for this program aligns with the Army's priorities in support of Digital Engineering and Transformation. Project ET8: Personnel Airdrop System improves Low Altitude and High-Altitude personnel parachutes and associated equipment to include canopy improvement based on integration of new technology with the goal of enhancing the insertion capability and safety of the airborne Soldier and increasing the performance, reliability, and durability of personnel airdrop equipment. Project S53: Funding is used to evaluate and integrate technologies and representative or prototype systems that help expedite Soldier Clothing and Individual Equipment technology transition from the laboratory to operational use. Efforts focus on proving out commonality across as broad a spectrum of users as possible to provide a modular, integrated uniform/clothing system from skin out and head-to-toe. It funds efforts to transition new technologies and domestically available fabrics with Flame Resistant (FR), moisture wicking, insect protection and camouflage technologies, including integration of fabrics appropriate for uniforms and equipment used in jungle/tropical and arctic environments. New technologies are identified to monitor health and improve Soldier survivability, reduce weight, and improve affordability, mobility and comfort in combat and training/administrative environments. Includes integration and interface on the Soldier system. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                                Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced           PE 0603827A / Soldier Systems - Advanced Development Component Development & Prototypes (ACD&P) Project S54: Small and medium arm weapon systems include weapons ranging up to 40 millimeter in caliber. Funding is used to support Small Arms Improvement and other domestic and foreign sources of small arms weapon systems to demonstrate, test and evaluate capability near or at planned operational requirements. These efforts focus on improvements designed to enhance lethality, target acquisition and tracking, fire control, usability, training effectiveness and reliability of weapons to include ammunition and counter UAS technologies when developing and/or evaluating standard and non-standard weapons. Focus areas include the maturing of technology through testing and evaluation of sub-system or system prototypes which demonstrates lightweight materials, thermal solutions, passive range finders, observation/situational awareness improvements, human-systems integration, robotic armament capability, less-lethal capability, advanced laser protection for optics, and equipment enhancements. Benefits include continuous improvements to small and medium arms weapon systems (such as M8 carbine), remote weapon systems, fire control equipment, optics, gun barrels, training devices, suppressors, component mounts, weapon mounts, ancillary items and weapon/ammunition interface. Project VS4: Supports efforts to evaluate integrated technologies and representative or prototype systems that help expedite Personal Protective Equipment (PPE) technology transition from the laboratory to operational use. The FY 2026 request was reduced by $1.74 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604035A$$, $$Low Earth Orbit (LEO) Satellite Capability$$, $$rdte_army_ba4$$, $$asa_alt$$, 2026, 17063000, 37433000, 21935000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 14, "original_pe": "0604035A", "page_header": "Department of the Army"}$$::jsonb, $$The United States Army Tactical Space Strategy provides tactical land component forces with space-based capabilities required to close the top three Large Scale Combat Operations (LSCO) gaps and counter adversarial surveillance and reconnaissance systems that affect friendly maneuver forces. National, DoD, commercial space-based, and High Altitude (HA) sensor data will be integrated into army and Joint ground architectures to provide resilient communications, assured Positioning, Navigation, and Timing (PNT), all domain sensing capabilities (including space, high altitude, aerial and terrestrial sensors, data transport, data fusion, data analytics), automated Processing Exploitation and Dissemination (PED) required in the targeting process (target recognition, machine learning and advanced algorithm development), and provide command and control (C2) of non-kinetic fires for counter ISR capabilities to enable maneuver force operations. These capabilities will enable rapid and responsive all-domain targeting applications required to engage and defeat A2/AD forces and enable force projection and freedom of maneuver in contested Multi-Domain Operations and continue to inform the Army and Joint Services Family of Integrated Targeting Cells (FIT-C). Provides prototyping, experimentation, and risk reduction activities for ground architecture, supporting wide-area, responsive, and deep-area sensing required for Beyond-Line-of-Sight (BLOS) targeting and C2 of non-kinetic fires for counter ISR operations, significantly reducing Sensor to Shooter (S2S) timelines and enabling freedom of maneuver for operational forces. It will enable Warfighters at echelon to conduct C2 of counter surveillance and reconnaissance operations and to dynamically task, receive and disseminate data to directly support live-fire S2S demonstrations and assessments. FY2026 base funding in the amount of $ 17.063 million provides prototyping, experimentation, and risk reduction activities for the Army as it continues to develop and field prototypes to close the all domain sensing capability gap and provide C2 of counter adversarial surveillance and reconnaissance systems. Complimentary AI/ ML technologies are assessed via various prototyping and ground station (FIT-C) architecture efforts. These Advanced Component Development and Prototypes efforts enable ground stations to dynamically task, receive, and disseminate data to directly support live-fire, Warfighting function system of system demonstrations and assessments, enabling wide-area, responsive, and deep-area sensing and force maneuver. Additionally, this funding supports C2 architecture prototyping and experimentation of counter ISR capabilities, along with navigation warfare (NAVWAR) technology integration and Positioning, Navigation and Timing (PNT) technology development and assessments, including experimentation and prototyping in denied, degraded, intermittent, or limited (DDIL) operating environments. The FY 2026 request was reduced by $0.24 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                            Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced         PE 0604035A / Low Earth Orbit (LEO) Satellite Capability Component Development & Prototypes (ACD&P)$$, NULL, 12575000, 16866000, 16871000, NULL, NULL, 78, $$RDTE - Vol 2 - Budget Activity 4B.pdf$$, NULL, FALSE, 21134000, 17063000, 319000, 319000, NULL, 319000, 17080000, $$The United States Army Tactical Space Strategy provides tactical land component forces with space-based capabilities required to close the top three Large Scale Combat Operations (LSCO) gaps and counter adversarial surveillance and reconnaissance systems that affect friendly maneuver forces. National, DoW, commercial space-based, and High Altitude (HA) sensor data will be integrated into army and Joint ground architectures to provide resilient communications, assured Positioning, Navigation, and Timing (PNT), all domain sensing capabilities (including space, high altitude, aerial and terrestrial sensors, data transport, data fusion, data analytics), automated Processing Exploitation and Dissemination (PED) required in the targeting process (target recognition, machine learning and advanced algorithm development), and provide command and control (C2) of non-kinetic fires for counter ISR capabilities to enable maneuver force operations. These capabilities will enable rapid and responsive all-domain targeting applications required to engage and defeat A2/AD forces and enable force projection and freedom of maneuver in contested Multi-Domain Operations and continue to inform the Army and Joint Services Family of Integrated Targeting Cells (FIT-C). Provides prototyping, experimentation, and risk reduction activities for ground architecture, supporting wide-area, responsive, and deep-area sensing required for Beyond-Line-of-Sight (BLOS) targeting and C2 of non-kinetic fires for counter ISR operations, significantly reducing Sensor to Shooter (S2S) timelines and enabling freedom of maneuver for operational forces. It will enable Warfighters at echelon to conduct C2 of counter surveillance and reconnaissance operations and to dynamically task, receive and disseminate data to directly support live-fire S2S demonstrations and assessments. FY2027 base funding in the amount of $0.319 million provides prototyping, experimentation, and risk reduction activities for the Army as it continues to develop and field prototypes to close the all-domain sensing capability gap and provide prototyping and experimentation for counter-adversarial surveillance and reconnaissance systems and their Command and Control (C2). Complimentary Artificial Intelligence/Machine Learning (AI/ML) technologies are assessed via various prototyping and ground station (FIT-C) architecture efforts. These Advanced Component Development and Prototypes efforts enable ground stations to dynamically task, receive, and disseminate data to directly support live-fire, Warfighting function system of system demonstrations and assessments, enabling wide-area, responsive, and deep-area sensing and force maneuver. Additionally, this funding supports C2 architecture prototyping and experimentation of counter-ISR capabilities, including integration of Electronic Warfare (EW) systems for spectrum dominance and disruption of adversary sensors. Efforts will also focus on technology integration and technology development and assessments, including experimentation and prototyping in denied, degraded, intermittent, or limited (DDIL) operating environments. EW prototyping will specifically address capabilities to defeat enemy electronic attack and protection measures, ensuring resilient sensing and C2 in contested electromagnetic environments. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                             Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced           PE 0604035A / Low Earth Orbit (LEO) Satellite Capability Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4B.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603801N$$, $$Innovative Naval Prototypes (INP) Adv Tec Dev$$, $$rdte_navy_ba3$$, $$onr$$, 2026, 0, 148737000, 140988000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "navy", "page_num": 27, "original_pe": "0603801N", "page_header": "Department of the Navy"}$$::jsonb, $$The Office of Naval Research (ONR) portfolio includes efforts that solve problems and respond to mission requirements, as well as, exploratory research for new ideas and breakthrough capabilities. Larger in scope, scale and risk Innovative Naval Prototypes (INP) are selected for their high-payoff and potential to revolutionize operational concepts. The efforts described in this Program Element (PE) continue the Applied Research work in PE 0602792N for promising INPs with Advanced Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                 Date: June 2025 Appropriation/Budget Activity                                                         R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 3: Advanced                 PE 0603801N / Innovative Naval Prototypes (INP) Adv Tec Dev Technology Development (ATD) Technology Development activities. INP investments define the future of U.S. naval forces. Due to high technical risk, INPs often have long trial-and-error timeframes to work through challenges, but typically no more than three years between decision points. INP efforts mature technologies from a Technology Readiness Level (TRL) of 2 or 3 to a TRL of 6. As such, INPs require applied and advanced technology development funding to bridge from concept to working prototype. INPs prove technological and capability potential, validate production feasibility, and acquisition potential. ONR demonstrates INPs in relevant environments. Successful experimentation and demonstrations present the Department of the Navy with disruptive capabilities that may lead to a new acquisition programs. INPs are selected by senior leadership in the Department of the Navy. This Program Element (PE) funds Advanced Technology Development (ATD) that includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Efforts in this PE generally have Technology Readiness Levels TRL) of 4 (component and/or breadboard validation in laboratory environment.), 5 (component and/or breadboard validation in relevant environment.), or 6 (system/subsystem model or prototype demonstration in a relevant environment). INP investments represent game changing technologies with the potential to revolutionize operational concepts. They are disruptive in nature, as they would dramatically change the way naval forces fight. Due to high technical risk, INPs typically have long duration but have no more than three years between decision points. INPs do not develop hardware for service use, rather they prove technological and production feasibility, and show naval utility and acquisition potential. The Office of Naval Research (ONR) demonstrates INPs in relevant environments. Successful experimentation and demonstrations present the Department of the Navy with disruptive capabilities that may lead to the obsolescence of existing capabilities and acquisition programs. The Department of the Navy would have to make significant acquisition decisions to integrate the new technological capabilities into naval warfighting systems. INPs are selected by a process that involves senior leadership in the Department of the Navy. Information security concerns preclude fully detailed descriptions of project efforts, research activities, and technology development plans. Specific information on each project and activity will be provided separately to the Congressional oversight committees. Due to the number of efforts in this PE, the programs described herein are representative of the work included in this PE. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                            Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 3: Advanced         PE 0603801N / Innovative Naval Prototypes (INP) Adv Tec Dev Technology Development (ATD)$$, NULL, 0, 0, 0, NULL, NULL, 26, $$RDTEN_BA1-3_Book.pdf$$, NULL, FALSE, 138667000, 0, 0, 0, NULL, 0, 0, $$The Office of Naval Research (ONR) portfolio includes efforts that solve problems and respond to mission requirements, as well as, exploratory research for new ideas and breakthrough capabilities. Larger in scope, scale and risk Innovative Naval Prototypes (INP) are selected for their high-payoff and potential to revolutionize operational concepts. The efforts described in this Program Element (PE) continue the Applied Research work in PE 0602792N for promising INPs with Advanced Technology Development activities. INP investments define the future of U.S. naval forces. Due to high technical risk, INPs often have long trial-and-error timeframes to work through challenges, but typically no more than three years between decision points. INP efforts mature technologies from a Technology Readiness Level (TRL) of 2 or 3 to a TRL of 6. As such, INPs require applied and advanced technology development funding to bridge from concept to working prototype. INPs prove technological Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                 Date: April 2026 Appropriation/Budget Activity                                                         R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 3: Advanced                 PE 0603801N / Innovative Naval Prototypes (INP) Adv Tec Dev Technology Development (ATD) and capability potential, validate production feasibility, and acquisition potential. ONR demonstrates INPs in relevant environments. Successful experimentation and demonstrations present the Department of the Navy with disruptive capabilities that may lead to a new acquisition programs. INPs are selected by senior leadership in the Department of the Navy. This Program Element (PE) funds Advanced Technology Development (ATD) that includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Efforts in this PE generally have Technology Readiness Levels TRL) of 4 (component and/or breadboard validation in laboratory environment.), 5 (component and/or breadboard validation in relevant environment.), or 6 (system/subsystem model or prototype demonstration in a relevant environment). INP investments represent game changing technologies with the potential to revolutionize operational concepts. They are disruptive in nature, as they would dramatically change the way naval forces fight. Due to high technical risk, INPs typically have long duration but have no more than three years between decision points. INPs do not develop hardware for service use, rather they prove technological and production feasibility, and show naval utility and acquisition potential. The Office of Naval Research (ONR) demonstrates INPs in relevant environments. Successful experimentation and demonstrations present the Department of the Navy with disruptive capabilities that may lead to the obsolescence of existing capabilities and acquisition programs. The Department of the Navy would have to make significant acquisition decisions to integrate the new technological capabilities into naval warfighting systems. INPs are selected by a process that involves senior leadership in the Department of the Navy. Information security concerns preclude fully detailed descriptions of project efforts, research activities, and technology development plans. Specific information on each project and activity will be provided separately to the Congressional oversight committees. Due to the number of efforts in this PE, the programs described herein are representative of the work included in this PE.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA1-3_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604129A$$, $$Advanced Power Applications$$, $$rdte_army_ba4$$, $$asa_alt$$, 2027, 0, 0, 0, NULL, $${"fy26_v180": {"note": "FY27_only_PE_no_FY26_reality", "source": "b1_null_zero_v180"}, "fy26_v182_disc_K": 0, "fy26_v182_supp_K": 5000, "fy26_v182_total_K": 5000, "fy26_v182_note_name": "Advanced Power Applications", "fy26_v182_source_file": "RDTE - Vol 2 - Budget Activity 4B.txt", "fy26_v182_source_line": 7567}$$::jsonb, NULL, NULL, 52800000, 58080000, 63888000, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 5000000, 48000000, 48000000, NULL, 48000000, 70277000, $$This Program Element (PE) implements Executive Order (EO) 14299 - Deploying Advanced Nuclear Reactor Technologies for National Security - The United States faces a critical national security imperative to ensure a resilient, secure, and reliable energy supply for critical defense facilities designated under section 824o-1(c) of title 16, United States Code, and other mission capability resources. It is the policy of the United States to ensure the rapid development, deployment, and use of advanced nuclear technologies to support national security objectives, such as the protection and operation of critical infrastructure, critical defense facilities, and other mission capability resources. The Secretary of the Army serves as the Department of War (DoW) Executive Agent (EA) for both installation and operational nuclear energy, will lead and begin planning for deployment of Microreactor Power Plants (MPPs). With this funding, the United States will for the first time deploy MPPs at scale, turning the nation into the global leader in installation and operational nuclear energy.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4B.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L033$$, $$LCS In-Service Modernization$$, $$proc_navy_1810_ba1$$, $$peo_usc$$, 2026, 38880000, 49028000, 56105000, NULL, $${"page": 95, "ba_num": "01", "source": "p1_fy26", "ba_name": "Ships support equipment", "line_no": "33", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "01", "appr": "OPN", "title": "P-1 Line 31", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 65113, "p1_line_num": 31, "fy27_total_K": 65113}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"disc_K": 91372, "li_num": 31, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/OPN_BA1_Book.txt"}, "fy26_v197": {"method": "title_fuzzy_partial", "delta_K": 99946, "src_pdf": "Budget J-Books/FY27/Navy/OPN_BA1_Book.pdf", "mapped_K": 5108087, "applied_at": "2026-05-09T_v197d", "table2_total_K": 5802107, "supersedes_partial": "fy26_v179_concentrated", "unmapped_residual_K": 694020}, "fy26t_qty": null, "fy26d_cost": 38880000, "fy26r_cost": 0, "ident_code": ""}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 188254000, 189458000, 65113000, 65113000, 0, 65113000, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA1_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305251A$$, $$Cyberspace Operations Forces and Force Support$$, $$rdte_army_ba4$$, $$arcyber$$, 2026, 5605000, 74000, 2270000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 15, "original_pe": "0305251A", "page_header": "Department of the Army"}$$::jsonb, $$U.S. Army Cyber Command (ARCYBER) is the supporting Army Headquarters under United States Cyber Command to operate and defend Army networks and deliver cyberspace effects against adversaries to defend the nation. ARCYBER pursues research and development of cyber-peculiar capabilities across ARCYBER's lines of effort in coordination with other cyber acquisition and research entities to satisfy ARCYBER's time-sensitive operational requirements. Previously this PE supported pilot and prototype capabilities to enter into Cooperative Research and Development Agreements (CRADAs) and Educational Partnership Agreements (EPAs) to provide rapid solutions to cyber via Technology Transfer (T2) mechanism. T2 enables ARCYBER to "SPIN OUT" its research and development advancements to industry and "SPIN IN" the best solutions from the private sector for the purpose of transitioning new capabilities to our warfighter. Will also have the authority for "Dual use" technologies that have both military and commercial markets to be transferred and transitioned. ARCYBER Technology and Innovation Center (ArCTIC) T2 fosters an environment where numerous promising approaches and solutions are able to be assessed in parallel to influence future capabilities. T2 provides ARCYBER the ability to influence future programs of record by prototyping solutions and assessing them against real-world environments to determine operational impact if transitioned and scaled. T2 activities will extend and promote this culture across all Army and partner scientific research and prototype endeavors. The ArCTIC capability and research areas are narrow enough to ensure that ArCTIC is remaining true to its core competencies, and broad enough so that the lab can accelerate development efforts across various technology readiness levels (TRLs) and capability categories. In FY 2026, this PE will provide the Army Service Component Commands (ASCCs) with persistent capability to execute operations which emphasize effects in the information dimension of the operational environment focused in five areas: (1) Enable decision-making; (2) Protect friendly information; (3) Educate and inform domestic audiences; (4) Inform and influence foreign audiences; (5) Conduct Information Warfare. This effort will field initial capabilities to the ASCCs in support of theater and transregional Information Advantage mission sets to fund Information Advantage capabilities. The capabilities support Army 2030 by enabling three Information Advantage Detachments, (USARPAC; USAREUR-AF; ARCYBER) to conduct Information Advantage Activities during competition, crisis, and conflict. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced          PE 0305251A / Cyberspace Operations Forces and Force Support Component Development & Prototypes (ACD&P)$$, NULL, 5483000, 5598000, 19387000, NULL, NULL, 100, $$RDTE - Vol 2 - Budget Activity 4B.pdf$$, NULL, FALSE, 2270000, 5605000, 22889000, 22889000, NULL, 22889000, 4627000, $$U.S. Army Cyber Command (ARCYBER) is the supporting Army Headquarters under United States Cyber Command to operate and defend Army networks and deliver cyberspace effects against adversaries to defend the nation. ARCYBER pursues research and development of cyber-peculiar capabilities across ARCYBER's lines of effort in coordination with other cyber acquisition and research entities to satisfy ARCYBER's time-sensitive operational requirements. Previously this PE supported pilot and prototype capabilities to enter into Cooperative Research and Development Agreements (CRADAs) and Educational Partnership Agreements (EPAs) to provide rapid solutions to cyber via Technology Transfer (T2) mechanism. T2 enables ARCYBER to "SPIN OUT" its research and development advancements to industry and "SPIN IN" the best solutions from the private sector for the purpose of transitioning new capabilities to our warfighter. Will also have the authority for "Dual use" technologies that have both military and commercial markets to be transferred and transitioned. ARCYBER Technology and Innovation Center (ArCTIC) T2 fosters an environment where numerous promising approaches and solutions are able to be assessed in parallel to influence future capabilities. T2 provides ARCYBER the ability to influence future programs of record by prototyping solutions and assessing them against real-world environments to determine operational impact if transitioned and scaled. T2 activities will extend and promote this culture across all Army and partner scientific research and prototype endeavors. The ArCTIC capability and research areas are narrow enough to ensure that ArCTIC is remaining true to its core competencies, and broad enough so that the lab can accelerate development efforts across various technology readiness levels (TRLs) and capability categories. In FY 2027, this PE will provide the Army Service Component Commands (ASCCs) with persistent capability to execute operations which emphasize effects in the information dimension of the operational environment focused in five areas: (1) Enable decision-making; (2) Protect friendly information; (3) Educate and inform domestic audiences; (4) Inform and influence foreign audiences; (5) Conduct Information Warfare. This effort will field initial capabilities to the ASCCs in support of theater and transregional Information Advantage mission sets to fund Information Advantage capabilities. The capabilities support Army 2030 by enabling three Information Advantage Detachments, (USARPAC; USAREUR-AF; ARCYBER) to conduct Information Advantage Activities during competition, crisis, and conflict. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced          PE 0305251A / Cyberspace Operations Forces and Force Support Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4B.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604201A$$, $$Aircraft Avionics$$, $$rdte_army_ba5$$, $$asa_alt$$, 2026, 2696000, 21173000, 7171000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 15, "original_pe": "0604201A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element provides funding to support modification and development activities necessary to support Aircraft Avionics modernization requirements necessary to meet the evolving Army Avionics priorities. A portion of this funding line is directly aligned to the Assured Positioning, Navigation, and Timing (A-PNT) Army Modernization Priority. Tasks in this Program Element support research, development, and test efforts in the Engineering and Manufacturing Development phases of these systems. Alternate Position, Navigation, and Timing (ALT-PNT) capabilities, non-Global Positioning System (non-GPS), and/or complimentary Positioning, Navigation, and Timing (PNT) solutions will be studied and developed as standalone or blended navigation functions. Alternate Position, Navigation, and Timing (ALT-PNT) enables precise navigation and timing during Multidomain Operations (MDO) operations in the absence of Global Positioning System (GPS) by leveraging Alternate Navigation (ALT-NAV) and Vision Based Navigation (VBN) efforts and providing a secure and reliable fused PNT solution utilizing new and existing high-grade sensors available on manned aviation aircraft. ALT-PNT utilizes Modular Open System Architecture (MOSA) standards allowing rapid and affordable platform integration, adopting of new technologies, and adjustment to changes in adversarial capability. The Improved Data Modem (IDM) is a mission computer that requires software to provide functionality. The IDM is the common solution for digitizing Army Aviation and is fielded on every modernized, rotary-wing Army aircraft. IDM provides digital air-to-air and air-to-ground connectivity and transmission of air-to-air target data between IDM equipped aircraft using legacy radio and crypto equipment. IDM also serves as interface between aircraft mission computers, data capable radios, and Tactical Internet (TI). IDM manages Situational Awareness (SA) data, processes command and control messages, and incorporates protocols for sending and receiving mission command digital messages on the TI, Private Net, and Longbow Net using the protocols Air Force Application Program Development Net (AFAPD) and Variable Messaging Format (VMF). The IDM 401 requires updated technology to mitigate obsolescence and enable multi-core processing to meet requirements for air to ground communications. The IDM Open System REMAN (OSR) will serve as the steppingstone for a longer-term solution, the General-Purpose Computing Platform (GPCP). Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                  Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System             PE 0604201A / Aircraft Avionics Development & Demonstration (SDD) The Aviation Mission Common Server (AMCS) will become a General-Purpose Computing Platform (GPCP). The GPCP will provide a more capable, computing environment to process broader use cases and enable the Next Generation Command and Control (NGC2) on the Aviation fleet. The GPCP will utilize a Modular Open Systems Approach (MOSA) with a nonproprietary Open Systems Architecture (OSA) to keep pace with evolving threats in the Multi-Domain Battlefield. The GPCP will enable the hosting of software applications to communicate, navigate, sense, and deploy weapon systems across the Joint Force in support of future aviation operations. It will support the future Common Digital Backbone for the enduring and future Army Aviation fleets with the ability for further growth to host flight critical capabilities. The GPCP will begin development in FY28 and production in FY31. The Aviation Mission Planning System (AMPS) is a system used to conduct pre-mission and aircraft performance planning. It receives data from multiple sources and provides that data digitally to the aircraft to support aviation missions. AMPS is used for automated mission planning, risk assessment, and transfer of mission data to aviation platforms within an aviation unit. This includes route generation, performance planning, communications planning, terrain analysis, data transfer, and mission rehearsal. These efforts include development and testing of a new underlying architecture to support the move of Army Aviation Mission Planning from the current structure to one that supports synchronization both vertically and horizontally between aviation and ground forces. It will allow aircrews to continually plan and update route, threat, and performance data throughout all phases of an aviation mission. Development of a mobile aircraft performance planning/weight and balance calculator is currently underway and will be the first migration of AMPS capabilities to a mobile hardware agnostic environment. The AN/ARC-220 High Frequency (HF) Radio is a US Army rotary wing high frequency solution which is operational on over 2,400 Army helicopters (primarily CH-47, UH-60, and AH-64). Key capabilities are voice and data, automatic link establishment, text messaging, position reporting, and selective calling. It is also voice interoperable with standard ground HF systems in use today. Efforts include development of an Airborne Radio Control Manager (ARCM) driver to enhance the modernization of the AN/ARC-220 HF Radio.$$, NULL, 23891000, 27180000, 19438000, NULL, NULL, 101, $$RDTE - Vol 3 - Budget Activity 5A.pdf$$, NULL, FALSE, 6909000, 17696000, 30658000, 30658000, NULL, 30658000, 2833000, $$This PE provides funding to support modification and development activities necessary to support Aircraft Avionics modernization requirements to meet the evolving Army Avionics priorities in support of the National Defense and National Military strategies. A portion of this program element, project C97, is directly aligned to the Assured Positioning, Navigation, and Timing (A-PNT) Army Modernization Priority. Tasks in this Program Element support research, development, and test efforts in the Engineering and Manufacturing Development phases of these systems. Alternate Position, Navigation, and Timing (ALT-PNT) capabilities, non-Global Positioning System (non-GPS), and/or complimentary Positioning, Navigation, and Timing (PNT) solutions will be studied and developed as standalone or blended navigation functions. A portion of this program element, project VU3, supports the development of hardware and the continuous integration and continuous development/delivery of software to meet both legacy and future aircraft platform avionics software and hardware requirements. Efforts include supporting Next Generation Command and Control (NGC2) requirements specified in the infrastructure annex of the NGC2 Initial Capabilities Document, while also addressing both the Improved Data Modem (IDM) obsolescence and necessary hardware and software enhancements to support emerging Army requirements and evolve Aviation platform capabilities in alignment with Army Senior Leader priorities. To meet the NGC2 requirements as specified in the infrastructure annex of the NGC2 Initial Capabilities Document, specifically, a software control plane so the compute environment is agnostic to the hardware and hardware that meets the Open-Source Container Initiative, this project supports the development of the General-Purpose Computing Platform (GPCP) to address both current hardware and software obsolescence issues of the IDM and the insertion of critical capabilities. A portion of this program element, project VU3, in parallel to the GPCP efforts supports the continuous integration and continuous development/delivery of the IDM/ IDM Open Systems REMAN (OSR) Interoperability Software that requires upgrading to address emerging requirements, cyber security enhancements and additional capabilities to meet emerging Army requirements. A portion of this program element, project VU3, includes an FY26 Congressional Add for Bandwidth Enhanced - Common Data Link (BE-CDL) Mode 300 advanced networking and platform integration. This BE-CDL Mode 300 protected waveform initiative focuses on finalization of BE-CDL Mode 303 equipment for incorporation into Launched Effects (LE) and Uncrewed Aircraft System (UAS). This will be achieved by producing refined networked waveform firmware and software, sufficient airborne kits for networked LE usage flight testing, performing full network sized flight test, incorporate fixes based on National Security Agency (NSA) testing, and continued development of C5ISR Modular Open Suite of Standards (CMOSS) Mounted Form Factor (CMFF) based BE-CDL Mode 303 communications solutions for rotary wing Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                                   Date: April 2026 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System                 PE 0604201A / Aircraft Avionics Development & Demonstration (SDD) aircraft. These, and other key items will enable adoption of this critically necessary technology for use in contested electronic warfare areas in anti-access area denial (A2AD) battlespace.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604611A$$, $$JAVELIN$$, $$rdte_army_ba5$$, $$asa_alt$$, 2026, 9810000, 7541000, 10405000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 16, "original_pe": "0604611A", "page_header": "Department of the Army"}$$::jsonb, $$The Javelin Advanced Anti-Tank Weapon System-Medium (AAWS-M) is a man-portable, fire-and-forget, medium-range missile with enhanced situational awareness and precision direct-fire effects to defeat armored vehicles, fortifications, and soft targets in a range of military operations. Javelin has a high kill rate against a variety of targets at extended ranges under day/night, battlefield obscurants, adverse weather and multiple counter-measure conditions. The system's soft launch feature permits firing from a fighting position or an enclosure. Javelin uses a modular design to allow the system to evolve to meet changing threats and requirements via both software and hardware upgrades. The system consists of a reusable Command Launch Unit (CLU) with a built-in-test (BIT), and a modular missile encased in a disposable launch tube assembly. The system also includes training devices for tactical training and classroom training. Javelin's fire-and-forget technology allows the gunner to fire and immediately take cover, to move to another fighting position, or to reload. The Javelin provides enhanced lethality through the use of a tandem multi- purpose warhead which will defeat all known armor threats. It is effective against both stationary and moving targets. This system also provides defensive capability against attacking/hovering helicopters. The CLU can also be used as a stand-alone surveillance and target acquisition asset. Javelin can be adapted for use on a variety of platforms and remote weapon stations using the Javelin Vehicle Platform Adapter Kit (JVPAK). The Javelin weapon system is an Army-led, Acquisition Category (ACAT) IC Major Defense Acquisition Program (MDAP) that has joint interest with United States forces and international partners. Research, Development, Test & Evaluation (RDT&E) funding provides for system improvements in accordance with the Javelin Capabilities Production Document objectives and user priorities for future development. FY 2026 dollars in the amount of $9.810 million will continue Javelin system improvements to address emerging threats, improve engagement timeline, and increase lethality. The FY 2026 request was reduced by $0.247 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                 Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System         PE 0604611A / JAVELIN Development & Demonstration (SDD)$$, NULL, 10333000, 10411000, 10412000, NULL, NULL, 105, $$RDTE - Vol 3 - Budget Activity 5A.pdf$$, NULL, FALSE, 10025000, 9810000, 10217000, 10217000, NULL, 10217000, 10577000, $$The Javelin Advanced Anti-Tank Weapon System-Medium (AAWS-M) is a man-portable, fire-and-forget, medium-range missile with enhanced situational awareness and precision direct-fire effects to defeat armored vehicles, fortifications, and soft targets in a range of military operations. Javelin has a high kill rate against a variety of targets at extended ranges under day/night, battlefield obscurants, adverse weather and multiple counter-measure conditions. The system's soft launch feature permits firing from a fighting position or an enclosure. Javelin uses a modular design to allow the system to evolve to meet changing threats and requirements via both software and hardware upgrades. The system consists of a reusable Command Launch Unit (CLU) with a built-in-test (BIT), and a modular missile encased in a disposable launch tube assembly. The system also includes training devices for tactical training and classroom training. Javelin's fire-and-forget technology allows the gunner to fire and immediately take cover, to move to another fighting position, or to reload. The Javelin provides enhanced lethality through the use of a tandem multi- purpose warhead which will defeat all known armor threats. It is effective against both stationary and moving targets. This system also provides defensive capability against attacking/hovering helicopters. The CLU can also be used as a stand-alone surveillance and target acquisition asset. Javelin can be adapted for use on a variety of mounted platforms and remote weapon stations using the Javelin Vehicle Platform Adapter Kit (JVPAK). The Javelin weapon system is an Army-led, Acquisition Category (ACAT) IC Major Defense Acquisition Program (MDAP) that has joint interest with United States forces and international partners. Research, Development, Test & Evaluation (RDT&E) funding provides for system improvements in accordance with the Javelin Capabilities Production Document objectives and user priorities for future development. FY 2027 dollars in the amount of $10.217 million will continue Javelin system improvements to address emerging threats, improve engagement timeline, and increase lethality.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604622A$$, $$Family of Heavy Tactical Vehicles$$, $$rdte_army_ba5$$, $$peo_cscss$$, 2026, 47064000, 40175000, 34690000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 16, "original_pe": "0604622A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) aligns system development and demonstration of Heavy Tactical Vehicles (HTV) with Multi-Domain Operations (MDO) requirements to support combat and combat support missions to include line haul, local haul, and unit resupply. HTV trucks transport water, ammunition, and general cargo over all terrains and throughout the battle-space. Systems include the Heavy Expanded Mobility Tactical Truck (HEMTT), Palletized Load System (PLS), Heavy Equipment Transporter System (HETS), Enhanced Heavy Equipment Transporter System (EHETS), Line Haul, Heavy Dump Truck (HDT), medium tactical trailers including the Medium Equipment Trailer (MET), the family of flatbed semitrailers to include but not limited to the 40-Ton M870, 34-Ton M872 and the 25-Ton M172 that support multiple Army missions and the development and demonstration of enablers. Recovery systems such as the Modular Catastrophic Recovery System (MCRS) and other heavy wreckers, that rescue large wheeled and track vehicle platforms in severe off-road conditions are also included. Periodic evolutionary upgrade of survivability and crew protection as described in the Long Term Protection Strategy (LTPS) is supported by this PE for both the HTV family of vehicles and the Family of Medium Tactical Vehicles (FMTV). Arctic and Demand Reduction Initiatives are also supported by this PE. The Common Tactical Truck (CTT) program is a Family of Vehicles (FoV) that will replace the M915 Line Haul Tractor (LHT), Palletized Load System (PLS), and Heavy Expanded Mobility Tactical Truck (HEMTT) by leveraging best commercial practices and mature commercially available technology, including Predictive Logistics, Advanced Driver Assistance Systems (ADAS), and autonomy ready, resulting in lower procurement costs through economies of scale. The FY 2026 cost of the Common Tactical Truck (CTT) Middle Tier of Acquisition effort is $11.3 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. The Leader Follower (LF) funding line supports the Autonomous Transport Vehicle-System (ATV-S) effort that equips Tactical Wheeled Vehicles with autonomous behaviors. Additionally, the capability gives convoy commanders flexibility to leverage the six levels of automated driving that range from Level 0 (Fully Manual) to Level 5 (Fully Autonomous), and any combination therein to conduct convoy operations. Autonomous driving behaviors enable increased operational efficiency of tactical wheeled vehicles resulting in an increase of sustainment throughput while reducing Soldier exposure to hostile threats. The FY 2026 cost of the Autonomous Transport Vehicle-System (ATV-S) Middle Tier of Acquisition effort is $16.8 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System          PE 0604622A / Family of Heavy Tactical Vehicles Development & Demonstration (SDD) In accordance with Section 1815 of the FY 2008 National Defense Authorization Act (P.L. 110-181), this item is necessary for use by the active and reserve components of the Armed Forces for homeland defense missions, domestic emergency responses, and providing military support to civil authorities. The FY 2026 request was reduced by $0.277 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.209 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 33039000, 33145000, 33200000, NULL, NULL, 106, $$RDTE - Vol 3 - Budget Activity 5A.pdf$$, NULL, FALSE, 33424000, 38664000, 43003000, 43003000, NULL, 43003000, 33532000, $$This Program Element (PE) aligns system development and demonstration of Heavy Tactical Vehicles (HTV) with Multi-Domain Operations (MDO) requirements to support combat and combat support missions to include line haul, local haul, and unit resupply. HTV trucks transport water, ammunition, and general cargo over all terrains and throughout the battle-space. Systems include the Heavy Expanded Mobility Tactical Truck (HEMTT), Palletized Load System (PLS), Heavy Equipment Transporter System (HETS), Enhanced Heavy Equipment Transporter System (EHETS), Line Haul, Heavy Dump Truck (HDT), medium tactical trailers including the Medium Equipment Trailer (MET), the family of flatbed semitrailers to include but not limited to the 40-Ton M870, 34-Ton M872 and the 25-Ton M172 that support multiple Army missions and the development and demonstration of enablers. Recovery systems such as the Modular Catastrophic Recovery System (MCRS) and other heavy wreckers, that rescue large wheeled and track vehicle platforms in severe off-road conditions are also included. Periodic evolutionary upgrade of survivability and crew protection as described in the Long Term Protection Strategy (LTPS) is supported by this PE for both the HTV family of vehicles and the Family of Medium Tactical Vehicles (FMTV). Arctic Initiatives are also supported by this PE. The Common Tactical Truck (CTT) program is a Family of Vehicles (FoV) that will replace the M915 Line Haul Tractor (LHT), Palletized Load System (PLS), and Heavy Expanded Mobility Tactical Truck (HEMTT) by leveraging best commercial practices and mature commercially available technology, including Predictive Logistics, Advanced Driver Assistance Systems (ADAS), and autonomy ready, resulting in lower procurement costs through economies of scale. The total cost of the CTT Middle Tier of Acquisition Rapid Prototyping effort is $58.8 million RDT&E from FY 2023 to FY 2026. The remainder of the CTT MTA Rapid Prototyping is fully funded across the Future Years Defense Program. The Leader Follower (LF) funding line supports the Autonomous Transport Vehicle-System (ATV-S) effort that equips Tactical Wheeled Vehicles with autonomous behaviors. Additionally, the capability gives convoy commanders flexibility to leverage the six levels of automated driving that range from Level 0 (Fully Manual) to Level 5 (Fully Autonomous), and any combination therein to conduct convoy operations. Autonomous driving behaviors enable increased operational efficiency of tactical wheeled vehicles resulting in an increase of sustainment throughput while reducing Soldier exposure to hostile threats. The total cost of the Autonomous Transport Vehicle-System (ATV-S) Middle Tier of Acquisition Rapid Prototyping effort is $93.214 million from FY 2023 to FY 2027. The ATV-S MTA-RP program is fully funded across the Future Years Defense Program. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System          PE 0604622A / Family of Heavy Tactical Vehicles Development & Demonstration (SDD) In accordance with Section 1815 of the FY 2008 National Defense Authorization Act (P.L. 110-181), this item is necessary for use by the active and reserve components of the Armed Forces for homeland defense missions, domestic emergency responses, and providing military support to civil authorities.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L034$$, $$Small & Medium UUV$$, $$proc_navy_1810_ba1$$, $$navsea$$, 2026, 91372000, 87828000, 118247000, NULL, $${"page": 95, "ba_num": "01", "source": "p1_fy26", "ba_name": "Ships support equipment", "line_no": "34", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "01", "appr": "OPN", "title": "P-1 Line 32", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 1719, "p1_line_num": 32, "fy27_total_K": 1719}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"disc_K": 3790, "li_num": 32, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/OPN_BA1_Book.txt"}, "fy26t_qty": null, "fy26d_cost": 91372000, "fy26r_cost": 0, "ident_code": ""}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 48780000, 7000000, 1719000, 1719000, 0, 1719000, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA1_Book.pdf$$) ON CONFLICT DO NOTHING;
