INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L037$$, $$LSD Midlife & Modernization$$, $$proc_navy_1810_ba1$$, $$peo_ships$$, 2026, 237728000, 154561000, 188254000, NULL, $${"page": 95, "ba_num": "01", "source": "p1_fy26", "ba_name": "Ships support equipment", "line_no": "37", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "01", "appr": "OPN", "title": "P-1 Line 34", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 110955, "p1_line_num": 34, "fy27_total_K": 110955}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"disc_K": 7000, "li_num": 34, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/OPN_BA1_Book.txt"}, "fy26t_qty": null, "fy26d_cost": 203442000, "fy26r_cost": 34286000, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, 826469000, NULL, NULL, NULL, FALSE, 49044000, 4079000, 110955000, 110955000, 0, 110955000, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA1_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604710A$$, $$Night Vision Systems - Eng Dev$$, $$rdte_army_ba5$$, $$asa_alt$$, 2026, 351274000, 145135000, 139309000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 16, "original_pe": "0604710A", "page_header": "Department of the Army"}$$::jsonb, $$A portion of this funding line is directly aligned to the Army Soldier Lethality Modernization Priority in support of situational awareness for the Close Combat Soldier. This program element provides night vision/reconnaissance, surveillance and target acquisition technologies required for United States defense forces to engage enemy forces twenty-four hours a day under conditions of degraded visibility due to darkness, adverse weather, battlefield obscurants, foliage and man-made structures. These developments and improvements to high performance night vision electro-optics, radar, laser, and thermal systems and integration of related multi-sensor suites will enable near to long range target acquisition, identification and engagement to include significant fratricide reduction, which will improve battlefield command and control in "around-the-clock" combat operations. Project BQ6 focuses on transitioning demonstrated technologies that bring improvements to provide Soldiers and Squads a single platform for increased lethality, mobility, and situational awareness to achieve overmatch against our current and future adversaries. Funded efforts will accelerate the implementation of components, Heads Up Display (HUD) improvements, terrain shared coordinate data and processing, algorithms including machine learning/artificial intelligence, human machine integration, and demonstrations in support of the next generation augmented vision and situational awareness. Efforts will provide rapid decision making and targeting capabilities with the integration of external video and data sources such as weapon sights, air and ground platforms, unmanned air and ground assets, and other data sources enabled by edge computing devices, advanced network services, and open resilient architecture. This project will provide data driven analytics to optimize unit performance and enhance lethality and to enable training in a mixed reality environment. The FY 2026 cost of the Integrated Visual Augmentation System (IVAS) Middle Tier of Acquisition effort is $85.5 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. This project includes costs for efforts associated with edge computing devices, movement of information and high-level processing, integration, and interface of products with the Soldiers' head, body, weapon, and platforms. To enable such data movement and integration, this project funds the establishment and baselining of a situational Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                     Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System              PE 0604710A / Night Vision Systems - Eng Dev Development & Demonstration (SDD) awareness architecture. Funding for this project aligns with the Army's Continuous Transformation priorities and National Defense Strategy. This project supports the Soldier Lethality Cross Functional Team. Project DI5 begins development on Future Advanced Long-range Common Optical/Netted-fires Sensor (FALCONS). FALCONS is the replacement for the Long Range Advanced Scout Surveillance System (LRAS3) and Fire Support Sensor System (FS3) providing an unmatched capability to detect, identify, and locate threats in all battlefield conditions at extended ranges, in all conditions, locate targets with the fidelity required to employ numerous Army and Joint precision, near precision, and conventional munitions, and have a networked capability to provide direct links for Scouts and Fire Supporters to streamline the kill chain. Project L67 develops, improves and miniaturizes high performance electro-optics, thermal and laser systems. It provides for systems integration of related multi- sensor suites to enable near to long-range target acquisition and engagement as well as improved battlefield command and control in around-the-clock combat operations. It also adapts demonstrated technologies that bring improvements to the mounted and dismounted Soldiers' equipment and capabilities. This project develops or enhances equipment that provides the individual Soldier's day and/or night situational awareness and individual targeting capability. This project includes cost associated with efforts for the development, integration and interface of products on Soldiers head, body and weapons. Funding in this project supports the Army Future's Command Situational Awareness Strategy. Funding in this project aligns with the Army's priorities in support of the National Defense Strategy. Project L70 supports the 3rd Generation Forward Looking Infrared (3GEN FLIR) B-Kit program, which incorporates the next generation of forward-looking infrared technologies. The 3GEN FLIR program provides a common 3GEN FLIR B-Kit for integration into US Army FLIR sensor systems in accordance with the approved Improved Forward Looking Infrared (I-FLIR) Capability Development Document (CDD). When integrated in platform sensor packages, 3GEN FLIR technology enhances the warfighters' survivability and lethality through increased identification range performance, while enabling the detection of difficult or obscured targets and faster threat detection through automated processes. Executing Army guidance to implement advancements in digital processing and artificial intelligence has positioned 3GEN FLIR as the lead sensor to provide the Army's path forward for AI/ML capabilities for ground platforms. The 3GEN FLIR B-Kit program is key to the maintenance of the Army's FLIR industrial base. Project L79 supports the Joint Effects Targeting System (JETS) program, which addresses the one-man, hand-held precision targeting gap identified by the Fires Center of Excellence (FCoE). JETS is a lightweight, handheld system that will provide the single dismounted observer with a common, enhanced day and night thermal capability to rapidly acquire, accurately locate, positively identify, and precisely designate targets. JETS can interface with existing and future Forward Entry Systems (FESs) and operate in environments where Global Positioning System (GPS) capabilities are degraded or denied and will integrate the Military-code (M- Code) GPS receivers. This project will address continued development and integration of improved precision targeting components to reduce size, weight, power, and cost of systems for dismounted precisions Fires mission. Funding in this project aligns with the Army's priorities in support of the National Defense Strategy. The FY 2026 request was reduced by $6.832 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                          Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System         PE 0604710A / Night Vision Systems - Eng Dev Development & Demonstration (SDD)$$, NULL, 152456000, 136056000, 128433000, NULL, NULL, 111, $$RDTE - Vol 3 - Budget Activity 5A.pdf$$, NULL, FALSE, 134589000, 461274000, 418427000, 418427000, NULL, 418427000, 129718000, $$A portion of this funding line is directly aligned to the Army Modernization Priority in support of situational awareness for the Soldier. This program element provides night vision, surveillance, target acquisition mission planning, data visualization technologies required for United States defense forces to engage enemy forces twenty-four hours a day under conditions of degraded visibility due to darkness, adverse weather, battlefield obscurants, foliage and man-made structures. These developments and improvements to high performance situational awareness systems, night vision electro-optics, radar, laser, and thermal systems and integration of related multi-sensor suites will enable near to long range target acquisition, identification and engagement to include significant fratricide reduction, which will improve battlefield command and control in "around-the-clock" combat operations. Project BQ6 focuses on transitioning demonstrated technologies that bring improvements to provide a modular, fused digital awareness system that enhances lethality, mobility, and situational awareness for dismounted Soldiers to achieve overmatch against our current and future adversaries. Funded efforts will drive competition with multiple vendors, establish a modular open system architecture for major components, accelerate the implementation of components, and improve thermal and low light sensor suites, terrain shared coordinate data and processing, algorithms including machine learning/artificial intelligence, human machine integration, and demonstrations in support of the next generation augmented vision and situational awareness capabilities. Efforts will provide rapid decision making and targeting capabilities with the integration of external video and data sources such as weapon sights, air and ground platforms, unmanned air and ground assets, and other data sources enabled by edge computing devices, advanced network services, and open resilient architecture. This project includes costs for efforts associated with edge computing devices, movement of information and high-level processing, integration, and interface of products/ capabilities with the Soldier as a platform. To enable such data movement and integration, this project funds the establishment and baselining of a Squad Architecture (SQD-A). SQD-A will increase lethality and survivability of the Close Combat Force through the development of operationally informed use cases and vignettes, in line with the Army Transformation Initiative and Situational Awareness Strategy. Funding for this project aligns with the Army's Continuous Transformation priorities and National Defense Strategy. This project supports the Futures and Concepts (FCC) Maneuver Future Capability Directorate. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                                     Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System                PE 0604710A / Night Vision Systems - Eng Dev Development & Demonstration (SDD) Project DI5 Future Advanced Long-range Common Optical/Netted-fires Sensor (FALCONS). FALCONS is the replacement for the Long Range Advanced Scout Surveillance System (LRAS3) and Fire Support Sensor System (FS3) providing an unmatched capability to detect, identify, and locate threats in all battlefield conditions at extended ranges, in all conditions, locate targets with the fidelity required to employ numerous Army and Joint precision, near precision, and conventional munitions, and have a networked capability to provide direct links for Scouts and Fire Supporters to streamline the kill chain. Project L67 develops, improves and miniaturizes high performance electro-optics, thermal and laser systems. It provides for systems integration of related multi- sensor suites to enable near to long-range target acquisition and engagement as well as improved battlefield command and control in around-the-clock combat operations. It also adapts demonstrated technologies that bring improvements to the mounted and dismounted Soldiers' equipment and capabilities. This project develops or enhances equipment that provides the individual Soldier's day and/or night situational awareness and individual targeting capability. This project includes cost associated with efforts for the development, integration and interface of products on Soldiers head, body and weapons. Funding in this project supports the Army Future's Command Situational Awareness Strategy. Funding in this project aligns with the Army's priorities in support of the National Defense Strategy. Project L70 supports the 3rd Generation Forward Looking Infrared (3GEN FLIR) B-Kit program, which incorporates the next generation of forward-looking infrared technologies. The 3GEN FLIR program provides a common 3GEN FLIR B-Kit for integration into US Army FLIR sensor systems in accordance with the approved Improved Forward Looking Infrared (I-FLIR) Capability Development Document (CDD). When integrated in platform sensor packages, 3GEN FLIR technology enhances the warfighters' survivability and lethality through increased identification range performance, while enabling the detection of difficult or obscured targets and faster threat detection through automated processes. Executing Army guidance to implement advancements in digital processing and artificial intelligence has positioned 3GEN FLIR as the lead sensor to provide the Army's path forward for AI/ML capabilities for ground platforms. The 3GEN FLIR B-Kit program is key to the maintenance of the Army's FLIR industrial base. Project L79 supports the Joint Effects Targeting System (JETS) program and the development of Handheld Fires (HHF), which addresses the one-man, hand-held precision targeting gap identified by the Fires Center of Excellence (FCoE). JETS is a lightweight, handheld system that will provide the single dismounted observer with a common, enhanced day and night thermal capability to rapidly acquire, accurately locate, positively identify, and precisely designate targets. The Handheld Fires System will be an advanced precision targeting system incorporating improved target acquisition sensors and optics, improved targeting sensors, targeting algorithms, and a Military Code (M-Code) Global Positing System (GPS) receiver while reducing size, weight, and power requirements. The total cost of the Integrated Visual Augmentation Systems IVAS 1.2, Rapid Prototyping Middle Tier of Acquisition (RP MTA) effort is $798.10 million RDT&E from FY 2022 to FY 2027. The total cost of the Soldier Borne Mission Command (SBMC) Rapid Prototyping Middle Tier of Acquisition (RP MTA) effort is $429.8 million RDT&E from FY 2025 to FY 2027. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0604710A / Night Vision Systems - Eng Dev Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604742A$$, $$Constructive Simulation Systems Development$$, $$rdte_army_ba5$$, $$asa_alt$$, 2026, 7790000, 29854000, 30097000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 16, "original_pe": "0604742A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element funds the development of constructive and wargame simulations used to realistically train commanders and their battle staffs on today's complex battlefield conditions. Project 361, Intelligence Simulation Systems, funds the development of the Intelligence Electronic Warfare Tactical Proficiency Trainer (IEWTPT). IEWTPT is a Non- System Training Device (NSTD) which supports home-station training by simulating and stimulating Military Intelligence (MI) organic or surrogate equipment. It enables sustainment of critical individual and collective MI tasks/skills and is the core of the U.S. Army Intelligence Center of Excellence (USAICoE) Military Intelligence (MI) holistic training strategy supporting mission command, targeting, and MI Soldier readiness. IEWTPT provides a realistic simulation intelligence target environment for multi-intelligence disciplines such as All Source Analysis, Signals Intelligence (SIGINT), Imagery Intelligence (IMINT), Open-Source Intelligence (OSINT), Human Intelligence (HUMINT), Geospatial Intelligence (GEOINT) and electronic warfare (EW) systems. IEWTPT provides training for analyst and system operators to exploit intelligence data during training, just as they would in "Real World" operations. The IEWTPT Technical Control Cell (TCC) is composed of two components: the Lower Enclave (LE) which supports exercise planning and development and drives the All Source and GEOINT (and emerging EW) training tasks and the Upper Enclave (UE) which supports all SIGINT related training and operates at the Top Secret / Sensitive Compartmented Information (TS/SCI) classification level. Project 362, Joint Land Component Constructive Training Capability (JLCCTC) supports Army Title X training worldwide for Army Commanders and their staff at Mission Training Complexes (MTCs), Training and Doctrine Command (TRADOC) facilities, and other customer locations. JLCCTC trains Commanders and their staff in Decisive Actions to include offensive, defensive, stability, and civil support operations. JLCCTC is a software modeling and simulation capability that contributes to Army Training Mission Area by providing appropriate levels of modeling and simulation resolution and fidelity to support unit collective and combined arms training. JLCCTC provides a composable federation configurable to any combination of models and simulations, as required by training exercise intent/design. JLCCTC provides accurate representations of tactically and operationally relevant land warfare operations executed in a contemporary Joint operating environment/context and in support of Army Training and Readiness. Next Generation Constructive (NGC) provides the constructive training environment to sufficiently train large scale combat operations (LSCO) in multi-domain operations, to include, joint, cyber, space, and maritime. NGC enables collective training to be conducted for Corps and down, while increasing efficiency in planning, preparing, and executing training events. Funding will continue development of the Intel, Sustainment, Cyber, and Maneuver/ Protection Warfighting Functions, STE Core Service in support of NGC development in accordance with validated STE-SW ICD FY24, AvSE development/integration; Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                            R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System      PE 0604742A / Constructive Simulation Systems Development Development & Demonstration (SDD) Development, Security, and Operations, DEVSECOPS implementation/execution; Technical Assessments, Soldier Touch Points (STPs), test planning events, and migration to a cloud environment.$$, NULL, 6384000, 6077000, 6127000, NULL, NULL, 115, $$RDTE - Vol 3 - Budget Activity 5A.pdf$$, NULL, FALSE, 28616000, 7790000, 5618000, 5618000, NULL, 5618000, 6445000, $$This PE funds the development of constructive and wargame simulations used to realistically train commanders and their battle staffs on today's complex battlefield conditions. Project 361, Intelligence Simulation Systems, funds the development of the Intelligence Electronic Warfare Tactical Proficiency Trainer (IEWTPT). IEWTPT is a Non- System Training Device (NSTD) which supports home-station training by simulating and stimulating Military Intelligence (MI) organic or surrogate equipment. It enables sustainment of critical individual and collective MI tasks/skills and is the core of the U.S. Army Intelligence Center of Excellence (USAICoE) Military Intelligence (MI) holistic training strategy supporting mission command, targeting, and MI Soldier readiness. IEWTPT provides a realistic simulation intelligence target environment for multi-intelligence disciplines such as All Source Analysis, Signals Intelligence (SIGINT), Imagery Intelligence (IMINT), Open-Source Intelligence (OSINT), Human Intelligence (HUMINT), Geospatial Intelligence (GEOINT) and electronic warfare (EW) systems. IEWTPT provides training for analyst and system operators to exploit intelligence data during training, just as they would in "Real World" operations. The IEWTPT Technical Control Cell (TCC) is composed of two components: the Lower Enclave (LE) which supports exercise planning and development and drives the All Source and GEOINT (and emerging EW) training tasks and the Upper Enclave (UE) which supports all SIGINT related training and operates at the Top Secret / Sensitive Compartmented Information (TS/SCI) classification level. Project 362, Joint Land Component Constructive Training Capability (JLCCTC) supports Army Title X training worldwide for Army Commanders and their staff at Mission Training Complexes (MTCs), Training and Doctrine Command (TRADOC) facilities, and other customer locations. JLCCTC trains Commanders and their staff in Decisive Actions to include offensive, defensive, stability, and civil support operations. JLCCTC is a software modeling and simulation capability that contributes to Army Training Mission Area by providing appropriate levels of modeling and simulation resolution and fidelity to support unit collective and combined arms training. JLCCTC provides a composable federation configurable to any combination of models and simulations, as required by training exercise intent/design. JLCCTC provides accurate representations of tactically and operationally relevant land warfare operations executed in a contemporary Joint operating environment/context and in support of Army Training and Readiness. Next Generation Constructive (NGC) provides the constructive training environment to sufficiently train large scale combat operations (LSCO) in multi-domain operations, to include, joint, cyber, space, and maritime. NGC enables collective training to be conducted for Corps and down, while increasing efficiency in planning, preparing, and executing training events. Funding will continue development of the Intel, Sustainment, Cyber, and Maneuver/ Protection Warfighting Functions, STE Core Service in support of NGC development in accordance with validated STE-SW ICD FY24, AvSE development/integration; Development, Security, and Operations, DEVSECOPS implementation/execution; Technical Assessments, Soldier Touch Points (STPs), test planning events, and migration to a cloud environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0604742A / Constructive Simulation Systems Development Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5A.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0205778A$$, $$Guided Multiple-Launch Rocket System (GMLRS)$$, $$rdte_army_ba7$$, $$asa_alt$$, 2026, 33307000, 70808000, 20590000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "army", "page_num": 23, "original_pe": "0205778A", "page_header": "Department of the Army"}$$::jsonb, $$Guided Multiple-Launch Rocket System (GMLRS) rockets are surface-to-surface artillery rockets fired from the Multiple Launch Rocket System (MLRS) and High Mobility Artillery Rocket System (HIMARS) launchers. GMLRS rockets provide 24/7, all-weather precision fires to engage both area and point targets at short, medium, and long ranges. The GMLRS Program currently consists of multiple variants: GMLRS Unitary utilizes a 200-pound high explosive warhead to engage point targets with limited collateral damage; GMLRS Dual Purpose Improved Conventional Munition (DPICM) cluster munition to engage area or imprecisely located targets; and GMLRS Alternative Warhead (AW) which has been developed as a non-cluster munition to engage the same target set as GMLRS DPICM. GMLRS DPICM Production was terminated in response to the June 2008 Department of Defense (DoD) Cluster Munitions Policy. GMLRS Unitary and AW are currently in full rate production. The GMLRS program will continue to leverage ongoing Government and Industry research and development efforts to extend range, increase survivability, and enhance lethality. The GMLRS program includes a modification that extends the maximum range (Extended Range (ER) GMLRS) and is capable of carrying both the Unitary and AW warheads. The GMLRS program also includes an Enhanced Alternative Warhead (EAW) modification that will service the existing GMLRS and ER-GMLRS AW targets while adding capability against light and medium armored vehicles. The GMLRS program is a component of an integrated fires development effort that includes survivability, resiliency, and effectiveness improvements against advanced threats from near-peer adversaries. These efforts include integration with an evolving common fires mission command, common development tools and processes, and annual test and evaluation to provide data to support program assessments and progress toward closure of performance gaps. GMLRS is part of the Army Transformation Initiative. The munitions developed under this funding line are part of the MLRS Family of Munitions (MFOM) that are deployed by the M142 HIMARS and M270 MLRS launchers. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 7: Operational       PE 0205778A / Guided Multiple-Launch Rocket System (GMLRS) Systems Development Project DL1: Completes ER-GMLRS system development and qualification with redesigned side mounted proximity sensor. DL1 also funds the Enhanced Alternative Warhead (EAW) system development and qualification. EAW system level qualification, integration, and test completes initially with standard range GMLRS rockets prior to integration of EAW into ER-GMLRS. Project EG2: The U.S. Army initially funded the development of the Guided Multiple Launch Rocket System (GMLRS) Alternative Warhead (AW) increment under this project code. Project EG3: Guided MLRS funding line supports GMLRS enhancements including development of Assured Position, Navigation, and Timing (APNT). The FY 2026 request was reduced by $0.043 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, NULL, 83055000, 161250000, 99589000, NULL, NULL, 225, $$RDTE - Vol 4 - Budget Activity 7.pdf$$, NULL, FALSE, 19838000, 33307000, 73639000, 73639000, NULL, 73639000, 81925000, $$Guided Multiple-Launch Rocket System (GMLRS) rockets are surface-to-surface artillery rockets fired from the Multiple Launch Rocket System (MLRS) and High Mobility Artillery Rocket System (HIMARS) launchers. GMLRS rockets provide 24/7, all-weather precision fires to engage both area and point targets at short, medium, and long ranges. The GMLRS Program currently consists of multiple variants: GMLRS Unitary utilizes a 200-pound high explosive warhead to engage point targets with limited collateral damage; GMLRS Dual Purpose Improved Conventional Munition (DPICM) cluster munition to engage area or imprecisely located targets; and GMLRS Alternative Warhead (AW) which has been developed as a non-cluster munition to engage the same target set as GMLRS DPICM. GMLRS DPICM Production was terminated in response to the June 2008 DoW Cluster Munitions Policy. GMLRS Unitary and AW are currently in full rate production. The ER-GMLRS Unitary entered production in FY 2024 and the ER-GMLRS AW variant is planned to enter production in FY 2027. The GMLRS program will continue to leverage ongoing government and industry research and development efforts to extend range, increase survivability, and enhance lethality. The GMLRS program includes a modification that extends the maximum range (Extended Range (ER) GMLRS) and can be produced with either the Unitary or AW warhead. The GMLRS program also includes an Enhanced Alternative Warhead (EAW) modification that will service the existing GMLRS and ER-GMLRS AW targets while adding capability against light and medium armored vehicles. The GMLRS program is a component of an integrated fires development effort that includes survivability, resiliency, and effectiveness improvements against advanced threats from near-peer adversaries. These efforts include integration with an evolving common fires mission command, common development tools and processes, and annual test and evaluation to provide data to support program assessments and progress toward closure of performance gaps. The munitions developed under this funding line are part of the MLRS Family of Munitions (MFOM) that are deployed by the M142 HIMARS and M270 MLRS launchers. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                            Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 7: Operational       PE 0205778A / Guided Multiple-Launch Rocket System (GMLRS) Systems Development Project DL1: Completes ER-GMLRS system development and qualification with redesigned side mounted proximity sensor. DL1 also funds the Enhanced Alternative Warhead (EAW) system development and qualification. EAW system level qualification, integration, and test completes initially with standard range GMLRS rockets prior to integration of EAW into ER-GMLRS. Project EG3: Guided MLRS funding line supports GMLRS enhancements including development of Assured Position, Navigation, and Timing (APNT).$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 7.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604804A$$, $$Logistics and Engineer Equipment - Eng Dev$$, $$rdte_army_ba5$$, $$asa_alt$$, 2026, 50194000, 58554000, 46829000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 17, "original_pe": "0604804A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) provides system development, demonstration, and test and evaluation funding for various projects. This PE includes the development of watercraft, military tactical and assault bridging, material handling equipment, construction equipment, engineer support and maintenance equipment, soldier support equipment (to include shelter systems, environmental control, field service equipment, camouflage systems and aerial delivery equipment), water purification equipment, petroleum distribution equipment, and mobile electric power. The FY 2026 request was reduced by $0.097 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.247 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                              Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System              PE 0604804A / Logistics and Engineer Equipment - Eng Dev Development & Demonstration (SDD)$$, NULL, 65282000, 58954000, 42641000, NULL, NULL, 120, $$RDTE - Vol 3 - Budget Activity 5B.pdf$$, NULL, FALSE, 45302000, 61194000, 65238000, 65238000, NULL, 65238000, 34311000, $$This Program Element (PE) provides system development, demonstration, and test and evaluation funding for various projects. This PE includes the development of watercraft, military tactical and assault bridging, material handling equipment, construction equipment, engineer support and maintenance equipment, advanced manufacturing, soldier support equipment (to include shelter systems, environmental control, field service equipment, camouflage systems and aerial delivery equipment), water purification and distribution equipment, petroleum distribution equipment, and mobile electric power and distribution systems. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0604804A / Logistics and Engineer Equipment - Eng Dev Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5B.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604805A$$, $$Command, Control, Communications Systems - Eng Dev$$, $$rdte_army_ba5$$, $$peo_c3t$$, 2026, 63725000, 47965000, 92300000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 17, "original_pe": "0604805A", "page_header": "Department of the Army"}$$::jsonb, $$Project 593, Joint Battle Command - Platform (JBC-P) FY 2026 funding was realigned to PE 0604818A / Army Tactical Command & Control Hardware & Software, Projects EJ6 and EK9, in support of in support of the Army's NGC2 initiative to modernize C2 systems, for the Data and Application Layers. The capability being developed under this project remains critical and relevant to the Warfighter. This capability, along with its resources and requirement will transition under the overarching NGC2 capability to eliminate stove-piping, reduce duplication of effort, and provide capability within a single NGC2 core architecture. Project 593 includes the Mounted Mission Command Family of Systems (MMC FoS), including MMC-Transport (MMC-T) and MMC-Software (MMC-S). The MMC-T program provides next-generation transceivers, encryption devices, and satellite communication waveforms (which are hosted in the transceiver). MMC-T provides a significant improvement over the existing BFT-2 capability by enabling smart routing across multiple network paths (Geosynchronous Equatorial Orbit (GEO), Low-Earth Orbit (LEO), and Line of Sight (LoS)) to mitigate risks posed by denied environments or signal jamming. New encryption devices provide protections against electronic warfare (EW) and cyber-attacks. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                               Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0604805A / Command, Control, Communications Systems - Eng Dev Development & Demonstration (SDD) The MMC-S program replaces JBC-P software on vehicles and in command posts by providing next generation C2/SA software that offers simplicity, intuitiveness, and enhanced capabilities over the legacy software. MMC-S utilizes the Tactical Assault Kit (TAK), a government-owned application, to enable convergence of Warfighting Functions and utilizes an agile Continuous Integration/Continuous Delivery (CI/CD) approach for software development. Project DH4, Command, Control, Communications, Computers, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Modular Open Suite of Standards (CMOSS) Mounted Form Factor (CMFF) delivers Software Defined Radio (SDR) cards, Cryptographic Subsystem (CSS) cards, Digital Radio Heads (DRH) and Victory Audio Adapter (VAX) required by the CMOSS Mounted Form Factor (CMFF) Abbreviated Capability Development Document (A-CDD) for the Ground and Aviation's tactical communication requirements. CMFF provides simultaneous transmission and reception of multiple waveforms across multiple channels in a single or multiple SDR card(s) integrated in the CMFF chassis with NSA certifiable CSS and interoperable with the Digital Radio Head. CMFF will introduce a Blocking Strategy roadmap. Block 1 starts with TSM and future blocks will build upon Block 1; Block 2 includes but is not limited to Single Channel Ground and Airborne Radio System (SINCGARS), Air Traffic Control (ATC), Warrior Robust Enhanced Network (WREN), initial Cryptographic Subsystem Card (CSS), Digital Radio Head (DRH), Victory Audio Adapter (VAX) and future advanced networking waveforms; Block 3 includes but is not limited to Mobile User Objective System (MUOS), Link-16, Second generation Anti-jam Tactical UHF Radio for NATO (SATURN), Demand Assigned Multiple Access (DAMA) and final CSS and DRH, and future advanced networking waveforms. Project DH5, CMFF Chassis funds Mounted Common Infrastructure (MCI) Chassis development, integration of capability cards into the chassis, testing and integration of the system solution into target platforms. CMOSS is a defined suite of open architecture and Army standards that facilitate the reduction of system size, weight, and power-cooling (SWaP-C) and ensure commonality across multiple platforms. Sharing of hardware and software components is enabled within the MCI Chassis. CMFF will help move the implementation of C5ISR/Electronic Warfare (EW)) capabilities away from costly and complex separate "stove-piped boxes" on individual platforms. The use of open standards will make it simpler and more cost-effective to upgrade capabilities or keep pace with commercial technology by eliminating complex integration challenges, lack of competition, and proprietary interfaces. The CMFF capability can only be realized when paired with the development of associated capability cards for integration into the chassis and peripheral enabling devices, such as antennae and appropriate user interfaces. Other programs are responsible for funding and developing the capability cards and peripheral devices; the CMFF MCI Chassis program is responsible for chassis development, system of system integration of the capability cards and external resources into the chassis and platform integration. Project DL9, the Assured Positioning, Navigation and Timing (APNT) project funds the development of CMFF APNT Card. The CMFF APNT Card provides the APNT solutions required by the CMFF A-CDD and distributes APNT data to capability cards within the CMFF chassis and external systems as needed. The CMFF APNT card provides trusted PNT by utilizing multiple PNT sources and leveraging open architectures. The CMFF APNT Card prototyping, and software development will be conducted in accordance with Modular Open Systems Approach (MOSA) (Reference House Report 116-442, 2020). The CMFF APNT Card complies with the PNT Reference Architecture and MOSA compliant hardware; CMOSS and software frameworks (PNT Operating System (pntOS)), to ensure a plug and play capability. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                 Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System              PE 0604805A / Command, Control, Communications Systems - Eng Dev Development & Demonstration (SDD)$$, NULL, 6030000, 5205000, 5227000, NULL, NULL, 121, $$RDTE - Vol 3 - Budget Activity 5B.pdf$$, NULL, FALSE, 88931000, 63725000, 5541000, 5541000, NULL, 5541000, 5239000, $$Project 593, Joint Battle Command - Platform (JBC-P) FY 2026 funding was realigned to PE 0604818A / Army Tactical Command & Control Hardware & Software, Projects EJ6 and EK9, in support of in support of the Army's NGC2 initiative to modernize C2 systems, for the Data and Application Layers. The capability being developed under this project remains critical and relevant to the Warfighter. This capability, along with its resources and requirement will transition under the overarching NGC2 capability to eliminate stove-piping, reduce duplication of effort, and provide capability within a single NGC2 core architecture. Project 593 includes the Mounted Mission Command Family of Systems (MMC FoS), including MMC-Transport (MMC-T) and MMC-Software (MMC-S). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                             Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System              PE 0604805A / Command, Control, Communications Systems - Eng Dev Development & Demonstration (SDD) The MMC-T program provides next-generation transceivers, encryption devices, and satellite communication waveforms (which are hosted in the transceiver). MMC-T provides a significant improvement over the existing BFT-2 capability by enabling smart routing across multiple network paths (Geosynchronous Equatorial Orbit (GEO), Low-Earth Orbit (LEO), and Line of Sight (LoS)) to mitigate risks posed by denied environments or signal jamming. New encryption devices provide protections against electronic warfare (EW) and cyber-attacks. The MMC-S program replaces JBC-P software on vehicles and in command posts by providing next generation C2/SA software that offers simplicity, intuitiveness, and enhanced capabilities over the legacy software. MMC-S utilizes the Tactical Assault Kit (TAK), a government-owned application, to enable convergence of Warfighting Functions and utilizes an agile Continuous Integration/Continuous Delivery (CI/CD) approach for software development. Project DH4, Command, Control, Communications, Computers, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Modular Open Suite of Standards (CMOSS) Mounted Form Factor (CMFF) delivers Software Defined Radio (SDR) cards, Cryptographic Subsystem (CSS) cards, Digital Radio Heads (DRH) and Victory Audio Adapter (VAX) required by the CMOSS Mounted Form Factor (CMFF) Abbreviated Capability Development Document (A-CDD) for the Ground and Aviation's tactical communication requirements. CMFF provides simultaneous transmission and reception of multiple waveforms across multiple channels in a single or multiple SDR card(s) integrated in the CMFF chassis with NSA certifiable CSS and interoperable with the Digital Radio Head. CMFF will introduce a Blocking Strategy roadmap. Block 1 starts with TSM and future blocks will build upon Block 1; Block 2 includes but is not limited to Single Channel Ground and Airborne Radio System (SINCGARS), Air Traffic Control (ATC), Warrior Robust Enhanced Network (WREN), initial Cryptographic Subsystem Card (CSS), Digital Radio Head (DRH), Victory Audio Adapter (VAX) and future advanced networking waveforms; Block 3 includes but is not limited to Mobile User Objective System (MUOS), Link-16, Second generation Anti-jam Tactical UHF Radio for NATO (SATURN), Demand Assigned Multiple Access (DAMA) and final CSS and DRH, and future advanced networking waveforms. This PE received $21.006 million due to a Rapid Acquisition Authority adjudicated requirement in FY 2025. This PE received $30.945 million due to a Rapid Acquisition Authority adjudicated requirement in FY 2026. The total cost of the CMFF RC Middle Tier of Acquisition (MTA) effort is $96.1 million RDT&E from FY25 to FY29. Project DH5, CMFF Chassis funds Mounted Common Infrastructure (MCI) Chassis development, integration of capability cards into the chassis, testing and integration of the system solution into target platforms. CMOSS is a defined suite of open architecture and Army standards that facilitate the reduction of system size, weight, and power-cooling (SWaP-C) and ensure commonality across multiple platforms. Sharing of hardware and software components is enabled within the MCI Chassis. CMFF will help move the implementation of C5ISR/Electronic Warfare (EW)) capabilities away from costly and complex separate "stove-piped boxes" on individual platforms. The use of open standards will make it simpler and more cost-effective to upgrade capabilities or keep pace with commercial technology by eliminating complex integration challenges, lack of competition, and proprietary interfaces. The CMFF capability can only be realized when paired with the development of associated capability cards for integration into the chassis and peripheral enabling devices, such as antennae and appropriate user interfaces. Other programs are responsible for funding and developing the capability cards and peripheral devices; the CMFF MCI Chassis program is responsible for chassis development, system of system integration of the capability cards and external resources into the chassis and platform integration. Approved Requirements: the CMOSS Mounted Form Factor Abbreviated Capabilities Development Document (A-CDD) 4 January 2021 and the Mounted Assured PNT System Capability Development Document 12 September 2020. Project DL9, the Assured Positioning, Navigation and Timing (APNT) project funds the development of CMFF APNT Card. The CMFF APNT Card provides the APNT solutions required by the CMFF A-CDD and distributes APNT data to capability cards within the CMFF chassis and external systems as needed. The CMFF APNT Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                               Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0604805A / Command, Control, Communications Systems - Eng Dev Development & Demonstration (SDD) card provides trusted PNT by utilizing multiple PNT sources and leveraging open architectures. The CMFF APNT Card prototyping, and software development will be conducted in accordance with Modular Open Systems Approach (MOSA) (Reference House Report 116-442, 2020). The CMFF APNT Card complies with the PNT Reference Architecture and MOSA compliant hardware; CMOSS and software frameworks (PNT Operating System (pntOS)), to ensure a plug and play capability with M-Code and ALTNAV. Funding has been realigned out of this line to support the Army's Next Generation Command and Control (NGC2) initiative.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5B.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605224A$$, $$Multi-Domain Intelligence$$, $$rdte_army_ba5$$, $$asa_alt$$, 2026, 34844000, 23605000, 18913000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 19, "original_pe": "0605224A", "page_header": "Department of the Army"}$$::jsonb, $$Multi-Domain Intelligence (MDI) is the Army Intelligence Enterprise's overarching modernization framework that drives modernization priorities to field a ready Army Intelligence team supporting Mission Command against all threats in Multi-Domain Operations (MDO). The MDI framework will allow intelligence professionals to execute the intelligence cycle and associated doctrinal functions with increased speed, precision, and accuracy in both competition and conflict. The framework's emphasis on modernizing sensors, enhancing data management practices, and advancing analytical tradecraft through technology will support commanders' ability to make sound, timely decisions, placing friendly forces in a position of decisive advantage. CK4: The Intelligence Applications and Integration (Intel Apps) Program is a software-centric, platform agnostic ACAT III Program that will provide the Next Generation intelligence capabilities aligned to the National Defense Strategy and Multi-Domain Operations by enabling intelligence professionals to work through the intelligence cycle with increased speed, precision and accuracy. The Intel Apps Program will synchronize applications (including All Source, Intelligence Support to Targeting, Weather Operational Effects, Information Collection Management, and Single Intelligence capabilities (HUMINT, SIGINT, IMINT) to be integrated into the Mission Command Platform architecture, including Next Generation Command and Control, onto dedicated Intelligence Edge Nodes where applicable, extending Army enterprise intelligence from the Army Intelligence Data Platform to the Tactical Edge. This line will also be used for the initiation of the AIDP SW ICD project, with initial award and development. DD8: The MDI funding will be used to enable Capability Drop 2 (CD2)/Army Intelligence Data Platform (AIDP) to incorporate user feedback in a Continuous Integration/ Continuous Deployment (CI/CD) environment. This environment will also implement a Development Security Operations (DEVSECOPS) approach for generating user feedback into system enhancements/improvements. This line will continue to inform and support Army Intelligence integration with the Next Generation Command and Control systems at the strategic and operational levels. DD9: The MDI funding will also be used for the modernization of Army Geospatial hardware and software capabilities. The funding will be used to continue the establishment of the Army Integrated Geospatial Enterprise Capability (AIGEC) and initiate activities for the One World Terrain - Operational (OWT-O). AIGEC and OWT-O build the foundational layer for Army products that utilize Geospatial capabilities including Next Generation Command and Control and the Army Intel Data Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                         Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System          PE 0605224A / Multi-Domain Intelligence Development & Demonstration (SDD) Platform. The Army will focus on leveraging commercial items and proven technologies to the maximum extent possible to reduce costs and maximize superior capabilities to be delivered to warfighters.$$, NULL, 51239000, 48478000, 49971000, NULL, NULL, 152, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, 18913000, 44844000, 49594000, 49594000, NULL, 49594000, 52492000, $$Multi-Domain Intelligence (MDI) is the Army Intelligence Enterprise's overarching modernization framework that drives modernization priorities to field a ready Army Intelligence team supporting Mission Command against all threats in Multi-Domain Operations (MDO). The MDI framework will allow intelligence professionals to execute the intelligence cycle and associated doctrinal functions with increased speed, precision, and accuracy in both competition and conflict. The framework's emphasis on modernizing sensors, enhancing data management practices, and advancing analytical trade craft through technology will support commanders' ability to make sound, timely decisions, placing friendly forces in a position of decisive advantage. DD8: FY27 funding in the amount of $34.830M supports development of the Army Intelligence Data Platform (AIDP). AIDP enables situational development, understanding, and intelligence support to targeting from strategic and operational echelons to the tactical edge. It sets the Army's intelligence data foundation and enables intelligence analysis at echelon, using data from all domains. All Theater Armies use AIDP as the common intelligence picture (CIP) to directly feed their Combatant Commands' common operating pictures (COP). AIDP utilizes agile software development processes to deliver user-prioritized incremental capability releases. DD9: FY27 funding in the amount of $14.764M supports the modernization of Army Geospatial hardware and software capabilities. The funding will be used to continue the development of the Army Geo Data Fabric (AGDF) and the NextGen GEOINT Workstation (NGWS), both of which align to the Army Integrated Geospatial Enterprise Capability (AIGEC) requirements. The funding will also be used to initiate software development activities for One World Terrain - Operational (OWT-O). AIGEC and OWT-O deliver the Geospatial capabilities that provide Army systems with authoritative geospatial data. Further details available in classified quad chart. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                            Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0605224A / Multi-Domain Intelligence Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5D.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605232A$$, $$Hypersonics EMD$$, $$rdte_army_ba5$$, $$cft_lrpf$$, 2026, 513027000, 772174000, 469775000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 19, "original_pe": "0605232A", "page_header": "Department of the Army", "fy26_v182_disc_K": 501530, "fy26_v182_supp_K": 19401, "fy26_v182_total_K": 520931, "fy26_v182_note_name": "Hypersonics EMD", "fy26_v182_source_file": "RDTE - Vol 3 - Budget Activity 5D.txt", "fy26_v182_source_line": 2159}$$::jsonb, $$This funding supports the fielding of critical enabling technologies and capabilities that address near-term and mid-term threats. It is directly aligned to the Army Long Range Precision Fires modernization priority. This Program Element includes the development and fielding of the LRHW to defeat Anti Access/Area Denial (A2/AD) capabilities, suppress adversary Long Range Fires, and engage other high payoff/time critical targets. The Army is working collaboratively with the Navy in the development of the LRHW and conducting Joint Flight Campaign (JFC) tests to evaluate overall system performance with added focus on missile body and payload performance. The LRHW system consists of the All Up Rounds (AUR) plus Canister (AUR+C) which includes the Common Hypersonic Glide Body (CHGB) with the Navy 34.5 inch booster, the Battery Operations Center (BOC) for command and control (C2), and the Transporter Erector Launcher (TEL). An LRHW Battery contains eight AUR+Cs, one BOC, and four TELs each carrying two AUR+Cs. Additionally, the LRHW will use a modified version of an existing C2 network, the Advanced Field Artillery Tactical Data System (AFATDS). Continued RDT&E investment is required beyond the initial prototype Battery to meet objective requirements and to maintain overmatch against evolving threats. Through implementation of planned Technology Insertions (TIs), the program will increase capability, upgrade the system to address obsolescence, and upgrade platform, launcher, and weapon control systems with mature technologies from Science and Technology (S&T). Qualification testing is also required to validate these developmental changes. Soldier operational testing of new capability is also required. The FY 2026 cost of the Long Range Hypersonic Weapon (LRHW) Ground Support Equipment (GSE) Middle Tier of Acquisition effort is $17.9 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. The FY 2026 request was reduced by $1 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                            Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System           PE 0605232A / Hypersonics EMD Development & Demonstration (SDD)$$, NULL, 357065000, 455003000, 525149000, NULL, NULL, 154, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, 452628000, 520931000, 446616000, 446616000, NULL, 446616000, 571647000, $$This funding supports the fielding of critical enabling technologies and capabilities that address near-term and mid-term threats. It is directly aligned to the Army Long Range Precision Fires modernization priority. This Program Element includes the development and fielding of the Long Range Hypersonic Weapon (LRHW) to defeat Anti Access/Area Denial (A2/AD) capabilities, suppress adversary Long Range Fires, and engage other high payoff/time critical targets. The Army is working collaboratively with the Navy in the development of the LRHW and conducting Joint Flight Campaign (JFC) tests to evaluate overall system performance with added focus on missile body and payload performance. The LRHW system consists of the All Up Rounds (AUR) plus Canister (AUR+C) which includes the Common Hypersonic Glide Body (CHGB) with the Navy 34.5 inch booster, the Battery Operations Center (BOC) for command and control (C2), and the Transporter Erector Launcher (TEL). An LRHW Battery contains eight AUR+Cs plus a reload of eight, one BOC, and four TELs each carrying two AUR+Cs. Additionally, the LRHW will use a modified version of an existing C2 network, the Advanced Field Artillery Tactical Data System (AFATDS). Continued RDT&E investment is required beyond the initial prototype Battery to meet objective requirements and to maintain overmatch against evolving threats. Through implementation of planned Technology Insertions (TIs), the program will increase capability, upgrade the system to address obsolescence, and upgrade platform, launcher, and weapon control systems with mature technologies from Science and Technology (S&T). Qualification testing is also required to validate these developmental changes. Soldier operational testing of new capability is also required. The total cost of the LRHW Ground Support Equipment (GSE) Middle Tier of Acquisition Rapid Fielding (RF) effort is $1,311 million from FY23 to FY28, including RDT&E ($538M) and procurement ($773.1M) of prototype units. The remainder of the LRHW GSE MTA RF is fully funded across the Future Years Defense. FY 2027 funding provides funding of test assets and tactical AUR+Cs; TI development and integration; test activities and events; and systems engineering and program management. FY27 funding includes $10M for cost reduction production changes developed by USW(A&S) Innovation Capability and Modernization (ICAM) investments. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0605232A / Hypersonics EMD Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5D.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605233A$$, $$Accessions Information Environment (AIE)$$, $$rdte_army_ba5$$, $$asa_alt_alt$$, 2026, 32710000, 26362000, 32265000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 19, "original_pe": "0605233A", "page_header": "Department of the Army"}$$::jsonb, $$The Accessions Information Environment (AIE) is transforming the Army's recruiting and accessions process by introducing a fully integrated enterprise system that incorporates modern business practices and enhanced recruiting abilities. This modernization enables recruiters to spend more time in the field engaging potential recruits, less time managing paperwork or pulling data from legacy systems and allows recruiters to operate efficiently and effectively with mobile devices. Built on Salesforce Public Sector Solutions and hosted in Amazon Web Services (AWS) Cloud, AIE provides a configurable, scalable solution for Army-wide talent acquisition. AIE streamlines the accessioning process for enlisted soldiers, commissioned officers, in-service personnel, and direct commissions. It provides eight core capabilities, including lead management, prospecting, interviewing, processing, pay and incentives, intelligence, marketing, and training. The program serves as the Army's official accessions system, enhancing coordination among various HR agencies to improve efficiency and the overall soldier experience. To enhance software development and deployment, AIE transitioned from traditional development methods to an Agile framework, incorporating human-centered design and security-focused processes. Partnering with early adopters from the National Guard, AIE released prototype software to gather user feedback. In early FY25, it deployed an initial version that introduced Lead Management and Prospecting capabilities, setting the foundation for continued development to support the Army's enlisted mission. FY 2026 Base dollars in the amount of $32.710 million support continued developmental configuration of AIE's solutions to meet the Enlisted Recruiting Mission, with an estimated deployment in 2QFY26. This includes ongoing incremental planning sessions, Agile development team operations, technical program management, interface development, cybersecurity, systems engineering test and continuous analysis of alternative approaches to meet evolving solution requirements. Following the deployment of the Enlisted Recruiting Mission, AIE will continue to address enhancements and backlog development. These activities set the conditions for the development of follow-on mission sets: In-Service and Direct Commission. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System             PE 0605233A / Accessions Information Environment (AIE) Development & Demonstration (SDD)$$, NULL, 38575000, 23297000, 7604000, NULL, NULL, 155, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, 37305000, 32710000, 33770000, 33770000, NULL, 33770000, 7680000, $$The Accessions Information Environment (AIE) is transforming the Army's recruiting and accessions process by introducing a fully integrated enterprise system that incorporates modern business practices and enhanced recruiting abilities. This modernization enables recruiters to spend more time in the field engaging potential recruits, less time managing paperwork or pulling data from legacy systems and allows recruiters to operate efficiently and effectively with mobile devices. Built on Salesforce Public Sector Solutions and hosted in Amazon Web Services (AWS) Cloud, AIE provides a configurable, scalable solution for Army-wide talent acquisition. AIE streamlines the accessioning process for enlisted soldiers, commissioned officers, in service personnel, and direct commissions. It provides eight core capabilities, including lead management, prospecting, interviewing, processing, pay and incentives, intelligence, marketing, and training. The program serves as the Army's official accessions system, enhancing coordination among various HR agencies to improve efficiency and the overall soldier experience. To enhance software development and deployment, AIE transitioned from traditional development methods to an Agile framework, incorporating human-centered design and security-focused processes. Partnering with early adopters from the National Guard, AIE released the Minimum Viable Product (MVP) 1QFY25 to gather user feedback. In FY26, AIE continues development of the Enlisted Recruiting Mission MVP and has expanded user adoption through Soldier Center-Design Exercise events. AIE deployed Leads and Prospect capabilities to the Indianapolis Recruiting Battalion in 1QFY26 and accelerated development of ROTC mission to support Army CIO's priorities. During FY27, AIE will conduct scaled deployment of approximately 22K Enlisted Recruiting users while continuously delivering enhancements for the Enlisted Mission under the overall Accessions Support effort. Additionally, start planning and development of ROTC, In Service and Direct Commission missions. FY 2027 dollars in the amount of $33.770 million supports scaled deployment of approximately 22K Enlisted Recruiting users while continuously delivering enhancements for the Enlisted Mission under the overall Accessions Support effort. Additionally, the funding supports planning and development of ROTC, In Service and Direct Commission missions. Development activities include ongoing incremental planning sessions, Agile development team operations, technical program management, interface development, cybersecurity, systems engineering test and continuous analysis of alternative approaches to meet evolving solution requirements. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                          Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System          PE 0605233A / Accessions Information Environment (AIE) Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5D.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605235A$$, $$Strategic Mid-Range Capability$$, $$rdte_army_ba5$$, $$cft_lrpf$$, 2026, 186304000, 255121000, 182823000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 19, "original_pe": "0605235A", "page_header": "Department of the Army"}$$::jsonb, $$This funding line is directly aligned to the Army Long-Range Precision Fires Modernization Priority. The Mid-Range Capability (MRC) Weapon System leverages other service technologies and integration of common hardware, software, and mutually supporting test events. MRC provides ground support equipment to include a Battery Operations Center (BOC) with support vehicles, launcher Payload Deployment System (PDS), and reload support to fire a mix of missiles capable of engaging strategic targets at mid-range distances. MRC leverages existing Standard Missile-6 (SM-6) and Tomahawk technology to include command and control systems and missile variants to provide a responsive, highly accurate capability designed for high value targets. The MRC is a ground launched, long-range precision fires offensive weapon system to defeat Anti-Access/Area-Denial (A2/AD) threats and other high value targets to enable warfighter dominance in support of Long-Range Precision Fires, Multi- Domain Operations, and Joint Force objectives. Four MRC batteries will be developed and fielded to Long-Range Fires Battalions 1 through 4. The initial prototype MRC battery was developed and fielded by Rapid Capabilities and Critical Technologies Office and three additional MRC batteries by Program Executive Office Missiles and Space utilizing RDT&E funds. The first MRC prototype weapon system battery, delivered in FY 2023 as the first unit of issue, provided residual combat capability consisting of one BOC, four launchers, one BOC Support Vehicle, and a reload capability. Also delivered was the basic load of missiles consisting of eight Tomahawk Block V and eight SM-6 Block IA. Follow-on delivery of the next three batteries (Battery 2 through 4) utilizes RDT&E under a Middle Tier of Acquisition Rapid Prototyping pathway. FY 2026 funding continues all aspects of developing MRC technology upgrades. Provides the prototype systems with iterative survivability, reliability, and operational effectiveness improvements based on evolving system requirements to ensure operational effectiveness. Base funding allows for continued development of system improvements utilizing evaluation, design, prototyping, testing, engineering, configuration management, component and system-level qualification activities, operational demonstrations, operator/maintainer training development, and integration of all functional support to ensure operational safety and effectiveness of all fielded and in- development systems meet performance needs. The Army is redesigning the BOC with a smaller footprint to support greater battlefield maneuverability and survivability. The redesigned BOC will feature a smaller form factor to enhance mobility, transportability, and interoperability with other system components aligned to mission requirements. This effort includes design, integration, and testing activities to ensure the improved BOC meets established system objectives and maintains operational effectiveness. The redesigned BOC will be implemented with the delivery of Battery 4. The FY 2026 cost of the Mid-Range Capability (MRC) Air Launched Effects (ALE) Middle Tier of Acquisition effort is $143 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System          PE 0605235A / Strategic Mid-Range Capability Development & Demonstration (SDD) The FY 2026 request was reduced by $3.465 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.$$, NULL, 80305000, 46362000, 18253000, NULL, NULL, 156, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, 176150000, 182128000, 82550000, 82550000, NULL, 82550000, 18649000, $$This funding line is directly aligned to the Army Long-Range Precision Fires modernization priority. The Mid-Range Capability (MRC) weapon system leverages other service technologies and integration of common hardware, software, and mutually supporting test events. The MRC is a ground launched, long-range precision fires offensive weapon system to defeat Anti-Access/Area-Denial (A2/AD) threats and other high value targets to enable warfighter dominance in support of Long-Range Precision Fires, Multi-Domain Operations, and Joint Force objectives. MRC provides ground support equipment to include a Battery Operations Center (BOC) with support vehicles, launcher Payload Deployment System, and reload support to fire a mix of missiles capable of engaging strategic targets at mid-range distances. MRC leverages existing Standard Missile-6 (SM-6) and Tomahawk technology to include command and control systems and missile variants to provide a responsive, highly accurate capability designed for high value targets. The first MRC prototype weapon system battery, delivered in FY 2023 as the first unit of issue, provided residual combat capability consisting of one BOC with support vehicles, four launchers, and a reload capability. Also delivered was the basic load of missiles consisting of eight Tomahawk Block V and eight SM-6 Block IA. Follow-on annual delivery of the next three batteries (Battery 2 through 4) utilizes RDT&E under a Middle Tier of Acquisition Rapid Prototyping pathway. Battery 2 was delivered in 4Q2024, Battery 3 was delivered in 4Q2025, and Battery 4's anticipated delivery date from contractor is 4Q2026. The Army is developing a BOC with a reduced footprint (RBF) to support greater battlefield maneuverability and survivability. The RBF will feature a smaller form factor to enhance mobility, transportability, and interoperability with other system components aligned to mission requirements. This effort includes design, integration, Common Autonomous Multi-Domain Launcher (CAML) integration, and testing activities to ensure the RBF meets established system objectives and maintains operational effectiveness. The RBF will be incorporated into MRC system with the fielding of Battery 4. FY 2027 funding in the amount of $82.550 million continues all aspects of developing MRC technology upgrades. Upgrades provide the prototype systems with iterative survivability, reliability, and operational effectiveness improvements based on evolving system requirements to ensure operational effectiveness. Base funding allows for continued development of system improvements utilizing evaluation, design, prototyping, testing, engineering, configuration management, component and system-level qualification activities, operational demonstrations, operator/maintainer training development, and integration of all functional support to ensure operational safety and effectiveness of all fielded and in-development systems to meet performance needs. Battery Operation Center (BOC) enhancements lead to the finalized system design of the Reduced BOC Footprint (RBF). System enhancements incorporated with RBF prepare the MRC system to interface with future Army munition launch capabilities. The total cost of the Mid-Range Capability (MRC) Middle Tier of Acquisition effort is $591.1 million RDT&E from FY 2024 to FY 2026. The MRC Middle Tier of Acquisition is fully funded across the Future Years Defense Program. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0605235A / Strategic Mid-Range Capability Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5D.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605236A$$, $$Integrated Tactical Communications$$, $$rdte_army_ba5$$, $$peo_c3t$$, 2026, 22732000, 18065000, 12224000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 19, "original_pe": "0605236A", "page_header": "Department of the Army"}$$::jsonb, $$This funding line supports the Army Next Generation Command Control (NGC2) initiative to modernize Command and Control (C2) systems, Infrastructure layer. The Tactical Communication Network Evaluation (TCNE) project supports the Army's Command and Control (C2) Infrastructure by demonstrating and integrating networked systems at scale, aligned with the Army's modernization priorities. TCNE designs network architectures based on continuous warfighter feedback, focusing on the division as the unit of maneuver. This project utilizes continuous test and evaluation, incorporating Soldier feedback for Verification & Validation, to ensure range expectations, system performance, and interoperability are met. FY26 funding will support network architecture development through engineering analysis, lab-based testing, cyber electromagnetic activities, and user evaluations. This enables continuous transformation of the Army Network, achieving modernization "in contact" and creating a seamless, unified communication network. Testing will also address and mitigate cyber vulnerabilities within the Army's Tactical Network. The FY 2026 request was reduced by $0.898 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, NULL, NULL, NULL, NULL, NULL, NULL, 157, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, 11778000, 22732000, NULL, NULL, NULL, NULL, NULL, $$Project CQ1 / Tactical Communication Network Evaluation (TCNE) in FY 2027 and beyond was realigned to PE 0605333A/C2 Infrastructure, Project C2G, Modular C2 Infrastructure as part of a new funding structure for the Next Generation Command and Control (NGC2) investment to modernize Command and Control (C2) systems for the Infrastructure Layer. This funding line supports the Army Next Generation Command Control (NGC2) initiative to modernize operational Command and Control (C2) systems, Infrastructure layer. The Tactical Communication Network Evaluation (TCNE) project supports the Army's Command and Control (C2) Infrastructure by demonstrating and integrating networked systems at scale, aligned with the Army's modernization priorities. TCNE continuously and simultaneously designs, tests, and validates multiple Army network architecture baselines integrating current and emerging network technologies. These designs are based on continuous warfighter, institutional, and product owner feedback, focusing on the division as the unit of maneuver. This project utilizes continuous test and evaluation, incorporating Soldier feedback for verification & validation, to ensure system and network performance, and interoperability are met. Funding has been realigned out of this line to support the Army's Next Generation Command and Control (NGC2) initiative.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5D.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605244A$$, $$Joint Reduced Range Rocket (JR3)$$, $$rdte_army_ba5$$, $$asa_alt$$, 2026, 28893000, 0, 13565000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 19, "original_pe": "0605244A", "page_header": "Department of the Army"}$$::jsonb, $$The Joint Reduced Range Rocket (JR3) is a replacement for the Low Cost Reduced Range Practice Rocket (LCRRPR). LCRRPR is the only live training rocket that supports the annual qualification and pre-deployment requirements for Active and National Guard High Mobility Artillery Rocket System (HIMARS) and MLRS launcher units. JR3 is required because the remaining inventory of launch pod containers and motors is insufficient to support LCRRPR production beyond FY 2030. FY 2026 funding in the amount of $28.893M continues the prototyping and development of the JR3. The munitions developed under this funding line are part of the MLRS Family of Munitions (MFOM) that are deployed by the M142 HIMARS and M270 MLRS launchers.$$, NULL, 23051000, 18031000, 3823000, NULL, NULL, 160, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, 13070000, 28893000, 16014000, 16014000, NULL, 16014000, NULL, $$The Joint Reduced Range Rocket (JR3) is a replacement for the Low Cost Reduced Range Practice Rocket (LCRRPR). LCRRPR is the only live training rocket that supports the annual qualification and pre-deployment requirements for Active and National Guard High Mobility Artillery Rocket System (HIMARS) and MLRS launcher units. JR3 is required because the remaining inventory of launch pod containers and motors is insufficient to support LCRRPR production beyond FY 2030. The total cost of the JR3 Middle Tier of Acquisition Rapid Prototyping (MTA RP) effort is $115.7 million RDT&E from FY 2025 to FY 2030. FY 2027 funding continues rapid prototyping with flight demonstrations and initiates qualification of the JR3. The munitions developed under this funding line are part of the MLRS Family of Munitions (MFOM) that are deployed by the M142 HIMARS and M270 MLRS launchers.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5D.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605275A$$, $$Electronic Warfare Systems Development$$, $$rdte_army_ba5$$, $$asa_alt$$, 2027, 0, 0, 0, NULL, $${}$$::jsonb, NULL, NULL, 141576000, 151695000, 59898000, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 59202000, 99691000, 99691000, NULL, 99691000, 60760000, $$The FY 2027 funding in the amount of $99.691 million supports the Electronic Warfare Agile Systems Development encompassing engineering, manufacturing, and software development for systems to plan, manage, detect, interpret, and shape the Electromagnetic Spectrum (EMS) and its use by friendly and hostile forces. The systems developed under this program provide the Army a means to see their own emissions preventing electronic fratricide, helping shape the electronic operating environment, and increasing Soldier and Command Post (CP) survivability. This program also provides timely rapid reprogramming of mission software supporting evolving Electronic Attack capabilities and supports information dissemination for Army supported, Joint and allied services. Together these systems enable understanding and control of the EMS for US Forces. Project Code A94 - Navigation Warfare (NAVWAR) provides Commanders and Soldiers with indications and warnings to Positioning, Navigation, and Timing (PNT) users that their navigation and timing may be compromised by jamming or spoofing. The system will detect, identify, and locate sources of PNT interference allowing Command and Control (C2) systems to display areas affected by interference, and provide actionable information necessary to implement measures to mitigate or eliminate the threat. The overall goal of NAVWAR Attack operations is to preserve PNT overmatch for friendly forces by creating a denied, degraded and/or disrupted operating environment for adversaries while opening windows of PNT superiority for friendly forces. NAVWAR Attack links in Fires, Aviation, and Electronic Warfare communities, producing outcomes that support Army NAVWAR dominance, informing NAVWAR Situational Awareness of effects in the PNT radio frequency spectrum. NAVWAR Attack will streamline these efforts, providing NAVWAR Attack effects and tools to the Commander to shape the electromagnetic operating environment. NAVWAR Attack aligns with the Multi-Domain Operations (MDO) concept and the Army Operations Concept by providing globally responsive arms teams with the ability to present multiple dilemmas to the enemy, limits enemy options and exploits the enemy's weaknesses. Approved Requirements: NAVWAR Attack Abbreviated Capabilities Development Document (A-CDD) 09 September 2022. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                               Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0605275A / Electronic Warfare Systems Development Development & Demonstration (SDD) Project Code A95 / Army Reprogramming Analysis Team (ARAT): The ARAT EW enterprise supports the tactical Commander by providing timely rapid reprogramming of mission software and information dissemination for the Army. ARAT supports integrated reprogramming of target acquisition, target engagement, platform survivability systems, and Aircraft Survivability Equipment (ASE). The ARAT rapid-reprogramming EW enterprise supports tactical requirements and readiness for deployed aircraft and ground-based terrestrial systems. ARAT identifies and analyzes threat signature changes which affect EW systems; determines the impact of observed signature changes; develops new mission software solutions to adapt the system to the threat changes; disseminates the mission software; and provides methods to upload the new mission software into the affected EW systems. Project Code A96 / Integrated Electronic Warfare Systems: Electromagnetic warfare (EW) capability gaps pose growing risks to the Army operational effectiveness, requiring strategic investments in next-generation solutions. Investment in developing advanced countermeasures and integration of artificial intelligence with advanced analytics are required to maintain operational superiority, as adversaries continue to advance their own EW technologies and tactics. Funding is intended to support the development of a Next-Generation modular, scalable multi-mission. EW suite of capabilities for a broad range of modern radio frequency-controlled threats. Efforts include the development and integration of new and existing techniques, as well as targeted hardware and software upgrades to improve threat identification, reduce response time, and increase overall mission effectiveness. These investments directly support Transformation in Contact (TiC) objectives and comply with relevant Presidential Directives, ensuring alignment with broader defense modernization priorities. Project Code A97 / Counter Surveillance Reconnaissance (CSR): The CSR Abbreviated Capabilities Development Document (A-CDD) was signed on 8 January 2024. We are chartered to develop a family of terrestrial EW effectors to counter space-based surveillance threats. CSR non-kinetic effects will disrupt enemy kill chains by protecting and concealing friendly maneuver. CSR will provide three distinct classified counter-space surveillance Lines of Effort (LOE) and mission planner software to orchestrate CSR non-kinetic effects. Further advocacy for CSR capabilities exists in Joint Emergent Operational Needs Statement (JEONS), Operational Needs Statements (ONS), and Combatant Command Integrated Priority Lists. The total cost of the Counter Surveillance Reconnaissance Middle Tier of Acquisition effort is $422,574 million from FY2027 to FY2031. The CSR program is fully funded across the Future Years Defense Program (FYDP). Project Code A98 / Spectrum Situational Awareness System (S2AS): S2AS supports Army key modernization initiatives by allowing commanders to sense and see themselves in the Electro- Magnetic Spectrum (EMS), preventing electronic fratricide, helping shape the electronic operating environment, and increasing Command Post (CP) survivability. Operationally S2AS allows commanders to determine and impact their visibility to enemy fire chain. S2AS is a dedicated EMS situational awareness management system that provides the Commander with real time EMS Situational Awareness to support Emissions Control (EMCON) decisions, Electromagnetic Interference (EMI) Resolution, and detect/warn operations centers of unauthorized or intentional sources of interference on today's complex battlefield. S2AS will employ sophisticated hardware and software to strengthen the capabilities of the Army and ensuring resilience against potential adversarial threats. S2AS will address current and future EMS challenges, ensuring awareness and secure use of the EMS. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0605275A / Electronic Warfare Systems Development Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5D.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605345A$$, $$Unmanned Aerial Systems Launched Effects Systems Development$$, $$rdte_army_ba5$$, $$asa_alt$$, 2027, 0, 0, 0, NULL, $${"fy26_v182_disc_K": 357529, "fy26_v182_supp_K": 15000, "fy26_v182_total_K": 372529, "fy26_v182_note_name": "Unmanned Aerial Systems Launched Effects Systems Development", "fy26_v182_source_file": "RDTE - Vol 3 - Budget Activity 5D.txt", "fy26_v182_source_line": 8081}$$::jsonb, NULL, NULL, 664264000, 562211000, 363923000, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 372529000, 816433000, 816433000, NULL, 816433000, 365652000, $$This capability portfolio provides support to the Army's UAS Priority to deliver cutting-edge technology and rapidly evolving critical capabilities. Project A56 - This effort was realigned from PE 0609345A/ Project A46 beginning FY 2027 and continues work previously performed under that PE. Long Range Precision Munition (LRPM) is the lethal variant of the Launched Effects (LE) Family of Systems which provide a range of capabilities through variations of platforms, payloads, and mission systems. LE provides tactical and operational flexibility through collaboration of heterogeneous groups of LE launched from multiple domains (land and air) in conjunction with other manned platforms, C2, unmanned systems, and sensors throughout the operational environment. The ability to interoperate and coordinate with other LE systems at long ranges and adapt to changing threats is a core concept of the Launched Effects Abbreviated Capability Development Document validated in June 2024. The primary target set for LRPM is Integrated Air Defense Systems. LRPM will provide Army Aviation and Ground Forces with a precise long range munition system to rapidly respond in a combat environment to improve the lethality and stand-off of Warfighters and aviation platforms in an Anti- Access Area Denial (A2AD) and positioning, navigation, and timing (PNT) denied environment. The total cost of the LRPM Middle Tier of Acquisition (MTA) Rapid Prototyping (RP) effort is $122.5 million RDT&E from FY24 to FY29. The LRPM MTA-RP is fully funded across the Future Years Defense Program. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                                 Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System              PE 0605345A / Unmanned Aerial Systems Launched Effects Systems Development Development & Demonstration (SDD) Project A58 - Lethal Semi-Autonomous Aerial Unmanned System - Engineering Development: Mobile Brigade Combat Teams (MBCTs) lack adequate organic capabilities at echelon to apply immediate, point, long range, and direct fire effects to destroy tanks, light armored vehicles, hardened targets, targets in defilade, and personnel targets, while producing minimal collateral damage in complex terrain in all environmental conditions. Development will focus on the Fire Control Stations (FCS), All-Up Round (AUR), and System Architecture. System Architecture will include integrating with Soldier Borne Mission command (SBMC), Next Generation Command and Control (NGC2) and complete Universal Vehicle Control (UVC) compliance and integration. Develop technology for incorporation into the CDD update, for the enduring program, and conduct tech enhancements from current global conflicts. The funding contained within this budget line and project will be used to conduct evaluations of technologies and capabilities in the loitering munitions capability space, hardware and system architecture engineering and integration activities, and testing and evaluation activities. In addition, LASSO is supporting Transformation in Contact (TiC) in support of Indo-Pacific efforts to expand prepositioned stocks and increase deployments and exercises to support strategic presence in the region. The total cost of the Low Altitude Stalking and Strike Ordinance (LASSO) Middle Tier of Acquisition (MTA) effort is $209.4 million RDT&E from FY25 to FY29. Project A59 - Soldier Borne Sensor (SBS): The SBS is a small unmanned aerial vehicle. The SBS provides a near term solution to three Army War-fighting Challenges at the Infantry Squad level: develop situational understanding, conduct air-ground reconnaissance, and conduct joint combined arms maneuver. The system is simple to deploy and use to support the squad leader's decision-making process. The system allows Soldiers to obtain local situational awareness and understanding of their immediate surroundings while remaining in covered or concealed positions. The SBS program will be procured through multiple phases. The program will develop, integrate, and qualify additional capabilities for each phase. Project A5A - Small Unmanned Aircraft Systems (SUAS) are critical aviation assets that increase lethality and security through organic aerial reconnaissance, surveillance, resupply, and targeting capabilities for battalion and below echelons. SUAS enhances situational awareness and force protection for maneuver elements operating in complex environments by providing real-time Full Motion Video (FMV) and sensor data through a variety of modular sensors. These multifaceted capabilities enable Army formations to leverage the air-ground littoral to project combat power across domains, disrupt near-peer threats, secure key terrain, lighten Soldier load, and support mission success through persistent overwatch. Leveraging a Modular Open Systems Approach (MOSA), SUAS platforms are designed for rapid adaptation through swappable payloads, advanced autonomous flight capabilities, and scalable software-ensuring relevance against both current and emerging operational threats. Project A5B - Uncrewed Vehicle Control (UVC) Scalable Control Interface (SCI) is a software suite that enables Soldiers to control multiple types of uncrewed or optionally-manned aircraft and payloads through a unified interface, offering scalable authority levels. It enhances the distribution of Unmanned Aircraft Systems (UAS) capabilities by increasing the number of control devices available to Soldiers, Commanders, and Battle Staff, allowing for the simultaneous operation of multiple aircraft and payloads from a single control node. Project A5C - Unmanned Aircraft Systems (UAS) are vital to multi-domain operations (MDO), enabling ground forces to project power across domains to defeat adversaries, secure terrain, and consolidate gains. This includes short and/or vertical takeoff and landing (S/VTOL) Group 4+, Brigade (BDE) and Ultra Endurance- UAS (UE-UAS; previously referred to as Long Endurance) platforms. This includes capabilities to support expeditionary, extended range reconnaissance, surveillance, target acquisition (RSTA), communications, lethality, and electronic warfare, as well as Human Machine Integrated Formations (HMIF) to refine solutions faster than adversaries. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                                 Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System              PE 0605345A / Unmanned Aerial Systems Launched Effects Systems Development Development & Demonstration (SDD) Project A5D - Launched Effects (LE) extends the speed, range, lethality and survivability of maneuver formations through the integration of air vehicles, mission systems, payloads, and behaviors. LE will provide Army formations with the ability to expedite and strengthening the kill web, facilitate the penetration and dis-integration of the enemy's Anti-Access Area Denial (A2AD) environment and extend the maneuver force's reach, lethality, and survivability. The UAS Marketplace expands the Defense Industrial Base, expedites capability delivery, and provides warfighters with vetted, flexible solutions to meet mission requirements. The UAS Marketplace operationalizes a streamlined acquisition framework for both Programs of Record (PoR) and emerging capabilities, while also serving as the mechanism to demonstrate, assess and perform verifications on a range of UAS solutions. The UAS Marketplace empowers the warfighter at the tactical edge, providing the flexibility to procure vetted, mission-specific UAS solutions. The PM UAS will leverage this centralized marketplace to execute UAS procurements and deliveries, ensuring soldiers are equipped through a modern, efficient, scalable, and capability-validated marketplace.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5D.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605347A$$, $$Counter Unmanned Aerial Systems (UAS) Development$$, $$rdte_army_ba5$$, $$asa_alt_alt$$, 2027, 0, 0, 0, NULL, $${}$$::jsonb, NULL, NULL, 154659000, 179711000, 154301000, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 140400000, 359182000, 359182000, NULL, 359182000, 155362000, $$Counter-small Unmanned Aircraft Systems (C-sUAS) funding supports ongoing efforts to provide forces at all echelons with cross-domain capabilities to identify, classify, track, and defeat Groups 1-3 UAS threats, while supporting joint operational requirements. These combined arms solutions support the full kill-chain and result in solutions addressing fixed/semi-fixed, mounted/mobile, dismounted, and handheld missions. Development efforts are aligned with the C-sUAS Capability Development Document (CDD) and Annexes, which codify the threshold and objective capability requirements for C-sUAS development. This funding line supports Homeland Defense and is an Air and Missile Defense Army modernization priority.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5D.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605531A$$, $$Counter - Small Unmanned Aircraft Systems Sys Dev & Demonstration$$, $$rdte_army_ba5$$, $$dw_osd$$, 2026, 55196000, 34701000, 59563000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 19, "original_pe": "0605531A", "page_header": "Department of the Army"}$$::jsonb, $$The Secretary of Defense (SecDef) designated the Secretary of the Army (SA) as the Department of Defense's (DoD) Executive Agent (EA) for Counter-small Unmanned Aircraft Systems (C-sUAS). The EA is tasked with leading, directing, and synchronizing DoD efforts to counter small Unmanned Aircraft System (sUAS) threats while minimizing unnecessary duplication and redundancy. The C-sUAS System Development and Demonstration efforts are in response to DoD Joint Requirements Oversight Council Memorandums (JROC-M) requirements for identification, development, testing, evaluation, and integration of technologies to defeat sUAS threats across the DoD. The efforts provide warfighters the ability to comprehensively detect, track, identify, and defeat threat Group 1, 2 and 3 UAS platforms. The efforts will be joint development efforts to provide integrated solutions to meet the needs of the Military Services and DoD Agencies against emerging threats.$$, NULL, 753000, 593000, 727000, NULL, NULL, 164, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, 57389000, 54078000, 695000, 695000, NULL, 695000, 731000, $$The Secretary of War (SecWar) designated the Secretary of the Army (SA) as the Department of War's (DoW) Executive Agent (EA) for Counter-small Unmanned Aircraft Systems (C-sUAS). The EA is tasked with leading, directing, and synchronizing DoW efforts to counter small Unmanned Aircraft System (sUAS) threats while minimizing unnecessary duplication and redundancy. The C-sUAS System Development and Demonstration efforts are in response to DoW Joint Requirements Oversight Council Memorandums (JROC-M) requirements for identification, development, testing, evaluation, and integration of technologies to defeat sUAS threats across the DoW. The efforts provide warfighters the ability to comprehensively detect, track, identify, and defeat threat Group 1, 2 and 3 UAS platforms. These joint development efforts will provide integrated solutions to meet the needs of the Military Services and DoW Agencies against emerging threats.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5D.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605625A$$, $$Manned Ground Vehicle$$, $$rdte_army_ba5$$, $$peo_gcs$$, 2026, 386393000, 565047000, 499478000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 19, "original_pe": "0605625A", "page_header": "Department of the Army"}$$::jsonb, $$The XM30 is a minimally manned, and open architected combat vehicle that maneuvers Soldiers to a point of positional advantage to engage in close combat and deliver decisive lethality during the execution of combined arms maneuver, while employing semi-autonomous systems. It is designed to operate with, and may operate without, a crew and Soldiers under armor, based on the commander's decision. The XM30 will not fight alone, but rather as part of a section, platoon, and company of mechanized infantry. These companies will execute cross-domain maneuver and defeat pacing threats in close proximity while maneuvering Soldiers to tactical objectives. Once the unit has transitioned to the combined mounted/dismounted fight, the XM30s support the dismounted element with advanced sensors, lethality, protection, and integrated mission command. This synergy is crucial to the Armored Brigade Combat Team's (ABCT) ability to defeat a near peer competitor. The XM30 provides a multitude of capabilities; principal among them are enhanced occupant survivability, overmatch lethality, and a modern system architecture with planned room for growth. The XM30 will provide the American Soldier improved underbody protection due to additional roof height and other enhancements while integrating Active Protection Systems. The XM913 50mm Cannon and Third Generation (3GEN) Forward Looking Infrared (Radar) (FLIR) optics regain penetration capabilities and standoff against near peer threats ensuring overmatch lethality. XM30 is designed for persistent modernization; it's built on a foundational open architecture using modern digital engineering tools that enable rapid upgrades to the vehicle at an accelerated pace and preclude vendor lock. The XM30 Combat Vehicle will be the primary vehicle within the ABCT for the transportation, and combat employment of infantry Soldiers. It will predominantly be organized into platoons and companies within the ABCT. The FY 2026 request was reduced by $3.033 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                            Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System           PE 0605625A / Manned Ground Vehicle Development & Demonstration (SDD)$$, NULL, 310576000, 131634000, 118460000, NULL, NULL, 166, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, 481247000, 372096000, 290069000, 290069000, NULL, 290069000, 108968000, $$The XM30 is a minimally manned, and open architected combat vehicle that maneuvers Soldiers to a point of positional advantage to engage in close combat and deliver decisive lethality during the execution of combined arms maneuver, while employing semi-autonomous systems. It is designed to operate with, and may operate without, a crew and Soldiers under armor, based on the commander's decision. The XM30 will not fight alone, but rather as part of a section, platoon, and company of mechanized infantry. These companies will execute cross-domain maneuver and defeat pacing threats in close proximity while maneuvering Soldiers to tactical objectives. Once the unit has transitioned to the combined mounted/dismounted fight, the XM30s support the dismounted element with advanced sensors, lethality, protection, and integrated mission command. This synergy is crucial to the Armored Brigade Combat Team's (ABCT) ability to defeat a competitor. The XM30 provides a multitude of capabilities; principal among them are enhanced occupant survivability, overmatch lethality, and a modern system architecture with planned room for growth. The XM30 will provide the American soldier improved underbody protection due to additional roof height and other enhancements. The XM30 has enhanced optics that regain penetration capabilities and standoff against near peer threats ensuring overmatch lethality. This combat vehicle is designed for persistent modernization. It's built on a foundational open architecture using modern digital engineering tools that enable rapid upgrades to the vehicle at an accelerated pace and precludes vendor lock. The XM30 Combat Vehicle will be the primary vehicle within the ABCT for the transportation, and combat employment of infantry soldiers. It will predominantly be organized into platoons and companies within the ABCT. The total cost of the XM30 Middle Tier of Acquisition - Rapid Prototyping (MTA-RP) effort is $1,536 million, Research, Development, Test & Evaluation, Army (RDT&E) from FY 2021 - FY 2025. This effort is fully funded across the Future Years Defense Program (FYDP). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0605625A / Manned Ground Vehicle Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5D.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0303032A$$, $$TROJAN - RH12$$, $$rdte_army_ba5$$, $$asa_alt$$, 2026, 3920000, 3879000, 3930000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 19, "original_pe": "0303032A", "page_header": "Department of the Army"}$$::jsonb, $$Trojan research and development supports Trojan Next Generation (Trojan NexGEN), formerly Trojan Classic XXI (TCXXI), future capabilities to fulfill the Army's need for worldwide, deployable, remotable, intelligence, surveillance and reconnaissance support that can dynamically execute operations from sanctuary-based to deployed assets in theater. In support of Army Modernization and Army Force Generation, Trojan NexGEN will provide soldiers with a real-world, hands-on, live and near-real time Signals Intelligence (SIGINT) training environment sustaining, maintaining and enhancing their military occupational specialty proficiencies and specific target expertise. This operational readiness training will fulfill the Army's larger intelligence training requirement via a secure, collaborative architecture. A key factor for future force success is the ability to collect, process, and use information about an adversary while preventing similar information from being disclosed. Trojan NexGEN is a combined operational and readiness mission system which uses advanced networking technology to provide seamless rapid radio relay, secure communications to include voice, data, and electronic reconnaissance support to U.S. forces throughout the world. Trojan NexGEN operations may be easily tailored to fit military intelligence unit training schedules and surged during specific events to involve every aspect of the tactical intelligence collection, processing, analysis and reporting systems. Engineers test and evaluate new digital intelligence collection, processing and dissemination technology using the fielded Trojan NexGEN systems prior to the acquisition of those technologies. As part of the objective intelligence architecture, these capabilities will enable processing and dissemination of real-time intelligence data from various sources to form the intelligence needed to issue orders inside the threat decision cycle. To that end, it is imperative that Trojan NexGEN keeps pace with digitization initiatives in order to respond aggressively to the emerging intelligence communication threat.$$, NULL, 3947000, 3939000, 3980000, NULL, NULL, 170, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, 3930000, 3920000, 3946000, 3946000, NULL, 3946000, 4021000, $$Trojan research and development supports Trojan Next Generation (Trojan NexGEN), formerly Trojan Classic XXI (TCXXI), future capabilities to fulfill the Army's need for worldwide, deployable, remotable, intelligence, surveillance and reconnaissance support that can dynamically execute operations from sanctuary-based to deployed assets in theater. In support of Army Modernization and Army Force Generation, Trojan NexGEN will provide soldiers with a real-world, hands-on, live and near-real time Signals Intelligence (SIGINT) training environment sustaining, maintaining and enhancing their military occupational specialty proficiencies and specific target expertise. This operational readiness training will fulfill the Army's larger intelligence training requirement via a secure, collaborative architecture. A key factor for future force success is the ability to collect, process, and use information about an adversary while preventing similar information from being disclosed. Trojan NexGEN is a combined operational and readiness mission system which uses advanced networking technology to provide seamless rapid radio relay, secure communications to include voice, data, and electronic reconnaissance support to U.S. forces throughout the world. Trojan NexGEN operations may be easily tailored to fit military intelligence unit training schedules and surged during specific events to involve every aspect of the tactical intelligence collection, processing, analysis and reporting systems. Engineers test and evaluate new digital intelligence collection, processing and dissemination technology using the fielded Trojan NexGEN systems prior to the acquisition of those technologies. As part of the objective intelligence architecture, these capabilities will enable processing and dissemination of real-time intelligence data from various sources to form the intelligence needed to issue orders inside the threat decision cycle. To that end, it is imperative that Trojan NexGEN keeps pace with digitization initiatives in order to respond aggressively to the emerging intelligence communication threat.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5D.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0303140A$$, $$Information Systems Security Program$$, $$rdte_army_ba7$$, $$dw_disa$$, 2026, 15040000, 15323000, 15733000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "army", "page_num": 23, "original_pe": "0303140A", "page_header": "Department of the Army"}$$::jsonb, $$This project supports the Army's Command Control (C2) Infrastructure strategy. A portion of this funding line is a key enabler of the Army Modernization Priorities in support of the Communications Security (COMSEC) Key Management Infrastructure (KMI) program. Project 491: Army Chief Information Officer/Deputy Chief of Staff, G-6 manages Information Assurance Development. Project 491: IA Development. Supports the implementation of the National Security Agency (NSA) developed Communications Security (COMSEC) Modernization and Key Management (KM) technologies within the Army. This includes current and next generation encryption techniques, current and future Key Management Infrastructure (KMI) and technology migrations. This program provides oversight in developing policies, guidance, standard operating procedures and recommendations in integrating COMSEC and KM techniques into specific systems in support of securing the Army Tactical and Enterprise Networks. This entails architecture studies, system integration and testing, developing installation kits, and technological collaborations with NSA, DISA and other Services for enterprise and last mile implementations. The program assesses, develops and integrates Cyber Security (CS)/COMSEC tools (hardware and software) which provide protection for fixed infrastructure post, camp and station networks as well as tactical networks. The cited work is consistent with Strategic Planning Guidance (SPG) and the Army Modernization and Strategy Plan (AMSP). IA Development funding implements and establishes functional and technical boundaries of cryptographic, key management and IA capabilities in coordination with the NSA, the DISA, and Joint Services, to secure National Security Systems (NSS), and National Security Information (NSI). Technical evaluations assess the security, operational effectiveness and network interoperability of advanced concept technologies to develop policies, standards, and fundamental building blocks for Army COMSEC capabilities that reduce the risk of future material solutions that could underperform and disrupt classified operations. Develop and publish the COMSEC Implementation Planning Guidance to identify, standardize, and govern the insertion of CS capabilities to bridge operational gaps and support the DoD and NSA mandated requirements to enhance network capacity while providing for secure information exchange of voice, video, and data in accordance with the Army Network Campaign Plan. This will be accomplished by interoperability evaluation, standards testing, and CS, System of System Network Vulnerability Assessments (SoS NVA) for Army Capability Sets for CS/COMSEC capabilities that provide protections for tactical and fixed infrastructure post, camp, and station networks. The program enables the continuation of oversight for the executions of the Army's COMSEC Modernization initiatives including major Advanced Cryptographic Capabilities (ACC) updates and replacements of existing devices and systems to meet NSA mandates. Continue to support the evaluation and testing of new Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                  Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 7: Operational           PE 0303140A / Information Systems Security Program Systems Development technologies to support DoD Cryptographic Moderation 2 (CM2) Army implementations including Transmission Security (TRANSEC), EKMS to KMI migration and tactical network/architecture future Capability Set developments. Provide proof of concepts to provide updated end-to-end, tactical-to-strategic COMSEC standardization and implementation guidance to meet Army's operational requirements. Continuous funding will enable the evaluations and maturity assessment of new COMSEC and key management capabilities developed by DoD joint KMI program for Army fielding to protect and strengthen the Army Network posture, with reduced cryptographic interoperability issues for both embedded and standalone systems. This funding also supports the risk reduction testing to document operational value of commercial products prior to insertion for Army use. Provide timely test and evaluate results to enable the Army to make sound investment strategic decisions and to reduce or eliminate duplications. Also supports efforts to update and develop policies to posture Army's operations to implement innovative cryptographic and key management tools and services. The Defensive Cyberspace Operations (DCO) program provides initial capabilities that enable passive and active cyberspace defense operations to preserve friendly cyberspace capabilities and protect data, networks, net-centric capabilities, and other designated systems. Big Data Pilot provides an advanced analytics capability capable of ingesting structured, semi-structured, and unstructured data from multiple data sources (e.g., Joint Regional Security Stacks (JRSS), intrusion detection systems, intrusion prevention systems, network device log files, trouble tickets, firewalls, proxies, web and applications server log files, etc) and proves situational awareness of cyberspace battlefield. It provides the computer network defense provider with common analytic platform which informs and reduces risk associated with future material solutions and forms a blueprint for future Big Data Analytics. Big Data (analysis-of-all DoD Information Network sensor data) provides two optimized and accredited clusters deployed in support of JRSS and Defense Research and Engineering Network (DREN) with a tools suite accessible to Cyber Mission Forces via secure remote access. The Army's DCO activities are a construct of active cyberspace defenses which provide synchronized, real-time capability to discover, detect, analyze, and mitigate threats to and vulnerability of DoD networks and systems. COMSEC is governed by the Chairman of the Joint Chiefs of Staff Instruction (CJCSA) 6510. In order to ensure Warfighters continue to have secured voice and data communications. Per National Security Agency (NSA) requirements, Army communications systems are required to support modern cryptographic capabilities by implementing continually enhanced communications security technologies. These efforts are consistent with Strategic Planning Guidance (SPG) and are key enablers of the Army Modernization in support of Army 2030/2040. Project DV5 Cryptographic Modernization (Crypto Mod): This project supports the Army's Command Control (C2) Infrastructure strategy. Crypto Mod performs test, evaluation, development, and configuration management for cryptographic devices that receive NSA communications security key and allow for secure communication through Army devices such as In Line Network Encryptors Family (INE), Link/Trunk Encryptors Family (LEF), and Secure Voice Family (SV). This program utilizes NSA developed Communications Security (COMSEC) technologies encryption, memory -safe software and physical separation, integrating these mechanisms into specified systems in support of securing all echelons of the Army Network. This effort supports network operations from end-to-end throughout the force structure thus mitigating networked vulnerabilities to Army information security systems. In order to ensure Warfighters continue to have secured voice and data communications, Army communications systems are required to be upgraded to security technologies including modern algorithms to meet emerging threat developed by our adversaries. Crypto Modernization necessitates the utilization of the latest NSA cryptographic capabilities in order to defeat adversarial efforts to decrypt, disrupt, or exploit US Army networks. COMSEC is the Army's implementation of NSA protections to create a unified network that is protected, resilient, and survivable against cyber security threats. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 7: Operational     PE 0303140A / Information Systems Security Program Systems Development The FY 2026 request was reduced by $0.691 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, NULL, 16030000, 16082000, 16120000, NULL, NULL, 230, $$RDTE - Vol 4 - Budget Activity 7.pdf$$, NULL, FALSE, 28027000, 15040000, 15932000, 15932000, NULL, 15932000, 16490000, $$Project 491: Army Chief Information Officer/Deputy Chief of Staff, G-6 manages Information Assurance Development. Project 491: IA Development. Supports the implementation of the National Security Agency (NSA) developed Communications Security (COMSEC) Moder